const QD={"QAIR1":{intro:"Ce sous-th\u00e8me \u00e9value la performance en qualit\u00e9 de l\u2019air int\u00e9rieur via un mod\u00e8le pr\u00e9dictif (simulation QAI, CDC QAI ou mesures) appliqu\u00e9 aux Blocs Homog\u00e8nes (BH) du b\u00e2timent.",context:"\u00c9valuation sur les polluants : COVT, Formald\u00e9hyde, Benz\u00e8ne, NO\u2082, PM\u2082.\u2085, PM\u2081\u2080 et CO\u2082. Classes A \u00e0 F d\u00e9terminent le nombre de points."},"QAIR1.1":{intro:"Cr\u00e9ation et dimensionnement des Blocs Homog\u00e8nes (BH) pour l\u2019\u00e9valuation de la QAI.",context:"Un BH regroupe des locaux pr\u00e9sentant des caract\u00e9ristiques homog\u00e8nes en termes d\u2019exposition \u00e0 la pollution ext\u00e9rieure, de ventilation et de mat\u00e9riaux en contact avec l\u2019air int\u00e9rieur."},"QAIR1.1.1":{attendu:"D\u00e9clarer la surface totale (en m\u00b2) des espaces caract\u00e9ristiques de l\u2019activit\u00e9 \u00e0 occupation autre que passag\u00e8re (dur\u00e9e de s\u00e9jour > 30 min).",definition:"Locaux \u00e0 occupation autre que passag\u00e8re : locaux impliquant une dur\u00e9e de s\u00e9jour > 30 min. Surface \u00e0 prendre en compte : surface utile. \u00c0 l\u2019international, la surface utilis\u00e9e localement peut \u00eatre prise en compte.",non_applicabilite:"En exploitation (Bâtiment & Gestion) : applicable uniquement si niveau > E vis\u00e9 sur chaque BH. Si niveau E vis\u00e9 globalement, inutile de renseigner.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong><br>Plans.</td><td>Surfaces sur les plans.</td></tr><tr><td><strong>Phases Réalisation et Exploitation (axes Bâtiment et Gestion)</strong><br>Plans.</td><td>Visite in situ et surfaces sur les plans.</td></tr></table>",important:"Pour \u00eatre certifi\u00e9, il est obligatoire de r\u00e9pondre \u00e0 cette exigence."},"QAIR1.1.1.a":{attendu:"D\u00e9clarer la surface totale (en m\u00b2) des blocs homog\u00e8nes cr\u00e9\u00e9s.",definition:"La somme des surfaces des BH doit repr\u00e9senter \u2265 80% de la surface totale des espaces caract\u00e9ristiques (QAIR1.1.1). Si non respect\u00e9 \u2192 PR QAIR1.1.2 non atteint.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong><br>Plans.</td><td>Surfaces sur les plans.</td></tr><tr><td><strong>Phases Réalisation et Exploitation (axes Bâtiment et Gestion)</strong><br>Plans.</td><td>Visite in situ et surfaces sur les plans.</td></tr></table>"},"QAIR1.1.2":{attendu:"S\u2019engager \u00e0 cr\u00e9er des Blocs Homog\u00e8nes (BH) et respecter : Somme surfaces BH \u2265 80% surface totale des espaces caract\u00e9ristiques.",non_applicabilite:"En exploitation : applicable uniquement si niveau > E vis\u00e9. Si niveau E vis\u00e9 globalement \u2192 consid\u00e9r\u00e9e comme atteinte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération.</td><td>Description de la méthode de calcul par échantillonnage à réaliser en introduisant la notion de blocs homogènes (BH).</td></tr><tr><td><strong>Phases Conception et Réalisation</strong><br>Plans de repérage des blocs homogènes et des locaux types, Calcul des surfaces à l\'échelle de l\'ouvrage, Plans / Coupes / Façades du projet, CCTP.</td><td>Cohérence de la détermination des blocs homogènes par rapport aux critères suivants : exposition à la pollution extérieure, caractéristiques de la ventilation et des matériaux en contact avec l\'air intérieur, occupation (durée, intensité)…</td></tr><tr><td><strong>Phase Exploitation</strong><br>Plans de repérage des blocs homogènes et des locaux types, Calcul des surfaces à l\'échelle de l\'ouvrage, Plans / Coupes / Façades du projet, DOE ou tout autre document permettant de justifier de l\'atteinte de l\'exigence (durée de validité illimitée tant que le bâtiment n\'a pas été modifié par rapport aux hypothèses de la preuve).</td><td>Cohérence de la détermination des blocs homogènes par rapport aux critères suivants : exposition à la pollution extérieure, caractéristiques de la ventilation et des matériaux en contact avec l\'air intérieur, occupation (durée, intensité)…</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE \u2014 Op\u00e9ration non certifiable si non atteint."},"QAIR1.2":{intro:"\u00c9valuation de la performance de qualit\u00e9 d\u2019air int\u00e9rieur par polluant et par BH."},"QAIR1.2.1":{attendu:"\u00c9valuer la performance QAI sur la base des \u00e9valuations par BH. 3 m\u00e9thodes : Simulation, CDC QAI ou Mesures.",evaluation:'Classes A\u2192F selon concentrations de polluants :<table style=\"margin:6px 0;width:100%;border-collapse:collapse;font-size:11px\"><tr style=\"background:#0C4A6E;color:#fff\"><td style=\"padding:5px 8px;text-align:center;font-weight:700;border:1px solid #0C4A6E\">A</td><td style=\"padding:5px 8px;text-align:center;font-weight:700;border:1px solid #0C4A6E\">B</td><td style=\"padding:5px 8px;text-align:center;font-weight:700;border:1px solid #0C4A6E\">C</td><td style=\"padding:5px 8px;text-align:center;font-weight:700;border:1px solid #0C4A6E\">D</td><td style=\"padding:5px 8px;text-align:center;font-weight:700;border:1px solid #0C4A6E\">E</td><td style=\"padding:5px 8px;text-align:center;font-weight:700;border:1px solid #0C4A6E\">F</td></tr><tr style=\"background:#F1F5F9\"><td style=\"padding:5px 8px;text-align:center;border:1px solid #E2E8F0\"><b>20</b> pts</td><td style=\"padding:5px 8px;text-align:center;border:1px solid #E2E8F0\"><b>16</b> pts</td><td style=\"padding:5px 8px;text-align:center;border:1px solid #E2E8F0\"><b>12</b> pts</td><td style=\"padding:5px 8px;text-align:center;border:1px solid #E2E8F0\"><b>8</b> pts</td><td style=\"padding:5px 8px;text-align:center;border:1px solid #E2E8F0\"><b>4</b> pts</td><td style=\"padding:5px 8px;text-align:center;border:1px solid #E2E8F0\"><b>0</b> pts</td></tr></table>',echelle:"Construction/R\u00e9novation :\nClasse A : COVT <500, Formald\u00e9hyde <10, Benz\u00e8ne <2, NO\u2082 \u226420, PM\u2082.\u2085 <10 (\u00b5g/m\u00b3)\nClasse B : COVT \u2265500\u20141000, Formald. \u226510\u201430, Benz. \u22652\u20145, NO\u2082 >20\u201440, PM\u2082.\u2085 \u226510\u201425\nClasse C : COVT >1000\u20141500, Formald. >30\u201450, Benz. >5\u201410\nClasse D : COVT >1500\u20142000, Formald. >50\u201470, Benz. >10\u201420\nClasse E : COVT >2000\u20143000, Formald. >70\u2014100, Benz. >20\u201430\nClasse F : COVT >3000, Formald. >100, Benz. >30",methodes:"Simulation : Mathis QAI (CSTB), Indalo (Octopus Lab), CONTAM ou \u00e9quivalent. | CDC QAI : cahier des charges d\u00e9finissant classe vis\u00e9e, BH et moyens. | Mesures : valeurs mesur\u00e9es in situ.",zone_entrepot:"Zone Entrep\u00f4t : classes B\u2192F d\u00e9finies selon produits en contact air int\u00e9rieur (\u00e9tiquetage A+/A) et d\u00e9bit d\u2019air neuf naturel.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération, Lettre d\'engagement sur les substances chimiques cancérigènes.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong><br>Caractéristiques sanitaires des matériaux, CCTP, Plans. Caractéristiques sanitaires des mobiliers (valeurs mesurées ou par défaut). Rapport de simulation ou Cahier des charges QAI selon l\'option choisie.</td><td>Cohérence entre les hypothèses saisies dans l\'outil et les éléments décrits et dessinés sur les sujets suivants : typologie de surface en contact avec l\'air intérieur, émission de polluants des matériaux, caractéristiques du mobilier (valeurs mesurées ou par défaut).</td></tr><tr><td><strong>Phase Réalisation</strong><br>Mise à jour des caractéristiques sanitaires des matériaux en cas de modification du projet, DOE, Fiches techniques et caractéristiques sanitaires des matériaux (si la simulation est choisie), Fiches de déclaration environnementale et sanitaire le cas échéant. Rapport de mesures QAI (si la mesure est choisie). Éléments contractuels des fournisseurs le cas échéant. Mise à jour des caractéristiques sanitaires des mobiliers (valeurs par défaut OU rapport/PV d\'essais dans le cas des valeurs mesurées) en cas de modification du projet.</td><td>Cohérence entre les hypothèses saisies dans l\'outil et les éléments mis en œuvre sur les sujets suivants : typologie de surface en contact avec l\'air intérieur, émission de polluants des matériaux, caractéristiques du mobilier, matériaux utilisés.<br>En cas de mesures QAI, vérification du respect des règles dans les documents suivants :<br>• \"Qualité de l\'air intérieur d\'un bâtiment en exploitation - règles d\'application pour la mesure\" de mai 2021 de l\'Alliance HQE-GBC,<br>• ou la série de normes EN 16798,<br>• ou le cadre de l\'évaluation LEVEL(S),<br>• ou \"D2.4 – ALDREN Methodology note on addressing health and wellbeing\" du projet d\'ALDREN.</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong><br>Plans, Rapport de mesures QAI (durée de validité illimitée tant qu\'il n\'y a pas de modification concernant : la qualité de l\'air extérieur, les caractéristiques sanitaires des mobiliers et des matériaux en contact avec l\'air intérieur, toute modification liée au système de ventilation et de filtration). Cahier des charges QAI si nécessaire (disponible au plus tard lors de la deuxième année du cycle).</td><td>Respect des règles de l\'un des documents suivants :<br>• \"Qualité de l\'air intérieur d\'un bâtiment en exploitation - règles d\'application pour la mesure\" de mai 2021 de l\'Alliance HQE-GBC,<br>• ou la série de normes EN 16798,<br>• ou le cadre de l\'évaluation LEVEL(S),<br>• ou \"D2.4 – ALDREN Methodology note on addressing health and wellbeing\" du projet d\'ALDREN.</td></tr></table>",important:"\u2b50 Exigence principale du th\u00e8me \u2014 jusqu\u2019\u00e0 20 pts sur 20."},"QAIR1.2.2":{important:"PRÉREQUIS OBLIGATOIRE pour la certification.",details:"Les évaluations peuvent se faire dans un seul BH qui répond à toutes les conditions : le BH est le plus représentatif de l\u2019activité du bâtiment, et présente les critères les plus défavorables en termes d\u2019exposition à la pollution.\nNote : le type d\u2019évaluation de la QAI est le même que celui de QAIR1.2.1 (simulation, CDC QAI ou mesures).",attendu:"V\u00e9rifier que les PM\u2081\u2080 simul\u00e9es ou mesur\u00e9es sont \u2264 50 \u00b5g/m\u00b3 (24H) ou \u2264 20 \u00b5g/m\u00b3 (long terme).",non_applicabilite:"Non applicable pour Zone Entrep\u00f4t. En exploitation : applicable si niveau > E vis\u00e9 sur chaque BH.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong><br>Plans. Rapport de simulation ou Cahier des charges QAI selon l\'option choisie.</td><td>Cohérence des hypothèses de la simulation.</td></tr><tr><td><strong>Phase Réalisation</strong><br>Plans. Rapport de simulation ou rapport de mesures selon l\'option choisie.</td><td>Cohérence des hypothèses de la simulation.<br>En cas de mesures QAI, vérification du respect des règles dans les documents suivants :<br>• \"Qualité de l\'air intérieur d\'un bâtiment en exploitation - règles d\'application pour la mesure\" de mai 2021 de l\'Alliance HQE-GBC,<br>• ou la série de normes EN 16798,<br>• ou le cadre de l\'évaluation LEVEL(S),<br>• ou \"D2.4 – ALDREN Methodology note on addressing health and wellbeing\" du projet d\'ALDREN.</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong><br>Plans, Rapport de mesures (durée de validité illimitée tant qu\'il n\'y a pas de modification concernant : la qualité de l\'air extérieur, les caractéristiques sanitaires des mobiliers et des matériaux en contact avec l\'air intérieur, toute modification liée au système de ventilation et de filtration). Cahier des charges QAI si nécessaire (disponible au plus tard lors de la deuxième année du cycle).</td><td>Respect des règles de l\'un des documents suivants :<br>• \"Qualité de l\'air intérieur d\'un bâtiment en exploitation - règles d\'application pour la mesure\" de mai 2021 de l\'Alliance HQE-GBC,<br>• ou la série de normes EN 16798,<br>• ou le cadre de l\'évaluation LEVEL(S),<br>• ou \"D2.4 – ALDREN Methodology note on addressing health and wellbeing\" du projet d\'ALDREN.</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE pour la certification."},"QAIR1.2.3":{important:"PRÉREQUIS OBLIGATOIRE pour la certification.",details:"Justification par mesures selon la norme ISO 16000-26. Mesures conformes aux règles de : \u2022 Alliance HQE-GBC (mai 2021) | \u2022 Série de normes EN 16798 | \u2022 LEVEL(S) indicator 4.1 (v1.1, jan. 2021) | \u2022 D2.4 ALDREN Methodology note.\n\nRemarque France : Indice de confinement (décret n°2012-14, modifié par Décret n°2022-1690). Non obligatoire mais recommandé.",attendu:"V\u00e9rifier que \u0394CO\u2082 (int\u00e9rieur \u2212 ext\u00e9rieur) \u2264 1350 ppm. Si CO\u2082 ext\u00e9rieur non mesur\u00e9 : valeur par d\u00e9faut 400 ppm \u2192 CO\u2082 int\u00e9rieur \u2264 1750 ppm.",non_applicabilite:"Non applicable Zone Entrep\u00f4t. Non applicable en Construction neuve et R\u00e9novation (consid\u00e9r\u00e9e atteinte). En exploitation : applicable si niveau > E vis\u00e9.",confinement:"Indice de confinement (optionnel mais recommand\u00e9) : 0 = nul, 1 = faible, 2 = moyen, 3 = \u00e9lev\u00e9, 4 = tr\u00e8s \u00e9lev\u00e9, 5 = extr\u00eame.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phases Programme, Conception et Réalisation</strong><br>Non concernées.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong><br>Plans, Rapport de mesures</td><td>Respect des règles de l\'un des documents suivants :<br>• \"Qualité de l\'air intérieur d\'un bâtiment en exploitation - règles d\'application pour la mesure\" de mai 2021 de l\'Alliance HQE-GBC,<br>• ou la série de normes EN 16798,<br>• ou le cadre de l\'évaluation LEVEL(S),<br>• ou \"D2.4 – ALDREN Methodology note on addressing health and wellbeing\" du projet d\'ALDREN.</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE pour la certification."},"QAIR1.2.4":{important:"PRÉREQUIS OBLIGATOIRE sauf Zone Entrepôt.",details:"Polluants concernés : COVT, Formaldéhyde, Benzène, NO\u2082, PM\u2082.\u2085, PM\u2081\u2080, CO\u2082. Les seuils Classe C doivent être respectés quel que soit le type de projet (construction neuve, rénovation ou exploitation).\nSi seuils dépassés : plan d\u2019actions correctives élaboré, justifié, et preuve de mise en \u0153uvre fournie.",attendu:"Si valeurs de r\u00e9f\u00e9rence sanitaires d\u00e9pass\u00e9es \u2192 \u00e9laborer un plan d\u2019actions correctives visant une meilleure classe pour chaque polluant concern\u00e9.",non_applicabilite:"Non applicable Zone Entrep\u00f4t. En exploitation : applicable si niveau > E vis\u00e9.",evaluation:"Atteinte si valeurs respectent seuils Classe C pour chaque polluant. OU si plan d\u2019actions correctives \u00e9labor\u00e9 et mis en \u0153uvre.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong><br>Plans d\'actions correctives en cas de dépassement des seuils.</td><td>Cohérence des actions du plan avec le contexte et la conception de l\'opération.</td></tr><tr><td><strong>Phases Réalisation et Exploitation (axes Bâtiment et Gestion)</strong><br>Plans d\'actions correctives mis en œuvre en fonction des seuils dépassés, ou rapport de mesures.</td><td>Cohérence des actions avec le contexte de l\'opération. Si mesure, vérification du respect des règles dans le document \"Qualité de l\'air intérieur d\'un bâtiment en exploitation - règles d\'application pour la mesure\" de mai 2021 de l\'Alliance HQE-GBC ou dans le document \"D2.4 – ALDREN Methodology note on addressing health and wellbeing\" du projet d\'ALDREN.</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE sauf Zone Entrep\u00f4t."},"QAIR2":{intro:"Le renouvellement de l\u2019air est essentiel pour le confort, l\u2019hygi\u00e8ne et la p\u00e9rennit\u00e9 du b\u00e2ti. Diff\u00e9rents syst\u00e8mes de ventilation sont autoris\u00e9s : naturelle, hybride et m\u00e9canique.",context:"Les d\u00e9bits minimaux doivent \u00eatre conformes aux r\u00e8gles d\u2019hygi\u00e8ne r\u00e9glementaires. Dispositifs d\u2019alerte/asservissement CO\u2082 ou humidit\u00e9 permettent de moduler les d\u00e9bits."},"QAIR2.1":{intro:"\u00c9valuation du syst\u00e8me de ventilation mis en place.",perimetre:"B\u00e2timent : syst\u00e8me de ventilation et dispositifs de gestion dans le p\u00e9rim\u00e8tre d\u2019action du demandeur. | Site/Parc : justification b\u00e2timent par b\u00e2timent."},"QAIR2.1.1":{important:"PRÉREQUIS OBLIGATOIRE.",attendu:"Indiquer le type de ventilation : naturelle non contr\u00f4l\u00e9e, naturelle contr\u00f4l\u00e9e, hybride (naturelle assist\u00e9e), ou m\u00e9canique.",details:"Naturelle non contr\u00f4l\u00e9e : ouverture manuelle sans dispositif de contr\u00f4le. Autoris\u00e9e uniquement en exploitation et Zone Entrep\u00f4t.\nNaturelle contr\u00f4l\u00e9e : ouvrants contr\u00f4l\u00e9s par un dispositif (asservissement CO\u2082, etc.).\nHybride : combinaison naturelle + m\u00e9canique basse pression (\u0394P \u2264 50 Pa).\nM\u00e9canique : ventilateurs entra\u00een\u00e9s par moteur \u00e9lectrique.",attention:"En France, le Code du travail (art. R4222-5) : a\u00e9ration par fen\u00eatres autoris\u00e9e si volume/occupant \u2265 15 m\u00b3 (bureaux) ou 24 m\u00b3 (autres).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong><br>CCTP, Plans techniques.</td><td>Définition des systèmes à mettre en place, cohérence des documents écrits et dessinés.</td></tr><tr><td><strong>Phase Réalisation</strong><br>DOE</td><td>Constat in situ de la typologie du système de ventilation mis en place.</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong><br>DOE ou tout autre document permettant de justifier de l\'atteinte de l\'exigence (durée de validité illimitée tant que le bâtiment n\'a pas été modifié par rapport aux hypothèses de la preuve).</td><td>Idem phase Réalisation</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE."},"QAIR2.1.2":{important:"PRÉREQUIS OBLIGATOIRE.",definition:"Déterminer la catégorie ODA de l\u2019air extérieur en comparant les concentrations de polluants aux valeurs limites : SO\u2082 (50 \u00b5g/m\u00b3), NO\u2082 (40 \u00b5g/m\u00b3), O\u2083 (25 jours > 120 \u00b5g/m\u00b3), Benzène (5 \u00b5g/m\u00b3), PM\u2081\u2080 (40 \u00b5g/m\u00b3), PM\u2082.\u2085 (25 \u00b5g/m\u00b3). Données : site Atmo France.",attendu:"D\u00e9terminer la qualit\u00e9 de l\u2019air ext\u00e9rieur (ODA 1, 2 ou 3) pour adapter la filtration.",methode:"Si donn\u00e9es dispo : ratio valeur observ\u00e9e / valeur limite pour SO\u2082, NO\u2082, O\u2083, Benz\u00e8ne, PM\u2081\u2080, PM\u2082.\u2085. Tous < 1 \u2192 ODA 1. Un ratio > 1 mais < 1,5 \u2192 ODA 2. Un > 1,5 \u2192 ODA 3.",par_defaut:"Sans donn\u00e9es : ODA 1 = zones rurales/urbaines peu pollu\u00e9es. ODA 2 = zones urbaines pollu\u00e9es. ODA 3 = r\u00e9gions industrialis\u00e9es/a\u00e9roports.",non_applicabilite:"Non applicable exploitation axe Gestion seul. Exploitation axe B\u00e2timent : applicable si niveau > E vis\u00e9.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Document sur la qualité de l\'air extérieur.</td><td>Cohérence entre les éléments du document sur la qualité de l\'air extérieur et les informations disponibles auprès des organismes spécifiques.</td></tr><tr><td><strong>Phases Conception et Réalisation</strong><br>Mise à jour du document sur la qualité de l\'air extérieur.</td><td>Cohérence entre les éléments du document sur la qualité de l\'air extérieur et les informations disponibles auprès des organismes spécifiques.</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong><br>Document sur la qualité de l\'air extérieur (durée de validité : 1 an).</td><td>Idem phases Conception et Réalisation.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong><br>Non concernée.</td><td>Sans objet</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE."},"QAIR2.1.3":{important:"PRÉREQUIS OBLIGATOIRE.",details:"Ventilation naturelle contrôlée : atteinte uniquement si air extérieur ODA 1.\nVentilation hybride ou mécanique : moyens de filtration adaptés nécessaires.\nOption alternative : filtration ciblée sur polluant(s) problématique(s) (ratio > 1,5), puis recalcul de la classe ODA et sélection du filtre correspondant.\nRéférence : Annexe 2 du guide du thème.",attendu:"S\u00e9lectionner la classe de filtre (SUP 2 en construction/r\u00e9novation, SUP 3 en exploitation) selon norme EN 16798-3.",filtration:"ODA 1 + SUP 2 \u2192 F7 | ODA 2 + SUP 2 \u2192 M5+F7 | ODA 3 + SUP 2 \u2192 F7+F7.\nVentilation naturelle contr\u00f4l\u00e9e : atteinte uniquement si air ext\u00e9rieur ODA 1.\nISO 16890 remplace EN 779 : M5 \u2248 ePM\u2081 5-35%, F7 \u2248 ePM\u2081 40-65%, F9 \u2248 ePM\u2081 80-90%.",non_applicabilite:"Non applicable Zone Entrep\u00f4t. Exploitation : d\u00e9pend du niveau, p\u00e9rim\u00e8tre et type de ventilation.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération.</td><td>Définition des objectifs à atteindre en cohérence avec l\'annexe A.3 de la norme NF EN 16798-3 concernant le niveau de filtration et la qualité d\'air intérieur.</td></tr><tr><td><strong>Phase Conception</strong><br>CCTP, Plans techniques.</td><td>En cas de ventilation mécanique ou hybride, cohérence entre les exigences de l\'annexe A.3 de la norme NF EN 16798-3 et les éléments du projet décrits et dessinés.</td></tr><tr><td><strong>Phase Réalisation</strong><br>DOE</td><td>En cas de ventilation mécanique ou hybride, cohérence entre les exigences de l\'annexe A.3 de la norme NF EN 16798-3 et les éléments du projet mis en place. Constat in situ du niveau de filtration.</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong><br>DOE ou tout autre document permettant de justifier de l\'atteinte de l\'exigence (durée de validité illimitée tant que le bâtiment n\'a pas été modifié par rapport aux hypothèses de la preuve).</td><td>Idem phase Réalisation</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE."},"QAIR2.1.4":{important:"PRÉREQUIS OBLIGATOIRE.",details:"Problématiques à considérer :\n\u2022 Thermiques : grilles à H > 1,8 m ou derrière corps de chauffe\n\u2022 Acoustiques : traitement acoustique des grilles (absorbeur dans l\u2019épaisseur du mur)\n\u2022 Qualité d\u2019air : grilles loin des orifices d\u2019air rejeté et aires de chargement.\nSi pas d\u2019enjeu pour Thermique ou Acoustique, la problématique est considérée comme traitée.",attendu:"Justifier le positionnement des entr\u00e9es/sorties d\u2019air selon 3 probl\u00e9matiques : thermique (grilles H > 1,8 m), acoustique (traitement acoustique des grilles), qualit\u00e9 d\u2019air (loin des rejets d\u2019air vici\u00e9).",non_applicabilite:"Non applicable exploitation axe Gestion seul.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong><br>Plans techniques.</td><td>Définition des systèmes à mettre en place, cohérence des documents écrits et dessinés.</td></tr><tr><td><strong>Phase Réalisation</strong><br>Plans techniques.</td><td>Constat in situ du positionnement des éléments d\'introduction d\'air neuf et d\'évacuation de l\'air vicié.</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong><br>Plans techniques (durée de validité illimitée tant que le bâtiment n\'a pas été modifié par rapport aux hypothèses de la preuve).</td><td>Idem phase Réalisation</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong><br>Non concernée</td><td>Sans objet</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE."},"QAIR2.1.5":{important:"PRÉREQUIS OBLIGATOIRE \u2014 les débits doivent être justifiés.",details:"Norme EN 16798-1 : 3 méthodes de détermination des débits :\n\u2022 Méthode 1 (Tab. B.6, B.7, B.8) : polluants bâtiment + occupation\n\u2022 Méthode 2 : débits asservis au taux d\u2019occupation\n\u2022 Méthode 3 : débits types par catégorie d\u2019air intérieur (I, II, III, IV).\nCatégorie II = situation normale (locaux tertiaires occupés en permanence).\nMesures en sortie de bouche (norme NF EN 12599).",attendu:"Garantir que le d\u00e9bit d\u2019air neuf (m\u00b3/h) correspond au contexte des locaux, adapt\u00e9 \u00e0 l\u2019activit\u00e9 et \u00e0 l\u2019occupation.",reglementation:"En France : Code du Travail + R\u00e8glement Sanitaire D\u00e9partemental Type (RSDT). Norme EN 16798-1 : d\u00e9bits allant au-del\u00e0 des minimums r\u00e9glementaires.",mesures:"R\u00e9alisation & Exploitation : mesures des d\u00e9bits en sortie de bouche (norme NF EN 12599).",non_applicabilite:"Non applicable Zone Entrep\u00f4t.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong><br>Programme de l\'opération.</td><td>Objectifs de débits à atteindre par local.</td></tr><tr><td><strong>Phase Conception</strong><br>CCTP, Plans, descriptifs des équipements choisis. En cas de ventilation naturelle : Document de justification du débit de ventilation.</td><td>Cohérence entre les hypothèses et les éléments décrits et dessinés sur les débits d\'air neuf.</td></tr><tr><td><strong>Phase Réalisation</strong><br>En cas de ventilation naturelle : document de justification du débit de ventilation. En cas de ventilation mécanique : descriptifs des équipements mis en œuvre, rapport de mesure des débits de ventilation.</td><td>Cohérence entre les hypothèses et les éléments décrits et dessinés sur les débits d\'air neuf.<br>Cohérence entre les hypothèses et les mesures de débits d\'air neuf.</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong><br>En cas de ventilation naturelle : document de justification du débit de ventilation. En cas de ventilation mécanique : descriptifs des équipements mis en œuvre, rapport de mesure des débits de ventilation.</td><td>Cohérence entre les hypothèses et les mesures de débits d\'air neuf.</td></tr></table>",important:"PR\u00c9REQUIS OBLIGATOIRE \u2014 les d\u00e9bits doivent \u00eatre justifi\u00e9s."},"QEAU1":{intro:"Ce sous-thème évalue la conception des réseaux de distribution d\'eau intérieurs : choix des matériaux, organisation et protection des réseaux.",context:"L\'objectif est de réduire le risque sanitaire lié à l\'altération des matériaux, aux piquages accidentels, aux retours d\'eau et à la mauvaise maîtrise de l\'hydraulique et de la température."},"QEAU1.1":{intro:"Choix des matériaux constitutifs des réseaux d\'eau intérieurs pour éviter l\'altération de la qualité de l\'eau.",context:"Les matériaux des canalisations, réservoirs et équipements fixes doivent éviter la dégradation des qualités organoleptiques, la dissolution de matières (plomb, cuivre…) et le développement bactérien."},"QEAU1.1.1":{attendu:"Justifier l\'absence de plomb dans le réseau intérieur OU démontrer que la teneur en plomb ne dépasse pas 10 μg/L d\'eau distribuée.",definition:"En neuf : interdiction de mettre en œuvre des canalisations en plomb. En existant : mesurer la teneur en plomb et s\'assurer du respect du seuil de 10 μg/L (Directive européenne n°98/83/CE).",non_applicabilite:"En rénovation et exploitation (axes Bâtiment et Gestion) : non-applicable si les réseaux d\'eau ne font pas partie des travaux de rénovation ou du périmètre de responsabilité du demandeur.",reglementation:"Arrêté du 29 mai 1997 (matériaux en contact avec l\'eau destinée à la consommation humaine). À l\'international, les réglementations locales équivalentes sont utilisables.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phases Programme, Conception et Réalisation</strong></td><td>Attestation absence de plomb (neuf) ou Résultats de diagnostic (rénovation)</td><td>Vérification de la teneur en plomb, mesures correctives si nécessaire</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE plomberie, Diagnostic</td><td>Vérification de la teneur en plomb dans l\'eau, du diagnostic et des mesures correctives</td></tr></table>"},"QEAU1.1.2":{attendu:"Choisir des matériaux résistants aux traitements thermiques ou chimiques de désinfection curative des réseaux d\'eau froide en cas de contamination.",definition:"Si une contamination est détectée sur le réseau d\'eau froide, il faut pouvoir procéder à un traitement curatif (chimique et/ou thermique). Les matériaux doivent être compatibles avec ces traitements.",non_applicabilite:"En rénovation et exploitation : non-applicable si les réseaux d\'eau ne font pas partie des travaux ou du périmètre de responsabilité du demandeur.",reglementation:"Guide technique du CSTB de 2012. À l\'international : réglementations locales équivalentes.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP</td><td>Respect des exigences du guide technique du CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE</td><td>Respect du guide CSTB ou équivalent + vérification in situ</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE ou tout autre document</td><td>Respect du guide CSTB ou équivalent + vérification in situ</td></tr></table>"},"QEAU1.2":{intro:"Organisation et protection des réseaux de distribution d\'eau intérieurs.",context:"Ce bloc d\'exigences concerne l\'identification des usages, la protection des réseaux et la procédure de mise en eau. Non-applicable en Exploitation axe Gestion seul."},"QEAU1.2.1":{attendu:"Identifier les usages de l\'eau sur l\'opération, localiser les points de puisage et organiser le réseau intérieur en réseaux types.",definition:"Un réseau type alimente des points de puisage à usages similaires en termes de qualité. En France : Décret n°2022-1720 du 29/12/2022 relatif aux usages de l\'eau.",reglementation:"Guide technique du CSTB. À l\'international : guides techniques locaux équivalents.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect des exigences du guide CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE</td><td>Respect du guide CSTB ou équivalent + vérification in situ</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE ou tout autre document</td><td>Respect du guide CSTB ou équivalent + vérification in situ</td></tr></table>"},"QEAU1.2.2":{attendu:"Respecter les règles de protection des équipements raccordés, des réseaux types et du branchement public (norme NF EN 1717).",definition:"Assurer la protection de tous les éléments du réseau intérieur. Choix des équipements de protection conformément à la norme NF EN 1717 (Mars 2001).",reglementation:"Guide Technique du CSTB – Chapitre V – Fiches n°1 à 4. Norme NF EN 1717. Guide technique du CSTB de 2012. À l\'international : guides techniques locaux équivalents.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect du guide CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE</td><td>Respect du guide CSTB + vérification in situ</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE (validité illimitée si bâtiment non modifié)</td><td>Respect du guide CSTB + vérification in situ</td></tr></table>"},"QEAU1.2.3":{attendu:"Définir et mettre en œuvre une procédure de réception de l\'installation : mise en eau par secteurs et puisage d\'eau pour les locaux non occupés.",definition:"Mise en eau par secteurs pour éviter stagnation et contamination. Puisage d\'eau pour les locaux non occupés. En exploitation : procédure de gestion des locaux inoccupés.",attention:"La procédure peut être mise en place par secteurs. S\'il n\'y a pas de période d\'inoccupation entre livraison et exploitation, seule l\'exigence de mise en eau s\'applique.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>Procédure de réception</td><td>Cohérence avec le planning et le phasage</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Rapport de mise en service</td><td>Constat in situ de la cohérence du rapport</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Application de la procédure</td><td>Procédure de gestion pour les locaux inoccupés (validité illimitée)</td></tr></table>"},"QEAU2":{intro:"Ce sous-thème concerne la maîtrise de la température et de la qualité de l\'eau dans les réseaux, la gestion de l\'eau non potable et les réseaux bouclés.",context:"Risques principaux : développement de légionelles (25°C–45°C), brûlures (>50°C), contamination bactériologique. Exposition par ingestion, inhalation et contact cutané."},"QEAU2.1":{intro:"Maîtrise des réseaux d\'Eau Chaude Sanitaire (ECS) et d\'Eau Froide Sanitaire (EFS).",context:"Non-applicable si : pas de réseaux d\'ECS, rénovation ne concerne pas les réseaux EFS/ECS, ou exploitation axe Gestion seul. Distribution par ballons ponctuels ≠ réseau."},"QEAU2.1.1":{attendu:"Mettre en œuvre un(des) réseau(x) d\'ECS assurant une température > 50°C en tout point (sauf antennes < 3 L). Si stockage ≥ 400 L : eau ≥ 55°C en permanence à la sortie ou portée à température au moins 1×/24h.",definition:"Maîtrise du couple risque légionelles (25–45°C) / risque brûlure (>50°C).",reglementation:"Arrêté du 30/11/2005. Guide CSTB – Ch. II – Fiche n°10. Circulaire DGS n°2007-126. À l\'international : guides équivalents.",attention:"Pour les territoires en climat chaud/humide (Réunion, Mayotte, Guadeloupe, Martinique, etc.), exigence obligatoirement atteinte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect du guide CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE ou tout autre document</td><td>Respect du guide CSTB + vérification in situ</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée si non modifié)</td><td>Respect du guide CSTB + vérification in situ</td></tr></table>"},"QEAU2.1.2":{attendu:"Température garantie à 55°C en tout point des systèmes de distribution d\'ECS (sauf antennes < 3 L). Veiller à éviter les brûlures aux points de puisage.",definition:"Solutions : bouclage du réseau (circulation permanente) ou rubans chauffants (vérifier compatibilité matériaux). Abaissement de température au plus près des points de puisage.",reglementation:"Arrêté du 30/11/2005. Guide CSTB – Partie I – Ch. II – Fiche n°10. À l\'international : guides équivalents.",attention:"Pour les territoires en climat chaud/humide : exigence obligatoirement atteinte. | Nota : pièce destinée à la toilette → température < 50°C ; doit contenir au moins une douche ou baignoire.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Vérification des dispositifs anti-brûlure</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE ou tout autre document</td><td>Vérification des dispositifs anti-brûlure</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée)</td><td>Constat in situ</td></tr></table>"},"QEAU2.1.3":{attendu:"Assurer le calorifugeage des réseaux d\'ECS.",definition:"Rénovation/existant : uniquement les réseaux rénovés. Liaison terminale entre boucle et point de puisage à proximité : non obligatoirement calorifugée (si encastré ou en zone chauffée).",attention:"Pour les territoires en climat chaud/humide : exigence obligatoirement atteinte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP</td><td>Présence du calorifugeage dans les CCTP</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE</td><td>Visite in situ, vérification du calorifugeage</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée)</td><td>Visite in situ, vérification du calorifugeage</td></tr></table>"},"QEAU2.1.4":{attendu:"Calorifugeage séparé des réseaux d\'ECS et d\'EFS ET dispositions pour éviter le réchauffement des canalisations d\'EFS.",definition:"Éloigner EFS et ECS (distance min. 15 cm), disposer l\'EFS loin de toute source de chaleur, sur-calorifuger l\'EFS. Rénovation : uniquement les réseaux rénovés.",attention:"Territoires en climat chaud/humide : exigence obligatoirement atteinte. Le calorifugeage et sur-calorifugeage de l\'EFS n\'est pas obligatoire dans ces territoires.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect des exigences du guide CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE</td><td>Constat in situ des dispositions prises</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée)</td><td>Constat in situ des dispositions prises</td></tr></table>"},"QEAU2.1.5":{attendu:"Identifier les points à risque du réseau intérieur, fournir une cartographie et prendre des dispositions pour prévenir le risque de développement de légionelles.",definition:"Réduire la distance entre points de puisage et réseau bouclé, proscrire les bras morts, concevoir un maillage simple. Cartographie : forme libre (plans, tableaux).",reglementation:"Arrêté du 30/11/2005. À l\'international : guides techniques locaux équivalents.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs à atteindre</td></tr><tr><td><strong>Phase Conception</strong></td><td>Cartographie, CCTP des dispositifs</td><td>Cohérence entre cartographie et documents</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Cartographie, DOE, visite in situ</td><td>Cohérence entre cartographie et éléments mis en œuvre</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Visite in situ</td><td>Cohérence des éléments mis en œuvre</td></tr></table>"},"QEAU2.2":{intro:"Surveillance de la qualité physico-chimique et bactériologique de l\'eau potable aux points d\'usage.",context:"Comprend les analyses D1, D1+D2, et les analyses bactériologiques complémentaires (légionnelles, Pseudomonas aeruginosa, microorganismes revivifiables)."},"QEAU2.2.1":{attendu:"Réaliser des analyses de la qualité physico-chimique de l\'eau aux points d\'usage (D1 et/ou D2), avec dispositions correctives en cas de non-conformité.",definition:"Exigence graduée : D1 + dispositions (2 pts) | D1+D2 + dispositions (4 pts) | + bactério légionnelles OU autres (5 pts) | + bactério légionnelles ET autres (6 pts). Analyses par laboratoire accrédité EA.",reglementation:"Arrêté du 11/01/2007, modifié le 30/12/2022 (limites de qualité des eaux). À l\'international : réglementations locales équivalentes.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>Documents de préparation des analyses</td><td>Vérification des polluants recherchés</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Analyse d\'eau (validité 1 an, D2 : 5 ans). Accréditation du labo</td><td>Adéquation des conclusions et actions correctives</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Analyse d\'eau (validité 1 an, D2 : 5 ans). Accréditation du labo</td><td>Vérification des seuils requis</td></tr></table>"},"QEAU2.2.2":{attendu:"Fournir à l\'exploitant un carnet sanitaire et/ou une analyse des risques inhérents à l\'installation.",definition:"Niv. 1 (1 pt) : Carnet sanitaire (plans, travaux, maintenance, traitements, résultats d\'analyses, températures). | Niv. 2 (2 pts) : + analyse des risques (points de contrôle, dispositions préventives, gammes de maintenance).",non_applicabilite:"Non-applicable en exploitation axe Gestion (traité dans Gestion Durable), ou si les réseaux ne font pas partie du périmètre du demandeur.",reglementation:"Arrêté du 30/12/2022 (évaluation des risques des installations intérieures). Obligatoire en France pour certains bâtiments (santé, écoles, crèches, sports, hôtels, etc.).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>Carnet sanitaire</td><td>Cohérence avec les dispositions prévues</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Carnet sanitaire + analyse des risques (validité 1 an)</td><td>Cohérence entre carnet et éléments du projet</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Carnet sanitaire + analyse des risques (validité 1 an)</td><td>Cohérence</td></tr></table>"},"QEAU2.3":{intro:"Réseau d\'eau non potable : maîtrise de la conception et protection du réseau d\'eau potable.",context:"Non-applicable si : pas de réseaux d\'eau non potable, exploitation axe Gestion seul, ou réseaux hors périmètre du demandeur."},"QEAU2.3.1":{attendu:"Maîtriser la conception du système de récupération d\'eau non potable pour usages internes. Filtration ≤ 1 mm en amont de la cuve. Fournir un carnet d\'entretien.",definition:"En France : arrêté du 21/08/2008 (récupération des eaux de pluie). À l\'international : norme EN 16941-1.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect de l\'arrêté du 21/08/2008 ou norme EN 16941-1</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, carnet sanitaire</td><td>Vérification + vérification in situ</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>DOE, carnet sanitaire (validité illimitée)</td><td>Tenue du carnet + vérification in situ</td></tr></table>"},"QEAU2.3.2":{attendu:"Assurer la séparation, la protection et la signalisation du réseau d\'eau non potable.",definition:"Séparation totale des réseaux. Signalétique pérenne (matériaux/couleurs différents — un autocollant ne suffit pas). Bac de disconnexion (AA, AB ou AE). Robinets verrouillables. Pictogramme à chaque point d\'usage.",reglementation:"Guide CSTB – Ch. III – Fiche n°3. À l\'international : guides équivalents.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect du guide CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE</td><td>Vérification in situ</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée)</td><td>Respect des exigences + vérification in situ</td></tr></table>"},"QEAU2.4":{intro:"En présence de réseau(x) bouclé(s) d\'ECS.",context:"Non-applicable si : pas de réseaux bouclés, exploitation axe Gestion seul, ou réseaux hors périmètre du demandeur."},"QEAU2.4.1":{attendu:"Contrôle de la température à chaque retour de boucle et aux points à risque identifiés.",definition:"Mise en place de simples sondes de température (pas d\'obligation de système automatique).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Description des dispositifs de contrôle</td></tr><tr><td><strong>Phase Réalisation et Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée)</td><td>Constat in situ des dispositifs de contrôle</td></tr></table>"},"QEAU2.4.2":{attendu:"Contrôle automatique des températures du réseau de bouclage, a minima sur les départs et retours de chaque boucle principale.",definition:"Relevé en continu, rapatriement des données, suivi en temps réel, alarmes en cas de température anormale. Si plusieurs réseaux séparés : contrôle de chaque départ et retour.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Description des dispositifs automatiques</td></tr><tr><td><strong>Phase Réalisation et Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée)</td><td>Constat in situ des dispositifs automatiques</td></tr></table>"},"QEAU2.4.3":{attendu:"Dimensionnement des réseaux en intégrant le calcul de l\'équilibrage, avec vitesse > 0,20 m/s dans tous les retours de boucle.",definition:"Conforme au Guide CSTB de 2012 (Kv/Ks des organes de réglage, pertes de charge, etc.). Un système auto-équilibré surdimensionne légèrement les réseaux.",reglementation:"Guide « Maîtrise du risque de développement des légionelles dans les réseaux d\'ECS » du CSTB – Ch. 3. À l\'international : guides équivalents.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP</td><td>Description des exigences CSTB pour le calcul de l\'équilibrage</td></tr><tr><td><strong>Phase Réalisation et Exploitation axe Bâtiment</strong></td><td>Calcul de l\'équilibrage (validité illimitée)</td><td>Respect des exigences du guide CSTB ou équivalent</td></tr></table>"},"QEAU2.4.4":{attendu:"Dispositions pour pouvoir inverser le sens de circulation colonne par colonne pour la maintenance préventive ou en cas de contamination.",definition:"Vanne d\'isolement sur alimentation « aller » + organe de réglage au pied de chaque colonne OU organe auto-nettoyant avec purge. Inversion uniquement si T° < 50°C. Désinfection par eau à 60°C + complément chloré (2 mg/L).",reglementation:"Guide CSTB de 2012 – Annexe 3 (procédure curative en présence de légionelles). À l\'international : guides équivalents.",attention:"La procédure doit prévoir la protection des utilisateurs habituels lors de la mise en œuvre.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Cohérence des éléments écrits/dessinés</td></tr><tr><td><strong>Phase Réalisation et Exploitation axe Bâtiment</strong></td><td>DOE (validité illimitée)</td><td>Constat in situ des dispositions prises</td></tr></table>"},"QEAU3":{intro:"Maîtrise des traitements d\'entretien et de décontamination des réseaux intérieurs.",context:"Non-applicable si : pas de traitements, ou en exploitation/rénovation lorsque les traitements ne font pas partie du périmètre du demandeur."},"QEAU3.1":{intro:"Choix des traitements d\'entretien du réseau intérieur : désinfection, anti-corrosion, anti-tartre.",context:"L\'eau à destination de la consommation humaine ne doit pas être traitée (Code de la Santé Publique en France)."},"QEAU3.1.1":{attendu:"Garantir l\'adéquation des traitements (produits et concentration) avec la nature de l\'eau et la constitution du réseau intérieur.",definition:"Par « adéquation » : choix de produits et concentrations compatibles avec l\'eau et les matériaux. Actions : calcul du potentiel d\'entartrage, points d\'injection, signalisation, sectionnement.",reglementation:"Circulaire DG 5/VS 4 n°2000-166 du 28/03/2000. Code de la Santé Publique. Guide CSTB. À l\'international : réglementations équivalentes.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect du guide CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE ou tout autre document</td><td>Vérification</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong></td><td>DOE (validité illimitée)</td><td>Respect des exigences + vérification in situ</td></tr></table>"},"QEAU3.1.2":{attendu:"Envisager dès la conception des méthodes de traitement autres que chimiques pour les traitements en continu et garantir l\'adéquation avec l\'eau et le réseau.",definition:"Exemples : ionisation (électrolyse argent/cuivre), filtration (micro, ultra, nano, osmose inverse). Le choix du dispositif doit être justifié.",attention:"Les systèmes avec résine et sel pour le traitement anti-tartre ne permettent PAS de répondre à cette exigence.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Description des systèmes mis en place</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE ou tout autre document</td><td>Vérification</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong></td><td>DOE (validité illimitée)</td><td>Vérification in situ</td></tr></table>"},"QEAU3.2":{intro:"Performance des traitements de désinfection et/ou anti-corrosion et/ou anti-tartre.",context:"Tubes témoins et robinets de prélèvement pour le contrôle de la performance."},"QEAU3.2.1":{attendu:"Mettre en place des tubes témoins sur les départs d\'EFS et d\'ECS ainsi que sur le retour d\'ECS (si réseau bouclé) et un robinet de prélèvement flambable en aval.",definition:"Cf Guide CSTB – Ch. II – Fiche n°12. Mettre en œuvre des matériaux inflammables ou incombustibles à proximité pour le flambage en toute sécurité.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Pas de points particuliers vérifiés a minima</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE ou tout autre document</td><td>Vérification</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong></td><td>DOE (validité illimitée)</td><td>Vérification in situ</td></tr></table>"},"QEAU3.2.2":{attendu:"Mettre en place des robinets de prélèvement avant et après le(s) dispositif(s) de traitement s\'il en existe.",definition:"Permettre les prélèvements pour vérifier l\'efficacité des traitements.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Respect du guide CSTB ou équivalent</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE</td><td>Vérification</td></tr><tr><td><strong>Phase Exploitation axes Bâtiment et Gestion</strong></td><td>DOE (validité illimitée)</td><td>Respect des exigences + vérification in situ</td></tr></table>"},"QEAU4":{intro:"Qualité des eaux des espaces de baignade (piscines, spas, etc.).",context:"Non-applicable si : pas d\'espaces de baignade, ou espaces hors périmètre du demandeur."},"QEAU4.1":{intro:"Actions de surveillance de la qualité de l\'eau des espaces de baignade.",context:"L\'apport de polluants par les usagers est une source intrinsèque de pollution. L\'ajout de produits chlorés peut dégrader la qualité (trichloramine, THM, etc.)."},"QEAU4.1.1":{attendu:"Implanter un dispositif de contrôle en continu de la qualité des eaux de baignade avant l\'arrivée dans le(s) bassin(s).",definition:"Aller plus loin que les robinets de prélèvements réglementaires. Sondes couplées à un système d\'alerte. Bonne qualité = efficacité du traitement + limitation de la pollution importée.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Cohérence des éléments écrits/dessinés</td></tr><tr><td><strong>Phase Réalisation et Exploitation</strong></td><td>DOE (validité illimitée)</td><td>Sans objet</td></tr></table>"},"QEAU4.1.2":{attendu:"Dimensionner l\'installation pour éviter les dépôts de pollution dans les eaux de baignade.",definition:"Prévenir : mauvaise circulation (débit non maîtrisé), encrassement rapide des filtres (prévoir un pré-filtre), zones mortes dans le bassin, mauvaise évacuation des eaux polluées, mauvaise diffusion du désinfectant.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Cohérence des éléments écrits/dessinés</td></tr><tr><td><strong>Phase Réalisation et Exploitation</strong></td><td>DOE (validité illimitée)</td><td>Sans objet</td></tr></table>"},"QEAU4.2":{intro:"Maîtrise des traitements des eaux de baignade.",context:"Limiter les sous-produits de la chloration (trichloramine, THM) tout en garantissant la désinfection."},"QEAU4.2.1":{attendu:"Veiller lors de la conception à limiter le recours à un traitement chimique complémentaire.",definition:"Dimensionner correctement le système filtrant et les locaux techniques. Positionner correctement l\'injection du désinfectant.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Cohérence des éléments écrits/dessinés</td></tr><tr><td><strong>Phase Réalisation et Exploitation</strong></td><td>DOE (validité illimitée)</td><td>Sans objet</td></tr></table>"},"QEAU4.2.2":{attendu:"Maîtriser la teneur en trichloramines dans l\'eau du(des) bassin(s). Seuils : < 0,3 mg/L (2 pts) ou < 0,1 mg/L (4 pts).",definition:"Deux possibilités : 1) Désinfection complémentaire (ionisation, ozonation, UV, piscines naturelles). 2) Extraction physique de la trichloramine (colonnes de strippage, dégazage naturel). Concentration dans l\'air < 0,5 mg/m³ (INRS).",reglementation:"INRS : méthode de prélèvement et d\'analyse de la trichloramine. Seuil 0,3 mg/L → teneur air = 0,5 mg/m³ (limite de confort INRS).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques</td><td>Cohérence des éléments écrits/dessinés</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, carnet de maintenance</td><td>Cohérence des éléments</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Résultats d\'analyses d\'eau (validité 1 an)</td><td>Respect des valeurs seuils</td></tr></table>"}
,
"ACOU2":{
  "intro":"Les indicateurs de performance acoustique ACOU2.1.1 \u00e0 ACOU2.1.7 d\u00e9finissent les crit\u00e8res d\u2019\u00e9valuation de chaque Bloc Homog\u00e8ne. Le score obtenu (0\u201320 points) pour chaque BH est calcul\u00e9 dans le fichier Excel th\u00e8me \u00e0 partir de ces indicateurs.",
  "context":"Chaque indicateur est \u00e9valu\u00e9 par type de local selon les tableaux \u00ab \u00c9chelles d\u2019\u00e9valuation \u00bb avec une notation par classes de performance (A \u00e0 F). Le r\u00e9sultat agr\u00e9g\u00e9 alimente la note ACOU1.1.3."
},
"ACOU2.1":{
  "intro":"Sept indicateurs acoustiques sont \u00e9valu\u00e9s par Bloc Homog\u00e8ne. Les indicateurs applicables varient selon le type d\u2019espace.",
  "context":"En exploitation axe Gestion : les indicateurs DnT,A / DnT,A,tr / L\u2019nT,w ne sont pas applicables. Les indicateurs LnAT / Tr / STI / sonorit\u00e9 \u00e0 la marche s\u2019appliquent avec des conditions particuli\u00e8res. En exploitation axe B\u00e2timent : si le niveau E n\u2019est pas atteint, un plan d\u2019actions incluant des objectifs chiffr\u00e9s et argument\u00e9s est demand\u00e9."
},
"ACOU2.1.1":{
  "attendu":"\u00c9valuer l\u2019isolement acoustique standardis\u00e9 pond\u00e9r\u00e9 vis-\u00e0-vis des bruits a\u00e9riens ext\u00e9rieurs pour chaque local du Bloc Homog\u00e8ne.",
  "definition":"<strong>DnT,A,tr = DnT,w + Ctr</strong><br><strong>Ctr</strong> : terme d\u2019adaptation prenant en compte les caract\u00e9ristiques du spectre d\u2019un bruit de trafic pond\u00e9r\u00e9 A.<br><strong>DnT,w</strong> : isolement acoustique standardis\u00e9 pond\u00e9r\u00e9. Il permet de caract\u00e9riser par une seule valeur l\u2019isolement aux bruits a\u00e9riens entre deux locaux, ou entre l\u2019ext\u00e9rieur et un local, en tenant compte de la dur\u00e9e de r\u00e9verb\u00e9ration du local de r\u00e9ception.",
  "non_applicabilite":"En Exploitation axe Gestion, cette exigence n\u2019est pas applicable.",
  "reglementation":"\u00c9tablissements d\u2019enseignement : article 2 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003). | H\u00f4tels : article 2 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003). | Valeurs d\u2019isolement jamais inf\u00e9rieures \u00e0 30 dB (dur\u00e9e de r\u00e9verb\u00e9ration de 0,5 s \u00e0 toutes les fr\u00e9quences)."
},
"ACOU2.1.2":{
  "attendu":"\u00c9valuer l\u2019isolement acoustique standardis\u00e9 pond\u00e9r\u00e9 vis-\u00e0-vis des bruits a\u00e9riens entre locaux pour chaque local du Bloc Homog\u00e8ne.",
  "definition":"<strong>DnT,A = DnT,w + C</strong><br><strong>C</strong> : terme d\u2019adaptation prenant en compte les caract\u00e9ristiques du spectre d\u2019un bruit rose pond\u00e9r\u00e9 A.<br><strong>DnT,w</strong> : isolement acoustique standardis\u00e9 pond\u00e9r\u00e9, entre deux locaux ou entre l\u2019ext\u00e9rieur et un local.",
  "non_applicabilite":"En Exploitation axe Gestion : non applicable.",
  "important":"\u2b50 Les exigences acoustiques ne concernent pas d\u2019\u00e9ventuelles cloisons modulaires temporaires.",
  "reglementation":"\u00c9tablissements d\u2019enseignement : article 2 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003). | H\u00f4tels : article 2 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003)."
},
"ACOU2.1.3":{
  "attendu":"\u00c9valuer le niveau de pression pond\u00e9r\u00e9 du bruit de choc standardis\u00e9 pour chaque local du Bloc Homog\u00e8ne.",
  "definition":"<strong>L\u2019nT,w</strong> : niveau de pression pond\u00e9r\u00e9 du bruit de choc standardis\u00e9 re\u00e7u dans une pi\u00e8ce quand une machine \u00e0 chocs normalis\u00e9e (annexe E de la norme NF EN ISO 10140-5) est plac\u00e9e dans un local ext\u00e9rieur.",
  "non_applicabilite":"En Exploitation axe Gestion : non applicable.",
  "attention":"Climat chaud et humide : les sols de type moquette sont proscrits (probl\u00e8mes d\u2019hygi\u00e8ne). Des solutions alternatives existent (r\u00e9silient, sol souple type linol\u00e9um ou PVC). En cas de rev\u00eatement de sol dur exig\u00e9 pour des raisons justifi\u00e9es, l\u2019atteinte de l\u2019exigence peut \u00eatre accept\u00e9e si le niveau minimum n\u2019est pas atteint.",
  "reglementation":"\u00c9tablissements d\u2019enseignement : article 3 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003). | H\u00f4tels : article 3 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003)."
},
"ACOU2.1.4":{
  "attendu":"\u00c9valuer le niveau de pression acoustique normalis\u00e9 des \u00e9quipements techniques pour chaque local du Bloc Homog\u00e8ne.",
  "definition":"<strong>LnAT</strong> : niveau de pression acoustique normalis\u00e9 caract\u00e9risant le bruit dans un local lorsqu\u2019un \u00e9quipement du b\u00e2timent est en fonctionnement.<br><strong>Bruit d\u2019\u00e9quipement permanent</strong> : fonctionnant \u2265 50% du temps d\u2019utilisation normale (ventilation, climatisation, chauffage\u2026).<br><strong>Bruit d\u2019\u00e9quipement intermittent</strong> : fonctionnant < 50% du temps d\u2019utilisation normale.",
  "evaluation":"Les bruits d\u2019\u00e9quipement sont pris en compte pour les appareils en r\u00e9gime nominal. Les \u00e9quipements de s\u00e9curit\u00e9 et de process ne sont pas inclus. | En exploitation axe B\u00e2timent : plan d\u2019actions si niveau E non atteint (pi\u00e8ges \u00e0 son, gainage acoustique, cloisons, baffles acoustiques). | En exploitation axe Gestion : v\u00e9rifier concordance entre \u00e9quipements en place, utilisation pr\u00e9vue et utilisation effective.",
  "reglementation":"\u00c9tablissements d\u2019enseignement : article 4 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003). | H\u00f4tels : article 4 de l\u2019arr\u00eat\u00e9 du 25 avril 2003 (JO 28 mai 2003)."
},
"ACOU2.1.5":{
  "attendu":"\u00c9valuer la dur\u00e9e de r\u00e9verb\u00e9ration moyenne pour chaque local du Bloc Homog\u00e8ne.",
  "definition":"<strong>Tr</strong> : dur\u00e9e, en secondes, n\u00e9cessaire pour que le niveau sonore dans un local d\u00e9croisse de 60 dB lorsque la source de bruit est instantan\u00e9ment interrompue. La dur\u00e9e de r\u00e9verb\u00e9ration moyenne Tr est la moyenne des dur\u00e9es de r\u00e9verb\u00e9ration sur les octaves centr\u00e9es sur 500, 1 000 et 2 000 Hz.",
  "evaluation":"En exploitation axe B\u00e2timent : plan d\u2019actions si niveau E non atteint (produits d\u2019insonorisation, panneaux acoustiques, plafonds techniques absorbants, absorbant mural). | En exploitation axe Gestion : v\u00e9rifier concordance entre les caract\u00e9ristiques des composants (rev\u00eatements, forme du local\u2026), l\u2019utilisation pr\u00e9vue et l\u2019utilisation effective.",
  "attention":"Pour les salles de spectacles, d\u2019autres indicateurs sont propos\u00e9s en alternative au Tr : clart\u00e9 de la musique (C80), d\u00e9finition de la parole (D50), et variation du niveau sonore."
},
"ACOU2.1.6":{
  "attendu":"\u00c9valuer l\u2019indice de transmission de la parole du syst\u00e8me de sonorisation permanent pour chaque local du Bloc Homog\u00e8ne.",
  "definition":"<strong>STI</strong> : indice de transmission de la parole, de 0 \u00e0 1. Il concerne le syst\u00e8me permanent de sonorisation de l\u2019espace. Mesur\u00e9 suivant la norme NF EN 60268-16.",
  "non_applicabilite":"En absence de syst\u00e8me permanent de sonorisation, les exigences relatives \u00e0 l\u2019indice STI sont non applicables.",
  "evaluation":"\u00c9chelle de qualit\u00e9 : Mauvais (0\u20130.3) | Limite (0.35\u20130.45) | Moyen (0.5\u20130.6) | Bon (0.65\u20130.75) | Excellent (0.8\u20131.0). | En exploitation axe B\u00e2timent : plan d\u2019actions si niveau E non atteint (changement du syst\u00e8me de sonorisation). | En exploitation axe Gestion : v\u00e9rifier concordance entre syst\u00e8me choisi, utilisation pr\u00e9vue et utilisation effective. | Cet indice n\u2019est pas r\u00e9f\u00e9renc\u00e9 dans la r\u00e9glementation acoustique actuelle en France."
},
"ACOU2.1.7":{
  "attendu":"\u00c9valuer la sonorit\u00e9 \u00e0 la marche des rev\u00eatements de sols pour chaque local du Bloc Homog\u00e8ne.",
  "definition":"La sonorit\u00e9 \u00e0 la marche est \u00e9valu\u00e9e sur la base d\u2019une mesure en laboratoire du niveau de bruit de choc \u00e9mis par le rev\u00eatement de sol, sur un plancher normalis\u00e9 (norme NF S 31-074).",
  "evaluation":"Classification : Classe A (Ln,e,w < 65 dB \u2014 sols PVC sur mousse, sols expans\u00e9s \u00e0 relief) | Classe B (65 \u2264 Ln,e,w < 75 dB \u2014 sols r\u00e9silients homog\u00e8nes ou h\u00e9t\u00e9rog\u00e8nes compacts) | Classe C (75 \u2264 Ln,e,w < 85 dB \u2014 sols durs) | Classe D (Ln,e,w \u2265 85 dB \u2014 sols durs en pose flottante). | En exploitation axe B\u00e2timent : plan d\u2019actions si niveau E non atteint (changement des rev\u00eatements de sols). | En exploitation axe Gestion : v\u00e9rifier concordance entre les rev\u00eatements en place, utilisation pr\u00e9vue et utilisation effective. | Cet indice n\u2019est pas r\u00e9f\u00e9renc\u00e9 dans la r\u00e9glementation acoustique actuelle en France."
},
"ACOU1":{intro:"Le sous-thème ACOU1 évalue la performance en confort acoustique dans les Blocs Homogènes (BH). L\'évaluation porte sur le périmètre d\'action du demandeur, à l\'échelle du sous-objet.",context:"Le confort acoustique est un enjeu majeur pour la qualité de vie des occupants. Il dépend de multiples facteurs : isolement vis-à-vis des bruits extérieurs et intérieurs, niveau de bruit des équipements, temps de réverbération, intelligibilité de la parole et sonorité à la marche. L\'évaluation repose sur un système de Blocs Homogènes (BH) permettant de regrouper des espaces aux caractéristiques acoustiques similaires."}
,"ACOU1.1":{intro:"Évaluation de la performance acoustique par Blocs Homogènes (BH), regroupant surface, engagement, performance et environnement sonore.",context:"Le thème se compose d\'un seul sous-thème performanciel sur la plateforme ISIA (exigences ACOU1.1.2 à ACOU1.1.3). L\'évaluation est préparée via un fichier Excel fourni sur la plateforme, qui combine les indicateurs de performance acoustique (ACOU2.1.1 à ACOU2.1.7) pour obtenir le score à reporter."}
,"ACOU1.1.1":{attendu:"Déclarer la surface totale des locaux caractéristiques de l\'activité, et à occupation autre que passagère, en m² de surface utile.",definition:"Locaux à occupation autre que passagère : locaux qui par destination impliquent une durée de séjour pour un occupant supérieure à une demi-heure. La surface à prendre en compte est la surface utile. | À l\'international, la surface utilisée localement peut être prise en compte. | La définition et la liste des espaces caractéristiques de l\'activité est donnée dans le document « Informations générales ».",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Programme de l\'opération</td><td>Surfaces sur les plans</td></tr><tr><td><strong>Phases Réalisation et Exploitation</strong></td><td>Plans</td><td>Visite in situ, surfaces sur les plans</td></tr></table>"}
,"ACOU1.1.1.a":{attendu:"Déclarer la surface totale des Blocs Homogènes (BH) créés.",definition:"Surface cumulée de tous les Blocs Homogènes définis pour le projet. Cette valeur est utilisée pour vérifier le respect de la règle ACOU1.1.2 (somme BH ≥ 80% surface totale)."}
,"ACOU1.1.2":{attendu:"S\'engager à créer des Blocs Homogènes (BH) et respecter la règle : Somme des surfaces des BH ≥ 80% de la surface totale des espaces caractéristiques de l\'activité à occupation autre que passagère.",definition:"Pour l\'évaluation du confort acoustique, il est demandé de créer des Blocs Homogènes (BH) et de respecter la règle de couverture de 80% minimum. | La surface à prendre en compte est la surface utile. À l\'international, la surface utilisée localement peut être prise en compte. | Les critères de détermination des Blocs Homogènes pour le confort acoustique sont disponibles dans le document « Informations générales ».",important:"Pour être certifié, il est obligatoire de répondre à cette exigence. PRE REQUIS.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Description de la méthode de calcul par échantillonnage à réaliser en introduisant la notion de blocs homogènes (BH)</td></tr><tr><td><strong>Phases Conception et Réalisation</strong></td><td>Plans de repérage des blocs homogènes et des locaux types, Calcul des surfaces à l\'échelle de l\'ouvrage, Plans / Coupes / Façades du projet, CCTP</td><td>Cohérence de la détermination des blocs homogènes par rapport aux critères suivants : surface, volume et profondeur, usage des locaux, systèmes constructifs (nature des parois, type de revêtements…), positionnement par rapport aux principales sources de bruit extérieur et intérieur (sensibilité-agressivité)…</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Plans de repérage des blocs homogènes et des locaux types, DOE ou tout autre document</td><td>Cohérence de la détermination des blocs homogènes (durée de validité illimitée, tant que le bâtiment n\'a pas été modifié par rapport aux hypothèses de la preuve)</td></tr></table>"}
,"ACOU1.1.3":{attendu:"Reporter dans la plateforme ISIA le nombre de points atteint en confort acoustique, calculé dans le fichier Excel fourni sur la plateforme (exigence IDEN1.1.3).",definition:"L\'exigence consiste à évaluer le niveau atteint en confort acoustique sur la base des évaluations par BH. Pour cela, déclarer le nombre de points atteint dans le fichier de calcul fourni. | La méthode d\'agrégation est disponible dans le document « Informations générales ». | Rappel : Le document « Level(s) indicator 4.4: Acoustics and protection against noise » version 1.1 de janvier 2021 donne des indications sur les dispositions à prendre pour créer une ambiance acoustique satisfaisante.",evaluation:"Résultat obtenu dans le fichier Excel : entre 0 et 20 points. | Les indicateurs de performance évalués par BH sont : DnT,A,tr (isolement bruits extérieurs), DnT,A (isolement bruits aériens entre locaux), L\'nT,w (bruit de choc), LnAT (bruit des équipements), Tr (temps de réverbération), STI (indice de transmission de la parole), Sonorité à la marche.",reglementation:"Arrêté du 23 juillet 2013 modifiant l\'arrêté du 30 mai 1996 (classement infrastructures transport terrestre) | Arrêté du 25 avril 2003 relatif à la limitation du bruit dans les établissements d\'enseignement (JO 28 mai 2003) | Arrêté du 25 avril 2003 relatif à la limitation du bruit dans les hôtels (JO 28 mai 2003) | Arrêté du 13 avril 2017 relatif aux caractéristiques acoustiques des bâtiments existants lors de travaux de rénovation importants | NF EN 12354-1 à 6 (Calcul de la performance acoustique des bâtiments) | NF EN ISO 10052 (Mesurages in situ) | NF EN ISO 16283-1 à 3 (Mesurage in situ de l\'isolation acoustique) | NF EN ISO 717-1 et 717-2 (Évaluation de l\'isolement acoustique) | NF EN ISO 3382 (Mesurage des paramètres acoustiques des salles) | NF S 31-080 (Bureaux et espaces associés - Niveaux de performance acoustique)",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Se reporter au chapitre « Indicateurs » du présent guide (Sous-thème ACOU2) pour les modes de preuve détaillés par indicateur.</td></tr></table>"}
,"ACOU1.1.4-REU":{attendu:"Identifier la nature de l\'environnement sonore de la construction, spécifiquement pour les territoires à climat chaud et chaud/humide.",definition:"Étude du contexte acoustique du site, par l\'une des options suivantes : | — Soit étude des isolements de façades à viser au regard du classement au bruit des infrastructures | — Soit mesures à effectuer en l\'absence de données sur le classement des infrastructures routières. | Indiquer sur le plan de masse l\'emplacement des locaux techniques, groupes frigorifiques, centrales de traitement d\'air, groupe de condensation. | La mise en place de solutions de ventilation naturelle doit tenir compte de l\'exposition au bruit des espaces.",non_applicabilite:"S\'applique uniquement sur les territoires français ultramarins suivants : La Réunion, Mayotte, Guadeloupe, Martinique, Saint Barthélemy, Saint Martin, Guyane, Nouvelle Calédonie, Polynésie française, Wallis et Futuna, et dans les zones à climat chaud et chaud/humide. | Applicable pour les bâtiments neufs et rénovés et en Exploitation Axe Bâtiment uniquement.",important:"Pour être certifié, il est obligatoire de répondre à cette exigence. Cette exigence a le statut de pré-requis.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Analyse de site, Plan masse avec repérage</td><td>Localisation des nuisances sonores</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plans de conception, CCTP, Étude acoustique</td><td>Localisation des nuisances sonores, résultats de l\'étude et/ou des mesures</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Plans d\'exécution, DOE, Visite in situ, Étude acoustique, Rapport de mesures</td><td>Localisation des nuisances sonores, résultats de l\'étude et/ou des mesures</td></tr><tr><td><strong>Phase Exploitation (axe Bâtiment)</strong></td><td>Plans, Visite in situ</td><td>Localisation des nuisances sonores, résultat de mesures si elles existent</td></tr></table>"}

,"HYGR1":{intro:"Le sous-thème HYGR1 évalue la performance en confort hygrothermique dans les Blocs Homogènes (BH). L\'évaluation porte sur le périmètre d\'action du demandeur, à l\'échelle du sous-objet.",context:"Le confort hygrothermique dépend de la température, de la vitesse d\'air, de l\'hygrométrie, des apports solaires, de la maîtrise de l\'ambiance thermique et des consignes de température. L\'évaluation repose sur un système de Blocs Homogènes (BH) permettant de regrouper des espaces aux caractéristiques thermiques similaires."}
,"HYGR1.1":{intro:"Évaluation de la performance hygrothermique par Blocs Homogènes (BH), regroupant surface, engagement, performance et dispositions architecturales.",context:"Le thème se compose d\'un seul sous-thème performanciel sur la plateforme ISIA (exigences HYGR1.1.2 à HYGR1.1.3). L\'évaluation est préparée via un fichier Excel fourni sur la plateforme, qui combine les indicateurs de performance (HYGR2.x) pour obtenir le score à reporter."}
,"HYGR1.1.1":{attendu:"Déclarer la surface totale des locaux caractéristiques de l\'activité, et à occupation autre que passagère, en m² de surface utile.",definition:"Locaux à occupation autre que passagère : locaux qui par destination impliquent une durée de séjour pour un occupant supérieure à une demi-heure. La surface à prendre en compte est la surface utile. | À l\'international, la surface utilisée localement peut être prise en compte. | La définition et la liste des espaces caractéristiques de l\'activité est donnée dans le document « Informations générales ».",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Programme de l\'opération</td><td>Surfaces sur les plans</td></tr><tr><td><strong>Phases Réalisation et Exploitation</strong></td><td>Plans</td><td>Visite in situ, surfaces sur les plans</td></tr></table>"}
,"HYGR1.1.1.a":{attendu:"Déclarer la surface totale des Blocs Homogènes (BH) créés.",definition:"Surface cumulée de tous les Blocs Homogènes définis pour le projet. Cette valeur est utilisée pour vérifier le respect de la règle HYGR1.1.2 (somme BH ≥ 80% surface totale)."}
,"HYGR1.1.2":{attendu:"S\'engager à créer des Blocs Homogènes (BH) et respecter la règle : Somme des surfaces des BH ≥ 80% de la surface totale des espaces caractéristiques.",definition:"Pour l\'évaluation du confort hygrothermique, il est demandé de créer des Blocs Homogènes (BH) et de respecter la règle de couverture de 80% minimum. | Un bloc homogène (BH) est constitué de locaux présentant des caractéristiques similaires : même orientation, même type de façade, même usage, même type de protections solaires, même hauteur sous plafond. | La surface à prendre en compte est la surface utile.",important:"Pour être certifié, il est obligatoire de répondre à cette exigence. PRE REQUIS.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Engagement à constituer des BH</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans, Carnet de vie</td><td>Cohérence du zonage en BH</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie</td><td>Cohérence entre BH définis et réalisés</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE ou document justificatif</td><td>Cohérence entre BH et éléments réalisés</td></tr></table>"}
,"HYGR1.1.3":{attendu:"Reporter dans la plateforme ISIA le nombre de points atteint en confort hygrothermique, calculé dans le fichier Excel fourni sur la plateforme.",definition:"L\'exigence consiste à évaluer le niveau atteint en confort hygrothermique sur la base des évaluations par BH. Déclarer le nombre de points atteint dans le fichier de calcul fourni. | Les indicateurs de performance évalués par BH sont détaillés dans le sous-thème HYGR2 : facteur solaire (HYGR2.1.1), protections solaires parois opaques (HYGR2.1.2-REU), ventilation naturelle (HYGR2.1.3-REU), systèmes de brassage d\'air (HYGR2.1.4-REU), températures de consigne (HYGR2.1.5), maîtrise ambiance thermique (HYGR2.1.5-REU), vitesses d\'air en refroidissement (HYGR2.1.6-REU), température résultante (HYGR2.1.6a/b/c), temps de dépassement (HYGR2.2.x-REU).",evaluation:"Résultat obtenu dans le fichier Excel : entre 0 et 20 points.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Se reporter au chapitre « Indicateurs » du présent guide (Sous-thème HYGR2) pour les modes de preuve détaillés par indicateur.</td></tr></table>"}
,"HYGR1.1.4-REU":{attendu:"Mettre en place des dispositions architecturales adaptées au climat et au site pour les territoires à climat chaud et chaud/humide.",definition:"Le demandeur identifie le statut de chaque bloc homogène : PASSIF (pas de refroidissement), MIXTE (refroidissement d\'appoint), REFROIDI (refroidissement permanent). | Les dispositions architecturales incluent : ventilation naturelle traversante, protections solaires, orientation, compacité, inertie, végétalisation.",non_applicabilite:"S\'applique uniquement sur les territoires français ultramarins : La Réunion, Mayotte, Guadeloupe, Martinique, Saint-Barthélemy, Saint-Martin, Guyane, Nouvelle-Calédonie, Polynésie française, Wallis et Futuna, et dans les zones à climat tropical, aride ou désertique.",important:"Pour être certifié, il est obligatoire de répondre à cette exigence. PRE REQUIS.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Définition des objectifs en matière de dispositions architecturales</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Carnet d\'entretien</td><td>Cohérence entre les caractérisations des dispositions et les éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Mesures de confort, Vérification in situ</td><td>Cohérence entre les dispositions et les éléments réalisés</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Idem Réalisation, Enquête de satisfaction</td><td>Cohérence entre dispositions, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2":{intro:"Le sous-thème HYGR2 regroupe les indicateurs de performance hygrothermique évalués par Bloc Homogène. Ces indicateurs alimentent le calcul du score global du thème.",context:"Les indicateurs couvrent : le facteur solaire des baies, les protections solaires des parois opaques, la ventilation naturelle, le brassage d\'air, les températures de consigne, la maîtrise de l\'ambiance par les usagers, les vitesses d\'air en cas de refroidissement, les températures résultantes et les temps de dépassement de la plage de confort."}
,"HYGR2.1":{intro:"Calcul de la performance hygrothermique via les indicateurs évalués par BH.",context:"Le calcul de la performance intègre facteur solaire, protections solaires, ventilation naturelle, brassage d\'air, températures de consigne, maîtrise de l\'ambiance, vitesses d\'air et températures résultantes. Certains indicateurs sont spécifiques aux climats chaud et chaud/humide (suffixe -REU)."}
,"HYGR2.1.1":{attendu:"Vérifier que le facteur solaire S des baies est inférieur au Smax réglementaire, sauf incompatibilité justifiée (sécurité…).",definition:"Deux méthodes possibles : | — Valeurs forfaitaires de référence (issues de PERENE) par type de paroi : Ouest S ≤ 0,25 ; Est, Nord S ≤ 0,3 ; Sud S ≤ 0,4. | — Pour La Réunion : valeurs suivant le guide PREBAT Livret 2 « Concevoir un bâtiment bioclimatique » (enveloppe bioclimatique en fonction de l\'orientation et de la surface de vitrage par rapport à la surface de plancher). | Note : dans l\'hémisphère Sud, inverser les orientations.",non_applicabilite:"Non applicable en exploitation axe Gestion. | Peut être déclarée non applicable en exploitation axe Bâtiment lorsque les facteurs solaires des baies sont hors du périmètre de responsabilités du demandeur.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération, exigences liées aux protections solaires</td><td>Définition des objectifs en matière de protection solaire</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Carnet d\'entretien, Héliodon, Note de caractérisation des protections solaires, Calcul des facteurs solaires, Repérage sur plan de zonage thermique</td><td>Cohérence entre les caractérisations des protections solaires, le calcul des facteurs solaires et les éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Héliodon, Note, Calcul facteurs solaires, Repérage, Mesures de confort et report Givoni, Vérification in situ</td><td>Cohérence entre les hypothèses du calcul et les éléments réalisés</td></tr><tr><td><strong>Phase Exploitation (axe Bâtiment et Gestion)</strong></td><td>Idem Réalisation + Enquête de satisfaction</td><td>Cohérence entre caractérisations, calcul, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.2-REU":{attendu:"Optimiser les protections solaires des parois opaques suivant les orientations ET privilégier l\'ombrage des façades par des doubles peaux / espaces tampons espacés de 3m, 1,5m, 0,8m.",definition:"Le choix des protections solaires doit être validé par l\'étude de solarisation / héliodon afin de confirmer et quantifier l\'efficacité des protections solaires et de privilégier l\'ombrage. | Facteur solaire des toitures ≤ 0,02 (surtoiture ventilée si ouvertures ≥ 20% surface toiture). | Facteur solaire des façades requis par défaut : Perene ≤ 0,05 avec Cm 0,3, ou valeurs du guide PREBAT.",non_applicabilite:"Non applicable en exploitation axe Gestion. | Peut être déclarée NA en exploitation axe Bâtiment si facteurs solaires hors périmètre du demandeur.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération, exigences liées aux protections solaires</td><td>Définition des objectifs en matière de protection solaire</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Carnet d\'entretien, Héliodon, Note de caractérisation, Calcul des facteurs solaires, Repérage sur plan de zonage thermique</td><td>Cohérence entre les caractérisations et les éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Héliodon, Note, Calcul facteurs solaires, Repérage, Mesures de confort et report Givoni, Vérification in situ</td><td>Cohérence entre les hypothèses du calcul et les éléments réalisés</td></tr><tr><td><strong>Phase Exploitation (axe Bâtiment et Gestion)</strong></td><td>Idem Réalisation + Enquête de satisfaction</td><td>Cohérence entre caractérisations, calcul, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.3-REU":{attendu:"Assurer une ventilation naturelle efficace protections solaires déployées, notamment par création de locaux traversants et de porosité minimale.",definition:"Définition extraite de PERENE et de la RTAADOM. La création de mouvements d\'air peut être réalisée par ventilation naturelle traversante, par ouverture des baies, puits dépressionnaires, ou systèmes intérieurs de brassages d\'air intégrés au bâti. | Calcul de la porosité : Sp = (Sp1 + Sp2)/2, SO = P × Sp. | Coefficient M selon type de menuiserie : Jalousie = 0,8 ; Coulissant 2 vantaux = 0,5 ; Coulissant 3 vantaux = 0,67 ; Ouvrant à la française, fenêtre, porte = 1. | SO réelle = M × SO_réservation.",non_applicabilite:"Non applicable pour le statut REFROIDI.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, exigences liées à la ventilation naturelle, au caractère traversant et aux porosités</td><td>Définition des objectifs en matière de ventilation naturelle</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Étude aéraulique, Note de caractérisation des porosités et flux, Simulations aéraulique, Maquette en soufflerie éventuelle, Repérage sur plan de zonage thermique</td><td>Cohérence entre les caractérisations de la ventilation naturelle et les éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Étude aéraulique, Note, Simulations, Maquette, Repérage, Mesures de confort dont vitesse d\'air et report Givoni, Vérification in situ</td><td>Cohérence entre les caractérisations et les éléments réalisés</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Idem Réalisation + Enquête de satisfaction et campagnes de mesures</td><td>Cohérence entre éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.4-REU":{attendu:"Améliorer l\'efficacité des moyens et systèmes assurant une bonne ventilation de confort en l\'absence de refroidissement.",definition:"Dispositions techniques pour le brassage de confort assurant une vitesse d\'air de 1 m/s à 1,5 m/s. | Brasseurs d\'air : puissance unitaire ≤ 60W, efficacité minimum 400 m³/Wh à vitesse minimum et 140 m³/Wh à vitesse maximum, consommation plus faible qu\'un système de refroidissement classique. | Brasseurs en plafonniers : ≥ 1,2m de diamètre, plan horizontal des pales à minimum 0,3m du plafond, vitesse de rotation variable et réglable, 1 brasseur/10 m², pales à plus de 1m des murs, performances acoustiques vérifiées.",non_applicabilite:"Statut PASSIF : si aucun système présent, l\'exigence est atteinte. | Statut MIXTE : si aucun système présent, l\'exigence est non applicable. | Statut REFROIDI : l\'exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, exigences liées au brassage d\'air</td><td>Objectifs en matière de brassage d\'air</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Étude aéraulique, Note de caractérisation des systèmes de brassage d\'air, Repérage sur plan de zonage thermique</td><td>Cohérence entre caractérisations de la ventilation naturelle et éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Étude aéraulique, Note, Repérage, Mesures de confort dont vitesse d\'air et report Givoni, Mesures de performance des systèmes, Vérification in situ</td><td>Cohérence entre systèmes de brassage et éléments réalisés</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Idem Réalisation + modalités d\'usage</td><td>Cohérence entre systèmes réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.5":{attendu:"Déterminer les températures ou plages de températures de consigne en utilisant l\'indicateur PPD (Predicted Percentage of Dissatisfied) de la norme ISO 7730. PPD ≤ 10% (soit PMV entre -0,5 et +0,5).",definition:"L\'indicateur PPD se calcule à partir du PMV (Vote Moyen Prévisible), norme NF EN ISO 7730. | Hypothèses par défaut : hiver 1 Clo / été 0,5 Clo ; métabolisme selon activité (sédentaire 1,2 Met, légère 1,6 Met, moyenne 2,0 Met) ; humidité 50% ; vitesse d\'air 0,1 m/s en hiver et 0,2 m/s en été ; température radiante moyenne = température de l\'air. | Exemple : bureau en hiver (1,2 Met, 1 Clo, 50% HR, 0,1 m/s) → température opérative de 20-22°C → PMV entre -0,33 et +0,1 → PPD ≤ 10%.",reglementation:"NF EN ISO 7730 — Ergonomie des ambiances thermiques. Annexe E : tableaux de détermination de température de consigne.",important:"PRE REQUIS. Applicable en construction neuve, rénovation, exploitation axes BD et GD, pour tous les statuts.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération</td><td>Exigences liées aux températures de consigne</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Note de caractérisation des dispositifs, Repérage sur plan de zonage</td><td>Cohérence entre les caractérisations et les éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Note de caractérisation, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations et éléments réalisés</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE ou document justificatif, Carnet de vie, Carnet d\'entretien, Note, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.5-REU":{attendu:"Permettre aux usagers de maîtriser individuellement l\'ambiance thermique dans les espaces où cela est pertinent.",definition:"En l\'absence de refroidissement : identification des espaces pertinents + possibilité pour l\'utilisateur d\'agir sur les protections solaires (réglage des protections solaires extérieures, ouverture des baies, fonctionnement indépendant des protections solaires, système de brassage d\'air). | En cas de refroidissement : identification des espaces + possibilité de régler/programmer la consigne de refroidissement + moyens de limiter la fourniture dans une plage de température déterminée. | Si non pertinent pour des raisons justifiées liées à l\'usage, l\'exigence est considérée comme atteinte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, exigences liées à la maîtrise de l\'ambiance thermique</td><td>Objectifs en matière de maîtrise de l\'ambiance thermique par les usagers</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Note de caractérisation des dispositifs, Repérage sur plan de zonage</td><td>Cohérence entre caractérisations des dispositifs et éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Note de caractérisation, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations et éléments réalisés</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE ou document justificatif, Carnet de vie, Carnet d\'entretien, Note, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.6-REU":{attendu:"En cas de refroidissement, assurer une vitesse d\'air ne nuisant pas au confort, selon le type d\'espace.",definition:"Vitesses d\'air maximales par type d\'espace (consigne proche de 26°C) : | — Bureau, salle de réunion, enseignement, accueil, spectacle, conférence : V ≤ 0,25 m/s (Niv.1) / V ≤ 0,22 m/s (Niv.2) | — Hôtellerie, internat, infirmerie, repos, sommeil : V ≤ 0,20 m/s (Niv.1) / V ≤ 0,15 m/s (Niv.2) | — Zone entrepôt, production, hall, exposition, vente, services : V ≤ 0,50 m/s (Niv.1) / V ≤ 0,40 m/s (Niv.2) | — Hall de gare, enregistrement, grands espaces circulation : V ≤ 0,80 m/s (Niv.1) / V ≤ 0,50 m/s (Niv.2) | Si température de consigne < 26°C, compensation possible : V ≤ 0,18 m/s si Tconsigne = 24°C, V ≤ 0,20 m/s si Tconsigne = 25°C.",non_applicabilite:"Statut PASSIF : non applicable. | Statut MIXTE : s\'applique lorsque le système de refroidissement d\'appoint fonctionne. | Statut REFROIDI : s\'applique.",attention:"Pour la justification de cette vitesse d\'air limite, la maîtrise d\'ouvrage doit justifier le choix de l\'appareil terminal de soufflage et la position des terminaux dans les espaces.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, Exigences liées à la limitation des vitesses d\'air</td><td>Objectifs en matière de limitation des vitesses d\'air</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Note de caractérisation des limitations des vitesses d\'air, Repérage sur plan de zonage</td><td>Cohérence entre caractérisations et éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Note de caractérisation, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations et éléments réalisés</td></tr><tr><td><strong>Phase Exploitation (axes BD et GD)</strong></td><td>DOE ou document justificatif, Carnet de vie, Carnet d\'entretien, Note, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.6a":{attendu:"Vérifier que la température résultante des locaux refroidis respecte les consignes définies en HYGR2.1.5 (PPD ≤ 10%).",definition:"Pour les locaux avec système de refroidissement, la température résultante doit être conforme aux consignes de température déterminées via le calcul PPD (norme ISO 7730).",non_applicabilite:"Pour le statut PASSIF, l\'exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, exigences liées aux températures de consigne</td><td>Objectifs en matière de température résultante</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, Note de caractérisation, Repérage sur plan de zonage</td><td>Cohérence entre caractérisations et éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, Carnet d\'entretien, Note, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations et éléments réalisés</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>DOE ou document justificatif, Carnet de vie, Carnet d\'entretien, Note, Repérage, Vérification in situ</td><td>Cohérence entre caractérisations, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.6b":{attendu:"Évaluer la température résultante des locaux non refroidis AVEC création de mouvement d\'air via simulation thermique dynamique et report sur le diagramme de Givoni.",definition:"L\'exigence requiert une simulation thermique dynamique (STD). | Étape 1 : Simulations en mode PASSIF, report des couples Température résultante / Hygrométrie sur le diagramme de Givoni, détermination du % de temps de dépassement. | Étape 2 : Simulation avec scénarios de refroidissement pour MIXTE/REFROIDI, report sur Givoni. | Logiciels acceptés : TRNSYS, Pléiade COMFIE, CoDyBA, T.A.S, Design Builder, Virtual Environment, etc.",non_applicabilite:"Non applicable pour le statut REFROIDI sans mouvement d\'air.",reglementation:"Référence : Diagramme de confort GIVONI (diagramme psychrométrique).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, exigences liées aux statuts et à la caractérisation en termes de confort</td><td>Objectifs en matière de statuts thermiques caractérisés</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, STD, Note de caractérisation des hypothèses et résultats, Report sur diagramme de Givoni, Repérage sur plan de zonage</td><td>Cohérence entre les exigences, les hypothèses des STD et les éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, STD, Mesures in situ, Note, Report Givoni, Repérage, Vérification in situ</td><td>Cohérence entre les exigences, les hypothèses des STD et les éléments réalisés</td></tr><tr><td><strong>Phase Exploitation (axe Bâtiment)</strong></td><td>Idem Réalisation + enquêtes de satisfaction et campagnes de mesures</td><td>Cohérence entre exigences, hypothèses STD, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.1.6c":{attendu:"Évaluer la température résultante des locaux non refroidis SANS création de mouvement d\'air via simulation thermique dynamique et report sur le diagramme de Givoni.",definition:"Même approche que HYGR2.1.6b mais pour les locaux SANS création de mouvement d\'air. Simulation thermique dynamique requise avec report sur diagramme de Givoni.",non_applicabilite:"Non applicable pour le statut REFROIDI.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, exigences liées aux statuts et à la caractérisation en termes de confort</td><td>Objectifs en matière de statuts thermiques caractérisés</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, STD, Note de caractérisation, Report sur diagramme de Givoni, Repérage sur plan de zonage</td><td>Cohérence entre les exigences, les hypothèses des STD et les éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, STD, Mesures in situ, Note, Report Givoni, Repérage, Vérification in situ</td><td>Cohérence entre les exigences, les hypothèses des STD et les éléments réalisés</td></tr><tr><td><strong>Phase Exploitation (axe Bâtiment)</strong></td><td>Idem Réalisation + enquêtes de satisfaction et campagnes de mesures</td><td>Cohérence entre exigences, hypothèses STD, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.2-REU":{intro:"Indicateurs spécifiques aux climats chaud et chaud/humide pour évaluer le temps de dépassement de la plage de confort.",context:"S\'applique aux territoires français ultra-marins et zones en climat tropical, aride ou désertique. Utilise le diagramme de Givoni et la simulation thermique dynamique pour déterminer les % de temps de dépassement."}
,"HYGR2.2.1-REU":{attendu:"Déterminer le pourcentage de temps de dépassement sur la période d\'occupation de la plage de confort du local en mode PASSIF, via simulation thermique dynamique et report sur diagramme de Givoni.",definition:"Simulation thermique dynamique requise : | Étape 1 : Simulations en mode PASSIF pour qualifier la performance du projet en passif. Report des couples Température résultante / Hygrométrie sur le diagramme de Givoni. Comparaison avec les vitesses d\'air atteintes en passif, ventilation naturelle, sans / avec brassage d\'air. Détermination du % de temps de dépassement de la plage de confort. | Étape 2 : Simulation intégrant les scénarios de refroidissement pour qualifier le confort sur l\'année suivant le scénario d\'usage retenu — pour MIXTE et REFROIDI.",non_applicabilite:"Non applicable en Axe GD seul. S\'applique en construction neuve, rénovation et exploitation axe BD, pour tous les statuts (PASSIF, MIXTE, REFROIDI).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme, exigences liées aux statuts, caractérisation confort, tolérance de sortie des plages de confort</td><td>Objectifs en matière de statuts thermiques</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans/Coupes/Façades, Carnet de vie, STD, Note de caractérisation, Report sur Givoni, Repérage sur plan de zonage</td><td>Cohérence entre exigences, hypothèses STD et éléments du projet</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Carnet de vie, STD, Mesures in situ, Note, Report Givoni, Repérage, Vérification in situ</td><td>Cohérence entre exigences, hypothèses STD et éléments réalisés</td></tr><tr><td><strong>Phase Exploitation (axe Bâtiment)</strong></td><td>Idem Réalisation + enquêtes de satisfaction et campagnes de mesures</td><td>Cohérence entre exigences, hypothèses STD, éléments réalisés et modalités d\'usage</td></tr></table>"}
,"HYGR2.2.2a-REU":{attendu:"Déterminer le pourcentage de temps de dépassement suivant le scénario d\'usage retenu pour le statut PASSIF.",definition:"Qualification du confort suivant le scénario d\'usage retenu (étape 2 de HYGR2.2.1-REU) : Pas de sortie de la plage de confort 1 m/s plus de x % du temps sur la période d\'occupation sur l\'année jusqu\'à 800m d\'altitude. | Dépassements tolérés s\'entendent en dehors du recours au refroidissement.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Idem HYGR2.2.1-REU.</td></tr></table>"}
,"HYGR2.2.2b-REU":{attendu:"Déterminer le pourcentage de temps de dépassement suivant le scénario d\'usage retenu pour le statut MIXTE.",definition:"Qualification du confort suivant le scénario d\'usage retenu (étape 2 de HYGR2.2.1-REU) : Pas de sortie de la plage de confort 1 m/s plus de x % du temps sur la période d\'occupation sur l\'année jusqu\'à 800m d\'altitude. | Dépassements tolérés s\'entendent en dehors du recours au refroidissement.",non_applicabilite:"Non applicable en Axe GD seul. S\'applique en construction neuve, rénovation et exploitation axe BD, pour le statut MIXTE.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Idem HYGR2.2.1-REU.</td></tr></table>"}
,"HYGR2.2.2c-REU":{attendu:"Vérifier l\'absence totale de sortie de la plage de confort pour le statut REFROIDI.",definition:"Qualification du confort suivant le scénario d\'usage retenu (étape 2 de HYGR2.2.1-REU) : L\'exigence requiert qu\'il n\'y ait AUCUNE sortie de la plage de confort 1 m/s sur la période d\'occupation sur l\'année jusqu\'à 800m d\'altitude.",non_applicabilite:"Non applicable en Axe GD seul. S\'applique en construction neuve, rénovation et exploitation axe BD, pour le statut REFROIDI.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Idem HYGR2.2.1-REU.</td></tr></table>"},"ONDE1":{intro:"Le th\u00e8me Ondes \u00e9lectromagn\u00e9tiques aborde les risques sanitaires li\u00e9s aux champs \u00e9lectromagn\u00e9tiques pr\u00e9sents dans ou autour des b\u00e2timents. Il couvre l\'identification des sources, l'\u00e9valuation des niveaux d\'exposition et les dispositions de limitation de l\'impact.",context:"Ce th\u00e8me traite de pr\u00e9occupations concernant un risque sanitaire identifi\u00e9 par la r\u00e9glementation pour certaines situations sp\u00e9cifiques et non av\u00e9r\u00e9 pour les autres situations, mais dont la prise en compte a \u00e9t\u00e9 reconnue utile."},"ONDE1.1":{intro:"Identification des sources d\'ondes \u00e9lectromagn\u00e9tiques provenant du milieu environnant et du projet lui-m\u00eame.",context:"Cette \u00e9tape est fondamentale pour comprendre le contexte d\'exposition. Le bloc ONDE1.1 peut \u00eatre d\u00e9clar\u00e9 non-applicable lorsque l\'axe Gestion est vis\u00e9 seul."},"ONDE1.1.1":{attendu:"R\u00e9aliser une identification des sources d\'ondes \u00e9lectromagn\u00e9tiques du milieu environnant (\u00e0 l\'ext\u00e9rieur des locaux). Ce travail d\'identification ne n\u00e9cessite pas de quantifier les \u00e9missions par simulation ou mesure.",definition:"Une identification des sources d'\u00e9missions basse fr\u00e9quence du milieu environnant (sources \u00ab \u00e9nergie \u00bb) et des sources radiofr\u00e9quences de l\'environnement imm\u00e9diat (sources \u00ab t\u00e9l\u00e9coms \u00bb) doit \u00eatre r\u00e9alis\u00e9e.<br>Sources \u00ab \u00e9nergie \u00bb potentielles : c\u00e2ble a\u00e9rien d\'alimentation \u00e9lectrique de train/tramway, ligne haute tension, transformateurs, etc.<br>Sources \u00ab t\u00e9l\u00e9coms \u00bb potentielles : \u00e9metteurs de radiodiffusion, sites radar, stations de base et relais de t\u00e9l\u00e9phonie mobile, etc.<br>En France, il est possible de se baser sur le site de l\'ANFR : http://www.cartoradio.fr.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Document sur les sources \u00e9lectromagn\u00e9tiques du milieu environnant ext\u00e9rieur.</td><td></td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Mise \u00e0 jour du document sur les sources \u00e9lectromagn\u00e9tiques du milieu environnant ext\u00e9rieur si modification des sources.</td><td>Coh\u00e9rence entre le document r\u00e9alis\u00e9 et les informations d\u00e9livr\u00e9es sur les sites internet sp\u00e9cialis\u00e9s.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Document sur les sources \u00e9lectromagn\u00e9tiques du milieu environnant ext\u00e9rieur (dur\u00e9e de validit\u00e9 du mode de preuve : 1 an).</td><td></td></tr></table>"},"ONDE1.1.2":{attendu:"R\u00e9aliser une identification des sources d\'ondes \u00e9lectromagn\u00e9tiques du projet (\u00e0 l\'int\u00e9rieur des locaux). Ce travail d\'identification ne n\u00e9cessite pas de quantifier les \u00e9missions par simulation ou mesure.",definition:"Sources \u00e9nergie : machineries communes, chauffage (planchers chauffants, plafonds rayonnants \u00e9lectriques), alimentation sp\u00e9cifique de l\'immeuble (transformateurs, groupes \u00e9lectrog\u00e8nes), ascenseurs, \u00e9quipements \u00e9lectrom\u00e9caniques, a\u00e9ror\u00e9frig\u00e9rants, colonnes montantes, syst\u00e8mes d'\u00e9clairage, etc.<br>Sources t\u00e9l\u00e9coms : bornes wifi, r\u00e9p\u00e9titeurs GSM, syst\u00e8mes antivol, objets connect\u00e9s sans fils, etc.<br>En France : la classification des sources est donn\u00e9e dans le dossier de l\'INRS \u00ab Champs \u00e9lectromagn\u00e9tiques \u00bb. L\'outil OSERAY de l\'INRS peut \u00eatre utilis\u00e9 pour identifier les risques.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Liste des sources d\'ondes \u00e9lectromagn\u00e9tiques et plans techniques.</td><td>Coh\u00e9rence entre la liste des sources et les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Liste des sources d\'ondes \u00e9lectromagn\u00e9tiques et DOE (dur\u00e9e de validit\u00e9 : illimit\u00e9e, tant que le b\u00e2timent n\'a pas \u00e9t\u00e9 modifi\u00e9).</td><td></td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Liste des sources et DOE ou tout autre document (dur\u00e9e de validit\u00e9 : illimit\u00e9e).</td><td>V\u00e9rification in situ.</td></tr></table>"},"ONDE2":{intro:"\u00c9valuation quantitative ou qualitative des niveaux d\'exposition aux champs \u00e9lectromagn\u00e9tiques \u00e0 l\'int\u00e9rieur des locaux.",context:"Cette \u00e9valuation se base sur les prescriptions r\u00e9glementaires applicables, notamment le d\u00e9cret n\u00b02016-1074 du 3 ao\u00fbt 2016 en France."},"ONDE2.1":{intro:"D\u00e9termination et mesure du niveau d\'exposition \u00e9lectromagn\u00e9tique \u00e0 l\'int\u00e9rieur des locaux du b\u00e2timent.",context:"Les mesures ou calculs doivent couvrir les zones de s\u00e9jour prolong\u00e9 et \u00eatre conformes aux normes applicables."},"ONDE2.1.1":{attendu:"D\u00e9terminer le champ \u00e9lectromagn\u00e9tique \u00e0 l\'int\u00e9rieur des locaux par analyse documentaire, \u00e9tudes, simulations ou mesures.",definition:"L'\u00e9valuation des risques doit prendre en consid\u00e9ration : l\'origine et les caract\u00e9ristiques des \u00e9missions, le r\u00e9sultat des \u00e9valuations d\'expositions, les informations sur les niveaux d'\u00e9mission fournis par les fabricants, les effets biophysiques directs ou indirects, l\'incidence sur les travailleurs \u00e0 risques particuliers.<br>Il existe plusieurs possibilit\u00e9s : par analyse documentaire (fiches techniques des \u00e9quipements rayonnants) ou par \u00e9tudes, simulations ou mesures.<br>En France, les centres de mesures physiques de l\'Assurance maladie (CARSAT/CRAM/CGSS) et l\'INRS sont comp\u00e9tents pour ces \u00e9valuations.",reglementation:"D\u00e9cret n\u00b02016-1074 du 3 ao\u00fbt 2016 relatif \u00e0 la protection des travailleurs contre les risques dus aux champs \u00e9lectromagn\u00e9tiques.<br>D\u00e9cret n\u00b02002-775 du 3 mai 2002 relatif aux valeurs limites d\'exposition du public.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Analyse documentaire, \u00e9tudes, simulations ou mesures d\u00e9terminant le champ EM \u00e0 l\'int\u00e9rieur des locaux, CCTP, plans, fiches techniques.</td><td>Coh\u00e9rence entre les hypoth\u00e8ses du calcul/fiches techniques et les \u00e9quipements du projet.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, analyse documentaire, \u00e9tudes, simulations ou mesures, fiches techniques.</td><td>V\u00e9rification de la conclusion sur les risques li\u00e9s aux champs EM ; Coh\u00e9rence entre hypoth\u00e8ses et \u00e9quipements install\u00e9s.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>DOE ou tout autre document (dur\u00e9e de validit\u00e9 : illimit\u00e9e, tant que le b\u00e2timent n\'a pas \u00e9t\u00e9 modifi\u00e9).</td><td>Coh\u00e9rence entre hypoth\u00e8ses et \u00e9quipements techniques install\u00e9s.</td></tr></table>"},"ONDE2.1.2":{attendu:"V\u00e9rifier que les niveaux mesur\u00e9s ou calcul\u00e9s respectent les seuils limites d\'exposition d\u00e9finis par la r\u00e9glementation, tant pour les radiofr\u00e9quences que pour les champs basse fr\u00e9quence 50-60 Hz.",definition:"La mesure des radiofr\u00e9quences est \u00e0 r\u00e9aliser selon le protocole de mesure de l\'ANFR (fr\u00e9quences de 9 kHz \u00e0 300 GHz). Le respect de la norme NF EN 50492 est \u00e9galement accept\u00e9.<br>Pour les champs basse fr\u00e9quence 50-60 Hz, trois niveaux d\'exigence sont d\u00e9finis avec des seuils progressifs.<br>Les mesures doivent \u00eatre r\u00e9alis\u00e9es dans les locaux susceptibles d'\u00eatre \u00e0 risque pour les occupants.",reglementation:"Recommandation 1999/519/CE du 12/07/99 du Conseil de l\'Union Europ\u00e9enne.<br>D\u00e9cret N\u00b0 2002-775 du 3 mai 2002 (transposition fran\u00e7aise).<br>Protocole de mesure de l\'ANFR.<br>Norme NF EN 50492 de janvier 2009.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Documents contractuels pr\u00e9voyant des mesures du champ EM en fin de r\u00e9alisation, ou simulation des champs EM.</td><td>Pr\u00e9sence dans le contrat de mesures des seuils limites d\'exposition.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Rapport de mesures d\u00e9terminant le champ EM \u00e0 l\'int\u00e9rieur des locaux.</td><td></td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Rapport de mesures (dur\u00e9e de validit\u00e9 : illimit\u00e9e, tant que le b\u00e2timent n\'a pas \u00e9t\u00e9 modifi\u00e9).</td><td>Respect des valeurs seuils limites d\'exposition.</td></tr></table>"},"ONDE3":{intro:"Mesures de limitation et de r\u00e9duction de l\'impact des sources d\'ondes \u00e9lectromagn\u00e9tiques identifi\u00e9es.",context:"Les dispositions peuvent \u00eatre de nature technique (choix d'\u00e9quipements), architecturale (positionnement, blindage) ou organisationnelle (recommandations d\'am\u00e9nagement)."},"ONDE3.1":{intro:"Limitation de l\'impact des sources d\'ondes \u00e9lectromagn\u00e9tiques identifi\u00e9es par des mesures techniques, architecturales et organisationnelles.",context:"Selon les r\u00e9sultats de l'\u00e9valuation, des mesures d\'att\u00e9nuation peuvent \u00eatre n\u00e9cessaires."},"ONDE3.1.1":{attendu:"Mettre en place des \u00e9quipements techniques et des dispositions architecturales permettant de prot\u00e9ger les travailleurs contre les risques dus aux champs \u00e9lectromagn\u00e9tiques.",definition:"Choix des \u00e9quipements : privil\u00e9gier les \u00e9quipements \u00e0 bon rendement \u00e9nerg\u00e9tique, utiliser des sources en courant continu, travailler les liaisons entre \u00e9quipements et r\u00e9seaux, limiter la pr\u00e9sence des sources au strict n\u00e9cessaire, optimiser le positionnement des sources.<br>Dispositions architecturales : \u00e9loigner les \u00e9quipements g\u00e9n\u00e9rateurs de champs des zones de s\u00e9jour prolong\u00e9, positionner les colonnes montantes \u00e0 l'\u00e9cart, utiliser des c\u00e2bles en tr\u00e8fle, positionner le transformateur \u00e0 l\'ext\u00e9rieur ou blinder le local.<br>Blindage : mettre en \u0153uvre un blindage \u00e9lectrique et magn\u00e9tique, utiliser des peintures anti-ondes, utiliser des IAC (Interrupteurs Automatiques de Champ).",non_applicabilite:"L\'exigence ONDE3.1.1 peut \u00eatre d\u00e9clar\u00e9e comme non-applicable lorsque l\'axe Gestion est vis\u00e9 seul.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Document sur le choix des \u00e9quipements et dispositions prises, CCTP, plans.</td><td>Comparaison entre \u00e9quipements techniques ; Coh\u00e9rence entre sources EM et \u00e9quipements ; Coh\u00e9rence entre dispositions list\u00e9es et \u00e9l\u00e9ments dessin\u00e9s.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE et mise \u00e0 jour de la note si le projet a \u00e9t\u00e9 modifi\u00e9.</td><td>Coh\u00e9rence de la note avec les \u00e9quipements install\u00e9s et plans ; Constat in situ des dispositions architecturales et techniques.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>DOE ou tout autre document. En cas de modification : document justifiant du choix et des dispositions (dur\u00e9e de validit\u00e9 : illimit\u00e9e).</td><td>Coh\u00e9rence de la note avec les \u00e9quipements install\u00e9s ; Constat in situ des dispositions.</td></tr></table>"},"ONDE3.1.2":{attendu:"R\u00e9aliser un document synth\u00e9tisant des recommandations d\'am\u00e9nagement et organisationnelles \u00e0 destination du futur occupant (en construction/r\u00e9novation) ou de l\'occupant (en exploitation).",definition:"Recommandations bas\u00e9es sur le d\u00e9cret n\u00b02016-1074 du 3 ao\u00fbt 2016, portant par exemple sur : choix d'\u00e9quipements de travail \u00e0 faible \u00e9mission, moyens techniques pour r\u00e9duire l'\u00e9mission, modification de la conception et de l\'agencement des lieux de travail, programmes de maintenance, \u00e9quipements de protection individuelle, mesures organisationnelles contre les effets indirects, plan d\'impl\u00e9mentation des bornes Wifi.",reglementation:"D\u00e9cret n\u00b02016-1074 du 3 ao\u00fbt 2016 relatif \u00e0 la protection des travailleurs contre les risques dus aux champs \u00e9lectromagn\u00e9tiques.<br>Directive 2013/35/UE du 26 juin 2013 (valeurs limites d\'exposition professionnelle).<br>Recommandation 1999/519/CE (valeurs limites pour le public).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Document sur l\'am\u00e9nagement et l\'organisation synth\u00e9tisant les recommandations \u00e0 destination du futur occupant.</td><td>Justification sur la mise en place de recommandations visant \u00e0 limiter l\'exposition aux champs EM au regard du contexte du projet.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Document sur l\'am\u00e9nagement et l\'organisation (dur\u00e9e de validit\u00e9 : illimit\u00e9e, tant que le b\u00e2timent n\'a pas \u00e9t\u00e9 modifi\u00e9).</td><td>Justification sur la mise en place de recommandations au regard du contexte du projet.</td></tr></table>"},"VISU1":{intro:"Le th\u00e8me Confort visuel \u00e9value la qualit\u00e9 de l'\u00e9clairage naturel et artificiel dans les b\u00e2timents. Il couvre l\'autonomie lumineuse, l\'indice de rendu des couleurs, l'\u00e9blouissement et l\'acc\u00e8s aux vues.",context:"L'\u00e9valuation s\'articule autour de trois composantes : besoin (quantit\u00e9 de lumi\u00e8re), absence de g\u00eane (\u00e9blouissement) et agr\u00e9ment (qualit\u00e9 de la lumi\u00e8re et des vues)."},"VISU1.1":{intro:"Performance en confort visuel \u00e9valu\u00e9e par blocs homog\u00e8nes (BH) avec un syst\u00e8me de classes de A \u00e0 F.",context:"P\u00e9rim\u00e8tre d'\u00e9valuation : \u00e0 l'\u00e9chelle du sous-objet pour un b\u00e2timent. Pour un site ou parc, les exigences doivent se justifier b\u00e2timent par b\u00e2timent."},"VISU1.1.1":{attendu:"D\u00e9clarer la surface totale des locaux caract\u00e9ristiques de l\'activit\u00e9 et \u00e0 occupation autre que passag\u00e8re, en m\u00b2 de surface utile.",definition:"Locaux \u00e0 occupation autre que passag\u00e8re : locaux qui par destination impliquent une dur\u00e9e de s\u00e9jour pour un occupant sup\u00e9rieure \u00e0 une demi-heure. La surface \u00e0 prendre en compte est la surface utile.<br>\u00c0 l\'international, la surface utilis\u00e9e localement peut \u00eatre prise en compte.",important:"Pour \u00eatre certifi\u00e9, il est obligatoire de valider cette exigence.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Plans.</td><td>Phases Programme et Conception : Surfaces sur les plans. Phases R\u00e9alisation et Exploitation : Surfaces sur les plans et visite in situ.</td></tr></table>"},"VISU1.1.1.a":{attendu:"D\u00e9clarer la surface totale des blocs homog\u00e8nes (BH).",definition:"La somme des surfaces des BH doit repr\u00e9senter au moins 80% de la surface totale des espaces caract\u00e9ristiques. Si la condition n\'est pas respect\u00e9e, le PR VISU1.1.2 n\'est pas atteint."},"VISU1.1.2":{attendu:"Cr\u00e9er des Blocs Homog\u00e8nes (BH) et respecter la r\u00e8gle : Somme des surfaces des BH \u2265 80% de la surface totale des espaces caract\u00e9ristiques de l\'activit\u00e9 \u00e0 occupation autre que passag\u00e8re.",definition:"La surface utile est prise en compte. \u00c0 l\'international, la surface utilis\u00e9e localement peut \u00eatre prise en compte.<br>Les crit\u00e8res de d\u00e9termination des Blocs Homog\u00e8nes pour le confort visuel sont disponibles dans le document \u00ab Informations g\u00e9n\u00e9rales \u00bb.",important:"Pour \u00eatre certifi\u00e9, il est obligatoire de valider cette exigence.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>Description de la m\u00e9thode de calcul par \u00e9chantillonnage en introduisant la notion de blocs homog\u00e8nes (BH).</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Plans de rep\u00e9rage des BH et des locaux types, Calcul des surfaces \u00e0 l'\u00e9chelle de l\'ouvrage, Plans / Coupes / Fa\u00e7ades, CCTP.</td><td>Coh\u00e9rence de la d\u00e9termination des BH par rapport aux crit\u00e8res.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Plans de rep\u00e9rage des BH et des locaux types, Calcul des surfaces, Plans / Coupes / Fa\u00e7ades, DOE ou tout autre document (dur\u00e9e de validit\u00e9 illimit\u00e9e).</td><td>Coh\u00e9rence de la d\u00e9termination des BH par rapport aux crit\u00e8res.</td></tr></table>"},"VISU1.1.3":{attendu:"\u00c9valuer le niveau atteint en confort visuel sur la base des \u00e9valuations par BH. D\u00e9clarer le nombre de points atteints dans le fichier de calcul.",definition:"La m\u00e9thode d\'agr\u00e9gation est disponible dans le document \u00ab Informations g\u00e9n\u00e9rales \u00bb.<br>Selon les locaux, des conditions minimales doivent \u00eatre respect\u00e9es en termes d\'acc\u00e8s \u00e0 la lumi\u00e8re naturelle, acc\u00e8s aux vues, niveaux d'\u00e9clairement et \u00e9blouissement en \u00e9clairage artificiel et/ou naturel.<br>En France, ces conditions minimales sont celles du Code du Travail ou du R\u00e8glement Sanitaire D\u00e9partemental type.",reglementation:"Document Level(s) indicator 4.3: Lighting and Visual Comfort, version 1.1 de janvier 2021.<br>Code du Travail fran\u00e7ais (articles R4213 et R4223).<br>R\u00e8glement Sanitaire D\u00e9partemental type.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Se reporter au chapitre \u00ab Indicateurs \u00bb du pr\u00e9sent guide (Sous-th\u00e8me VISU2).</td><td></td></tr></table>"},"VISU2":{intro:"Indicateurs de performance du confort visuel \u00e9valu\u00e9s par blocs homog\u00e8nes.",context:"Six indicateurs couvrent l\'autonomie lumineuse, l\'indice de rendu des couleurs, l'\u00e9blouissement en \u00e9clairage artificiel et naturel, l\'acc\u00e8s aux vues et la ma\u00eetrise de l\'ambiance visuelle."},"VISU2.1":{intro:"Indicateurs de performance du confort visuel d\u00e9taill\u00e9s par type de local.",context:"Chaque indicateur est \u00e9valu\u00e9 par BH selon des tableaux d'\u00e9chelles d'\u00e9valuation sp\u00e9cifiques \u00e0 chaque type de local (classes A \u00e0 F)."},"VISU2.1.1":{attendu:"S\'assurer qu\'un niveau d'\u00e9clairement minimum en Lux est offert aux occupants des locaux, \u00e0 la fois par l'\u00e9clairage artificiel et par l'\u00e9clairage naturel (autonomie lumineuse).",definition:"\u00c9clairage artificiel : justifier que le syst\u00e8me d'\u00e9clairage permet d\'obtenir une capacit\u00e9 minimale d'\u00e9clairement \u00e0 maintenir (norme NF EN 12464-1).<br>Autonomie lumineuse : pourcentage de temps sur les heures de jour de la p\u00e9riode d\'occupation pendant lequel le niveau d'\u00e9clairement sur 80% de la surface du plan utile est sup\u00e9rieur ou \u00e9gal au niveau retenu.<br>Hypoth\u00e8ses : plan utile minimal de profondeur 2,5 x distance plan utile/linteau, hauteur du plan de travail 0,7 m (bureaux) ou 0 m (cr\u00e8ches, halls), facteurs de r\u00e9flexion par d\u00e9faut Sols 20%, Murs 50%, Plafonds 70%.<br>Grille r\u00e9guli\u00e8re avec espacement maximal 0,2*5 log10(d) o\u00f9 d est la plus grande dimension.<br>Calculs effectu\u00e9s avec un logiciel valid\u00e9 (r\u00e9f\u00e9rence CIE 171:2006).",attention:"Pour les b\u00e2timents en R\u00e9novation ou en Exploitation Axe B\u00e2timent : le niveau E (4 points) est atteint si le Code du Travail est respect\u00e9 (voir annexe 2). Pour atteindre un niveau sup\u00e9rieur, un calcul d\'autonomie doit \u00eatre r\u00e9alis\u00e9.<br>Pour les b\u00e2timents en exploitation Axe Gestion : cet indicateur n\'est pas pris en compte.<br>Pour tous les types de b\u00e2timents : les niveaux minima d'\u00e9clairement en Lux doivent \u00eatre garantis par l'\u00e9clairage artificiel seul.",reglementation:"Norme NF EN 12464-1.<br>Publication CIE 171:2006 \u00ab Test cases to assess the accuracy of lighting computer programs \u00bb.<br>Code du Travail fran\u00e7ais (articles R4213, R4223).<br>Norme NF X35-103 (annexe A) : m\u00e9thode de mesure des niveaux d'\u00e9clairement.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Implantation de l'\u00e9clairage artificiel, Fiches techniques des \u00e9quipements, Calculs d\'autonomie lumineuse, CCTP, Plan de masse avec les avoisinants.</td><td>V\u00e9rification des heures d\'occupation, du calcul et des hypoth\u00e8ses de calcul (zone d\'int\u00e9r\u00eat, heures de jour, grille, type de ciel, etc.).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Mise \u00e0 jour des implantations et fiches techniques si le projet a \u00e9t\u00e9 modifi\u00e9, DOE.</td><td>V\u00e9rification in situ de la concordance entre les hypoth\u00e8ses retenues et la r\u00e9alit\u00e9 du projet.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Implantation et fiches techniques des \u00e9quipements d'\u00e9clairage artificiel, Calculs d\'autonomie lumineuse, DOE ou tout autre document (dur\u00e9e de validit\u00e9 illimit\u00e9e).</td><td>V\u00e9rification in situ de la concordance entre les hypoth\u00e8ses retenues et la r\u00e9alit\u00e9 du projet.</td></tr></table>"},"VISU2.1.2":{attendu:"V\u00e9rifier que l\'indice de rendu des couleurs (Ra) des sources lumineuses est conforme aux valeurs de r\u00e9f\u00e9rence par type de local.",definition:"L\'indice Ra est celui retenu dans le r\u00e9f\u00e9rentiel ou dans la norme NF EN 12464-1. Il s\'agit de prendre en compte l\'indice de rendu des couleurs le plus d\u00e9favorable (dans le cas de sources lumineuses d\'IRC diff\u00e9rents dans un m\u00eame local).<br>Seules les sources principales du local sont \u00e0 consid\u00e9rer. Si un \u00e9clairage localis\u00e9 est pr\u00e9sent, c\'est la source lumineuse la plus proche de la t\u00e2che visuelle qui est \u00e0 consid\u00e9rer.",reglementation:"Norme NF EN 12464-1.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP.</td><td></td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td></td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE ou tout autre document (dur\u00e9e de validit\u00e9 illimit\u00e9e).</td><td>Valeurs des indices de rendu des couleurs par source lumineuse.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>DOE ou tout autre document (dur\u00e9e de validit\u00e9 illimit\u00e9e) OU \u00c9tat des lieux des \u00e9quipements.</td><td>Valeurs des indices de rendu des couleurs par source lumineuse.</td></tr></table>"},"VISU2.1.3":{attendu:"V\u00e9rifier que le taux d'\u00e9blouissement unifi\u00e9 (UGR) de l\'installation d'\u00e9clairage respecte les valeurs de r\u00e9f\u00e9rence par type de local.",definition:"L\'UGR est \u00e0 consid\u00e9rer au sens de la norme NF EN 12464-1. L\'UGR calcul\u00e9 est relatif \u00e0 la totalit\u00e9 de l\'installation d'\u00e9clairage g\u00e9n\u00e9ral.<br>L\'UGR est \u00e0 consid\u00e9rer en local \u00ab libre \u00bb (sans masques). Seules les sources principales du local sont \u00e0 consid\u00e9rer.<br>En pr\u00e9sence d\'une gradation de la lumi\u00e8re artificielle, il faut consid\u00e9rer la puissance maximale.",attention:"Pour les b\u00e2timents en R\u00e9novation ou en Exploitation : le niveau E (4 points) est atteint si les articles R4223-2, R4223-6 et R.4223-8 du Code du Travail sont respect\u00e9s (voir annexe 2). Pour atteindre un niveau sup\u00e9rieur, un calcul d\'UGR doit \u00eatre r\u00e9alis\u00e9.",reglementation:"Norme NF EN 12464-1.<br>Code du Travail fran\u00e7ais (articles R4223-2, R4223-6, R4223-8).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP et/ou calcul des UGR.</td><td>Valeurs des UGR par luminaire et/ou v\u00e9rification du calcul et des hypoth\u00e8ses de calcul.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE et/ou mise \u00e0 jour des calculs des UGR si le projet a \u00e9t\u00e9 modifi\u00e9 et/ou mesures in situ.</td><td>Valeurs des UGR par luminaire et/ou v\u00e9rification du calcul, V\u00e9rification in situ de la concordance.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>DOE ou tout autre document (dur\u00e9e de validit\u00e9 illimit\u00e9e).</td><td>Valeurs des UGR, v\u00e9rification des hypoth\u00e8ses de calcul, V\u00e9rification in situ de la concordance.</td></tr></table>"},"VISU2.1.4":{attendu:"\u00c9valuer le niveau d'\u00e9blouissement d\'inconfort en \u00e9clairage naturel, bas\u00e9 sur le type de protection solaire mis en place sur le bloc homog\u00e8ne.",definition:"L'\u00e9valuation se base sur le type de protection solaire et, en cas d\'absence, sur la configuration justifiant cette absence (orientation Nord, masques proches, configuration d\'ouvertures, ou calcul DGP).<br>Dans le cas de multiples orientations ou de protections diff\u00e9rentes, la solution la plus d\u00e9favorable est retenue.<br>Pour les territoires en climat chaud et chaud/humide, les protections solaires ext\u00e9rieures sont prioritaires.",attention:"Pour les b\u00e2timents en R\u00e9novation ou en Exploitation Axe B\u00e2timent : le niveau E (4 points) est atteint si les articles R.4223-2, R.4223-7 et R.4223-8 du Code du Travail sont respect\u00e9s. Pour atteindre un niveau sup\u00e9rieur, la m\u00eame \u00e9valuation qu\'en Construction est \u00e0 mener.<br>Pour les b\u00e2timents en exploitation Axe Gestion : cet indicateur n\'est pas pris en compte.",reglementation:"Normes NF EN 14500 (2021), NF EN 14501 (2021).<br>Code du Travail fran\u00e7ais (articles R4223-2, R4223-7, R4223-8).<br>Norme NF EN 17037.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plan masse.</td><td>Description des protections solaires et des caract\u00e9ristiques techniques (orientation des ouvertures, taux d\'ombrage, coefficient d\'ouverture de la toile).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td></td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE ou tout autre document (dur\u00e9e de validit\u00e9 illimit\u00e9e).</td><td>Caract\u00e9ristiques techniques, V\u00e9rification in situ.</td></tr></table>"},"VISU2.1.5":{attendu:"\u00c9valuer la qualit\u00e9 de l\'acc\u00e8s aux vues sur l\'ext\u00e9rieur \u00e0 partir de points de r\u00e9f\u00e9rence dans la surface utile. L\'indicateur se d\u00e9compose en 2 crit\u00e8res : la distance de vue et la composante de vue.",definition:"Une vue comprend trois composantes : ciel, paysage, sol. L\'indicateur est inspir\u00e9 de la norme EN 17037. Seuls 2 crit\u00e8res sont pris en compte : la distance de vue et la composante de vue.<br>Point de r\u00e9f\u00e9rence : observateur aux 3/4 de la profondeur normale \u00e0 la fa\u00e7ade, \u00e0 1,30 m du sol.<br>Nombre de points = Somme (Distance de vue + Composantes de vue).<br>La v\u00e9g\u00e9tation n\'est pas \u00e0 consid\u00e9rer comme un obstacle. Les atriums peuvent \u00eatre consid\u00e9r\u00e9s comme des espaces ext\u00e9rieurs.",attention:"Pour les b\u00e2timents en R\u00e9novation ou en Exploitation Axe B\u00e2timent : le niveau E (4 points) est atteint si l\'article R4223-3 du Code du Travail est respect\u00e9 (voir annexe 2). Pour atteindre un niveau sup\u00e9rieur, un calcul d\'acc\u00e8s aux vues doit \u00eatre r\u00e9alis\u00e9.<br>Pour les b\u00e2timents en exploitation Axe Gestion : cet indicateur n\'est pas pris en compte.",reglementation:"Norme EN 17037 \u00ab Lumi\u00e8re naturelle dans les b\u00e2timents \u00bb (d\u00e9cembre 2018).<br>Code du Travail fran\u00e7ais (article R4213-3).<br>Lettre-circulaire DRT n\u00b090/11 du 28 juin 1990.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>\u00c9tude justificative du crit\u00e8re saisi (distance de vue, composantes de vue), Plan de masse avec les avoisinants.</td><td>V\u00e9rification des valeurs pour chaque crit\u00e8re et des donn\u00e9es d\'entr\u00e9e utilis\u00e9es (positionnement de l\'observateur, zone d\'int\u00e9r\u00eat, etc.).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, Mise \u00e0 jour de l'\u00e9tude justificative, Plan de masse avec les avoisinants.</td><td></td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE ou tout autre document, \u00c9tude justificative, Plan de masse (dur\u00e9e de validit\u00e9 illimit\u00e9e).</td><td>V\u00e9rification des valeurs pour chaque crit\u00e8re et des donn\u00e9es d\'entr\u00e9e, V\u00e9rification in situ.</td></tr></table>"},"VISU2.1.6":{attendu:"\u00c9valuer la capacit\u00e9 des usagers \u00e0 ma\u00eetriser l\'ambiance visuelle de leur espace de travail, en \u00e9clairage artificiel et en \u00e9clairage naturel.",definition:"\u00c9clairage artificiel : \u00e9valuation de la pr\u00e9sence de dispositifs (gradation, temp\u00e9rature de couleur, allumage progressif, etc.), du zonage (tramage et profondeur) et de la ma\u00eetrise de l\'ambiance lumineuse.<br>\u00c9clairage naturel (non concern\u00e9 en Exploitation Gestion) : \u00e9valuation de la pr\u00e9sence de dispositifs (stores, rideaux), de leur motorisation et de leur type (individuels ou collectifs).<br>L'\u00e9valuation ne concerne que l'\u00e9clairage g\u00e9n\u00e9ral (pas l'\u00e9clairage d\'appoint).<br>D\u00e9finition \u00ab usagers \u00bb : personnes amen\u00e9es \u00e0 travailler ou \u00e0 occuper de fa\u00e7on permanente le b\u00e2timent.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP ; plans techniques.</td><td>Description des dispositifs de ma\u00eetrise de l\'ambiance visuelle (\u00e9clairage artificiel et \u00e9clairage naturel).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td></td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>DOE ou tout autre document (dur\u00e9e de validit\u00e9 illimit\u00e9e).</td><td>Description des dispositifs de ma\u00eetrise de l\'ambiance visuelle, V\u00e9rification in situ de la concordance entre les hypoth\u00e8ses retenues et la r\u00e9alit\u00e9 du projet.</td></tr></table>"},"ACES2":{intro:"Facilit\u00e9 d\u0027acc\u00e8s",context:"R\u00e9unir les conditions d\u0027un cheminement optimal et \u00e9quitable entre les visiteurs, depuis l\u0027entr\u00e9e sur la parcelle jusqu\u0027aux circulations horizontales et verticales."},
"ACES1":{intro:"Exigences g\u00e9n\u00e9rales",context:"Les exigences ACES 1.1.1 (Respect de la r\u00e9glementation ERP) et ACES 1.1.2 (Comp\u00e9tence en accessibilit\u00e9) ont \u00e9t\u00e9 <strong>supprim\u00e9es</strong> dans la version de septembre 2024 du r\u00e9f\u00e9rentiel HQE-BD v4.1.<br><br>Le th\u00e8me Accessibilit\u00e9 d\u00e9marre donc directement aux sous-th\u00e8mes performanciels :<br>\u2022 <strong>ACES 2</strong> \u2014 Facilit\u00e9 d\u0027acc\u00e8s<br>\u2022 <strong>ACES 3</strong> \u2014 Facilit\u00e9 d\u0027usage<br>\u2022 <strong>ACES 4</strong> \u2014 S\u00e9curit\u00e9"},
"ACES2.1":{intro:"Cheminements ext\u00e9rieurs et stationnement",context:"\u00c9valuer les circulations ext\u00e9rieures, les rev\u00eatements de sols et la pr\u00e9sence de places de stationnement adapt\u00e9es."},
"ACES2.1.1":{attendu:"\u00c9valuer les circulations ext\u00e9rieures (planes ou avec d\u00e9vers limit\u00e9) et les rampes si contraintes de site.",definition:"D\u00e9vers max 2%. En cas de contrainte de site : rampes avec bordures chasse-roues (10 cm), inclinaison max 5% (tol\u00e9rance 8% sur L < 2m, 10% sur L < 0,50m), paliers de repos tous les 7 m, rev\u00eatement antid\u00e9rapant.",non_applicabilite:"S\u0027il n\u0027existe pas de cheminements ext\u00e9rieurs.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Pr\u00e9sence des intentions</td></tr><tr><td><strong>Conception</strong></td><td>Plans</td><td>Coh\u00e9rence intentions / caract\u00e9ristiques</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Plans et/ou visite in situ</td><td>Pente des circulations, rampes</td></tr></table>"},
"ACES2.1.2":{attendu:"Rev\u00eatements des sols ext\u00e9rieurs facilitant la circulation des personnes.",definition:"Non r\u00e9fl\u00e9chissants, non meubles, antid\u00e9rapants. Pulv\u00e9rulents proscrits sauf liant am\u00e9liorant. Irr\u00e9gularit\u00e9s \u2264 5 mm. Trous et fentes \u2264 2 cm.<br>Normes : NF P 05-011, NF P 05-012, CEN/TS 16165.",non_applicabilite:"S\u0027il n\u0027existe pas de cheminements ext\u00e9rieurs.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Pr\u00e9sence dans le programme des intentions</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ ou doc technique</td><td>Caract\u00e9ristiques des rev\u00eatements ext\u00e9rieurs</td></tr></table>"},
"ACES2.1.3":{attendu:"Pr\u00e9sence et caract\u00e9ristiques de places de stationnement adapt\u00e9es.",definition:"Nombre conforme \u00e0 la r\u00e9glementation OU 1 place adapt\u00e9e par tranche de 50 places. Places au plus proche des acc\u00e8s, signal\u00e9es et mat\u00e9rialis\u00e9es.<br>Dimensions : L=500 cm, l=330 cm (250+80 passage), H min 215 cm si couvert, d\u00e9vers 2% max, connect\u00e9e sans seuil au cheminement.",non_applicabilite:"S\u0027il n\u0027existe pas de places de stationnement.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Pr\u00e9sence dans le programme de places adapt\u00e9es</td></tr><tr><td><strong>Conception</strong></td><td>Sch\u00e9mas des places</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ ou photographies</td><td>Pr\u00e9sence et caract\u00e9ristiques des places adapt\u00e9es</td></tr></table>"},
"ACES2.2":{intro:"Acc\u00e8s \u00e9quitable au b\u00e2timent",context:"Garantir des acc\u00e8s dignes, des dispositifs de communication et contr\u00f4le utilisables par tous, des portes d\u0027entr\u00e9e adapt\u00e9es et des seuils franchissables."},
"ACES2.2.1":{attendu:"Acc\u00e8s principal digne, configur\u00e9 pour \u00e9viter toute forme de discrimination.",definition:"Acc\u00e8s d\u0027usage (hors acc\u00e8s techniques). L\u0027entr\u00e9e ne peut se faire par un \u00e9l\u00e9vateur.<br>Sans contrainte de site : niveau d\u0027entr\u00e9e cal\u00e9 sur le niveau de r\u00e9f\u00e9rence ext\u00e9rieur.<br>Avec contrainte de site : justifier la contrainte et minimiser la diff\u00e9renciation des parcours.",attention:"Pour acc\u00e9der aux classes C, B ou A, la validation du premier niveau de cette exigence est obligatoire.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions + note contrainte si applicable</td><td>Pr\u00e9sence des intentions concernant les acc\u00e8s</td></tr><tr><td><strong>Conception</strong></td><td>Intentions + plans + note contrainte</td><td>Acc\u00e8s au niveau de r\u00e9f\u00e9rence, entr\u00e9e accessible pour tous</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ + note contrainte si applicable</td><td>Dispositions prises pour limiter la diff\u00e9renciation</td></tr></table>"},
"ACES2.2.2":{attendu:"Dispositifs de communication et de contr\u00f4le d\u0027acc\u00e8s utilisables par tous.",definition:"Espace d\u0027usage 80\u00d7130 cm pr\u00e9vu pour chaque \u00e9quipement. Ne n\u00e9cessitant pas d\u0027actions simultan\u00e9es.",non_applicabilite:"Si l\u0027op\u00e9ration ne dispose d\u0027aucun dispositif de communication et/ou de contr\u00f4le.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intention de mettre en place un (des) dispositif(s)</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ ou doc technique</td><td>Pr\u00e9sence, positionnement et caract\u00e9ristiques du dispositif</td></tr></table>"},
"ACES2.2.3":{attendu:"Portes de(des) entr\u00e9e(s) principale(s) utilisables par tous.",definition:"Entr\u00e9e principale = espace accueillant les flux de visiteurs (hors techniques).<br>Niv.1 : sas avec portes manuelles (\u2264 40N), porte tambour adapt\u00e9e (\u00d8 int \u2265 360 cm + porte secondaire), ou portes manuelles sans sas (\u2264 20N).<br>Niv.2 : entr\u00e9e sans sas ou sas ferm\u00e9 avec portes automatiques.<br>Niv.3 : toutes les entr\u00e9es au niv.2.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions sur la typologie et configuration des portes</td></tr><tr><td><strong>Conception</strong></td><td>Plans, CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ, tests manom\u00e9triques</td><td>Typologie et configuration des portes des entr\u00e9es principales</td></tr></table>"},
"ACES2.2.4":{attendu:"Seuil(s) d\u0027entr\u00e9e franchissable(s) sans effort.",definition:"Seuils des acc\u00e8s techniques et d\u0027usage courant inf\u00e9rieurs \u00e0 2 cm. Pour les seuils de plus de 5 mm, le ressaut doit \u00eatre biseaut\u00e9 (r\u00e8gle de 1 hauteur pour 3 longueurs).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions pour les dimensions des ressauts des seuils</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ</td><td>Dimension des ressauts des seuils d\u0027entr\u00e9e</td></tr></table>"},
"ACES2.3":{intro:"Espace d\u0027accueil convivial",context:"\u00c9valuer la qualit\u00e9 de l\u0027espace d\u0027accueil : visibilit\u00e9 depuis l\u0027entr\u00e9e, mobilier adapt\u00e9 et dispositifs de communication."},
"ACES2.3.1":{attendu:"Accueil en relation visuelle directe avec la(les) entr\u00e9e(s) principale(s) et mobilier de la banque d\u0027accueil confortable.",definition:"Comptoir bas (H sous plan 70 cm, profondeur 50 cm, largeur \u2265 1/3 et \u2265 90 cm) et comptoir haut.<br>Niv.2 : zone d\u0027attente avec assises + BIM (Boucle \u00e0 Induction Magn\u00e9tique) connect\u00e9e \u00e0 un microphone et amplificateur.",non_applicabilite:"Si l\u0027op\u00e9ration ne dispose pas d\u0027espace d\u0027accueil au niveau de(s) entr\u00e9e(s) principale(s).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Intentions concernant l\u0027accueil</td></tr><tr><td><strong>Conception</strong></td><td>CCTP, plans</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ ou photographies</td><td>Visibilit\u00e9 de l\u0027accueil, caract\u00e9ristiques mobilier et \u00e9quipements</td></tr></table>"},
"ACES2.4":{intro:"Desserte verticale \u00e9quitable",context:"\u00c9valuer la desserte par ascenseur et les caract\u00e9ristiques des cabines.",important:"Si l\u0027op\u00e9ration ne dispose pas de diff\u00e9rents niveaux, tout le bloc ACES2.4 est non applicable."},
"ACES2.4.1":{attendu:"Toutes les fonctions desservies par un ascenseur.",definition:"Niv.1 : au moins 50% des fonctions (en nombre de pi\u00e8ces) desservies. Pour les fonctions sp\u00e9cifiques, 100%.<br>Niv.2 : toutes les surfaces de tous les niveaux desservies.",attention:"Pour acc\u00e9der aux classes C, B ou A, la validation du premier niveau de cette exigence est obligatoire.",non_applicabilite:"Si l\u0027op\u00e9ration ne dispose pas de diff\u00e9rents niveaux.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Intentions concernant les niveaux et fonctions accessibles</td></tr><tr><td><strong>Conception</strong></td><td>Plans, coupes</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Plans, coupes et/ou visite in situ</td><td>Niveaux et fonctions accessibles par un ascenseur</td></tr></table>"},
"ACES2.4.3":{attendu:"Ascenseurs conformes et confortables.",definition:"Conformes \u00e0 NF-EN-81-70:2018.<br>Type 1 : 100\u00d7130 cm, 450 kg (existants uniquement).<br>Type 2 : 110\u00d7140 cm, 630 kg.<br>Type 3 : 110\u00d7210 cm, 1000 kg ou plus.",non_applicabilite:"Si l\u0027op\u00e9ration ne dispose pas de diff\u00e9rents niveaux.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions concernant les cabines d\u0027ascenseurs</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ, doc technique, conformit\u00e9</td><td>Dimensions des cabines ; Caract\u00e9ristiques des cabines</td></tr></table>"},
"ACES2.5":{intro:"Circulation horizontale ais\u00e9e",context:"\u00c9valuer les circulations int\u00e9rieures : absence de d\u00e9vers, traitement des rampes, caract\u00e9ristiques des rev\u00eatements et seuils."},
"ACES2.5.1":{attendu:"Circulations int\u00e9rieures planes et sans d\u00e9vers, ou trait\u00e9es par des rampes si contraintes de site.",definition:"Niv.1 : Circulations non planes trait\u00e9es par \u00e9l\u00e9vateurs.<br>Niv.2 : Circulations planes ou trait\u00e9es par rampes (sans d\u00e9vers, anti-glissant, pente max 5%/6%/8%/10%/12% selon longueur, mains courantes si pente > 4%, paliers de repos tous les 10 m).<br>Patios et terrasses clos et couverts inclus.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Intentions concernant les circulations int\u00e9rieures</td></tr><tr><td><strong>Conception</strong></td><td>Plans + CCTP si \u00e9l\u00e9vateurs</td><td>Altim\u00e9trie, caract\u00e9ristiques rampes/\u00e9l\u00e9vateurs</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ + doc technique</td><td>Altim\u00e9trie, rampes, \u00e9l\u00e9vateurs, rev\u00eatements</td></tr></table>"},
"ACES2.5.2":{attendu:"Caract\u00e9ristiques des circulations int\u00e9rieures permettant un d\u00e9placement ais\u00e9.",definition:"Largeur \u2265 140 cm (r\u00e9tr\u00e9cissements ponctuels \u2264 120 cm sur \u2264 150 cm). Espaces de rotation \u00d8 150 cm tous les 10 m. Rev\u00eatements antid\u00e9rapants, non r\u00e9fl\u00e9chissants, irr\u00e9gularit\u00e9s \u2264 5 mm, trous/fentes \u2264 2 cm. Seuils des portes d\u0027usage < 2 cm.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions concernant les circulations</td></tr><tr><td><strong>Conception</strong></td><td>Plans annot\u00e9s, CCTP</td><td>Altim\u00e9trie, contrainte de site, rampes, \u00e9l\u00e9vateurs</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Plans et visite in situ</td><td>Dimensions, rev\u00eatements, seuils, rotations</td></tr></table>"},
"ACES3":{intro:"Facilit\u00e9 d\u0027usage",context:"Assurer que les mouvements et gestes ordinaires puissent s\u0027effectuer sans difficult\u00e9s, notamment pour les visiteurs plus sensibles."},
"ACES3.2":{intro:"Stimuli sensoriels dans les circulations",context:"\u00c9valuer les contrastes visuels des sols, murs, portes et poign\u00e9es dans les circulations."},
"ACES3.2.2":{attendu:"Sols, murs, portes et poign\u00e9es contrast\u00e9s.",definition:"Contraste de 30 points LRV (Light Reflectance Value) entre : sols/murs et \u00e9l\u00e9ments structurants, portes/paroi supports, poign\u00e9es/paroi support ou fond visuel. Justifiable par nuancier RAL ou luminance-m\u00e8tre.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Intentions sur les contrastes</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ</td><td>Contraste des sols, murs, portes et poign\u00e9es</td></tr></table>"},
"ACES3.3":{intro:"Commandes, portes et amplification des sons",context:"\u00c9valuer les dispositifs de commande, les portes et la pr\u00e9sence d\u0027\u00e9quipements d\u0027aide."},
"ACES3.3.1":{attendu:"Dispositifs de commandes faciles \u00e0 atteindre.",definition:"Espace d\u0027usage 80\u00d7130 cm. Commandes \u00e0 plus de 40 cm d\u0027un angle int\u00e9rieur (si parois > 25 cm). Commandes murales entre 90 et 110 cm. Ne n\u00e9cessitant pas d\u0027actions simultan\u00e9es.<br>Concern\u00e9es : interphones, contr\u00f4les d\u0027acc\u00e8s, interrupteurs, stores/volets, contr\u00f4le thermique, boutons d\u0027appel ascenseurs, \u00e9quipements logistiques.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions architecturales</td><td>Intentions sur l\u0027implantation des commandes</td></tr><tr><td><strong>Conception</strong></td><td>CCTP, plans</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Liste des commandes, visite in situ</td><td>Implantation, espaces d\u0027usage, typologies des commandes</td></tr></table>"},
"ACES3.3.3":{attendu:"Pr\u00e9sence d\u0027\u00e9quipements d\u0027aides \u00e0 l\u0027ex\u00e9cution des t\u00e2ches de manutention, levage, chargement et d\u00e9chargement.",definition:"Cat\u00e9gorie 1 : \u00c9quipements de manutention (convoyeurs, filmeuses, palans, distributeurs de palette).<br>Cat\u00e9gorie 2 : Dispositifs de mise \u00e0 quai, chargement/d\u00e9chargement ais\u00e9s et portes \u00e9lectriques.",non_applicabilite:"Si l\u0027op\u00e9ration ne pr\u00e9sente pas de zones de chargement.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions sur les \u00e9quipements de manutention</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Doc technique, photographies, visite in situ</td><td>Pr\u00e9sence d\u0027\u00e9quipements aidant la manutention</td></tr></table>"},
"ACES3.3.4":{attendu:"Man\u0153uvre de portes ais\u00e9e et limitant le risque de chocs.",definition:"Espace de man\u0153uvre devant chaque porte (1,70 m en poussant, 2,20 m en tirant). Retournement dans les sas (\u00d8 150 cm).<br>Niv.2 : + s\u00e9curisation des d\u00e9battements de porte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions concernant les portes</td></tr><tr><td><strong>Conception</strong></td><td>CCTP, plans</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>DOE, visite in situ</td><td>Configurations et caract\u00e9ristiques des portes</td></tr></table>"},
"ACES3.4":{intro:"Ergonomie des espaces d\u0027hygi\u00e8ne",context:"\u00c9valuer le nombre, l\u0027implantation et l\u0027\u00e9quipement des sanitaires."},
"ACES3.4.1":{attendu:"Sanitaires r\u00e9guli\u00e8rement pr\u00e9vus en nombre suffisant.",definition:"Pr\u00e9sence d\u0027au moins un sanitaire par niveau. Pour les grandes op\u00e9rations, dimensionnement par \u00e9tude de flux (distance max 40 m).<br>Pour la logistique : vestiaires et sanitaires, ratio H/F 50/50.",non_applicabilite:"Uniquement applicable aux secteurs Commerce, Logistique, Transport, Spectacle, Culture, B\u00e2timents d\u0027exposition.",attention:"Pour acc\u00e9der aux classes C, B ou A, la validation du premier niveau de cette exigence est obligatoire.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Typologie du b\u00e2timent et intentions sur le nombre de sanitaires</td></tr><tr><td><strong>Conc./R\u00e9al./Exploit.</strong></td><td>Plans et justificatif</td><td>Nombre de sanitaires. Justificatif du dimensionnement</td></tr></table>"},
"ACES3.4.2":{attendu:"Pr\u00e9sence d\u0027une cabine adapt\u00e9e dans chaque bloc sanitaire ou a minima \u00e0 chaque niveau.",definition:"Cabine adapt\u00e9e : espace d\u0027usage 80\u00d7130 cm au droit de la cuvette, aire de rotation \u00d8 150 cm, lavabo adapt\u00e9.<br>Niv.1 : une cabine adapt\u00e9e \u00e0 chaque niveau desservi par ascenseur.<br>Niv.2 : une cabine adapt\u00e9e dans chaque bloc sanitaire.",attention:"Pour acc\u00e9der aux classes C, B ou A, la validation du premier niveau de cette exigence est obligatoire.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions concernant les cabines adapt\u00e9es</td></tr><tr><td><strong>Conception</strong></td><td>Liste des sanitaires + plans annot\u00e9s</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite in situ + plan des sanitaires annot\u00e9</td><td>Nombre et emplacement (Blocs H/F) des cabines adapt\u00e9es. Aire de rotation</td></tr></table>"},
"ACES3.4.3":{attendu:"\u00c9quipements minimaux pr\u00e9sents dans les cabines et espaces sanitaires.",definition:"Cabines : loquets/verrous sans effort, indicateur d\u0027occupation.<br>Cabines adapt\u00e9es : cuvette H 45-50 cm, barre d\u0027appui coud\u00e9e, lunette rabattable, barre d\u0027aide \u00e0 la fermeture de porte, lave-mains \u00e0 plus de 30 cm du nez de cuvette, commande de chasse d\u0027eau accessible.",non_applicabilite:null,preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions sur les \u00e9quipements sanitaires</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Liste d\u0027\u00e9quipements, doc technique, visite</td><td>Pr\u00e9sence, caract\u00e9ristiques et implantation des \u00e9quipements</td></tr></table>"},
"ACES4":{intro:"S\u00e9curit\u00e9",context:"Minimiser les risques de chute et de choc dans les circulations horizontales et verticales."},
"ACES4.1":{intro:"Cheminement garanti sans obstacle",context:"\u00c9valuer le traitement des obstacles, des leurres visuels et des dispositifs de s\u00e9curit\u00e9 contre les chutes."},
"ACES4.1.1":{attendu:"Circulations horizontales et verticales libres d\u0027obstacles.",definition:"Niv.1 : obstacles rep\u00e9rables et d\u00e9tectables (contrast\u00e9s, d\u00e9tectables \u00e0 la canne blanche < 40 cm).<br>Niv.2 : cheminement garanti libre d\u0027obstacle (couloir virtuel 140 cm, obstacles hors cheminement, obstacles en hauteur contrast\u00e9s et d\u00e9tectables \u00e0 la canne).",attention:"Pour acc\u00e9der aux classes C, B ou A, la validation du premier niveau de cette exigence est obligatoire.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions</td></tr><tr><td><strong>Conception</strong></td><td>Intentions</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Liste d\u0027obstacles, visite in situ</td><td>Mode de traitement des obstacles. Coh\u00e9rence liste/visite</td></tr></table>"},
"ACES4.1.2":{attendu:"Mat\u00e9rialisation des \u00e9l\u00e9ments pouvant cr\u00e9er un leurre visuel.",definition:"Parois vitr\u00e9es, miroirs ou mat\u00e9riau r\u00e9fl\u00e9chissant > 50 cm de large : 2 bandes contrast\u00e9es de 10 cm de largeur \u00e0 110 cm et 160 cm de hauteur.",non_applicabilite:"Si le b\u00e2timent ne pr\u00e9sente pas d\u0027\u00e9l\u00e9ments pouvant cr\u00e9er un leurre visuel.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions sur la mise en place de leurres visuels</td></tr><tr><td><strong>Conception</strong></td><td>Liste des leurres visuels</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Liste des leurres, visite in situ</td><td>Modes de traitement des leurres visuels. Coh\u00e9rence liste/visite</td></tr></table>"},
"ACES4.1.3":{attendu:"Pr\u00e9sence de dispositifs de s\u00e9curit\u00e9 en cas de risque de chute.",definition:"Dispositif de protection proportionn\u00e9 au risque l\u00e0 o\u00f9 une circulation surplombe une zone plus basse avec un \u00e9cart > 25 cm. D\u00e9tectable \u00e0 la canne et contrast\u00e9.",non_applicabilite:"Si l\u0027op\u00e9ration ne comporte pas de situations de risques de chute.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Modes de traitement des risques de chute</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Liste des risques de chutes, visite in situ</td><td>Modes de traitement. Coh\u00e9rence liste/visite</td></tr></table>"},
"ACES4.2":{intro:"Escaliers s\u00fbrs",context:"\u00c9valuer la morphologie des escaliers et la pr\u00e9sence de dispositifs tactiles et visuels.",important:"Si l\u0027op\u00e9ration ne comporte pas d\u0027escaliers ou d\u0027emmarchements, le bloc ACES4.2 est non applicable."},
"ACES4.2.1":{attendu:"Morphologie d\u0027escalier facilitant son franchissement et pr\u00e9sence de mains courantes.",definition:"Niv.1 (20-25 marches) : girons \u2265 22 cm, relation de Blondel (60 \u2264 2h+g \u2264 64 cm), d\u00e9bord nez \u2264 1 cm, mains courantes des deux c\u00f4t\u00e9s.<br>Niv.2 (< 20 marches) : mains courantes interm\u00e9diaires si largeur > 420 cm.",non_applicabilite:"Si pas d\u0027escaliers ou d\u0027emmarchements.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions concernant les escaliers et mains courantes</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>Relation de Blondel, largeur des girons</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Doc technique, photographies, visite in situ</td><td>Paliers, mains courantes, dimensions</td></tr></table>"},
"ACES4.2.2":{attendu:"Pr\u00e9sence d\u0027un dispositif tactile et visuel en amont de chaque vol\u00e9e d\u0027escaliers descendante.",definition:"Largeur min 40 cm. Escalier ferm\u00e9 : d\u00e9bute \u00e0 1 giron du nez de la 1\u00e8re marche (50 cm pour le neuf). Espace ouvert : \u00e0 50 cm du nez. Parall\u00e8le et couvrant toute la largeur. Nez de marches contrast\u00e9s et non glissants.",non_applicabilite:"Si pas d\u0027escaliers ou d\u0027emmarchements.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Intentions concernant ces dispositifs</td></tr><tr><td><strong>Conception</strong></td><td>CCTP</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Doc technique, photographies, visite in situ</td><td>Pr\u00e9sence, largeur et positionnement du dispositif tactile</td></tr></table>"},
"ACES4.3":{intro:"Zones de chargement s\u00fbres",context:"\u00c9valuer les \u00e9quipements de s\u00e9curit\u00e9 au niveau des zones de chargement.",important:"Si l\u0027op\u00e9ration ne comporte pas de zones de chargement, le bloc ACES4.3 est non applicable."},
"ACES4.3.1":{attendu:"Pr\u00e9sence d\u0027un syst\u00e8me actif de calage ou guide des remorques.",definition:"Syst\u00e8me actif de calage int\u00e9gr\u00e9 dans le sol, asservi \u00e0 l\u0027ouverture/fermeture des portes de quai, d\u00e9tection de pr\u00e9sence, ou tout syst\u00e8me emp\u00eachant le d\u00e9part inopin\u00e9 du camion.",non_applicabilite:"Si l\u0027op\u00e9ration ne pr\u00e9sente pas de zones de chargement.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>Coh\u00e9rence doc/caract\u00e9ristiques du projet</td></tr><tr><td><strong>Conception</strong></td><td>CCTP des \u00e9quipements de quai</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite de site, DOE</td><td>Asservissement du syst\u00e8me \u00e0 l\u0027ouverture/fermeture des portes</td></tr></table>"},
"ACES4.3.2":{attendu:"Mise en place de feux pour s\u00e9curiser les op\u00e9rations de chargement/d\u00e9chargement.",definition:"Feux de signalisation install\u00e9s au niveau des zones de chargement pour signaler la mise \u00e0 quai et s\u00e9curiser les op\u00e9rations.",non_applicabilite:"Si l\u0027op\u00e9ration ne pr\u00e9sente pas de zones de chargement.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Intentions</td><td>-</td></tr><tr><td><strong>Conception</strong></td><td>CCTP des \u00e9quipements de quai</td><td>-</td></tr><tr><td><strong>R\u00e9al./Exploit.</strong></td><td>Visite de site, DOE</td><td>Pr\u00e9sence de feux de signalisation au niveau des zones de chargement</td></tr></table>"},"TRAN1":{intro:"Dispositifs pr\u00e9sents sur site",context:"P\u00e9rim\u00e8tre: site dans sa globalit\u00e9, b\u00e2timent et parcelle."},"TRAN1.1":{intro:"Acc\u00e8s et flux",context:"NA si axe Gestion seul vis\u00e9."},"TRAN1.1.1":{attendu:"Zones de livraison et d\u00e9chets avec acc\u00e8s diff\u00e9renci\u00e9s",definition:"Zones livraison/d\u00e9chets doivent avoir acc\u00e8s clairement diff\u00e9renci\u00e9s et s\u00e9curis\u00e9s par rapport aux autres acc\u00e8s. Acc\u00e8s livraison commun avec d\u00e9chets accept\u00e9, mais distincts des pi\u00e9tons et v\u00e9los.",non_applicabilite:"Si acc\u00e8s livraison ou d\u00e9chets manquants.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>D\u00e9finition des objectifs</td><td>-</td></tr><tr><td><strong>Conception</strong></td><td>Plan de masse/sch\u00e9ma flux</td><td>-</td></tr><tr><td><strong>R\u00e9alisation</strong></td><td>DOE, plan masse, visite in situ</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>DOE, plan masse, visite in situ</td><td>-</td></tr></table>"},"TRAN1.1.2":{attendu:"S\u00e9curisation de tous les types d\u0027acc\u00e8s",definition:"Acc\u00e8s pi\u00e9tons et v\u00e9los distincts des flux motoris\u00e9s. Cheminements distingu\u00e9s par s\u00e9paration physique. Travers\u00e9es en continuit\u00e9 directe. Marquage ou changement de rev\u00eatement au sol entre modes doux et autres modes n\u0027est PAS suffisant.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>D\u00e9finition et justification des objectifs</td><td>-</td></tr><tr><td><strong>Conception</strong></td><td>Plan de masse/sch\u00e9ma flux</td><td>-</td></tr><tr><td><strong>R\u00e9alisation</strong></td><td>DOE, plan masse, visite in situ</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>DOE, plan masse, visite in situ</td><td>-</td></tr></table>"},"TRAN1.2":{intro:"V\u00e9los",context:"Bloc peut ne pas \u00eatre applicable dans certaines conditions (axe Gestion seul, secteur Logistique, certaines activit\u00e9s). Points d\u00e9duits si NA."},"TRAN1.2.1":{attendu:"Emplacements v\u00e9los dimensionn\u00e9s",definition:"Emplacements v\u00e9los dimensionn\u00e9s au regard des flux utilisateurs. Bureaux: 1.5% surface plancher ou 15% effectif. Industriel/tertiaire hors bureaux: 15% effectif. Service public: 15% effectif agents/usagers. Ensembles commerciaux: selon taille parc stationnement (10%/<40pl, 5%/40-400pl, 2%/>400pl).<br>R\u00e9glementation: D\u00e9cret n\u00b02022-930, Arr\u00eat\u00e9 30 juin 2022.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>D\u00e9finition et justification des objectifs, dimensionnement</td><td>-</td></tr><tr><td><strong>Conception</strong></td><td>Plans d\u0027architecture, nombre places v\u00e9lo</td><td>-</td></tr><tr><td><strong>R\u00e9alisation</strong></td><td>DOE, plans, fiches techniques, CCTP, visite in situ</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>DOE, dimensionnement, plans, fiches, CCTP, visite in situ</td><td>-</td></tr></table>"},"TRAN1.2.2":{attendu:"Emplacements v\u00e9los s\u00e9curis\u00e9s et abrit\u00e9s",definition:"Emplacements v\u00e9los s\u00e9curis\u00e9s et abrit\u00e9s: attacher roue ou cadre, espace r\u00e9serv\u00e9, couvert. Peut \u00eatre ext\u00e9rieur si couvert et m\u00eame unit\u00e9 fonci\u00e8re.<br>R\u00e9glementation: D\u00e9cret n\u00b02022-930, Arr\u00eat\u00e9 30 juin 2022.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>D\u00e9finition des objectifs</td><td>-</td></tr><tr><td><strong>Conception</strong></td><td>CCTP, plan masse, plans architecture</td><td>-</td></tr><tr><td><strong>R\u00e9alisation</strong></td><td>DOE, visite in situ</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>DOE, visite in situ</td><td>-</td></tr></table>"},"TRAN1.2.3":{attendu:"Espaces communs pour personnel cycliste",definition:"Vestiaires ET douches accessibles pour le personnel cycliste. Mutualisation possible si m\u00eame parcelle, d\u00e9di\u00e9s aux utilisateurs, dimensionnement suffisant. Pour DOM-TOM: mutualisation hors parcelle possible avec conventions.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>D\u00e9finition des objectifs</td><td>-</td></tr><tr><td><strong>Conception</strong></td><td>CCTP, plan masse, plans architecture</td><td>-</td></tr><tr><td><strong>R\u00e9alisation</strong></td><td>DOE, visite in situ</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>DOE, visite in situ</td><td>-</td></tr></table>"},"TRAN1.3":{intro:"V\u00e9hicules \u00e9lectriques",context:"NA si axe Gestion seul ou parc stationnement \u2264 10 emplacements."},"TRAN1.3.1":{attendu:"Zone stationnement v\u00e9hicules propres",definition:"Emplacements pour v\u00e9hicules \u00e9lectriques/hybrides rechargeables dimensionn\u00e9s selon flux. Tertiaire/industriel: <40 pl = 10% pr\u00e9-\u00e9quip\u00e9es, >40 pl = 20%. Commerces/cin\u00e9mas: <40 pl = 5%, >40 pl = 10%. Niveau 2: 20% totalit\u00e9 pr\u00e9-\u00e9quip\u00e9s. Niveau 3: Niveau 2 ET mise en place effective de bornes (5% \u00e9quip\u00e9s + 15% pr\u00e9-\u00e9quip\u00e9s). Mutualisation possible (m\u00eame parcelle, d\u00e9di\u00e9s, dimensionnement suffisant). DOM-TOM: mutualisation hors parcelle possible.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>D\u00e9finition des objectifs</td><td>-</td></tr><tr><td><strong>Conception</strong></td><td>CCTP, plans</td><td>-</td></tr><tr><td><strong>R\u00e9alisation</strong></td><td>DOE, plans, fiches, visite in situ</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>DOE, plans, fiches, visite in situ</td><td>-</td></tr></table>"},"TRAN2":{intro:"Offre de transports \u00e0 proximit\u00e9",context:"Important: Si projets nouvelles lignes en cours, futures lignes prises en compte si connues."},"TRAN2.1":{intro:"Transports en commun",context:"Applicable tous secteurs sauf conditions sp\u00e9cifiques (impossibilit\u00e9 TC ET liaison <20min, secteur Logistique, activit\u00e9s sp\u00e9cifiques). NA d\u00e9duit points TRAN2.1."},"TRAN2.1.1":{attendu:"Nombre de lignes accessibles",definition:"Comptabiliser lignes TC depuis entr\u00e9e principale. Distance urbain: 400m (800m 2e seuil). Distance rural: 1km (2km 2e seuil). Lignes trains/TER et bus interurbains comptabilis\u00e9es. En exploitation Gestion: 1 ligne=1pt, 2 lignes=2pts, 3+=3pts.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports proximit\u00e9</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour si modification</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document relatif, plan localisation, plan masse</td><td>-</td></tr></table>"},"TRAN2.1.2":{attendu:"Fr\u00e9quence de desserte",definition:"Fr\u00e9quence moyenne entre heures de pointe et creuses. Si aucun arr\u00eat <800m urbain, prendre en compte fr\u00e9quence dans rayon 1km. Rural: 20min = environ 1.3km. En exploitation Gestion: navettes possibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document, plan, horaires et fr\u00e9quences</td><td>-</td></tr></table>"},"TRAN2.1.3":{attendu:"Correspondance ligne transport <20 min",definition:"Correspondance = ligne TC non recens\u00e9e dans rayon 800m et accessible en <20min TC. En exploitation Gestion: navettes possibles. Hors milieu urbain: 20min peut \u00eatre r\u00e9alis\u00e9e en transports particuliers.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document, plan, horaires</td><td>-</td></tr></table>"},"TRAN2.1.4":{attendu:"Acc\u00e8s parking relais/gare/arr\u00eat bus interurbain",definition:"Connexion \u00e0 parking relais, gare trains (TER), arr\u00eat bus interurbains accessible modes doux <20min. En exploitation Gestion: navettes possibles. DOM-TOM: gares routi\u00e8res, t\u00e9l\u00e9ph\u00e9rique urbain, BHNS.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document, plan, horaires</td><td>-</td></tr></table>"},"TRAN2.2":{intro:"V\u00e9hicules \u00e9lectriques et v\u00e9los",context:""},"TRAN2.2.1":{attendu:"Station v\u00e9los libre-service",definition:"Localisation par rapport \u00e0 station v\u00e9los libre-service. Distance \u00e0 pied. Urbain: 400m/800m. Rural: 1km/2km. Flottes priv\u00e9es valoris\u00e9es si 2+ prestataires. NA pour secteur Logistique, Aire de service, A\u00e9rogare. Ne s\u0027applique pas en exploitation Gestion.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>Document, plan localisation stations, plan masse</td><td>-</td></tr></table>"},"TRAN2.2.2":{attendu:"Station v\u00e9hicules \u00e9lectriques libre-service",definition:"Localisation par rapport station v\u00e9hicule \u00e9lectrique (VL). Urbain: 400m. Rural: 1km. NA similaire \u00e0 TRAN2.2.1 + NA si activit\u00e9s sp\u00e9cifiques et Niv.3 TRAN1.3.1 atteint. Ne s\u0027applique pas en exploitation Gestion. Niv.1: borne de recharge (v\u00e9hicule d\u00e9di\u00e9 pas obligatoire). Niv.2: station compl\u00e8te (borne + v\u00e9hicule).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>Document, plan localisation bornes/stations, plan masse</td><td>-</td></tr></table>"},"TRAN2.3":{intro:"Gares et a\u00e9roports",context:""},"TRAN2.3.1":{attendu:"Temps d\u0027acc\u00e8s gare TGV ou a\u00e9roport",definition:"Applicable: Bureaux, H\u00f4tellerie, Transport, Spectacle, Culture, Exposition. NA pour certaines activit\u00e9s. Ne s\u0027applique pas en exploitation Gestion. Temps d\u0027acc\u00e8s moyen (pointe + creuse) via SIG/Googlemap/Mappy. Temps de correspondance: Voiture/TC=5min, Voiture/Avion=30min, TC/Avion=30min. DOM-TOM: gares TGV non consid\u00e9r\u00e9es.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>Document, plan localisation gares/a\u00e9roports, plan masse</td><td>-</td></tr></table>"},"TRAN2.4":{intro:"Pistes cyclables",context:"NA possible international, secteur Logistique, Aire de service, A\u00e9rogare."},"TRAN2.4.1":{attendu:"Acc\u00e8s raisonnablement s\u00e9curis\u00e9",definition:"Trajet entr\u00e9e parcelle \u2192 piste/r\u00e9seau cyclable le plus proche est s\u00e9curis\u00e9. Types d\u0027am\u00e9nagements: pistes cyclables, voies vertes, bandes cyclables, couloirs bus, zones 30, zones de rencontre, zones pi\u00e9tonnes. Acc\u00e8s s\u00e9curis\u00e9 si: am\u00e9nagement clairement distingu\u00e9 OU urbain voie \u226450km/h 1 voie OU rural voie \u226490km/h 1 voie.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document</td><td>-</td></tr></table>"},"TRAN2.4.2":{attendu:"R\u00e9seau cyclable s\u00e9curis\u00e9",definition:"Itin\u00e9raire cyclable atteignant un point >2.5km \u00e0 vol d\u0027oiseau, empruntant >50% piste cyclable/voie verte, sans discontinuit\u00e9s >250m.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document</td><td>-</td></tr></table>"},"TRAN2.4.3":{attendu:"R\u00e9seau cyclable \u00e9tendue \u00e9lev\u00e9e >5km",definition:"Itin\u00e9raire cyclable atteignant un point >5km \u00e0 vol d\u0027oiseau, empruntant >50% piste cyclable/voie verte, sans discontinuit\u00e9s >250m.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document</td><td>-</td></tr></table>"},"TRAN2.5":{intro:"Infrastructures routi\u00e8res",context:"NA en exploitation axe Gestion."},"TRAN2.5.1":{attendu:"Route d\u00e9partementale ou art\u00e8re urbaine structurante",definition:"Connexion au r\u00e9seau routier. Urbain: art\u00e8re urbaine (boulevard, avenue, rue principale multi-voies, rue traversante, rue connectant 2 centres-villes). Rural: route d\u00e9partementale reliant chefs-lieux.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>Document</td><td>-</td></tr></table>"},"TRAN2.5.2":{attendu:"Routes express ou autoroutes accessibles",definition:"Routes avec chauss\u00e9es s\u00e9par\u00e9es, 2+ voies par direction, acc\u00e8s d\u00e9nivel\u00e9s. Boulevards p\u00e9riph\u00e9riques et rocades inclus.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B</strong></td><td>Document</td><td>-</td></tr></table>"},"TRAN2.6":{intro:"Transport multimodal",context:"Applicable UNIQUEMENT secteur Logistique (transport de marchandises)."},"TRAN2.6.1":{attendu:"Site offrant transport multimodal",definition:"Raccordement fer, fluvial, route. Points si possibilit\u00e9 de raccord multimodal.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Document offre transports</td><td>-</td></tr><tr><td><strong>Conception+R\u00e9alisation</strong></td><td>Mise \u00e0 jour</td><td>-</td></tr><tr><td><strong>Exploitation B+G</strong></td><td>Document</td><td>-</td></tr></table>"},"SERV1":{intro:"Performance sur le th\u00e8me Services",context:"P\u00e9rim\u00e8tre d\u0027\u00e9valuation :<br>\u25aa Cas d\u0027un sous-objet : prendre en compte le site dans sa globalit\u00e9.<br>\u25aa Cas d\u0027un b\u00e2timent (objet) : p\u00e9rim\u00e8tre des responsabilit\u00e9s et spatial = ensemble du b\u00e2timent et sa parcelle.<br>\u25aa Cas d\u0027un site : \u00e9valuation mutualis\u00e9e \u00e0 plusieurs b\u00e2timents.<br>\u25aa Cas d\u0027un parc : exigences propres \u00e0 chaque site et op\u00e9ration."},
"SERV1.1":{intro:"Performance sur le th\u00e8me Services",context:"Une seule exigence SERV1.1.1 couvrant les services \u00e0 proximit\u00e9 et au sein du b\u00e2timent. Niveaux A \u00e0 F, 0 \u00e0 20 points. \u00c9valuation via fichier Excel de calcul joint \u00e0 l\u0027exigence IDEN1.1.3."},
"SERV1.1.1":{attendu:"Performance sur le th\u00e8me Services",definition:"Cette exigence \u00e9value la prise en compte des services offerts \u00e0 proximit\u00e9 et au sein du b\u00e2timent.<br><br><strong>Services \u00e0 proximit\u00e9 du b\u00e2timent :</strong><br>Deux cat\u00e9gories retenues : utilisation quotidienne et hebdomadaire.<br>Typologies : Restauration (max 3), Commerces de proximit\u00e9 (max 7), Activit\u00e9s m\u00e9dicales (max 2), Parcs (max 3), Activit\u00e9s sportives (max 3), Services locaux (max 3).<br><br><strong>Distances :</strong><br>\u25aa Milieu urbain : 400 m (distance r\u00e9elle \u00e0 pied)<br>\u25aa Milieu rural : 1 km<br>\u25aa DOM-COM : 800 m (urbain) / 2 km (rural)<br><br><strong>Services au sein du b\u00e2timent :</strong><br>Services li\u00e9s au B\u00e2timent (Construction, R\u00e9novation, Exploitation axe B\u00e2timent) : restaurant d\u0027entreprise, caf\u00e9t\u00e9ria, coin cuisine, salle de sport, cr\u00e8che, salle de repos, etc.<br>Services li\u00e9s \u00e0 la Gestion (Exploitation axe Gestion) : wifi, conciergerie, relais poste, paniers bio, pr\u00eat v\u00e9los, etc.<br>Nombre maximum : 15 services.<br><br><strong>M\u00e9thode de notation :</strong><br>R\u00e9sultat obtenu dans le fichier Excel \u00e0 reporter : entre 0 et 20 points.<br>La note est attribu\u00e9e en fonction du pourcentage points atteints / points disponibles. Les pond\u00e9rations (0,1 ou 2) sont attribu\u00e9es par type de service selon l\u0027activit\u00e9 du b\u00e2timent.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Programme</strong></td><td>Note sur les services \u00e0 proximit\u00e9 et au sein du b\u00e2timent.<br>Dur\u00e9e de validit\u00e9 : 1 an.</td><td rowspan=\"3\">Coh\u00e9rence entre le document r\u00e9alis\u00e9 et les informations li\u00e9es aux distances des trajets d\u00e9livr\u00e9es sur les sites internet sp\u00e9cialis\u00e9s.<br>Pour les services pris en compte dans l\u0027\u00e9tude mais n\u0027\u00e9tant pas encore pr\u00e9sents, v\u00e9rification :<br>\u25aa existence d\u0027un permis de construire valid\u00e9 par les autorit\u00e9s locales<br>\u25aa date de livraison pr\u00e9vue moins de deux ans avant la mise en service du b\u00e2timent.</td></tr><tr><td><strong>Conception / R\u00e9alisation</strong></td><td>Mise \u00e0 jour de la note sur les services \u00e0 proximit\u00e9 et au sein du b\u00e2timent si modification de l\u0027offre de services.<br>Dur\u00e9e de validit\u00e9 : 1 an.</td></tr><tr><td><strong>Exploitation (B\u00e2timent et Gestion)</strong></td><td>Note sur les services \u00e0 proximit\u00e9 et au sein du b\u00e2timent.<br>Dur\u00e9e de validit\u00e9 : 1 an.</td></tr></table>"},"ENER1":{intro:"Consommation \u00e9nerg\u00e9tique pendant l\u0027utilisation du b\u00e2timent",context:"La performance \u00e9nerg\u00e9tique des b\u00e2timents r\u00e9pond \u00e0 plusieurs enjeux : \u00e9puisement des ressources, r\u00e9duction des \u00e9missions de gaz \u00e0 effet de serre, r\u00e9duction de la facture \u00e9nerg\u00e9tique.<br>Tous les postes de consommations \u00e9nerg\u00e9tiques seront pris en compte : postes immobiliers RE2020, immobiliers hors RE2020, et mobiliers.<br>R\u00e9f\u00e9rences : RE2020, Dispositif Eco Energie Tertiaire (D\u00e9cret Tertiaire), IPMVP."}
,"ENER1.1":{intro:"La consommation \u00e9nerg\u00e9tique pendant l\u0027utilisation du b\u00e2timent",context:"Deux exigences : consommation d\u0027\u00e9nergie primaire (classes A-F, 0-20 pts) et r\u00e9duction de la consommation d\u0027\u00e9nergie (5 niveaux, 0-10 pts)."}
,"ENER1.1.1":{attendu:"Consommation d\u0027\u00e9nergie primaire - unit\u00e9 : kWhEP/m\u00b2SDP.an",definition:"\u00c9valuer les consommations \u00e9nerg\u00e9tiques au plus pr\u00e8s des futures consommations r\u00e9elles du b\u00e2timent, d\u00e9duction faite le cas \u00e9ch\u00e9ant de la production d\u0027\u00c9nergie Renouvelable autoconsom\u00e9e.<br><br>Les classes \u00e9nerg\u00e9tiques sont d\u00e9termin\u00e9es par type d\u0027activit\u00e9 (groupes A \u00e0 D). Tous les postes de consommations \u00e9nerg\u00e9tiques sur le p\u00e9rim\u00e8tre spatial du sous-objet sont \u00e0 consid\u00e9rer.<br><br><strong>Coefficients de conversion :</strong><br>\u2022 1 kWhEF \u21d4 2,58 kWhEP pour l\u0027\u00e9lectricit\u00e9<br>\u2022 1 kWhEF \u21d4 1 kWhEP pour les autres \u00e9nergies (gaz, r\u00e9seaux de chaleur, bois, etc.)",reglementation:"RE2020 : D\u00e9cret n\u00b0 2021-1004 du 29/07/2021, Arr\u00eat\u00e9 du 04/08/21.<br>Dispositif Eco Energie Tertiaire : D\u00e9cret n\u00b0 2019-771 du 23/07/2019, Arr\u00eat\u00e9 du 10/04/2020 (m\u00e9thode), Arr\u00eat\u00e9s valeurs absolues I \u00e0 IV.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u0027op\u00e9ration.<br>D\u00e9finition des objectifs de consommations r\u00e9elles.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.<br>D\u00e9finition des sc\u00e9narios d\u0027usage (nombre d\u0027occupants, consignes de temp\u00e9rature, horaires de fonctionnement).<br>Coh\u00e9rence fichier m\u00e9t\u00e9o / localisation projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des consommations r\u00e9elles.<br>CCTP. Plans.</td><td>V\u00e9rification sc\u00e9narios d\u0027usage correspondant aux sc\u00e9narios d\u00e9finis par le ma\u00eetre d\u0027ouvrage.<br>Coh\u00e9rence hypoth\u00e8ses de calcul et \u00e9l\u00e9ments du projet (parois, \u00e9quipements techniques, \u00e9clairage, ventilation).<br>Coh\u00e9rence fichier m\u00e9t\u00e9o / localisation projet.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des consommations r\u00e9elles.<br>DOE. Annexe environnementale.</td><td>V\u00e9rification sc\u00e9narios d\u0027usage. Coh\u00e9rence hypoth\u00e8ses de calcul et \u00e9l\u00e9ments du projet. Coh\u00e9rence fichier m\u00e9t\u00e9o / localisation projet.</td></tr><tr><td><strong>Phase Exploitation (B et G)</strong></td><td>SANS factures : idem R\u00e9alisation.<br>AVEC Factures, m\u00e9thode simplifi\u00e9e : Relev\u00e9 consommations, sc\u00e9narios occupation nominale, mod\u00e8le correctif, annexe environnementale.<br>AVEC Factures, m\u00e9thode d\u00e9taill\u00e9e : sc\u00e9narios occupation nominale, calcul th\u00e9orique r\u00e9ajust\u00e9, annexe environnementale.</td><td>SANS factures : idem R\u00e9alisation.<br>AVEC m\u00e9thode simplifi\u00e9e : Coh\u00e9rence p\u00e9rim\u00e8tre \u00e9valuation / factures.<br>AVEC m\u00e9thode d\u00e9taill\u00e9e : Coh\u00e9rence hypoth\u00e8ses de calcul et \u00e9l\u00e9ments du projet. Coh\u00e9rence fichier m\u00e9t\u00e9o / localisation.</td></tr></table>"}
,"ENER1.1.1.a":{attendu:"Classe correspondante \u00e0 la consommation d\u0027\u00e9nergie primaire",definition:"Reporter la classe de consommation d\u0027\u00e9nergie atteinte (A \u00e0 F), calcul\u00e9e dans le fichier Excel fourni en IDEN1.1.3.<br><br>Les valeurs seuils de consommation sont d\u00e9termin\u00e9es par groupe d\u0027activit\u00e9 (A, B, C, D) selon le tableau des valeurs seuils.<br>Unit\u00e9 : kWhEP/m\u00b2SDP.an.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>D\u00e9finition des objectifs de consommations r\u00e9elles.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des consommations r\u00e9elles. CCTP. Plans.</td><td>V\u00e9rification sc\u00e9narios d\u0027usage et coh\u00e9rence hypoth\u00e8ses de calcul.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des consommations r\u00e9elles. DOE.</td><td>Idem Conception.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Relev\u00e9s de consommations ou calcul \u00e9nerg\u00e9tique.</td><td>Coh\u00e9rence p\u00e9rim\u00e8tre d\u0027\u00e9valuation.</td></tr></table>"}
,"ENER1.1.2":{attendu:"R\u00e9duction de la consommation d\u0027\u00e9nergie",definition:"R\u00e9duction de la consommation \u00e9nerg\u00e9tique effective par rapport \u00e0 la consommation \u00e9nerg\u00e9tique effective sur la p\u00e9riode de r\u00e9f\u00e9rence d\u0027au moins : 5%, 10%, 15%, 20%, 25% ou 30%.<br><br>Le p\u00e9rim\u00e8tre d\u0027\u00e9valuation est l\u0027ensemble des postes de consommations \u00e9nerg\u00e9tiques (postes immobiliers r\u00e9glementaires, postes immobiliers hors r\u00e9glementation, postes mobiliers), d\u00e9duction faite le cas \u00e9ch\u00e9ant de la production d\u0027\u00c9nergie Renouvelable autoconsom\u00e9e, hormis les \u00e9ventuelles consommations IRVE.",non_applicabilite:"Le b\u00e2timent est en construction neuve ou en r\u00e9novation.<br>Le b\u00e2timent est en exploitation axe Gestion uniquement (dans ce cas cette exigence se trouve dans le th\u00e8me Gestion).",attention:"Les points attribu\u00e9s dans cette exigence seront d\u00e9duits du total de points applicables. L\u0027exigence n\u0027est donc applicable que pour l\u0027axe B\u00e2timent.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>AVEC Factures, m\u00e9thode simplifi\u00e9e :<br>\u2022 Relev\u00e9 des consommations d\u0027\u00e9nergie<br>\u2022 D\u00e9finition des sc\u00e9narios d\u0027occupation nominale<br>\u2022 Mod\u00e8le de calcul math\u00e9matique correctif<br>\u2022 Annexe environnementale.<br><br>AVEC Factures, m\u00e9thode d\u00e9taill\u00e9e :<br>\u2022 D\u00e9finition des sc\u00e9narios d\u0027occupation nominale<br>\u2022 Calcul th\u00e9orique de consommation r\u00e9ajust\u00e9e<br>\u2022 Annexe environnementale.</td><td>AVEC m\u00e9thode simplifi\u00e9e : Coh\u00e9rence entre le p\u00e9rim\u00e8tre d\u0027\u00e9valuation et celui des factures.<br><br>AVEC m\u00e9thode d\u00e9taill\u00e9e : Coh\u00e9rence entre les hypoth\u00e8ses de calcul et les \u00e9l\u00e9ments du projet (parois, \u00e9quipements, \u00e9clairage, ventilation). Coh\u00e9rence fichier m\u00e9t\u00e9o / localisation.</td></tr></table>"}
,"ENER1.2":{intro:"\u00c9valuation NZEB",context:"\u00c9valuation de la demande d\u0027\u00e9nergie primaire par rapport au NZEB (Nearly Zero Energy Building). Directive 2010/31/UE."}
,"ENER1.2.1":{attendu:"\u00c9valuation de la demande d\u0027\u00e9nergie primaire par rapport au NZEB (Nearly Zero Energy Building)",definition:"Cette exigence demande d\u0027\u00e9valuer les consommations \u00e9nerg\u00e9tiques en kWhEP/m\u00b2Sref.an sur le p\u00e9rim\u00e8tre des postes de consommations r\u00e9glementaires en vigueur, d\u00e9fini par la r\u00e9glementation locale mettant en \u0153uvre la directive 2010/31/UE (surface RT/RT2012 ou surface utile RE2020 en France).<br><br><strong>Constructions neuves :</strong> Consommation d\u0027\u00e9nergie primaire inf\u00e9rieure d\u0027au moins 10% aux seuils fix\u00e9s pour les exigences NZEB. En France : inf\u00e9rieure de 10% aux seuils RT2012, et conforme RE2020.<br><br><strong>R\u00e9novation :</strong> R\u00e9duction de 30% minimum de la consommation d\u0027\u00e9nergie primaire (ou partie r\u00e9nov\u00e9e), valid\u00e9e par certificat de performance \u00e9nerg\u00e9tique.<br><br><strong>Exploitation (construits avant 31/12/2020) :</strong> Certificat de performance \u00e9nerg\u00e9tique classe A minimum d\u00e9livr\u00e9, ou b\u00e2timent dans les 15% les plus performants du parc national.<br><br><strong>Exploitation (construits apr\u00e8s 31/12/2020) :</strong> Consommation d\u0027\u00e9nergie primaire inf\u00e9rieure de 10% aux seuils NZEB. Si alignement Taxinomie europ\u00e9enne : calcul ACV RE2020 ou EN 15978 requis.",non_applicabilite:"B\u00e2timents hors de l\u0027Union Europ\u00e9enne.",reglementation:"Directive 2010/31/UE relative \u00e0 la performance \u00e9nerg\u00e9tique des b\u00e2timents.<br>En France : RT2012, RE2020, Taxinomie europ\u00e9enne.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u0027op\u00e9ration.<br>D\u00e9finition des objectifs vis\u00e9s.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calculs r\u00e9glementaires. CCTP. Plans.<br>A d\u00e9faut : Certificat de performance \u00e9nerg\u00e9tique, Rapport d\u0027Audit \u00e9nerg\u00e9tique, Calcul \u00e9nerg\u00e9tique (SED).</td><td>Atteinte du niveau demand\u00e9. V\u00e9rification des sc\u00e9narios d\u0027usage. Coh\u00e9rence hypoth\u00e8ses de calcul et \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calculs ci-dessus \u00e9ventuellement mis \u00e0 jour. DOE.</td><td>Atteinte du niveau demand\u00e9. V\u00e9rification sc\u00e9narios d\u0027usage. Coh\u00e9rence hypoth\u00e8ses/\u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Calculs r\u00e9glementaires ou Certificat de performance \u00e9nerg\u00e9tique (DPE, etc.), ou Calcul \u00e9nerg\u00e9tique (SED).<br>Si alignement Taxinomie : Calcul ACV (RE2020 ou EN 15978 ou E+/C-) si applicable.</td><td>Atteinte du niveau demand\u00e9. Coh\u00e9rence hypoth\u00e8ses de calcul et \u00e9l\u00e9ments du projet.</td></tr></table>"}
,"ENER2":{intro:"Exigences additionnelles li\u00e9es \u00e0 l\u0027efficacit\u00e9 \u00e9nerg\u00e9tique des activit\u00e9s particuli\u00e8res",context:"Deux types d\u0027activit\u00e9s particuli\u00e8res : les entrep\u00f4ts frigorifiques et les data centers."}
,"ENER2.1":{intro:"Exigences additionnelles aux activit\u00e9s logistiques (entrep\u00f4ts frigorifiques)",context:"Applicable uniquement aux entrep\u00f4ts frigorifiques (x*)."}
,"ENER2.1.1":{attendu:"Expression de la valeur du COP global de l\u0027installation de l\u0027entrep\u00f4t frigorifique",definition:"Le but est d\u0027\u00e9valuer et de limiter les consommations d\u0027\u00e9nergie primaire du b\u00e2timent pour les syst\u00e8mes frigorifiques.<br><br>L\u0027indicateur retenu est le Coefficient de Performance (COP) ou EER global de l\u0027installation. Il int\u00e8gre les \u00e9quipements sur le circuit de condensation et les pompes n\u00e9cessaires \u00e0 la circulation du fluide/frigoporteur dans les circuits de distribution, mais exclut les \u00e9quipements des \u00e9vaporateurs/diffuseurs.<br><br>Le COP \u00e0 consid\u00e9rer est une pond\u00e9ration des COP \u00e9t\u00e9 et hiver : <strong>COP = (1/4 COP pointe + 3/4 COP moyen)</strong>.<br><br>Si plusieurs entrep\u00f4ts de temp\u00e9ratures diff\u00e9rentes sur une m\u00eame op\u00e9ration, tous doivent respecter les exigences du niveau vis\u00e9.",non_applicabilite:"Si l\u0027op\u00e9ration n\u0027est pas un entrep\u00f4t frigorifique, l\u0027exigence est \u00ab Non applicable \u00bb.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u0027op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP.</td><td>Coh\u00e9rence entre les hypoth\u00e8ses de calcul et les \u00e9l\u00e9ments du projet d\u00e9crits et dessin\u00e9s.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation (B et G)</strong></td><td>Calcul du COP ou EER \u00e0 partir de mesures in situ.</td><td>\u2022 Quantit\u00e9 de chaleur ou d\u0027\u00e9nergie frigorifique fournie (\u00e9nergie utile)<br>\u2022 Quantit\u00e9 d\u0027\u00e9nergie de haute valeur introduite dans le syst\u00e8me.</td></tr></table>"}
,"ENER2.2":{intro:"Exigences additionnelles aux data centers",context:"Applicable uniquement aux data centers (x**). Si l\u0027op\u00e9ration n\u0027est pas un data center, le bloc d\u0027exigences 2.2 est \u00ab Non applicable \u00bb."}
,"ENER2.2.1":{attendu:"Dispositions justifi\u00e9es et satisfaisantes prises pour limiter les consommations d\u0027\u00e9nergie relativement aux data centers",definition:"R\u00e9duire la consommation d\u0027\u00e9nergie d\u0027un data center. Justifier les dispositions prises relatives \u00e0 :<br><br><strong>\u00c9co-conception du data center :</strong><br>R\u00e9flexions d\u00e8s la conception pour r\u00e9duire les impacts environnementaux (localisation, source de refroidissement naturel, r\u00e9cup\u00e9ration de chaleur, etc.).<br><br><strong>Crit\u00e8res d\u0027achats des \u00e9quipements :</strong><br>\u2022 \u00c9quipements informatiques : mat\u00e9riel \u00e9co-labellis\u00e9 (80plus gold, Energy Star, EPEAT), temp\u00e9rature et humidit\u00e9 souples (recommandations ASHRAE).<br>\u2022 \u00c9quipements de production de froid : choix de la technologie (free cooling, free chilling, natural cooling), COP \u00e9lev\u00e9.<br>\u2022 Autres \u00e9quipements : ventilateurs, onduleurs, surveillance, contr\u00f4le d\u0027acc\u00e8s.<br><br><strong>Dispositions architecturales :</strong><br>\u2022 All\u00e9es chaudes et all\u00e9es froides<br>\u2022 Confinement des all\u00e9es froides<br>\u2022 Refroidissement par rang\u00e9e<br>\u2022 Gestion des obstacles (c\u00e2bles, etc.)",non_applicabilite:"Si l\u0027op\u00e9ration n\u0027est pas un data center.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u0027op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP.</td><td>V\u00e9rification de la coh\u00e9rence entre l\u0027argumentaire d\u00e9velopp\u00e9 pour justifier de l\u0027atteinte de l\u0027objectif et la description des travaux.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation (B et G)</strong></td><td>DOE ou tout autre document permettant de faire \u00e9tat des dispositions prises, visite in situ, photos.</td><td>V\u00e9rification de la coh\u00e9rence entre l\u0027argumentaire d\u00e9velopp\u00e9 pour justifier de l\u0027atteinte de l\u0027objectif et la description des travaux.</td></tr></table>"}
,"ENER2.2.2":{attendu:"\u00c9valuation du PUE (Power Usage Effectiveness)",definition:"Le PUE (Power Usage Effectiveness) d\u00e9fini par le consortium Green Grid compare l\u0027\u00e9nergie totale consomm\u00e9e par un centre informatique et l\u0027\u00e9nergie utilis\u00e9e par les \u00e9quipements informatiques et r\u00e9seaux.<br><br><strong>M\u00e9thodologie de calcul :</strong><br>1. Identification et classement des sous-syst\u00e8mes en 3 cat\u00e9gories : Charge informatique (serveurs, stockage, r\u00e9seaux), Infrastructure physique (alimentation, refroidissement, autres), Non pris en compte.<br>2. Calcul des consommations sur une ann\u00e9e compl\u00e8te (comportement climatique via STD).<br>3. <strong>PUE = Conso \u00e9nerg\u00e9tique totale du centre / Conso des \u00e9quipements informatiques.</strong><br>4. Justification du niveau de TIER (I \u00e0 IV) du data center.",non_applicabilite:"Si l\u0027op\u00e9ration n\u0027est pas un data center.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u0027op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul du PUE.<br>CCTP.<br>Plans techniques.</td><td>Coh\u00e9rence entre les hypoth\u00e8ses de calcul et les \u00e9l\u00e9ments du projet d\u00e9crits et dessin\u00e9s.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation (B et G)</strong></td><td>Calcul du PUE \u00e0 partir de mesures in situ.</td><td>\u2022 \u00c9nergie totale consomm\u00e9e du centre informatique<br>\u2022 \u00c9nergie utilis\u00e9e par les \u00e9quipements informatiques.</td></tr></table>"}
,"EAU1":{
  intro:"Réduction de la consommation d\'eau potable",
  context:"L\'eau potable peut être économisée en agissant principalement à deux échelles :<br>• Limiter les besoins en eau dans les sanitaires : ce levier d\'action passe par la mise en œuvre de dispositifs hydro-économes, c\'est à dire des dispositifs visant à diminuer les volumes d\'eau utilisés pour les équipements sanitaires de l\'ouvrage (WC, urinoirs, robinets, douches)<br>• Limiter le recours à l\'eau potable pour les usages autres que « alimentaire » et « hygiène corporelle »."
},
"EAU1.1":{
  intro:"Consommation d\'eau potable",
  context:"Pour évaluer cette exigence, il convient de reporter dans l\'exigence EAU1.1.1.a dans ISIA la classe de consommation d\'eau atteinte, calculée dans le fichier Excel fourni en IDEN1.1.3.<br>Cette exigence a pour but d\'évaluer la consommation d\'eau potable du sous-objet en fonction de la typologie du bâtiment. La valeur de la consommation d\'eau est exprimée en m³/m².an."
},
"EAU1.1.1":{
  intro:"Consommation d\'eau potable en m³/m²sdp.an",
  context:"Classification de la consommation d\'eau potable de Classe A (économie maximale) à Classe F (consommation élevée), déterminée par la consommation annuelle par m² de surface de plancher déportée, selon 15 typologies de secteurs d\'activité."
},
"EAU1.1.1.a":{
  attendu:"Classe correspondante à la consommation d\'eau potable en m³/m²sdp.an. L\'évaluation porte sur 15 typologies de secteurs d\'activité avec classification de Classe A (20 points) à Classe F (0 point).",
  definition:"Les types de consommations concernés sont : sanitaires et lavabos, éviers, douches et baignoires, équipements de chauffage, ventilation et conditionnement d\'air, entretien des locaux, arrosage de végétaux, tests de sécurité incendie, appareils électroménagers, équipements de loisirs, éléments décoratifs.<br><br><strong>Spécifications techniques taxinomie européenne :</strong><br>• Débit robinets de lavabo ou cuisine : ≤ 6 l/min<br>• Débit de douches : ≤ 8 l/min<br>• Toilettes cuvette + réservoir chasse complète max 6 litres et volume moyen ≤ 3.5 litres<br>• Urinoirs max 2 litres/cuvette/heure et chasse ≤ 1 litre<br>• Récupérations d\'eau (pluviales, grises) en déduction.<br><br><strong>Périmètre fonctionnel, spatial, période de référence :</strong> 12 mois.<br><br><strong>Remarques :</strong> Outil Excel disponible, document Level(s) indicator 3.1, indice WEI+.",
  notation:"Classe A: 20 points | Classe B: 16 points | Classe C: 12 points | Classe D: 8 points | Classe E: 4 points | Classe F: 0 point",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération -> Définition des objectifs à atteindre</td><td>Définition des objectifs de consommation d\'eau potable visagrés</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul de la consommation d\'eau potable, CCTP, Plans, Fiches techniques</td><td>Conformité des débits, Utilisation des eaux pluviales récupérées, Usage d\'autres sources d\'eau non potable, Justification des ratios de consommation utilisés et du nombre d\'occupants</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Mise à jour du calcul de la consommation d\'eau potable en cas de modification du projet, DOE -> Cohérence des hypothèses de calculs avec les éléments mis en œuvre, Fiches techniques équipements, Utilisation eaux pluviales récupérées, Usage d\'autres sources d\'eau non potable, Justification des ratios</td><td>Vérification de l\'adéquation entre les équipements installés et les spécifications techniques</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment et Gestion</strong></td><td>Factures de consommations d\'eau, ou calcul de la consommation d\'eau potable -> Fiches techniques équipements, Utilisation des eaux pluviales récupérées, Usage d\'autres sources d\'eau non potable, Justification des ratios, Recoupement entre la consommation calculée et les factures</td><td>Vérification de l\'adéquation entre les factures de consommations présentées et l\'usage nominal</td></tr></table>"
},
"EAU1.1.2":{
  attendu:"Réduction de la consommation d\'eau potable effective par rapport à la consommation d\'eau potable effective sur la période de référence.",
  definition:"CAS 1 et CAS 2 avec périmètres distincts. Période de comparaison : au moins 12 mois conscutifs avant et après les travaux. Exemples de dispositions de réduction : changement de matériel, installation de détecteurs, etc.",
  non_applicabilite:"Cette exigence est non applicable en construction, rénovation et en exploitation axe Gestion.",
  notation:"<5%: 0pts | 5-10%: 1pt | 10-15%: 2pts | 15-20%: 3pts | 20-30%: 4pts | ≥30%: 5pts",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Factures ou relevés des consommations, RMA -> Pourcentage d\'amélioration des consommations annuelles globales</td><td>Pourcentage d\'amélioration calculé, cohérence avec factures</td></tr><tr><td><strong>Autres phases</strong></td><td>Non concernées</td><td>Sans objet</td></tr></table>"
},
"EAU2":{
  intro:"Gestion des eaux pluviales et des eaux usées à la parcelle",
  context:"L\'objectif est d\'évaluer la performance des dispositions mises en œuvre afin de gérer les eaux pluviales de manière durable, tout en répondant aux exigences réglementaires en vigueur.<br>Cette gestion durable des eaux pluviales permet ainsi de :<br>• Favoriser l\'infiltration de l\'eau pluviale sur la parcelle, par la mise en place de surfaces perméables,<br>• Prévenir le risque de débordement du réseau d\'assainissement en aval, voire d\'inondation par les cours d\'eau,<br>• Limiter la pollution diffuse et le risque de pollution accidentelle au milieu naturel."
},
"EAU2.1":{
  intro:"Gestion des eaux pluviales",
  context:"Pour optimiser les choix d\'aménagement, le maître d\'ouvrage peut ou doit intervenir sur quatre critères complémentaires :<br>• Mettre en place des techniques de gestion des eaux pluviales permettant d\'assurer une régulation hydraulique et de favoriser autant que possible l\'infiltration sur la parcelle (fonction « régulation hydraulique »),<br>• Limiter l\'imperméabilisation au droit de la parcelle (fonction « infiltration »),<br>• Assurer un abattement de la pollution chronique (fonction « dépollution »),<br>• Prendre en compte le risque de pollution accidentelle (fonction « dépollution »).<br><br>Important : Lorsqu\'une opération de construction comporte plusieurs bâtiments et qu\'une partie de ces bâtiments est incluse dans le périmètre de certification, ce sous-thème peut s\'appliquer au global sur l\'ensemble de la zone d\'aménagement."
},
"EAU2.1.1":{
  attendu:"Régulation hydraulique et conformité de la gestion des eaux pluviales sur la parcelle du projet.",
  definition:"Trois types d\'évaluations possibles : débit de fuite, hauteur d\'eau H ou abattement de la lame d\'eau. Volume de stockage calculé selon méthode des pluies (pluie de 10 ans ou centenale selon contexte).",
  non_applicabilite:"Cette exigence est non applicable en exploitation axe Gestion. Elle peut être déclarée non applicable en exploitation axe Bâtiment si cet enjeu est hors du périmètre de responsabilités du demandeur.",
  notation:"Non applicable: non scored | Non atteint: 0pts | Niveaux 1-5: 1-5pts | Pluie d\'intensité centenale/2H (meilleur niveau): 5pts",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération, Prescriptions d\'assainissement locales (Règlement d\'assainissement, PLU, cahier des charges de ZAC, dossier loi sur l\'eau…).</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul de dimensionnement du volume à stocker au droit de la parcelle, du débit de fuite ou de l\'abattement, Plans de masse et d\'assainissement, CCTP, Notice hydraulique du permis de construire ou d\'aménager, Attendus du permis de construire ou d\'aménager.</td><td>Cohérence entre les hypothèses de calcul et les éléments du projet décrits et dessinés, notamment : cohérence des formules utilisées avec les formules réglementaires locales, capacité des dispositifs de rétention prévus, affectation des coefficients de ruissellement réglementaires avec les typologies de surface du projet.</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Mise à jour du calcul de dimensionnement en cas de modification du projet, Mise à jour de la notice hydraulique en cas de permis de construire modificatif, Attendus du permis de construire ou d\'aménager initial et modificatif, DOE.</td><td>Cohérence entre les hypothèses de calcul et les éléments du projet décrits et dessinés : cohérence des formules, capacité des dispositifs de rétention prévus.</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Calcul de dimensionnement, Convention de rejet ou de déversement établie avec le gestionnaire de réseau, DOE, Prescriptions d\'assainissement locales.</td><td>Affectation des coefficients de ruissellement réglementaires avec les typologies de surface du projet. Visite in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concernée.</td><td>Sans objet</td></tr></table>"
},
"EAU2.1.2.a":{
  intro:"Taux d\'absorption de la parcelle du projet (%)",
  context:"Champ de saisie pour le taux d\'absorption de la parcelle du projet en pourcentage."
},
"EAU2.1.2":{
  attendu:"Taux d\'absorption de la parcelle Tp du projet.",
  definition:"Tabs = (1-Cimp)×100, où Cimp est la somme des surfaces imperméabilises divisée par la surface totale de la parcelle. Formules de coefficients d\'imperméabilisation fournis. DOM-TOM remarques particulières.",
  non_applicabilite:"Cette exigence est non applicable en exploitation axe Gestion. Elle peut être déclarée non applicable en exploitation axe Bâtiment si cet enjeu est hors du périmètre de responsabilités du demandeur.",
  notation:"Tp<5%: 0pts | 5%≤Tp<10%: 1pt | 10%≤Tp<20%: 2pts | 20%≤Tp<35%: 3pts | 35%≤Tp<50%: 4pts | Tp≥50%: 5pts",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul du taux d\'absorption, Plan masse. (+ Evaluation de l\'impact des événements cycloniques).</td><td>Cohérence entre les hypothèses de calcul et les éléments du projet décrits et dessinés. (+ Mesures prises pour prendre en compte les événements cycloniques).</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Mise à jour du calcul du taux d\'absorption en cas de modification du projet, DOE. (+ Evaluation de l\'impact des événements cycloniques).</td><td>Cohérence entre les hypothèses de calcul et les éléments du projet mis en œuvre. Constat in situ. (+ Mesures prises pour prendre en compte les événements cycloniques).</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Calcul du taux d\'absorption, DOE (si présent). (+ Evaluation de l\'impact des événements cycloniques).</td><td>Cohérence entre les hypothèses de calcul et les éléments du projet mis en œuvre. Constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concernée.</td><td>Sans objet</td></tr></table>"
},
"EAU2.1.3.a":{
  intro:"Taux d\'absorption contextualisé (%)",
  context:"Champ de saisie pour le taux d\'absorption contextualisé en pourcentage."
},
"EAU2.1.3":{
  attendu:"Taux d\'absorption contextualisé Tq combinant la parcelle (Tp) et le quartier (Tq).",
  definition:"Deux méthodes d\'évaluation : 1) Méthode simplifiée basée sur débit de fuite et taux du quartier, 2) Méthode détaillée utilisant le ratio vert/gris du PLU. Matrice croisée pour classification A-F selon Taux du candidat vs Taux du quartier.",
  non_applicabilite:"Cette exigence est non applicable en exploitation axe Gestion. Elle peut être déclarée non applicable en exploitation axe Bâtiment si cet enjeu est hors du périmètre de responsabilités du demandeur.",
  notation:"Classe A: 5pts | Classe B: 4pts | Classe C: 3pts | Classe D: 2pts | Classe E: 1pt | Classe F: 0pt",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération, calcul du taux d\'absorption du quartier si la correspondance avec le débit de fuite réglementaire n\'est pas retenue. Documents d\'urbanisme locaux justifiant le taux d\'absorption du quartier selon la méthode choisie.</td><td>Détermination du contexte du taux d\'absorption. En cas de calcul du taux d\'absorption du quartier : Cohérence des hypothèses de calcul avec le contexte urbain.</td></tr><tr><td><strong>Phases Conception et Réalisation</strong></td><td>Mise à jour du calcul du taux d\'absorption du quartier si la correspondance avec le débit de fuite réglementaire n\'est pas retenue et que le contexte urbain est modifié. Documents d\'urbanisme locaux justifiant le taux d\'absorption du quartier selon la méthode choisie.</td><td>En cas de calcul du taux d\'absorption du quartier : Cohérence des hypothèses de calcul avec le projet urbain.</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Calcul du taux d\'absorption du quartier si la correspondance avec le débit de fuite réglementaire n\'est pas retenue. Documents d\'urbanisme locaux justifiant le taux d\'absorption du quartier selon la méthode choisie.</td><td>En cas de calcul du taux d\'absorption du quartier : Cohérence des hypothèses de calcul avec le projet urbain.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concernée.</td><td>Sans objet</td></tr></table>"
},
"EAU2.1.4":{
  attendu:"Gestion des pollutions chroniques et prétraitement des eaux de ruissellement avant infiltration ou rejet.",
  definition:"Quatre niveaux cumulatifs d\'évaluation : Niveau 0 (NA si conditions mét), Niveau 1 (décantation mécanique simple : grilles avaloirs, filtres, regards), Niveau 2 (prétraitement toutes pluies de 6h avec décantation ou filtration, pluie d\'occurrence ≤1 mois), Niveau 3 (prétraitement au-delà pluie mensuelle d\'une durée de 6h, décantation MES efficace à vitesse horizontale <1m/h, taux abattement 80% MES/DCO/métaux/HC).",
  non_applicabilite:"Cette exigence est non applicable en exploitation axe Gestion. Elle peut être déclarée non applicable en exploitation axe Bâtiment si cet enjeu est hors du périmètre de responsabilités du demandeur.",
  notation:"Non applicable: non scored | Non atteint: 0pts | Décantation mécanique simple: 1pt | Système de prétraitement par décantation ou filtration (pluie d\'occurrence ≤1 mois d\'une durée de 6 heures): 2pts | Système de prétraitement par décantation ou filtration (pluie d\'occurrence >1 mois d\'une durée de 6 heures): 3pts",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération, Prescriptions d\'assainissement locales (Règlement d\'assainissement, PLU, cahier des charges de ZAC, dossier loi sur l\'eau…).</td><td>Définition des objectifs à atteindre (selon niveau choisi).</td></tr><tr><td><strong>Phase Conception</strong></td><td>Notice hydraulique du permis de construire ou d\'aménager, Attendus du permis de construire ou d\'aménager, CCTP, Plans techniques.</td><td>Cohérence des exigences réglementaires avec les éléments décrits et dessinés du projet.</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Calcul de dimensionnement du prétraitement des EP, Mise à jour de la notice hydraulique en cas de permis de construire modificatif, Attendus du permis de construire ou d\'aménager initial et modificatif, DOE.</td><td>Cohérence du calcul du dimensionnement des EP avec les éléments mis en œuvre. Constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Calcul de dimensionnement du prétraitement des EP, Convention de rejet ou de déversement établie avec le gestionnaire de réseau, DOE.</td><td>Cohérence du calcul du dimensionnement des EP avec les éléments mis en œuvre. Constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concernée.</td><td>Sans objet</td></tr></table>"
},
"EAU2.1.5":{
  attendu:"Gestion des pollutions accidentelles dans les zones à risque (parkings, aires de livraison, stockage, etc.).",
  definition:"Quatre niveaux cumulatifs : Niveau 0 (risque identifié mais pas de dispositions), Niveau 1 (dispositif de traitement), Niveau 2 (+ avertisseur saturation), Niveau 3 (+ notice entretien), Niveau 4 (+ procédure intervention).",
  non_applicabilite:"Cette exigence est non applicable en exploitation axe Gestion et en cas d\'absence de risque de pollution accidentelle identifié. Elle peut être déclarée non applicable en exploitation axe Bâtiment si cet enjeu est hors du périmètre de responsabilités du demandeur.",
  notation:"Non applicable: non scored | Non atteint: 0pts | Niveau 1 (dispositif de traitement): 2pts | Niveau 2 (+avertisseur saturation): 3pts | Niveau 3 (+notice entretien): 4pts | Niveau 4 (+procédure intervention): 5pts",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Liste des zones imperméabilisées à risque, Programme de l\'opération.</td><td>Définition des objectifs à atteindre (selon niveau choisi).</td></tr><tr><td><strong>Phase Conception</strong></td><td>Mise à jour de la liste des zones imperméabilisées à risque en cas de modification du programme. CCTP, Plans techniques : du dispositif de traitement, du dispositif avertisseur de saturation (si niveau 2), Notice d\'entretien semestriel du dispositif (si niveau 3), Procédure d\'intervention et de gestion des polluants (si niveau 4).</td><td>Cohérence de la liste avec les éléments décrits et dessinés (niveaux 1 et 2).</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Mise à jour de la liste des zones imperméabilisées à risque. DOE : du dispositif de traitement, du dispositif avertisseur de saturation (si niveau 2), Notice d\'entretien semestriel du dispositif (si niveau 3), Procédure d\'intervention et de gestion des polluants (si niveau 4).</td><td>Constat in situ. Cohérence de la notice avec le dispositif (si niveau 3). Application de la procédure (si niveau 4).</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Liste des zones imperméabilisées à risque. Descriptifs des dispositifs en place (DOE ou autres documents) (niveaux 1 et 2). Notice d\'entretien semestriel du dispositif (si niveau 3). Procédure d\'intervention et de gestion des polluants (si niveau 4).</td><td>Constat in situ (niveaux 1 et 2). Cohérence de la notice avec le dispositif (si niveau 3). Application de la procédure (si niveau 4).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concernée.</td><td>Sans objet</td></tr></table>"
},
"EAU2.2":{
  intro:"Gestion des eaux usées",
  context:"Ce bloc d\'exigences est non applicable en exploitation axe Gestion.<br>Il peut être déclaré non applicable en exploitation axe Bâtiment si cet enjeu est hors du périmètre de responsabilités du demandeur.<br>Dans ces cas, les points attribués dans cette exigence seront déduits du total de points applicables."
},
"EAU2.2.1":{
  attendu:"Identification de tous les types d\'eaux usées présentes sur le site.",
  definition:"Typologies d\'eaux usées : eaux grises (lavabos, douches, baignoires), eaux vannes (toilettes, urinoirs), eaux industrielles, eaux de process, eaux de nettoyage, etc.",
  notation:"Non atteint: 0pts | Atteint: 0pts",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Liste des types d\'eaux usées présentes sur l\'opération, Programme de l\'opération.</td><td>Définition des eaux usées présentes dans le programme.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Mise à jour de la liste des types d\'eaux usées présentes sur le site en cas de modification du programme de l\'opération.</td><td>Mise à jour de la liste si changement depuis le programme.</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>Mise à jour de la liste des types d\'eaux usées présentes sur le site en cas de modification du programme de l\'opération.</td><td>Constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Liste des types d\'eaux usées présentes sur le site.</td><td>Constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concernée.</td><td>Sans objet</td></tr></table>"
},
"EAU2.2.2":{
  attendu:"Assainissement des eaux usées (collectif ou non collectif) conforme à la réglementation en vigueur.",
  definition:"Deux cas distincts : <br><strong>CAS 1 - Système de traitement EU :</strong> Systèmes innovants acceptés (bassins à microphytes, lagunage, épuration sur lits de roseaux, micro-stations). Conformité à réglement L1331-1.<br><strong>CAS 2 - Raccordement réseau :</strong> Raccordement réseau unitaire ou séparatif avec limitation 20% surverses EP.<br><strong>Assainissement non collectif :</strong> Normes MES ≤ 30 mg/L, DBO5 ≤ 40 mg/L, arrêtés 1996/2007/2009/2012/2015. Diagnostic assainissement obligatoire.",
  notation:"6 niveaux (0-5pts) pour assainissement collectif et non collectif",
  preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\'opération, Prescriptions d\'assainissement locales (Règlement d\'assainissement, PLU, cahier des charges de ZAC, dossier loi sur l\'eau…).</td><td>Définition des objectifs à atteindre. Présence de réseaux collectifs à proximité de la parcelle (dans le cas de raccordement à un réseau unitaire ou séparatif).</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans et descriptif du dispositif d\'assainissement, Notice hydraulique du permis de construire ou d\'aménager, Attendus du permis de construire ou d\'aménager.</td><td>Cohérence entre la réponse saisie dans l\'outil et les éléments du projet décrits et dessinés. Indication du ou des points de raccordement.</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, Plans et descriptif du dispositif d\'assainissement, Mise à jour de la notice hydraulique en cas de permis de construire modificatif, Attendus du permis de construire ou d\'aménager initial et modificatif.</td><td>Cohérence entre la réponse saisie dans l\'outil et les éléments du projet mis en œuvre. Constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Bâtiment</strong></td><td>Plans et descriptif du dispositif d\'assainissement, Convention de rejet ou de déversement établie avec le gestionnaire de réseau, Prescriptions d\'assainissement locales (Règlement d\'assainissement, PLU, cahier des charges de ZAC, dossier loi sur l\'eau…).</td><td>Cohérence entre la réponse saisie dans l\'outil et les éléments du projet mis en œuvre. Constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concernée.</td><td>Sans objet</td></tr></table>"
},"DECH1":{intro:"Conception du b\u00e2timent et d\u00e9chets d\u2019activit\u00e9",context:"Ce sous-th\u00e8me \u00e9value la conception du b\u00e2timent pour la gestion des d\u00e9chets d\u2019activit\u00e9 (zones de stockage, dimensionnement, positionnement) et les quantit\u00e9s de d\u00e9chets produits et valoris\u00e9s. | P\u00e9rim\u00e8tre : sous-objet, b\u00e2timent, site ou parc selon le contexte de la demande."},
"DECH1.1":{intro:"Conception du b\u00e2timent pour la gestion des d\u00e9chets",context:"NA si axe Gestion seul vis\u00e9 (pour DECH1.1.1, DECH1.1.2 et DECH1.1.3). NA si construction neuve ou r\u00e9novation (pour DECH1.1.4)."},
"DECH1.1.1":{attendu:"Pr\u00e9sence de zones de stockage des d\u00e9chets avec possibilit\u00e9 de nettoyage et pr\u00e9sence d\u2019un syst\u00e8me de ventilation.",definition:"Garantir la pr\u00e9sence d\u2019une ou plusieurs zone(s) de stockage des d\u00e9chets (a minima d\u2019activit\u00e9 et d\u2019entretien/maintenance). Il peut s\u2019agir de zones ext\u00e9rieures ou int\u00e9rieures. | \u25b6 Local int\u00e9rieur : conditions d\u2019hygi\u00e8ne r\u00e9glementaires \u00e0 respecter : possibilit\u00e9 de nettoyage (arriv\u00e9e d\u2019eau et siphon au sol), syst\u00e8me de ventilation ad\u00e9quat (ventilation naturelle autoris\u00e9e pour papiers/cartons/emballages, VMC requise pour les autres d\u00e9chets). | Note : pour les b\u00e2timents produisant des biod\u00e9chets (>10 tonnes/an ou >60 l/an d\u2019huiles alimentaires), un local de stockage r\u00e9frig\u00e9r\u00e9 doit \u00eatre mis en place (Arr\u00eat\u00e9 du 12 juillet 2011). | \u25b6 Local ext\u00e9rieur : zone prot\u00e9g\u00e9e du vent et de la pluie, arri\u00e9e d\u2019eau et siphon d\u2019\u00e9vacuation. | \u25b6 Collectes pneumatiques : zones de stockage avec points de collectes pneumatiques accept\u00e9es sous conditions (identification des d\u00e9chets non accept\u00e9s, locaux compl\u00e9mentaires si n\u00e9cessaire, conditions sanitaires d\u00e9finies). | \u25b6 Points d\u2019Apport Volontaire (PAV) impos\u00e9s : le b\u00e2timent doit \u00eatre concern\u00e9 par l\u2019utilisation des PAV, PAV accessibles, conditions sanitaires d\u00e9finies. | Mutualisation possible si zones sur m\u00eame parcelle, d\u00e9di\u00e9es aux utilisateurs du b\u00e2timent, et respectant les crit\u00e8res de l\u2019exigence. | Sp\u00e9cificit\u00e9 DOM-TOM / climat tropical : cette exigence est obligatoire. Local ext\u00e9rieur doit \u00eatre prot\u00e9g\u00e9 du soleil, du vent, de la pluie et des animaux.",non_applicabilite:"Lorsque seul l\u2019axe Gestion est vis\u00e9, cette exigence est non applicable. Les points seront d\u00e9duits du total de points disponibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans architecturaux, Plans techniques, Informations sur les conditions sanitaires appliqu\u00e9es aux PAV (g\u00e9rant des PAV, dispositions pr\u00e9vues pour le maintien des conditions sanitaires\u2026).</td><td>Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, description des PAV, visite in situ.</td><td>V\u00e9rification/visite in situ des dispositions mises en \u0153uvre (point d\u2019eau, ventilation, PAV).</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Description des PAV, DOE ou tout autre document permettant de justifier l\u2019exigence (plans, fiches sur les syst\u00e8mes mis en place) (dur\u00e9e de validit\u00e9 illimit\u00e9e sauf modification du projet), visite in situ.</td><td>V\u00e9rification/visite in situ des dispositions mises en \u0153uvre (point d\u2019eau, ventilation, PAV).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet.</td></tr></table>"},
"DECH1.1.2":{attendu:"Dimension adapt\u00e9e au flux de d\u00e9chets de la zone de stockage finale de d\u00e9chets.",definition:"Assurer un dimensionnement ad\u00e9quat des locaux/zones d\u00e9chets et respecter les conditions de stockage r\u00e9glementaires. Concevoir des locaux/zones d\u00e9chets adapt\u00e9(e)s au contexte de l\u2019op\u00e9ration et justifier le dimensionnement en fonction des quantit\u00e9s estim\u00e9es et du choix des fili\u00e8res de traitement. | Le dimensionnement d\u00e9pend : des typologies de d\u00e9chets identifi\u00e9es, du mode de traitement choisi (valorisation sur site ou enl\u00e8vement), des flux de d\u00e9chets (quantit\u00e9s produites et rythmes de production), de la pr\u00e9sence ou non de tri \u00e0 la source, de la nature des fili\u00e8res d\u2019enl\u00e8vement choisies, du tri pour syst\u00e8me de consigne. | En exploitation axe B\u00e2timent : adapter la fr\u00e9quence d\u2019enl\u00e8vement \u00e0 la capacit\u00e9 de stockage, prendre des dispositions pour optimiser la maniabilit\u00e9 des d\u00e9chets dans les locaux/zones d\u00e9chets. | Cas particulier des collectes pneumatiques : le dimensionnement des zones de stockage doit respecter les conditions sp\u00e9cifiques (locaux compl\u00e9mentaires si certains d\u00e9chets non accept\u00e9s ; \u00e9tude des flux non obligatoire pour d\u00e9chets accept\u00e9s par la collecte pneumatique). | Lorsque des PAV sont impos\u00e9s dans le cadre d\u2019une ZAC ou d\u2019un quartier : prouver que l\u2019effectif du b\u00e2timent a \u00e9t\u00e9 pris en compte pour le dimensionnement des collecteurs ; si PAV existants, justifier que les donn\u00e9es de collecte permettent de r\u00e9pondre \u00e0 l\u2019augmentation des flux ; si certains d\u00e9chets ne peuvent pas \u00eatre amen\u00e9s aux PAV, dimensionnement justifi\u00e9 du local d\u00e9chet.",non_applicabilite:"Lorsque seul l\u2019axe Gestion est vis\u00e9, cette exigence est non applicable. Les points seront d\u00e9duits du total de points disponibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans architecturaux, Plans techniques, Note de dimensionnement des locaux d\u00e9chets / PAV.</td><td>Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA : coh\u00e9rence du calcul r\u00e9alis\u00e9 avec les plans des locaux d\u00e9chets / note des PAV.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, Mise \u00e0 jour du calcul justifiant les surfaces des locaux d\u00e9chets si le projet a \u00e9t\u00e9 modifi\u00e9, dossier PAV (dimensionnement\u2026), visite in situ.</td><td>Identification/visite in situ afin de v\u00e9rifier le dimensionnement des locaux / PAV.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE (ou tout autre document permettant de justifier de l\u2019atteinte de l\u2019exigence), Note de dimensionnement des locaux d\u00e9chets / PAV (dur\u00e9e de validit\u00e9 illimit\u00e9e sauf modification du projet), visite in situ.</td><td>Visite in situ, coh\u00e9rence entre la visite et le calcul justifiant les surfaces.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet.</td></tr></table>"},
"DECH1.1.3":{attendu:"Positionnement des zones d\u00e9chets permettant une bonne organisation des flux de d\u00e9chets.",definition:"\u00c9valuer les \u00e9l\u00e9ments intrins\u00e8ques permettant une bonne organisation des flux de d\u00e9chets : choix de positionnement des diff\u00e9rentes zones d\u00e9chets pris en compte pour faciliter la collecte, le regroupement et l\u2019enl\u00e8vement. | Plusieurs approches : distance entre zones d\u00e9chets/PAV et zones de production (chemins d\u2019acc\u00e8s, distances \u00e0 parcourir) ; positionnement adapt\u00e9 aux autres flux de circulation (assurer qu\u2019il n\u2019y ait pas d\u2019interf\u00e9rences entre circuits de collecte et circuits des occupants, que le circuit de collecte n\u2019interf\u00e8re pas avec la livraison, que le stockage \u00e0 faible fr\u00e9quence ne perturbe pas la gestion r\u00e9guli\u00e8re, facilit\u00e9 d\u2019acc\u00e8s pour les services de collecte depuis l\u2019ext\u00e9rieur). | Pr\u00e9sence de zones de collecte interm\u00e9diaire des d\u00e9chets d\u2019activit\u00e9 : optimisation de la position pour encourager les d\u00e9p\u00f4ts volontaires, pr\u00e9sence d\u2019une zone de regroupement pour faciliter la collecte par le personnel de m\u00e9nage. | Note : La distance est calcul\u00e9e sur un cheminement pi\u00e9ton type (pas \u00e0 vol d\u2019oiseau). La distance entr\u00e9e du b\u00e2timent / PAV est inf\u00e9rieure ou \u00e9gale \u00e0 70m.",non_applicabilite:"Lorsque seul l\u2019axe Gestion est vis\u00e9, cette exigence est non applicable. Les points seront d\u00e9duits du total de points disponibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, Plans architecturaux, justification de la distance entre les entr\u00e9es du b\u00e2timent et les zones d\u00e9chets/PAV.</td><td>Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, note concernant le positionnement des PAV.</td><td>Identification/visite in situ de v\u00e9rifier le positionnement des locaux.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE ou tout autre document permettant de justifier l\u2019exigence (plans, fiches sur les syst\u00e8mes mis en place) (dur\u00e9e de validit\u00e9 illimit\u00e9e sauf modification du projet).</td><td>Identification/visite in situ de v\u00e9rifier le positionnement des locaux.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet.</td></tr></table>"},
"DECH1.1.4":{attendu:"Pratiques de r\u00e9duction du volume de d\u00e9chets d\u2019activit\u00e9s.",definition:"Le but de cette exigence est d\u2019encourager la r\u00e9duction du volume de d\u00e9chets d\u2019activit\u00e9s une fois que ceux-ci sont produits. R\u00e9duire le volume des d\u00e9chets permet une optimisation de leur transport pour traitement, et une diminution de la surface des zones d\u00e9chets. La r\u00e9duction du volume de d\u00e9chets d\u2019activit\u00e9 n\u2019est pas un \u00e9l\u00e9ment de qualit\u00e9 intrin\u00e8que du b\u00e2timent. N\u00e9anmoins, le propri\u00e9taire peut encourager cette pratique par la mise \u00e0 disposition d\u2019un syst\u00e8me de r\u00e9duction et l\u2019allocation d\u2019un espace pour accueillir ce syst\u00e8me. | dispositions prises pour r\u00e9duire les consommables : distributeurs rechargeables au lieu de produits individuels. | dispositions prises pour r\u00e9duire l\u2019encombrement des d\u00e9chets d\u2019activit\u00e9s : broyage ou compactage par exemple.",non_applicabilite:"Dans le cas o\u00f9 le b\u00e2timent est en construction neuve ou r\u00e9novation (en programme, conception ou r\u00e9alisation), cette exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme, Conception et R\u00e9alisation</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Justificatif des pratiques de r\u00e9duction du volume de d\u00e9chets, dispositifs mis en place (DOE ou tout autre document justificatif, plans, fiches descriptives des dispositifs) (dur\u00e9e de validit\u00e9 : 2 ans), visite in situ.</td><td>Identification/visite in situ afin de v\u00e9rifier les dispositifs mis en place et les pratiques.</td></tr></table>"},
"DECH1.2":{intro:"Quantit\u00e9s de d\u00e9chets d\u2019activit\u00e9s produits et valoris\u00e9s",context:"NA si construction neuve ou r\u00e9novation (en programme, conception ou r\u00e9alisation). | En exploitation Axe B\u00e2timent, si les d\u00e9chets d\u2019activit\u00e9s sont hors du p\u00e9rim\u00e8tre des responsabilit\u00e9s du demandeur, le bloc peut \u00eatre d\u00e9clar\u00e9 comme non applicable."},
"DECH1.2.1":{intro:"Pourcentage global de d\u00e9chets d\u2019activit\u00e9s valoris\u00e9s sur le p\u00e9rim\u00e8tre certifi\u00e9",context:"Reporter le pourcentage de valorisation globale calcul\u00e9 dans le fichier Excel de calcul."},
"DECH1.2.1.a":{attendu:"Pourcentage global de d\u00e9chets d\u2019activit\u00e9s valoris\u00e9s sur le p\u00e9rim\u00e8tre certifi\u00e9.",definition:"\u00c9valuer la quantit\u00e9 de d\u00e9chets d\u2019activit\u00e9s produits et valoris\u00e9s annuellement lors de l\u2019exploitation du b\u00e2timent. Reporting le plus fin et d\u00e9taill\u00e9 possible avec des donn\u00e9es r\u00e9elles, les quantit\u00e9s exprim\u00e9es en kg/an. | En exploitation, l\u2019ann\u00e9e prise en compte correspond aux 12 mois pr\u00e9c\u00e9dents par rapport \u00e0 la date de l\u2019\u00e9valuation, avec une tol\u00e9rance \u00e0 quelques mois. | D\u00e9chets concern\u00e9s \u2013 Non dangereux : Papier/carton, Verre, M\u00e9tal, Plastique, Bois, Textile, Biod\u00e9chets, Autres d\u00e9chets non dangereux. D\u00e9chets dangereux : Cartouches d\u2019encre, Piles et accumulateurs, DEEE, Autres d\u00e9chets dangereux. | Si donn\u00e9es r\u00e9elles indisponibles : renseigner et justifier des ratios ou faire une estimation par typologie de d\u00e9chets.",reglementation:"Code de l\u2019environnement concernant les circuits de traitement des d\u00e9chets d\u2019activit\u00e9 : r\u00e9cup\u00e9ration et conservation des BSDD, tenue d\u2019un registre chronologique, tra\u00e7abilit\u00e9 des d\u00e9chets non r\u00e9glement\u00e9s.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme, Conception et R\u00e9alisation</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Justificatif des donn\u00e9es r\u00e9elles (ou ratios) de d\u00e9chets d\u2019activit\u00e9 produits / valoris\u00e9s par typologie de d\u00e9chets et/ou Justificatif des ratios utilis\u00e9s (dur\u00e9e de validit\u00e9 : 1 an). Respect de la r\u00e9glementation (Code de l\u2019environnement) concernant les circuits de traitement des d\u00e9chets d\u2019activit\u00e9 : r\u00e9cup\u00e9ration et conservation des BSDD conform\u00e9ment \u00e0 la r\u00e9glementation, tenue et conservation d\u2019un registre chronologique, tra\u00e7abilit\u00e9 des d\u00e9chets non r\u00e9glement\u00e9s.</td><td>Coh\u00e9rence entre les \u00e9l\u00e9ments du justificatif et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr></table>"},
"DECH1.2.2":{intro:"Pourcentage de d\u00e9chets d\u2019activit\u00e9s valoris\u00e9s mati\u00e8re",context:"Reporter la valeur absolue dans DECH1.2.2 et la classe atteinte dans DECH1.2.2.a."},
"DECH1.2.2.a":{attendu:"Pourcentage de d\u00e9chets d\u2019activit\u00e9s valoris\u00e9s mati\u00e8re.",definition:"Indiquer la part de valorisation mati\u00e8re dans le total de d\u00e9chets d\u2019activit\u00e9s produits. Le pourcentage de d\u00e9chets valoris\u00e9s mati\u00e8re s\u2019\u00e9value par rapport \u00e0 la masse totale de d\u00e9chets g\u00e9n\u00e9r\u00e9s, que ceux-ci soient valorisables ou non. M\u00eame si l\u2019op\u00e9ration produit des d\u00e9chets dangereux qui ne peuvent \u00eatre valoris\u00e9s, ceux-ci ne peuvent pas \u00eatre exclus du calcul du pourcentage. | D\u00e9finition du terme \u00ab Valorisation mati\u00e8re autre que le R\u00e9emploi \u00bb : voir d\u00e9finition dans l\u2019exigence DECH1.2.1.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme, Conception et R\u00e9alisation</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Justificatif des quantit\u00e9s de d\u00e9chets d\u2019activit\u00e9 valoris\u00e9s par typologie de d\u00e9chet (dur\u00e9e de validit\u00e9 : 1 an).</td><td>Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr></table>"},
"DECH2":{intro:"D\u00e9chets d\u2019entretien et de maintenance",context:"Ce sous-th\u00e8me \u00e9value les quantit\u00e9s de d\u00e9chets d\u2019entretien et de maintenance produits et valoris\u00e9s. | P\u00e9rim\u00e8tre : sous-objet, b\u00e2timent, site ou parc selon le contexte."},
"DECH2.1":{intro:"D\u00e9chets d\u2019entretien et de maintenance",context:"NA si construction neuve ou r\u00e9novation (en programme, conception ou r\u00e9alisation). | En exploitation Axe B\u00e2timent, si les d\u00e9chets d\u2019entretien/maintenance sont hors du p\u00e9rim\u00e8tre des responsabilit\u00e9s du demandeur, le sous-th\u00e8me peut \u00eatre d\u00e9clar\u00e9 comme non applicable."},
"DECH2.1.1":{intro:"Pourcentage global de d\u00e9chets d\u2019entretien/maintenance valoris\u00e9s sur le p\u00e9rim\u00e8tre certifi\u00e9",context:"Reporter le pourcentage de valorisation globale calcul\u00e9 dans le fichier Excel de calcul."},
"DECH2.1.1.a":{attendu:"Pourcentage global de d\u00e9chets d\u2019entretien/maintenance qui seront valoris\u00e9s sur le p\u00e9rim\u00e8tre certifi\u00e9.",definition:"\u00c9valuer la quantit\u00e9 de d\u00e9chets d\u2019entretien/maintenance produits et valoris\u00e9s annuellement lors de l\u2019exploitation du b\u00e2timent, exprim\u00e9es en kg/an. | D\u00e9chets concern\u00e9s \u2013 Non dangereux : Papier/carton, Verre, M\u00e9tal, Plastique, Bois, Textile, Graisse, Autres biod\u00e9chets, Autres d\u00e9chets non dangereux. D\u00e9chets dangereux : Fluides frigorig\u00e8nes, DEEE, Filtres (ventilo-convecteurs + CTA\u2026), Autres d\u00e9chets dangereux (a\u00e9rosols, bidons et chiffons souill\u00e9s, bouteilles de gaz, hydrocarbure, d\u00e9chet liquide ou solide toxique en quantit\u00e9 dispers\u00e9e, etc.). | Accent particulier sur l\u2019estimation des DEEE (lampes, \u00e9crans\u2026) et des Filtres des ventilo-convecteurs + CTA. | Source des donn\u00e9es : les volumes annuels peuvent \u00eatre estim\u00e9s par les p\u00e9riodicit\u00e9s de remplacement (dur\u00e9e de vie) transmises par les fabricants. | Si donn\u00e9es r\u00e9elles indisponibles : renseigner et justifier des ratios ou estimer par typologie de d\u00e9chets. | Les d\u00e9chets d\u2019entretien et de maintenance correspondent aux d\u00e9chets produits dans le cadre des op\u00e9rations d\u2019entretien et de maintenance n\u00e9cessaire au bon fonctionnement du b\u00e2timent (filtres de ventilo-convecteurs, relamping\u2026). Les d\u00e9chets issus de gros travaux de remplacements (CAPEX) et de r\u00e9novation ne sont pas comptabilis\u00e9s dans cette cat\u00e9gorie. | Les biod\u00e9chets issus de l\u2019entretien des espaces verts peuvent \u00eatre comptabilis\u00e9s ici (cat\u00e9gorie \u00ab Autres biod\u00e9chets \u00bb). Attention \u00e0 ne pas les comptabiliser deux fois avec les d\u00e9chets organiques d\u2019activit\u00e9s. Les r\u00e9sidus des bacs \u00e0 graisse sont \u00e0 comptabiliser dans la cat\u00e9gorie \u00ab Graisse \u00bb.",reglementation:"Code de l\u2019environnement concernant les circuits de traitement des d\u00e9chets d\u2019entretien/maintenance : r\u00e9cup\u00e9ration et conservation des BSDD, tenue d\u2019un registre chronologique, tra\u00e7abilit\u00e9 des d\u00e9chets non r\u00e9glement\u00e9s. Protocole de tri des d\u00e9chets d\u2019entretien/maintenance associ\u00e9 aux interventions.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme, Conception et R\u00e9alisation</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Justificatif des donn\u00e9es r\u00e9elles (ou ratios) de d\u00e9chets d\u2019entretien et maintenance produits / valoris\u00e9s par typologie de d\u00e9chets et/ou Justificatif des ratios utilis\u00e9s (dur\u00e9e de validit\u00e9 : 1 an). Respect de la r\u00e9glementation. Protocole de tri, dispositions pour optimiser le tri et le stockage, photos/plan des zones, contrats entre collecteur et entreprise de valorisation.</td><td>Coh\u00e9rence entre les \u00e9l\u00e9ments du justificatif et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr></table>"},
"DECH2.1.2":{intro:"Pourcentage de d\u00e9chets d\u2019entretien/maintenance valoris\u00e9s mati\u00e8re",context:"Reporter la valeur absolue dans DECH2.1.2 et la classe atteinte dans DECH2.1.2.a."},
"DECH2.1.2.a":{attendu:"Pourcentage de d\u00e9chets d\u2019entretien/maintenance valoris\u00e9s mati\u00e8re.",definition:"Indiquer la part de valorisation mati\u00e8re dans le total des d\u00e9chets d\u2019entretien/maintenance produits. Le pourcentage s\u2019\u00e9value par rapport \u00e0 la masse totale de d\u00e9chets g\u00e9n\u00e9r\u00e9s, que ceux-ci soient valorisables ou non. | D\u00e9finition du terme \u00ab valorisation mati\u00e8re \u00bb : Cf la d\u00e9finition dans l\u2019exigence DECH1.2.1.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme, Conception et R\u00e9alisation</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Justificatif des quantit\u00e9s de d\u00e9chets d\u2019entretien et maintenance valoris\u00e9s par typologie de d\u00e9chet (dur\u00e9e de validit\u00e9 : 1 an).</td><td>Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr></table>"},
"DECH3":{intro:"D\u00e9chets de chantier",context:"Ce sous-th\u00e8me \u00e9value les quantit\u00e9s de d\u00e9chets de chantier produits et valoris\u00e9s, y compris le r\u00e9emploi et la r\u00e9utilisation des terres. | P\u00e9rim\u00e8tre : sous-objet, b\u00e2timent, site ou parc. | NA si exploitation sans travaux de r\u00e9novation r\u00e9cents ou pr\u00e9vus (axe B\u00e2timent) ou si exploitation axe Gestion."},
"DECH3.1":{intro:"Quantit\u00e9s de d\u00e9chets de chantier produits et valoris\u00e9s",context:"NA si exploitation (axe B\u00e2timent sans travaux de r\u00e9novation r\u00e9cents ou pr\u00e9vus). NA si exploitation axe Gestion."},
"DECH3.1.1":{intro:"Pourcentage global de d\u00e9chets de chantier valoris\u00e9s (Hors terres)",context:"Reporter le pourcentage de valorisation globale calcul\u00e9 dans le fichier Excel de calcul."},
"DECH3.1.1.a":{attendu:"Pourcentage global de d\u00e9chets de chantier qui seront valoris\u00e9s (HORS Terres).",definition:"\u00c9valuer la quantit\u00e9 de d\u00e9chets de chantier produits et valoris\u00e9s. | Le document \u00ab Level(s) indicator 2.2: Construction and Demolition waste and materials \u00bb version 1.1 de janvier 2021 donne le cadre europ\u00e9en \u00e0 respecter (Protocole de 2016, Directive 2018/850, Directive 2008/98/CE, D\u00e9cision n\u00b0 2014/955/UE du 18/12/14). | Ce document est accompagn\u00e9 d\u2019un tableur Excel \u00ab UM3_indicator_2.2_excel_v1.1 \u00bb. | Remarque : le diagnostic d\u00e9chets ou PEMD est obligatoire pour certains types de travaux (d\u00e9molition ou r\u00e9novation significative). | D\u00e9chets concern\u00e9s \u2013 Non dangereux : Papier, M\u00e9tal, Plastique, Verre, Bois, Fractions min\u00e9rales (B\u00e9ton, Briques, Tuiles), Pl\u00e2tre, Textile, Emballages, Autres d\u00e9chets inertes, Autres d\u00e9chets non dangereux. D\u00e9chets dangereux : d\u00e9chets d\u2019amiante, solvants, peintures, vernis, colles, etc. | Les quantit\u00e9s sont exprim\u00e9es en kg, pour la totalit\u00e9 de la dur\u00e9e du chantier. | Remarques : les terres ne sont pas concern\u00e9es (voir DECH3.1.3 et DECH3.1.4). Pour le b\u00e9ton en \u00ab valorisation mati\u00e8re \u00bb, respecter les recommandations de la norme NF EN 206/CN de d\u00e9cembre 2014. | D\u00e9finition des termes \u00ab D\u00e9chets de chantier \u00bb : d\u00e9chets produits dans le cadre des op\u00e9rations de construction et de reconstruction ainsi que lors des travaux de r\u00e9novation (hors remplacements \u00e0 l\u2019identique). Les terres ne sont pas comptabilis\u00e9es dans cette cat\u00e9gorie. | \u00ab Travaux de r\u00e9novation \u00bb : travaux de type Gros \u0153uvre, second \u0153uvre, et modifications des \u00e9quipements techniques entra\u00eenant des travaux sur la structure et/ou le second \u0153uvre. | En France, compl\u00e9ment sur les PEM disposant d\u2019une \u00e9valuation environnementale de la circularit\u00e9 (Ecoscale ou \u00e9quivalent) : produit recyclable = capable d\u2019int\u00e9grer une fili\u00e8re de recyclage.",reglementation:"Code de l\u2019environnement (Partie r\u00e9glementaire, Livre V, Titre IV \u00ab D\u00e9chets \u00bb) relativement au suivi des d\u00e9chets : r\u00e9cup\u00e9ration et conservation des BSDD (article R541-45), tenue d\u2019un registre chronologique (article L541-7, R541-43). | D\u00e9cret n\u00b02007-1467 du 12 octobre 2007, relatif au titre V de la partie r\u00e9glementaire du Code de l\u2019environnement. | Les d\u00e9chets de chantier poss\u00e8dent des r\u00e9glementations diff\u00e9rentes selon leur typologie (d\u00e9chets dangereux, d\u00e9chets inertes, d\u00e9chets ultimes/DIB/DRATS, d\u00e9chets d\u2019emballages).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Justificatif des quantit\u00e9s de d\u00e9chets produits / valoris\u00e9s par typologie de d\u00e9chet. Justificatif des ratios utilis\u00e9s. Pr\u00e9sence d\u2019une phase de d\u00e9molition ou non.</td><td rowspan=\"4\">Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Mise \u00e0 jour du justificatif des quantit\u00e9s de d\u00e9chets produits / valoris\u00e9s (ou des ratios utilis\u00e9s) par typologie de d\u00e9chets. CCTP / Charte de chantier \u00e0 faibles nuisances.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Mise \u00e0 jour du justificatif des quantit\u00e9s de d\u00e9chets produits / valoris\u00e9s par typologie de d\u00e9chets. Bilan des d\u00e9chets de chantier ; Bordereaux d\u2019enl\u00e8vement des d\u00e9chets de chantier.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Justificatif des donn\u00e9es r\u00e9elles (ou ratios) pour les d\u00e9chets produits / valoris\u00e9s par typologie de d\u00e9chets et/ou Justificatif des ratios utilis\u00e9s. En cas de chantier de r\u00e9novation r\u00e9cent : Bilan des d\u00e9chets de chantier. Bordereaux d\u2019enl\u00e8vement des d\u00e9chets de chantier (dur\u00e9e de validit\u00e9 : 1 an). Pr\u00e9sentation du projet, plan pluriannuel de travaux (s\u2019il existe). Respect de la r\u00e9glementation (Code de l\u2019environnement) : BSDD, registre chronologique, tra\u00e7abilit\u00e9 des d\u00e9chets non r\u00e9glement\u00e9s.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet.</td></tr></table>"},
"DECH3.1.2":{intro:"Pourcentage de d\u00e9chets de chantier valoris\u00e9s mati\u00e8re (R\u00e9utilisation sans garantie de site et d\u2019usage, Recyclage, R\u00e9g\u00e9n\u00e9ration, HORS Terre)",context:"Reporter la valeur absolue dans DECH3.1.2 et la classe atteinte dans DECH3.1.2.a."},
"DECH3.1.2.a":{attendu:"Pourcentage de d\u00e9chets de chantier valoris\u00e9s mati\u00e8re (R\u00e9utilisation sans garantie de site et d\u2019usage, Recyclage, R\u00e9g\u00e9n\u00e9ration, HORS Terre).",definition:"Indiquer la part de valorisation mati\u00e8re (R\u00e9utilisation sans garantie de site et d\u2019usage, Recyclage, R\u00e9g\u00e9n\u00e9ration) dans le total de d\u00e9chets de chantier produits. Le pourcentage s\u2019\u00e9value par rapport \u00e0 la masse totale de d\u00e9chets g\u00e9n\u00e9r\u00e9s. M\u00eame si l\u2019op\u00e9ration produit des d\u00e9chets dangereux qui ne peuvent \u00eatre valoris\u00e9s, ceux-ci ne peuvent pas \u00eatre exclus du calcul. | Les terres ne sont pas concern\u00e9es (voir DECH3.1.3 et DECH3.1.4). | D\u00e9finition du terme \u00ab Valorisation mati\u00e8re \u00bb : Cf exigence DECH3.1.1. | Note compl\u00e9mentaire sur la \u00ab r\u00e9utilisation \u00bb : la r\u00e9utilisation prise en compte n\u2019a pas de garantie de site et d\u2019usage. Il s\u2019agit d\u2019une op\u00e9ration o\u00f9 le bien usag\u00e9 est d\u00e9pos\u00e9 dans les d\u00e9ch\u00e8teries (hors zone de r\u00e9emploi), prend un statut de d\u00e9chet, puis subit une op\u00e9ration de \u00ab pr\u00e9paration en vue de la r\u00e9utilisation \u00bb. | Remarque pour La R\u00e9union : le r\u00e9pertoire des fili\u00e8res de valorisation est disponible sur http://www.btp-reunion.net/",reglementation:"Cf exigence DECH3.1.1.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Justificatif des quantit\u00e9s de d\u00e9chets valoris\u00e9s mati\u00e8re par typologie de d\u00e9chet. Justificatif des ratios utilis\u00e9s.</td><td rowspan=\"4\">Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Mise \u00e0 jour du justificatif des quantit\u00e9s de d\u00e9chets valoris\u00e9s mati\u00e8re (ou des ratios utilis\u00e9s) par typologie de d\u00e9chets en cas de modification des hypoth\u00e8ses d\u2019usage.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Mise \u00e0 jour du justificatif des quantit\u00e9s de d\u00e9chets valoris\u00e9s mati\u00e8re (ou des ratios utilis\u00e9s) par typologie de d\u00e9chets en cas de modification des hypoth\u00e8ses d\u2019usage. Carnet de vie.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Justificatif des quantit\u00e9s de d\u00e9chets valoris\u00e9s par typologie de d\u00e9chet (dur\u00e9e de validit\u00e9 : 1 an).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"DECH3.1.3":{attendu:"R\u00e9emploi terre sur site.",definition:"Limiter l\u2019\u00e9vacuation hors site des terres excav\u00e9es en valorisant le r\u00e9emploi des terres excav\u00e9es sur le site m\u00eame de leur excavation. | Le r\u00e9emploi des terres est valoris\u00e9 lorsque : les terres non pollu\u00e9es excav\u00e9es au cours d\u2019activit\u00e9s de construction sont utilis\u00e9es aux fins de construction dans leur \u00e9tat naturel sur le site m\u00eame de leur excavation ; et s\u2019il existe des r\u00e9glementations locales concernant la gestion des terres non pollu\u00e9es excav\u00e9es, le r\u00e9emploi de ces terres doit \u00eatre conforme (ou en l\u2019absence de r\u00e9glementations, analyses montrant que les terres ne sont pas pollu\u00e9es). | Pour rappel : les terres r\u00e9employ\u00e9es sur le site m\u00eame de leur excavation n\u2019ont pas le statut de d\u00e9chets ; les terres excav\u00e9es et transport\u00e9es en dehors du site ont un statut de d\u00e9chets. | M\u00e9thode de calcul : quantit\u00e9s en volume (m3) ou en masse (kg). Les terres pollu\u00e9es peuvent \u00eatre exclues du calcul. Pourcentage = (quantit\u00e9 de terres r\u00e9employ\u00e9es sur site / quantit\u00e9 de terres excav\u00e9es totale du chantier) x 100% | Remarque La R\u00e9union : attention particuli\u00e8re \u00e0 la couche de terre v\u00e9g\u00e9tale (mise de c\u00f4t\u00e9 pour la pr\u00e9server) et dispositions relatives aux termites.",non_applicabilite:"Cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable dans les cas suivants : il n\u2019y a pas de travaux de terrassement sur le chantier ; il n\u2019y a pas d\u2019utilisation de terres dans le projet ; le type de terre n\u2019est pas compatible avec le projet (terre trop argileuse, terre pollu\u00e9e\u2026). Les points seront d\u00e9duits du total de points disponibles.",reglementation:"Directive 2008/98/CE du Parlement europ\u00e9en et du Conseil du 19 novembre 2008 relative aux d\u00e9chets ; D\u00e9cision de la commission du 18 d\u00e9cembre 2014 (2014/955/UE) ; Ordonnance n\u00b0 2010-1579 du 17 d\u00e9cembre 2010 ; D\u00e9cret n\u00b0 2016-288 du 10 mars 2016 ; D\u00e9cret n\u00b0 2021-321 du 25 mars 2021 relatif \u00e0 la tra\u00e7abilit\u00e9 des d\u00e9chets, terres excav\u00e9es et s\u00e9diments ; Arr\u00eat\u00e9 du 31 mai 2021 fixant le contenu des registres d\u00e9chets ; Arr\u00eat\u00e9 du 4 juin 2021 fixant les crit\u00e8res de sortie du statut de d\u00e9chet pour les terres excav\u00e9es et s\u00e9diments ; Arr\u00eat\u00e9 du 21 d\u00e9cembre 2021 fixant les crit\u00e8res de sortie du statut de d\u00e9chet pour les am\u00e9nagements constitu\u00e9s de d\u00e9blais de terres naturelles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases hors exploitation axe gestion</strong></td><td>Justificatif (objectif pour la phase programme) des quantit\u00e9s de terres excav\u00e9es non pollu\u00e9es r\u00e9employ\u00e9es sur site.</td><td>Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"DECH3.1.4":{attendu:"R\u00e9utilisation TERRE hors site.",definition:"\u00c9valuer la part des terres r\u00e9utilis\u00e9es en dehors du site de leur excavation apr\u00e8s avoir \u00e9t\u00e9 envoy\u00e9es dans des installations class\u00e9es qui attestent qu\u2019elles sont aptes \u00e0 \u00eatre r\u00e9utilis\u00e9es (le site de l\u2019excavation est celui de l\u2019op\u00e9ration objet de la certification). | La r\u00e9utilisation des terres hors site est valoris\u00e9e lorsque : au moins 30% des terres sont r\u00e9utilis\u00e9es hors site ; la gestion des terres excav\u00e9es hors site doit \u00eatre conforme \u00e0 la l\u00e9gislation sur les d\u00e9chets ; le demandeur doit fournir les preuves (tra\u00e7abilit\u00e9, attestations des installations class\u00e9es). | Pour rappel : les terres r\u00e9employ\u00e9es sur le site m\u00eame de leur excavation n\u2019ont pas le statut de d\u00e9chets ; les terres r\u00e9employ\u00e9es en dehors du site ont un statut de d\u00e9chets (tra\u00e7abilit\u00e9 et responsabilit\u00e9). | M\u00e9thode de calcul : quantit\u00e9s en volume (m3) ou en masse (kg). Le pourcentage s\u2019\u00e9value par rapport \u00e0 la masse totale de terres excav\u00e9es g\u00e9n\u00e9r\u00e9es (les terres pollu\u00e9es ne peuvent pas \u00eatre exclues du calcul). Pourcentage = (quantit\u00e9 de terres excav\u00e9es r\u00e9utilis\u00e9es hors site / quantit\u00e9 de terres excav\u00e9es totale du chantier) x 100% | Remarque La R\u00e9union : attention particuli\u00e8re \u00e0 la couche de terre v\u00e9g\u00e9tale et dispositions relatives aux termites.",non_applicabilite:"Cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable dans les cas suivants : il n\u2019y a pas de travaux de terrassement sur le chantier ; au moins 70% de la quantit\u00e9 totale des terres excav\u00e9es (pollu\u00e9es et non pollu\u00e9es) est r\u00e9employ\u00e9 sur site (voir l\u2019exigence \u00ab R\u00e9emploi Terre sur site \u00bb). Les points seront d\u00e9duits du total de points disponibles.",reglementation:"Directive 2008/98/CE ; D\u00e9cision de la commission du 18 d\u00e9cembre 2014 (2014/955/UE) ; Ordonnance n\u00b0 2010-1579 du 17 d\u00e9cembre 2010 ; D\u00e9cret n\u00b0 2016-288 du 10 mars 2016 ; D\u00e9cret n\u00b0 2021-321 du 25 mars 2021 ; Arr\u00eat\u00e9 du 31 mai 2021 ; Arr\u00eat\u00e9 du 4 juin 2021 ; Arr\u00eat\u00e9 du 21 d\u00e9cembre 2021.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectif de terres r\u00e9utilis\u00e9es hors site. Les justificatifs fournis par les installations class\u00e9es sont \u00e0 privil\u00e9gier s\u2019ils existent d\u00e9j\u00e0 en phase Programme.</td><td rowspan=\"3\">Aptitude des terres \u00e0 \u00eatre r\u00e9utilis\u00e9es.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Justificatifs des terres r\u00e9utilis\u00e9es hors site. Les justificatifs fournis par les installations class\u00e9es sont \u00e0 privil\u00e9gier s\u2019ils existent d\u00e9j\u00e0 en phase Conception.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation (axe B\u00e2timent)</strong></td><td>Justificatifs des terres r\u00e9utilis\u00e9es hors site classEs ET d\u2019autres justificatifs (tra\u00e7abilit\u00e9, etc.).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COMM1":{intro:"Organisation du commissionnement",context:"Dans ce r\u00e9f\u00e9rentiel, le commissionnement (ou recommissionnement, ou r\u00e9trocommissionnement) consiste : | En construction neuve ou r\u00e9novation : En une bonne mise au point des installations et \u00e0 s\u2019assurer du bon lancement de l\u2019exploitation future, et il peut \u00eatre r\u00e9alis\u00e9 par une personne d\u00e9sign\u00e9e au sein de l\u2019\u00e9quipe de ma\u00eetrise d\u2019\u0153uvre. Il s\u2019agit ici de s\u2019assurer d\u2019une bonne mise en \u0153uvre classique du b\u00e2timent, r\u00e9alis\u00e9e par la ma\u00eetrise d\u2019\u0153uvre. | En exploitation Axe B\u00e2timent : En une bonne optimisation des installations afin de s\u2019assurer du bon suivi d\u2019exploitation du b\u00e2timent (par exemple management \u00e9nerg\u00e9tique suite \u00e0 l\u2019audit \u00e9nerg\u00e9tique), et il peut \u00eatre r\u00e9alis\u00e9 par l\u2019entit\u00e9 exploitante du b\u00e2timent. Il s\u2019agit ici de v\u00e9rifier une bonne mise en route classique de l\u2019exploitation du b\u00e2timent r\u00e9alis\u00e9e par l\u2019exploitant. | Au premier niveau de certification, il ne s\u2019agit donc pas d\u2019une mission de commissionnement au sens strict, mais d\u2019une mise en route de l\u2019exploitation. | IMPORTANT : Dans ce document, il est fait allusion dans le texte \u00e0 l\u2019\u00ab agent de commissionnement \u00bb. Cela ne veut pas dire qu\u2019il faut passer une mission de commissionnement. Il s\u2019agit juste d\u2019une appellation courte, prise par convention, mais cette personne peut \u00eatre le MOE, un AMO Environnement, ou l\u2019exploitant (en exploitation)."},
"COMM1.1":{intro:"Agent de commissionnement",context:"Une personne est missionn\u00e9e en tant qu\u2019agent de commissionnement, recommissionnement ou r\u00e9trocommissionnement par le demandeur sur la base d\u2019un cahier des charges identifi\u00e9 selon l\u2019exigence COMM2.1.1. | Pour les b\u00e2timents neufs et r\u00e9nov\u00e9s, l\u2019agent de commissionnement a mis en place une \u00e9quipe de commissionnement, qui sera manag\u00e9e par l\u2019agent de commissionnement. Les membres de l\u2019\u00e9quipe sont en g\u00e9n\u00e9ral des membres de l\u2019\u00e9quipe projet (ma\u00eetre d\u2019ouvrage, concepteurs, etc.), aux comp\u00e9tences compl\u00e9mentaires, ainsi que le futur exploitant (ou comp\u00e9tence \u00e9quivalente). | Pour les b\u00e2timents existants, l\u2019\u00e9quipe comprend a minima le propri\u00e9taire gestionnaire et l\u2019exploitant."},
"COMM1.1.1":{attendu:"Missionner un agent de commissionnement (ou recommissionnement ou r\u00e9trocommissionnement). | Rappel : Il n\u2019est pas n\u00e9cessaire pour \u00eatre certifi\u00e9 d\u2019avoir une mission sp\u00e9cifique de commissionnement avec un acteur diff\u00e9rent des acteurs de l\u2019op\u00e9ration (Exemples : ma\u00eetre d\u2019\u0153uvre ou AMO en construction ou r\u00e9novation, et AMO ou exploitant en exploitation).",definition:"Premier niveau : Ma\u00eetrise d\u2019\u0153uvre, MOA ou exploitant. Ce niveau est obligatoire pour \u00eatre certifi\u00e9. A ce premier niveau, il est admis que la personne missionn\u00e9e soit issue d\u2019une entit\u00e9 faisant partie de la maitrise d\u2019\u0153uvre, de la MOA, ou de l\u2019exploitant. Dans le cas d\u2019un montage d\u2019op\u00e9ration en march\u00e9 global, la personne missionn\u00e9e ne peut faire partie de l\u2019entit\u00e9 de march\u00e9 global que dans le cas o\u00f9 des clauses de performance (exemple Contrat de Performance Energ\u00e9tique) sont contractualis\u00e9es. | Deuxi\u00e8me niveau : Tierce partie int\u00e9gr\u00e9e. A ce niveau, l\u2019agent de commissionnement peut \u00eatre une tierce partie int\u00e9gr\u00e9e \u00e0 la Ma\u00eetrise d\u2019Ouvrage, aux entreprises titulaires des march\u00e9s de maitrise d\u2019\u0153uvre, de travaux et d\u2019exploitation. C\u2019est le cas par exemple d\u2019une personne appartenant \u00e0 une autre agence ou un service sp\u00e9cifique d\u2019un bureau d\u2019\u00e9tude ou au service central de \u00ab commissionnement \u00bb d\u2019un exploitant multi technique, mais qui n\u2019appartient pas \u00e0 l\u2019\u00e9quipe d\u00e9di\u00e9e au b\u00e2timent. De plus, cette personne doit justifier d\u2019une exp\u00e9rience minimale finalis\u00e9e (c\u2019est \u00e0 dire jusqu\u2019aux essais fonctionnels) en commissionnement sur au moins deux op\u00e9rations du m\u00eame type. Exemples d\u2019\u00e9l\u00e9ments pour consid\u00e9rer qu\u2019une op\u00e9ration est de m\u00eame type : m\u00eame taille de b\u00e2timent (par exemple < ou > \u00e0 5000m\u00b2), pr\u00e9sence de process particuliers (datacenters, process froids) ou de syst\u00e8mes complexes, m\u00eame typologie de b\u00e2timent, pr\u00e9sence de m\u00eames types de syst\u00e8mes, GTB incluse ou non, etc. | Troisi\u00e8me niveau : Tierce partie int\u00e9gr\u00e9e et qualifi\u00e9e. A ce niveau, l\u2019agent de commissionnement respecte les m\u00eames conditions qu\u2019au niveau pr\u00e9c\u00e9dent. L\u2019agent de commissionnement doit en compl\u00e9ment justifier : D\u2019une comp\u00e9tence minimale est de 5 jours de formation en commissionnement, en neuf ou en r\u00e9novation. La qualification/certification de personne est un plus (CBCP ou \u00e9quivalent). A noter qu\u2019en France l\u2019OPQIBI propose aussi une qualification en ing\u00e9nierie du commissionnement. Si cette qualification est apport\u00e9e en justification, il convient de d\u00e9montrer que la personne choisie comme agent de commissionnement est bien celle qui a permis l\u2019obtention de cette qualification. L\u2019agent de commissionnement peut aussi justifier de ses comp\u00e9tences avec une certification d\u2019entreprise en commissionnement CBCF ou \u00e9quivalent (pr\u00e9cision : pour \u00eatre certifi\u00e9e CBCF, l\u2019entreprise doit justifier a minima de deux r\u00e9f\u00e9rences en commissionnement et de 2 personnes form\u00e9es CBCP). Si cette justification est apport\u00e9e, il convient de d\u00e9montrer que la personne choisie comme agent de commissionnement est bien celle qui a permis l\u2019obtention de cette certification. | Quatri\u00e8me niveau : Tierce partie ind\u00e9pendante. A ce niveau, l\u2019agent de commissionnement respecte les m\u00eames conditions qu\u2019au niveau pr\u00e9c\u00e9dent. Il convient cependant \u00e0 ce niveau d\u2019\u00e9viter les conflits d\u2019int\u00e9r\u00eat : L\u2019agent de commissionnement est donc une tierce partie totalement ind\u00e9pendante des march\u00e9s de maitrise d\u2019\u0153uvre, de travaux et d\u2019exploitation, et justifie de ses comp\u00e9tences ou de sa qualification en la mati\u00e8re.",notation:"Non atteint : 0 point | Ma\u00eetrise d\u2019\u0153uvre, MOA ou exploitant : 1 point | Tierce partie int\u00e9gr\u00e9e : 3 points | Tierce partie int\u00e9gr\u00e9e et qualifi\u00e9e : 4 points | Tierce partie ind\u00e9pendante : 5 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Niveau 1 :<br>\u2022 Consultation (si pas encore missionn\u00e9)<br>\u2022 Contrat d\u2019AMO, de ma\u00eetrise d\u2019\u0153uvre ou d\u2019exploitant<br>\u2022 ou lettre de mission destin\u00e9e \u00e0 une personne interne \u00e0 la maitrise d\u2019ouvrage (demandeur)<br>Niveau 2 :<br>\u2022 Consultation (si pas encore missionn\u00e9)<br>\u2022 Contrat avec l\u2019entit\u00e9 d\u00e9sign\u00e9e<br>\u2022 Organigramme<br>\u2022 Preuves d\u2019exp\u00e9rience sur deux op\u00e9rations de m\u00eame type<br>Niveau 3 (en compl\u00e9ment niveau pr\u00e9c\u00e9dent) :<br>\u2022 Preuve de la formation (minimum 5 jours) ou de sa certification de personne en commissionnement (type CBCP ou \u00e9quivalent) ou qualification (OPQIBI).<br>Niveau 4 (en compl\u00e9ment niveau pr\u00e9c\u00e9dent) :<br>\u2022 Contrat entre demandeur et agent de commissionnement (au lieu du contrat avec l\u2019entit\u00e9 d\u00e9sign\u00e9e)</td><td>Sans objet</td></tr></table>"},
"COMM1.2":{intro:"P\u00e9rim\u00e8tres",context:"Les p\u00e9rim\u00e8tres temporel (les phases couvertes par la mission de commissionnement, recommissionnement ou r\u00e9trocommissionnement) et fonctionnel (les syst\u00e8mes sur lesquels va porter la mission) sont d\u00e9finis."},
"COMM1.2.1":{attendu:"P\u00e9rim\u00e8tre fonctionnel. | Rappel : Cette exigence peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre AOR classique, d\u2019une mission d\u2019AMO environnement, d\u00e9finissant les essais des entreprises et en suivant la r\u00e9alisation. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"En fonction des objectifs du commissionnement (COM2.1.1), le p\u00e9rim\u00e8tre fonctionnel inclut a minima 4 syst\u00e8mes parmi les 7 suivants : chauffage, ventilation, refroidissement, ECS, CFO, syst\u00e8me impliquant la production d\u2019\u00e9nergies renouvelables locales et GTB. | Conditions particuli\u00e8res : Si une GTB est pr\u00e9sente, elle doit faire partie des 4 syst\u00e8mes choisis dans le p\u00e9rim\u00e8tre. Si le projet comporte un ou plusieurs syst\u00e8mes de PLE (production locale d\u2019\u00e9nergie, panneaux solaires par ex.), ceux-ci doivent \u00e9galement faire partie des 4 syst\u00e8mes choisis dans le p\u00e9rim\u00e8tre. | Le p\u00e9rim\u00e8tre doit tenir compte des enjeux du projet et de ses objectifs (COMM2.1.1), (par exemple on inclura l\u2019ECS dans un projet h\u00f4telier). | IMPORTANT : Un syst\u00e8me est comptabilis\u00e9 en tant que tel dans le p\u00e9rim\u00e8tre si, pour les r\u00e8gles d\u2019\u00e9chantillonnage pr\u00e9vues : Tous ses \u00e9l\u00e9ments principaux (production, g\u00e9n\u00e9ration, pompes, etc.) sont inclus. Le pourcentage d\u2019\u00e9l\u00e9ments \u00ab finaux \u00bb inclus (\u00e9metteurs, terminaux, r\u00e9gulations, etc.) correspond au minimum au niveau de contr\u00f4le III du tableau d\u2019\u00e9chantillonnage (En France cela correspond aux ex-essais COPREC d\u00e9sormais \u00ab Attestations de contr\u00f4le de l\u2019AQC \u00bb). | En France, pour la GTB, et pour les b\u00e2timents qui y sont soumis, le \u00ab D\u00e9cret BACS \u00bb relatif au syst\u00e8me d\u2019automatisation et de contr\u00f4le des b\u00e2timents non r\u00e9sidentiels et \u00e0 la r\u00e9gulation automatique de la chaleur est respect\u00e9. | P\u00e9rim\u00e8tre de base : Ce niveau est obligatoire pour \u00eatre certifi\u00e9. A ce premier niveau, il s\u2019agit de s\u2019assurer de la bonne mise en fonctionnement sur le p\u00e9rim\u00e8tre de base (a minima 4 syst\u00e8mes parmi les 7 suivants : chauffage, ventilation, refroidissement, ECS, CFO, syst\u00e8me impliquant la production d\u2019\u00e9nergies renouvelables locales et GTB), en lien avec les entreprises, sur la base d\u2019objectifs fix\u00e9s, et de tests / v\u00e9rifications bien d\u00e9finis. Cf. ci-dessus pour les conditions particuli\u00e8res. | P\u00e9rim\u00e8tre \u00e9tendu : En fonction des objectifs du commissionnement (COM2.1.1), le p\u00e9rim\u00e8tre fonctionnel inclut a minima 7 syst\u00e8mes parmi les suivants : chauffage, ventilation, refroidissement, CFO, syst\u00e8me impliquant des \u00e9nergies renouvelables locales, GTB, ECS (si enjeux), protections solaires et ouvrants motoris\u00e9s, ascenseurs et \u00e9quipements \u00e9lectrom\u00e9caniques, enveloppe, syst\u00e8mes de s\u00e9curit\u00e9 (s\u00e9curit\u00e9 incendie, syst\u00e8me anti-intrusion) et de communication (r\u00e9seau smart, r\u00e9seau VDI). Conditions particuli\u00e8res : Les m\u00eames conditions qu\u2019au niveau pr\u00e9c\u00e9dent s\u2019appliquent. L\u2019enveloppe doit \u00eatre incluse obligatoirement au p\u00e9rim\u00e8tre \u00e0 ce niveau. | P\u00e9rim\u00e8tre \u00e9tendu et supervision : En compl\u00e9ment du niveau pr\u00e9c\u00e9dent, il est demand\u00e9 l\u2019int\u00e9gration pour le p\u00e9rim\u00e8tre fonctionnel choisi ci-dessus et les objectifs fix\u00e9s en COMM2.1.1, d\u2019une solution de monitoring \u00e0 distance des syst\u00e8mes techniques (supervision) permettant a minima : la d\u00e9tection de d\u00e9fauts, le suivi de la performance.",notation:"Non atteint : 0 point | P\u00e9rim\u00e8tre de base : 2 points | P\u00e9rim\u00e8tre \u00e9tendu : 4 points | P\u00e9rim\u00e8tre \u00e9tendu et supervision : 5 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Cahier des charges du commissionnement, avec indication des p\u00e9rim\u00e8tres fonctionnel et temporel choisis.</td><td>Sans objet</td></tr></table>"},
"COMM1.2.2":{attendu:"P\u00e9rim\u00e8tre temporel. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre AOR classique, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"En fonction des objectifs du commissionnement (COM2.1.1), le p\u00e9rim\u00e8tre temporel doit \u00eatre d\u00e9fini. | P\u00e9rim\u00e8tre de base : Ce niveau est obligatoire pour \u00eatre certifi\u00e9. Le p\u00e9rim\u00e8tre temporel couvre a minima : Pour les b\u00e2timents neufs ou r\u00e9nov\u00e9s : en phase conception (au plus tard en DCE) jusqu\u2019\u00e0 la phase de r\u00e9alisation, y compris la r\u00e9ception. Pour les b\u00e2timents existants : un recommissionnement ou r\u00e9trocommissionnement ponctuel (batterie de tests/r\u00e9glages \u00e0 un moment donn\u00e9 ou sur une saison, en fonction des choix faits dans le p\u00e9rim\u00e8tre fonctionnel) ou un cycle de moins de 3 ans. | P\u00e9rim\u00e8tre \u00e9tendu : Le p\u00e9rim\u00e8tre temporel couvre a minima : Pour les b\u00e2timents neufs ou r\u00e9nov\u00e9s : la fin de la phase programme, les phases de conception et de r\u00e9alisation, y compris la r\u00e9ception, ainsi que les 18 premiers mois d\u2019exploitation (dont l\u2019ann\u00e9e de parfait ach\u00e8vement). Pour les b\u00e2timents existants : un commissionnement ou r\u00e9trocommissionnement sur un cycle de 3 ans ou plus. | IMPORTANT : Les 18 premiers mois d\u2019exploitation d\u00e9butent lorsqu\u2019a minima 20% des surfaces (hors parties communes du b\u00e2timent) sont occup\u00e9es.",notation:"Non atteint : 0 point | P\u00e9rim\u00e8tre de base : 1 point | P\u00e9rim\u00e8tre \u00e9tendu : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Cahier des charges du commissionnement, avec indication des p\u00e9rim\u00e8tres fonctionnel et temporel choisis.</td><td>Sans objet</td></tr></table>"},
"COMM2":{intro:"Mission de commissionnement",context:"La mission de commissionnement comprend la d\u00e9finition des objectifs, la planification des actions, la r\u00e9alisation des essais, le suivi des travaux, la sensibilisation des occupants, le transfert des informations et la r\u00e9daction du rapport final."},
"COMM2.1":{intro:"D\u00e9finition des objectifs",context:"Contribution de la personne missionn\u00e9e en tant qu\u2019agent de commissionnement \u00e0 la sp\u00e9cification d\u00e9taill\u00e9e des objectifs du demandeur (maitre d\u2019ouvrage), des performances attendues, des hypoth\u00e8ses de conception, et inclusion dans le programme d\u00e9taill\u00e9 de l\u2019op\u00e9ration."},
"COMM2.1.1":{attendu:"D\u00e9finition des objectifs du commissionnement ou recommissionnement ou r\u00e9trocommissionnement. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"Premier niveau : D\u00e9finition des objectifs. Ce niveau est obligatoire pour \u00eatre certifi\u00e9. | Pour un b\u00e2timent en construction neuve ou r\u00e9novation : Les sp\u00e9cifications d\u00e9taill\u00e9es du programme, en construction neuve ou en r\u00e9novation, qui peuvent \u00eatre exprim\u00e9es sous forme de moyens ou de performances, sont autant que possible v\u00e9rifiables soit au cours des travaux, soit \u00e0 la r\u00e9ception, soit au cours de l\u2019ann\u00e9e de parfait ach\u00e8vement. L\u2019agent de commissionnement (id\u00e9alement en phase programme, sinon au d\u00e9but de son intervention) collabore avec le demandeur (maitre d\u2019ouvrage par exemple) afin d\u2019\u00e9tablir clairement ces sp\u00e9cifications. Elles constituent la base contractuelle des exigences du demandeur (maitre d\u2019ouvrage par exemple) pour son b\u00e2timent. Dans le langage du commissionnement, on parle des \u00ab Exigences du Propri\u00e9taire pour le Projet \u00bb ou EPP, qui peuvent \u00e9voluer en cours de route. Les hypoth\u00e8ses de conception doivent aussi \u00eatre d\u00e9finies, afin d\u2019orienter et de faciliter le travail ult\u00e9rieur des concepteurs. Ces sp\u00e9cifications peuvent porter sur diff\u00e9rentes th\u00e9matiques (unique ou combin\u00e9es) en fonction des objectifs du demandeur et du contexte de l\u2019op\u00e9ration : performance \u00e9nerg\u00e9tique, r\u00e9silience / adaptabilit\u00e9 du b\u00e2timent, maintenabilit\u00e9 (des syst\u00e8mes, de l\u2019enveloppe, etc.), confort / sant\u00e9 des occupants (mesures de QAI, ventilation, mesures acoustiques, temp\u00e9ratures, etc.), num\u00e9rique (utilisation de maquette exploitation, etc.), performance thermique (\u00e9tanch\u00e9it\u00e9 \u00e0 l\u2019air, int\u00e9grit\u00e9 thermique, etc.), etc. | Cas particuliers : Lors de la phase programme, si le maitre d\u2019ouvrage a r\u00e9pondu correctement \u00e0 cette exigence sans l\u2019aide de l\u2019agent de commissionnement, cette exigence est consid\u00e9r\u00e9e comme atteinte. Si les objectifs (ou le programme) ont \u00e9t\u00e9 d\u00e9finis apr\u00e8s le d\u00e9but de l\u2019intervention de l\u2019agent de commissionnement (p\u00e9rim\u00e8tre temporel de base), celui-ci v\u00e9rifie que les exigences des objectifs ou du programme (ou EPP) sont bien d\u00e9finies pour mener \u00e0 bien le commissionnement lors de la conception. Si n\u00e9cessaire, un cahier des charges compl\u00e9mentaire sera r\u00e9dig\u00e9 si toutes les exigences ne sont pas d\u00e9finies. | Pour un b\u00e2timent existant en exploitation, les actions suivantes compl\u00e8tent les pr\u00e9c\u00e9dentes : Etat des lieux du fonctionnement des syst\u00e8mes, inspection des syst\u00e8mes, \u00e9tude des donn\u00e9es disponibles (par ex via la GTB), analyse du fonctionnement des syst\u00e8mes. Identification des anomalies de fonctionnement. Collecte et \u00e9tude de tous les documents utiles (plans, descriptifs, DOE, rapports divers, contrats, relev\u00e9s et factures, documents de suivi, etc.). Retours sur la satisfaction des occupants (confort, dysfonctionnements, g\u00eanes ressenties), interviews des utilisateurs et des intervenants. Ces actions peuvent conduire \u00e0 la s\u00e9lection des syst\u00e8mes sur lesquels il sera plus rentable ou plus pertinent de mener une mission de recommissionnement (selon le p\u00e9rim\u00e8tre fonctionnel choisi). A l\u2019issue de son analyse, l\u2019agent de commissionnement \u00e9tablit une liste de mesures \u00e0 mettre en place pour am\u00e9liorer et optimiser le fonctionnement des syst\u00e8mes. L\u2019agent de commissionnement et le demandeur s\u2019accordent sur la liste des mesures \u00e0 mettre en place en fonction des objectifs vis\u00e9s. Note : le terme \u00ab mesures \u00bb est \u00e0 prendre au sens large (dispositions techniques, ajout de composants ou au contraire simplification, instrumentation, fonctions de la GTB, etc.). | Deuxi\u00e8me niveau : D\u00e9finition des objectifs et engagement sur les charges. Les objectifs fix\u00e9s au niveau ci-dessus permettent au demandeur de s\u2019engager sur une diminution des charges en exploitation du b\u00e2timent, sur les th\u00e9matiques et p\u00e9rim\u00e8tres choisis. Exemples : Cet engagement peut prendre la forme d\u2019un CPE (selon Directive Europ\u00e9enne 2012/27/UE), ou de la mise en place d\u2019un protocole de type IPMVP pour l\u2019\u00e9nergie (si un protocole IPMVP est mis en place, sa r\u00e9alisation par une personne qualifi\u00e9e CMVP est souhaitable). L\u2019engagement peut porter sur d\u2019autres th\u00e9matiques, par exemple les co\u00fbts de maintenance, sur la base d\u2019un engagement en co\u00fbt global. Etc.",notation:"Non atteint : 0 point | D\u00e9finition des objectifs : 2 points | D\u00e9finition des objectifs et engagement sur les charges : 5 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Niveau 1 : Programme d\u00e9taill\u00e9, y compris fiches individuelles des espaces<br>Niveau 2 : Engagement sur les charges.</td><td>Sans objet</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Niveau 1 :<br>\u2022 Document exposant les performances attendues<br>\u2022 Document d\u2019\u00e9tat des lieux<br>\u2022 Diagnostic \u00e9nerg\u00e9tique s\u2019il existe<br>\u2022 Synth\u00e8se des investigations<br>\u2022 Liste des mesures \u00e0 mettre en place<br>Niveau 2 : Engagement sur les charges.</td><td>Sans objet</td></tr></table>"},
"COMM2.2":{intro:"Actions de commissionnement (ou recommissionnement / r\u00e9trocommissionnement)",context:"Cette section d\u00e9crit l\u2019ensemble des actions \u00e0 mener dans le cadre de la mission de commissionnement : plan de commissionnement, examen critique, d\u00e9finition des essais, inclusion des responsabilit\u00e9s, suivi des travaux, implication de l\u2019exploitant, mise au point, r\u00e9ception, sensibilisation, transfert, documentation, tests saisonniers, rapport final et r\u00e9glages."},
"COMM2.2.1":{attendu:"Plan de Commissionnement. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"L\u2019agent de commissionnement met en place un Plan de commissionnement (ou recommissionnement ou r\u00e9trocommissionnement). | Premier niveau : Plan de commissionnement minimum. Ce niveau est obligatoire pour \u00eatre certifi\u00e9. Le plan de commissionnement comporte a minima les \u00e9l\u00e9ments suivants : La d\u00e9finition des objectifs du commissionnement. La mise en place de la pr\u00e9paration \u00e0 l\u2019exploitation future (essais pr\u00e9vus et leurs crit\u00e8res d\u2019acceptation, intervenants, documents remis, formation de l\u2019exploitant). Ce doit \u00eatre un document contractuel joint aux diff\u00e9rents march\u00e9s. | Deuxi\u00e8me niveau : Plan de commissionnement complet. Ce niveau vient en compl\u00e9ment du niveau pr\u00e9c\u00e9dent. L\u2019agent de commissionnement met en place un Plan de commissionnement (ou recommissionnement ou r\u00e9trocommissionnement) complet. En programme, il r\u00e9dige les grandes lignes du plan de commissionnement, et le d\u00e9taille au fur et \u00e0 mesure du projet. Le plan de commissionnement est un document \u00e9volutif qui se pr\u00e9cise au fur et \u00e0 mesure de l\u2019avancement du projet. Ce plan int\u00e8gre a minima les points suivants : activit\u00e9s pr\u00e9vues selon p\u00e9rim\u00e8tres fonctionnels et temporels choisis, calendrier, r\u00f4les et responsabilit\u00e9s des membres de l\u2019\u00e9quipe de commissionnement, outils, livrables. | Il est recommand\u00e9 de pr\u00e9parer au plus t\u00f4t (a minima en conception) les documents et outils qui seront r\u00e9dig\u00e9s ou utilis\u00e9s par la suite, et d\u2019adapter ces documents \u00e0 la complexit\u00e9 et aux sp\u00e9cificit\u00e9s du projet.",notation:"Non atteint : 0 point | Plan de commissionnement minimum : 1 point | Plan de commissionnement complet : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>1\u00e8re version du Plan de commissionnement (grandes lignes) si l\u2019intervention de commissionnement commence en programme.</td><td>Sans objet</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Plan de commissionnement (plan mis \u00e0 jour si n\u00e9cessaire si l\u2019intervention a commenc\u00e9 avant la conception).</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Plan de recommissionnement ou r\u00e9trocommissionnement.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.2":{attendu:"Examen critique des diff\u00e9rentes \u00e9tapes de la conception, des plans et des sp\u00e9cifications (CCTP).",non_applicabilite:"Dans le cas o\u00f9 l\u2019op\u00e9ration est en programme, ou en r\u00e9alisation, ou en exploitation axe B\u00e2timent, cette exigence est non applicable.",definition:"L\u2019agent de commissionnement proc\u00e8de \u00e0 un examen critique des diff\u00e9rentes \u00e9tapes de la conception, des plans et des sp\u00e9cifications (CCTP), centr\u00e9 sur le commissionnement (selon le p\u00e9rim\u00e8tre fonctionnel choisi). Il s\u2019assure que le demandeur a bien arbitr\u00e9 les \u00e9l\u00e9ments issus de ces examens critiques et que les acteurs de l\u2019op\u00e9ration en sont inform\u00e9s. Ces \u00e9tapes d\u2019examen critique et d\u2019arbitrage sont incluses au plan de commissionnement. Ils sont aussi consign\u00e9s dans le registre des probl\u00e8mes pour cette \u00e9tape. | Si certains locaux sont livr\u00e9s \u00ab en blanc \u00bb l\u2019examen du cahier des charges \u00ab preneurs \u00bb est \u00e0 inclure dans cet examen.",notation:"Non applicable | Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>Examen critique des documents de conception.<br>Document d\u2019arbitrage du demandeur.<br>Registre des probl\u00e8mes.</td><td>Sans objet</td></tr><tr><td><strong>Autres phases</strong></td><td>Non concern\u00e9es.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.3":{attendu:"D\u00e9finition des essais fonctionnels. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"L\u2019agent de commissionnement, avec son \u00e9quipe de commissionnement, d\u00e9finit les essais fonctionnels \u00e0 r\u00e9aliser sur les p\u00e9rim\u00e8tres fonctionnel et temporel choisis. | Important : Cette d\u00e9finition des essais comporte, pour chaque syst\u00e8me ou \u00e9l\u00e9ment inclus au p\u00e9rim\u00e8tre fonctionnel du commissionnement, des indicateurs pertinents, et des crit\u00e8res d\u2019acceptation des r\u00e9sultats des essais sur ces indicateurs. | Option 1 : Dans cette option, les essais sont d\u00e9finis en coh\u00e9rence avec les objectifs de l\u2019op\u00e9ration. Cela vise \u00e0 v\u00e9rifier le fonctionnement des syst\u00e8mes inclus dans le p\u00e9rim\u00e8tre fonctionnel. En compl\u00e9ment des essais statiques r\u00e9alis\u00e9s par les entreprises (ou l\u2019exploitant pour les b\u00e2timents existants axe B\u00e2timent), l\u2019agent de commissionnement s\u2019assure que des essais fonctionnels (avec \u00e9laboration de sc\u00e9narios fonctionnels pertinents) sont bien d\u00e9finis. Pour les b\u00e2timents existants (axe B\u00e2timent), ces essais permettent notamment de v\u00e9rifier, sur les syst\u00e8mes du p\u00e9rim\u00e8tre, le maintien des performances dans le temps et la conformit\u00e9 r\u00e9glementaire (exemple : d\u00e9bit air neuf/personne). Les r\u00e8gles d\u2019\u00e9chantillonnages sont conformes aux r\u00e8gles d\u00e9finies dans le p\u00e9rim\u00e8tre fonctionnel. Cette d\u00e9finition comporte \u00e9galement un crit\u00e8re d\u2019acceptation des r\u00e9sultats de ces essais, adapt\u00e9 \u00e0 chaque syst\u00e8me inclus au p\u00e9rim\u00e8tre. Pour les constructions neuves ou r\u00e9novations, la planification de ces essais fonctionnels int\u00e8grera les contraintes de planning de l\u2019op\u00e9ration et sera int\u00e9gr\u00e9e au plan de commissionnement. | Option 2 : En compl\u00e9ment des essais d\u00e9finis dans l\u2019option 1, des essais dynamiques coordonn\u00e9s entre lots du p\u00e9rim\u00e8tre sont d\u00e9finis. Il s\u2019agit de v\u00e9rifier que le fonctionnement de chaque lot du p\u00e9rim\u00e8tre est bien conforme, notamment lors d\u2019essais combin\u00e9s r\u00e9alis\u00e9s avec la GTB afin de v\u00e9rifier notamment la bonne interop\u00e9rabilit\u00e9 des syst\u00e8mes. Pour les b\u00e2timents existants (axe B\u00e2timent), les essais sont coordonn\u00e9s entre syst\u00e8mes inclus dans le p\u00e9rim\u00e8tre. En France, pour les b\u00e2timents qui y sont soumis, la GTB r\u00e9pond aux caract\u00e9ristiques du \u00ab D\u00e9cret BACS \u00bb relatif au syst\u00e8me d\u2019automatisation et de contr\u00f4le des b\u00e2timents non r\u00e9sidentiels et \u00e0 la r\u00e9gulation automatique de la chaleur. | Option 3 : En compl\u00e9ment des essais d\u00e9finis dans l\u2019option 1, pour les b\u00e2timents d\u2019une superficie sup\u00e9rieure \u00e0 5 000 m\u00b2, les essais suivants sont d\u00e9finis : Essais d\u2019\u00e9tanch\u00e9it\u00e9 \u00e0 l\u2019air selon la norme EN 13829 (Performance thermique des b\u00e2timents \u2013 D\u00e9termination de la perm\u00e9abilit\u00e9 \u00e0 l\u2019air des b\u00e2timents \u2013 M\u00e9thode de pressurisation par ventilateur). Essai d\u2019int\u00e9grit\u00e9 thermique selon la norme EN 13187 (Performance thermique des b\u00e2timents \u2013 D\u00e9tection qualitative des irr\u00e9gularit\u00e9s thermiques sur les enveloppes des b\u00e2timents \u2013 M\u00e9thode infrarouge) OU selon des processus de contr\u00f4le de la qualit\u00e9 solides et tra\u00e7ables mis en place au cours du processus de construction.",notation:"Non atteint : 0 point | Option 1 : 3 points | Option 2 OU Option 3 : 4 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Plan d\u2019essais fonctionnels.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.4":{attendu:"Inclusion des responsabilit\u00e9s et des t\u00e2ches des entreprises. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"Pour les op\u00e9rations en construction ou r\u00e9novation, cette exigence concerne les responsabilit\u00e9s et les t\u00e2ches des entreprises en mati\u00e8re de commissionnement dans les DCE et ensuite dans les contrats/march\u00e9s. Le ma\u00eetre d\u2019\u0153uvre peut indiquer ces \u00e9l\u00e9ments. Pour les b\u00e2timents existants en exploitation (axe B\u00e2timent), cette exigence concerne les responsabilit\u00e9s de l\u2019exploitant (et ses \u00e9ventuels prestataires) dans son contrat d\u2019exploitation. | En construction neuve / r\u00e9novation : L\u2019agent de commissionnement participe aux \u00e9changes pendant la phase ACT et/ou la n\u00e9gociation avec les entreprises. Dans les documents de consultation des entreprises (DCE) et ensuite dans les contrats/march\u00e9s sont incluses les responsabilit\u00e9s et les t\u00e2ches des entreprises en mati\u00e8re de commissionnement. Il est essentiel d\u2019inclure dans les documents contractuels les responsabilit\u00e9s et les t\u00e2ches des entreprises en mati\u00e8re de commissionnement, y compris l\u2019installation, le r\u00e9glage et le d\u00e9marrage de l\u2019\u00e9quipement, la documentation et les essais fonctionnels (avec leurs indicateurs et leurs crit\u00e8res d\u2019acceptation des r\u00e9sultats). Ainsi que la confirmation de ces responsabilit\u00e9s et t\u00e2ches. | Pour les b\u00e2timents existants : L\u2019agent de recommissionnement ou r\u00e9trocommissionnement v\u00e9rifie que le contrat de l\u2019exploitant comporte bien ses responsabilit\u00e9s et ses t\u00e2ches en mati\u00e8re de recommissionnement (ou r\u00e9trocommissionnement), notamment le suivi des performances, le r\u00e9glage de l\u2019\u00e9quipement, la documentation et les essais fonctionnels (avec leurs indicateurs et leurs crit\u00e8res d\u2019acceptation des r\u00e9sultats).",notation:"Non atteint : 0 point | Atteint : 4 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>D\u00e9finition des objectifs.</td><td>Sans objet</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>DCE (Conception), DOE (R\u00e9alisation), Registre des probl\u00e8mes.</td><td>Responsabilit\u00e9s et t\u00e2ches des entreprises en mati\u00e8re de commissionnement.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Responsabilit\u00e9s et t\u00e2ches de l\u2019exploitant et de ses prestataires, Registre des probl\u00e8mes.</td><td>Responsabilit\u00e9s et t\u00e2ches de l\u2019exploitant et de ses prestataires en mati\u00e8re de commissionnement.</td></tr></table>"},
"COMM2.2.5":{attendu:"Avis sur les documents soumis par les entreprises.",non_applicabilite:"Dans le cas o\u00f9 l\u2019op\u00e9ration est en programme, ou en conception, ou en exploitation axe B\u00e2timent, cette exigence est non applicable.",definition:"L\u2019agent de commissionnement examine et \u00e9met un avis sur les documents soumis par les entreprises (\u00e9tudes d\u2019ex\u00e9cution) : Il v\u00e9rifie le respect des objectifs (programme) et des cahiers des charges. Il examine les manuels d\u2019exploitation-maintenance. Il \u00e9met un avis sur ces documents. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Le ma\u00eetre d\u2019\u0153uvre peut la r\u00e9aliser. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement.",notation:"Non applicable | Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>March\u00e9s, Registre des probl\u00e8mes.</td><td>Responsabilit\u00e9s et t\u00e2ches des entreprises en mati\u00e8re de commissionnement.</td></tr><tr><td><strong>Autres phases</strong></td><td>Non concern\u00e9es.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.6":{attendu:"Suivi des travaux.",non_applicabilite:"Dans le cas o\u00f9 l\u2019op\u00e9ration est en programme, ou en conception, ou en exploitation axe B\u00e2timent, cette exigence est non applicable.",definition:"Observation permanente de la r\u00e9alisation, tenue d\u2019un registre des probl\u00e8mes (li\u00e9s \u00e0 l\u2019installation, aux interfaces entres lots, \u00e0 la mise en route et aux essais fonctionnels), et suivi des modifications en cours de chantier et des actions correctives suite \u00e0 \u00e9carts. | V\u00e9rification que les \u00e9quipements compris dans le p\u00e9rim\u00e8tre fonctionnel et qui sont pos\u00e9s sont bien ceux pr\u00e9vus. | Suivi de l\u2019auto-contr\u00f4le des entreprises (y compris les r\u00e9glages). | En fin de travaux, l\u2019agent de commissionnement examine les manuels d\u2019exploitation et de maintenance (fournis par les entreprises). | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Le ma\u00eetre d\u2019\u0153uvre peut la r\u00e9aliser. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement.",notation:"Non applicable | Non atteint : 0 point | Atteint : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Registre des probl\u00e8mes, et solutions apport\u00e9es<br>Fiches d\u2019auto-contr\u00f4le des entreprises<br>Comptes-rendus.</td><td>Sans objet</td></tr><tr><td><strong>Autres phases</strong></td><td>Non concern\u00e9es.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.7":{attendu:"Implication du futur exploitant.",non_applicabilite:"Si le futur exploitant (personne qui sera effectivement sur site lors de l\u2019exploitation) n\u2019est pas connu, ou si l\u2019op\u00e9ration est en programme ou en exploitation axe B\u00e2timent, cette exigence est non applicable. Dans ces cas, les points attribu\u00e9s seront d\u00e9duits du nombre total de points disponibles.",definition:"Incitation \u00e0 impliquer le plus t\u00f4t possible le futur exploitant (s\u2019il est connu) afin de b\u00e9n\u00e9ficier de son exp\u00e9rience et de limiter les probl\u00e8mes futurs. | L\u2019exploitant participe a minima \u00e0 la d\u00e9finition / analyse des essais (avec leurs indicateurs et leurs crit\u00e8res d\u2019acceptation des r\u00e9sultats) et \u00e0 la mise en service. Il est pr\u00e9sent lors des r\u00e9unions n\u00e9cessaires et/ou lors des essais. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement.",notation:"Non applicable | Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Comptes rendus.</td><td>Sans objet</td></tr><tr><td><strong>Autres phases</strong></td><td>Non concern\u00e9es.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.8":{attendu:"Mise au point des installations, r\u00e9alisation des essais d\u00e9finis et analyses. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre AOR classique, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"Mise au point des installations, r\u00e9alisation des essais d\u00e9finis et analyses. | Premier niveau : V\u00e9rification des essais fonctionnels. L\u2019agent de commissionnement : V\u00e9rifie avec son \u00e9quipe que la mise au point des installations, la r\u00e9alisation des essais fonctionnels d\u00e9finis (avec leurs indicateurs et leurs crit\u00e8res d\u2019acceptation des r\u00e9sultats), et leur analyse sont bien r\u00e9alis\u00e9es. S\u2019assure que ces conclusions sont remont\u00e9es au demandeur (par exemple Ma\u00eetre d\u2019Ouvrage) et aux acteurs responsables des syst\u00e8mes (en construction r\u00e9novation) ou \u00e0 l\u2019exploitant (en b\u00e2timents existants), sur le p\u00e9rim\u00e8tre fonctionnel choisi. | Deuxi\u00e8me niveau : R\u00e9alisation d\u2019essais contradictoires. L\u2019agent de commissionnement, en fonction des essais r\u00e9alis\u00e9s et de leurs conclusions (anomalies, etc.) : Supervise (ou r\u00e9alise en pr\u00e9sence des entreprises concern\u00e9es ou de l\u2019exploitant en b\u00e2timents existants) des mesures/essais contradictoires, avec des r\u00e8gles d\u2019\u00e9chantillonnage qu\u2019il d\u00e9termine selon le p\u00e9rim\u00e8tre fonctionnel et les r\u00e8gles d\u2019\u00e9chantillonnage qui avaient \u00e9t\u00e9 choisies dans le p\u00e9rim\u00e8tre (COMM1.2.1). Des r\u00e8gles de r\u00e9sultats acceptables sont \u00e9galement d\u00e9finies afin d\u2019\u00e9viter les taux d\u2019\u00e9checs trop importants. Le taux de r\u00e9sultats acceptable est a minima de 75%. S\u2019assure \u00e9galement que les actions correctives sont bien men\u00e9es et qu\u2019elles permettent un bon fonctionnement. | Pour les deux niveaux mentionn\u00e9s ci-dessus : Le taux de r\u00e9sultats acceptable est a minima de 75% sur chacun des indicateurs que l\u2019agent de commissionnement a d\u00e9fini.",notation:"Non atteint : 0 point | V\u00e9rification des essais fonctionnels : 3 points | R\u00e9alisation d\u2019essais contradictoires : 5 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs d\u2019essais fonctionnels avec p\u00e9rim\u00e8tres.</td><td>Sans objet</td></tr><tr><td><strong>Phase Conception</strong></td><td>Contrat et cahier des charges.</td><td>Sans objet</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Niveau 1 :<br>\u2022 Fiches op\u00e9ratoires de MAP (Mise Au Point)<br>\u2022 R\u00e9sultats des essais<br>\u2022 Registre des probl\u00e8mes.<br>Niveau 2 :<br>\u2022 Mission de l\u2019agent de commissionnement<br>\u2022 R\u00e9sultats des essais contradictoires<br>\u2022 Registre des probl\u00e8mes</td><td>Sans objet</td></tr></table>"},
"COMM2.2.9":{attendu:"R\u00e9ception des travaux et r\u00e9serves.",non_applicabilite:"Dans le cas o\u00f9 l\u2019op\u00e9ration est en programme, ou en conception, ou en exploitation axe B\u00e2timent, cette exigence est non applicable.",definition:"L\u2019agent de commissionnement participe \u00e0 la r\u00e9ception des travaux. Celle-ci se d\u00e9roule selon les conditions et crit\u00e8res d\u2019acceptation d\u00e9finis en amont avec le maitre d\u2019ouvrage. Il veille \u00e0 la consignation pr\u00e9cise des r\u00e9serves. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement.",notation:"Non applicable | Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>PV de r\u00e9ception sign\u00e9 et d\u00e9tail des r\u00e9serves ; Registre des probl\u00e8mes.</td><td>Sans objet</td></tr><tr><td><strong>Autres phases</strong></td><td>Non concern\u00e9es.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.10":{attendu:"Sensibilisation, information, formation. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre classique, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"Sensibilisation des occupants (ou futurs occupants) et r\u00e9daction d\u2019un guide d\u2019usage. | Premier niveau : Sensibilisation et guide d\u2019usage. Une ou des actions de sensibilisation des occupants/utilisateurs sont men\u00e9es, afin qu\u2019ils soient inform\u00e9s des enjeux du projet et de la fa\u00e7on dont ils ont \u00e9t\u00e9 trait\u00e9s (par exemple : confort d\u2019\u00e9t\u00e9, QAI, \u00e9conomies d\u2019\u00e9nergie, etc.) afin que leur comportement et leur utilisation des syst\u00e8mes favorisent les strat\u00e9gies et solutions techniques mises en \u0153uvre et ne les contrarient pas. Un guide d\u2019usage pour les occupants est \u00e9labor\u00e9 et diffus\u00e9. Pour les b\u00e2timents neufs ou r\u00e9nov\u00e9s, ce guide d\u2019usage s\u2019adresse aux futurs usagers. Si le guide d\u2019usage est r\u00e9dig\u00e9 par un autre acteur de l\u2019op\u00e9ration, l\u2019agent de commissionnement l\u2019enrichit et le compl\u00e8te si n\u00e9cessaire par rapport au p\u00e9rim\u00e8tre fonctionnel choisi. Une pr\u00e9sentation physique des \u00e9l\u00e9ments techniques du b\u00e2timent est r\u00e9alis\u00e9e pour les occupants/utilisateurs. Cela concerne a minima les \u00e9l\u00e9ments inclus dans le p\u00e9rim\u00e8tre fonctionnel choisi. Note : Si des travaux preneurs sont pr\u00e9vus, cette pr\u00e9sentation est r\u00e9alis\u00e9e apr\u00e8s ceux-ci, pour celles qui concernent les acteurs concern\u00e9s par les parties privatives. Elle est donc au besoin renouvel\u00e9e apr\u00e8s l\u2019arriv\u00e9e de chaque preneur. | Deuxi\u00e8me niveau : Suivi d\u2019appropriation. En compl\u00e9ment du niveau pr\u00e9c\u00e9dent : Un suivi d\u2019appropriation par les occupants/utilisateurs du guide d\u2019usage et du fonctionnement des \u00e9l\u00e9ments du p\u00e9rim\u00e8tre est mis en place sur a minima une ann\u00e9e apr\u00e8s la livraison du b\u00e2timent (b\u00e2timent neuf ou r\u00e9nov\u00e9s) ou a minima une ann\u00e9e apr\u00e8s la fin de la mission de l\u2019agent de commissionnement (b\u00e2timent existant). Exemples de dispositions minimales : enqu\u00eate aupr\u00e8s des occupants/utilisateurs, ateliers de retours d\u2019exp\u00e9rience avec les occupants/utilisateurs, analyse des r\u00e9sultats et actions en cons\u00e9quence.",notation:"Non atteint : 0 point | Sensibilisation et guide d\u2019usage : 1 point | Suivi d\u2019appropriation : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme (pour les deux niveaux)</strong></td><td>Objectifs en termes de sensibilisation, information, formation, suivi d\u2019appropriation.</td><td>Sans objet</td></tr><tr><td><strong>Phase Conception (pour les deux niveaux)</strong></td><td>D\u00e9finition des missions de r\u00e9daction du guide d\u2019usage, des sensibilisations, information, formation, suivi d\u2019appropriation<br>D\u00e9finition des cahiers des charges de sensibilisation, information, formation, suivi d\u2019appropriation.</td><td>Sans objet</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Niveau 1 :<br>\u2022 Supports de sensibilisation et guide d\u2019usage annex\u00e9 au DOE<br>\u2022 CR de r\u00e9union et feuille de pr\u00e9sence \u00e0 la pr\u00e9sentation<br>Niveau 2 : D\u00e9finition de la mission future d\u2019appropriation</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Niveau 1 :<br>\u2022 Supports de sensibilisation et guide d\u2019usage annex\u00e9 au DOE<br>\u2022 CR de r\u00e9union et feuille de pr\u00e9sence \u00e0 la pr\u00e9sentation.<br>Niveau 2 :<br>\u2022 Mission de l\u2019agent de commissionnement incluant cette phase.<br>\u2022 R\u00e9sultats de l\u2019enqu\u00eate, analyse et actions en cons\u00e9quence.<br>\u2022 Guide d\u2019usage annex\u00e9 au DOE</td><td>Sans objet</td></tr></table>"},
"COMM2.2.11":{attendu:"Transfert des informations, formation de l\u2019exploitant.",non_applicabilite:"Cette exigence est non-applicable en exploitation axe B\u00e2timent.",definition:"Il s\u2019agit ici de s\u2019assurer du bon transfert des informations et de la bonne compr\u00e9hension de l\u2019exploitant. | Premier niveau : Transfert d\u2019information. Transfert des informations : Selon les p\u00e9rim\u00e8tres fonctionnels et temporels choisis, l\u2019agent de commissionnement, recommissionnement ou r\u00e9trocommissionnement : Assure a minima une r\u00e9union de transfert avec le propri\u00e9taire/gestionnaire, son personnel et les intervenants. Transmet les documents list\u00e9s en COMM2.2.12. | Deuxi\u00e8me niveau : D\u00e9finition de la (des) formation(s) de l\u2019exploitant. Formation : L\u2019agent de commissionnement v\u00e9rifie que les formations n\u00e9cessaires \u00e0 l\u2019exploitant, et/ou aux futurs intervenants et au personnel du demandeur sont bien d\u00e9finies et r\u00e9alis\u00e9es, afin que chacun maitrise bien les aspects techniques et organisationnels de sa mission et des interfaces avec les autres acteurs. Ces formations - ainsi que les qualifications et comp\u00e9tences des formateurs - doivent \u00eatre coh\u00e9rentes avec les objectifs du commissionnement, ses p\u00e9rim\u00e8tres, et le contexte du b\u00e2timent et de son management. Cette(ces) formation(s) met(tent) en \u00e9vidence des points de vigilance et des recommandations. Notes : Si une GTB est pr\u00e9sente, et pour les b\u00e2timents qui y sont soumis, la formation relative \u00e0 celle-ci r\u00e9pond en France aux exigences (fonctionnement et modalit\u00e9s de param\u00e9trage) du \u00ab D\u00e9cret BACS \u00bb. Si des travaux preneurs sont pr\u00e9vus, ces formations sont r\u00e9alis\u00e9es apr\u00e8s ceux-ci, pour celles qui concernent les acteurs concern\u00e9s par les parties privatives. | Troisi\u00e8me niveau : V\u00e9rification / r\u00e9alisation de la (des) formation(s) et dispositions prises. L\u2019agent de commissionnement v\u00e9rifie que les formations ont bien \u00e9t\u00e9 assimil\u00e9es par leurs destinataires et qu\u2019aucune information ne leur manque, et si besoin prend des dispositions pertinentes. Exemple de dispositions pertinentes : L\u2019agent de commissionnement assure lui-m\u00eame un compl\u00e9ment de formation, et/ou demande des formations compl\u00e9mentaires, et/ou il demande de nouvelles sessions de formation aux entreprises, etc.",notation:"Non applicable | Non atteint : 0 point | Transfert d\u2019information : 2 points | D\u00e9finition de la (des) formation(s) de l\u2019exploitant : 3 points | V\u00e9rification / r\u00e9alisation de la (des) formation(s) et dispositions prises : 5 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme (pour les trois niveaux)</strong></td><td>Objectifs en termes de transfert d\u2019information et de formation de l\u2019exploitant.</td><td>Sans objet</td></tr><tr><td><strong>Phase Conception (pour les trois niveaux)</strong></td><td>D\u00e9finition de la mission de l\u2019agent de commissionnement en termes de transfert d\u2019information et de formation de l\u2019exploitant.</td><td>Sans objet</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Niveau 1 :<br>\u2022 CR de r\u00e9union<br>\u2022 Documents remis et annex\u00e9s au DOE.<br>Niveaux 2 et 3 : Supports de formation (annex\u00e9s au DOE) et feuille d\u2019\u00e9margement.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.12":{attendu:"Fourniture des documents : DOE, DIUO, DUEM, Manuel des Syst\u00e8mes. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Elle peut \u00eatre r\u00e9alis\u00e9e, en construction/r\u00e9novation, dans le cadre d\u2019une mission de ma\u00eetrise d\u2019\u0153uvre AOR, ou d\u2019une mission d\u2019AMO environnement. Elle peut aussi \u00eatre r\u00e9alis\u00e9e par l\u2019exploitant du b\u00e2timent en exploitation.",definition:"Il s\u2019agit ici de s\u2019assurer que les documents n\u00e9cessaires \u00e0 une bonne exploitation sont bien transmis (ou pr\u00e9sents sur l\u2019op\u00e9ration pour les b\u00e2timents existants). | Premier niveau : DOE, DIUO, DUEM. Fourniture ou pr\u00e9sence des documents : DOE*, DIUO*, DUEM*, par les acteurs concern\u00e9s, et avec prise en compte des remarques de l\u2019agent de commissionnement afin qu\u2019ils soient clairs, complets, \u00e0 jour et exploitables. * Rappel des acronymes : DOE : Dossier des Ouvrages Ex\u00e9cut\u00e9s. DIUO : Dossier des Interventions Ult\u00e9rieures sur l\u2019Ouvrage. DUEM : Dossier d\u2019Utilisation, d\u2019Exploitation et de Maintenance. En construction/r\u00e9novation : il s\u2019agit de fournir les documents. En exploitation : il s\u2019agit de s\u2019assurer de la pr\u00e9sence des documents. | Deuxi\u00e8me niveau : Manuel des syst\u00e8mes. Constitution ou pr\u00e9sence du Manuel des syst\u00e8mes, y compris la GTB si le b\u00e2timent en est \u00e9quip\u00e9. Le Manuel des syst\u00e8mes tient compte des remarques de l\u2019agent de commissionnement. Notes : Le Manuel des syst\u00e8mes synth\u00e9tise les informations n\u00e9cessaires \u00e0 la bonne exploitation du b\u00e2timent, qui peuvent \u00eatre contenues dans les autres documents : DOE, DUEM, manuels d\u2019installations, notice de maintenance, logiciel des automates, liste des adressages IP, mot de passe utilisateurs, tables d\u2019\u00e9changes\u2026 etc.) Le Manuel des syst\u00e8mes est r\u00e9dig\u00e9 par l\u2019agent de commissionnement, sauf mention contraire dans le DCE.",notation:"Non atteint : 0 point | Documents : DOE, DIUO, DUEM : 1 point | Manuel des syst\u00e8mes : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme (pour les deux niveaux)</strong></td><td>Objectifs de diffusion des documents (qui, quand).</td><td>Sans objet</td></tr><tr><td><strong>Phase Conception (pour les deux niveaux)</strong></td><td>Int\u00e9gration dans la mission des acteurs concern\u00e9s de la demande de fourniture des documents.</td><td>Sans objet</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Niveau 1 : DOE, DIUO, DUEM avec remarques de l\u2019agent de commissionnement prises en compte<br>Niveaux 2 et 3 : Manuel des Syst\u00e8mes.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.13":{attendu:"Tests saisonniers (hiver, \u00e9t\u00e9, et mi-saison), et actions correctives si n\u00e9cessaire.",non_applicabilite:"Dans le cas o\u00f9 l\u2019op\u00e9ration a choisi le p\u00e9rim\u00e8tre temporel de base, cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",definition:"Des tests dits saisonniers sont r\u00e9alis\u00e9s tout au long des 18 premiers mois (en construction ou r\u00e9novation), ou pendant l\u2019exploitation pour les b\u00e2timents existants en axe B\u00e2timent, de fa\u00e7on \u00e0 observer le fonctionnement des syst\u00e8mes dans diff\u00e9rentes configurations, notamment : p\u00e9riodes \u00e0 forte charge, en chauffage et en refroidissement, p\u00e9riodes \u00e0 charge faible ou variable o\u00f9 \u00e0 la fois les syst\u00e8mes de chaud et de froid peuvent \u00eatre sollicit\u00e9s (mi-saison), fonctionnement optimal selon la programmation de l\u2019occupation du b\u00e2timent, selon l\u2019asservissement \u00e0 l\u2019occupation ou d\u2019autres logiques de contr\u00f4le/commande, fonctionnement des cascades et commutations de syst\u00e8mes \u00e0 base d\u2019\u00e9nergies multiples, des d\u00e9lestages pour effacement de pointe, suivi de l\u2019autoconsommation ou du renvoi sur le r\u00e9seau des \u00e9nergies produites sur le site, \u00e9tude des pannes et des al\u00e9as, etc. | Ces tests sont \u00e0 adapter \u00e0 la complexit\u00e9 des syst\u00e8mes et aux exigences de fonctionnement c\u00f4t\u00e9 utilisateurs. Ils doivent inclure aussi : Des r\u00e8gles d\u2019\u00e9chantillonnage et des indicateurs d\u2019acceptation (minimum 75% d\u2019acceptation sur chaque indicateur choisi par l\u2019agent de commissionnement, idem exigence COMM2.2.8). Une identification des anomalies, correction et v\u00e9rification. La formalisation des r\u00e9sultats des tests, conclusions et recommandations. | Rappel : Les 18 premiers mois d\u2019exploitation d\u00e9butent lorsqu\u2019a minima 20% des surfaces (hors parties communes du b\u00e2timent) sont occup\u00e9es. Durant cette p\u00e9riode, des tests peuvent \u00eatre n\u00e9cessaires avec des sc\u00e9narios distincts d\u2019occupation des locaux afin de prendre en compte la r\u00e9alit\u00e9 de fonctionnement du b\u00e2timent. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Le ma\u00eetre d\u2019\u0153uvre (si sa mission AOR va jusqu\u2019\u00e0 18 mois), et/ou l\u2019AMO, et/ou l\u2019exploitant du b\u00e2timent peuvent r\u00e9aliser cette exigence (si elle est vis\u00e9e).",notation:"Non applicable | Non atteint : 0 point | Atteint : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs de r\u00e9alisation des tests.</td><td>Sans objet</td></tr><tr><td><strong>Phase Conception</strong></td><td>Int\u00e9gration des tests d\u00e9finis dans la mission des acteurs concern\u00e9s.</td><td>Sans objet</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Int\u00e9gration des tests d\u00e9finis dans la mission des acteurs concern\u00e9s, ou \u00e0 d\u00e9faut preuve qu\u2019un contrat sera pass\u00e9.<br>R\u00e9sultats des tests saisonniers.</td><td>Sans objet</td></tr></table>"},
"COMM2.2.14":{attendu:"Rapport final de commissionnement \u00e0 l\u2019issue de la mission. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. Si le ma\u00eetre d\u2019\u0153uvre, l\u2019AMO ou l\u2019exploitant ont \u00e9t\u00e9 d\u00e9sign\u00e9s, ils peuvent r\u00e9diger ce rapport, si cette exigence est vis\u00e9e.",definition:"L\u2019agent de commissionnement, \u00e0 l\u2019issue de sa mission li\u00e9e aux p\u00e9rim\u00e8tres fonctionnel et temporel choisis, r\u00e9dige un rapport final, tirant parti des rapports d\u2019avancement r\u00e9dig\u00e9s \u00e0 chaque phase. En effet, le rapport de commissionnement est un document \u00e9volutif qui se pr\u00e9cise au fur et \u00e0 mesure de l\u2019avancement du projet. Rappel : Pour les b\u00e2timents existants en exploitation axe B\u00e2timent, il s\u2019agit d\u2019un rapport de recommissionnement ou de r\u00e9trocommissionnement. | Premier niveau : Rapport de commissionnement. En particulier ce rapport inclut (en fonction des exigences retenues) le rappel des objectifs, la synth\u00e8se de chaque \u00e9tape de l\u2019op\u00e9ration, les tests et leurs r\u00e9sultats, le programme de formation, des recommandations de bonnes pratiques. Il est compl\u00e9t\u00e9 par des annexes techniques si n\u00e9cessaire. Ce rapport inclut une synth\u00e8se des apports principaux du commissionnement, en termes techniques. Il peut \u00e9galement inclure (non obligatoire) une \u00e9valuation des apports principaux en termes financiers. L\u2019agent de commissionnement v\u00e9rifie ainsi que tout est bien en place, sur les plans technique et organisationnel, pour chaque partie prenante (propri\u00e9taire gestionnaire et surtout exploitant), notamment sur les points suivants : contrats, documents techniques et autres (plans d\u2019actions pour l\u2019exploitation, plan pr\u00e9visionnel d\u2019entretien et de maintenance, manuel des syst\u00e8mes, etc.), moyens de mesure et de suivi, documents de reporting, planification, proc\u00e9dures, personnes responsables, etc., et qu\u2019il n\u2019y a plus de probl\u00e8me qui ne soit pas r\u00e9solu ou pris en charge. Ces \u00e9l\u00e9ments sont pr\u00e9sent\u00e9s au demandeur (ma\u00eetre d\u2019ouvrage par exemple), et pris en compte par les acteurs en charge de la future exploitation du b\u00e2timent. | Deuxi\u00e8me niveau : Rapport de commissionnement et Plan de recommissionnement. Sur la base des enseignements de la mission de commissionnement, de l\u2019instrumentation/supervision mise en place, et selon les sp\u00e9cificit\u00e9s du b\u00e2timent, de ses syst\u00e8mes, de son mode futur d\u2019occupation, des \u00e9ventuels points de vigilance, l\u2019agent de commissionnement r\u00e9dige les grandes lignes d\u2019un plan de recommissionnement (ou r\u00e9tro commissionnement) destin\u00e9 aux acteurs qui seront en charge de l\u2019exploitation du b\u00e2timent. Note : Dans le cas des b\u00e2timents existants en exploitation axe B\u00e2timent, il s\u2019agit d\u2019un plan pour un recommissionnement ou r\u00e9trocommissionnement futur.",notation:"Non atteint : 0 point | Rapport de commissionnement : 3 points | Rapport de commissionnement et Plan de recommissionnement : 5 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectif de r\u00e9daction d\u2019un rapport de commissionnement.</td><td>Sans objet</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Niveau 1 :<br>\u2022 Rapport de commissionnement avec prise en compte des avis<br>\u2022 CR de pr\u00e9sentation<br>Niveau 2 : Plan de recommissionnement</td><td>Niveau 1 : V\u00e9rifier que le rapport final tire bien parti des rapports d\u2019avancement r\u00e9dig\u00e9s \u00e0 chaque phase.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Niveau 1 : Idem phases Conception et R\u00e9alisation.<br>Niveau 2 : Plan de recommissionnement, r\u00e9trocommissionnement</td><td>Sans objet</td></tr></table>"},
"COMM2.2.15":{attendu:"R\u00e9glages / optimisation des performances.",non_applicabilite:"Dans le cas o\u00f9 l\u2019op\u00e9ration est en Construction ou en R\u00e9novation, cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",definition:"Les mesures de correction retenues (lors de l\u2019\u00e9tat des lieux du b\u00e2timent existant, ou pr\u00e9vues dans le plan de commissionnement initial pour les b\u00e2timents neufs et r\u00e9nov\u00e9s) sont mises en place, et le fonctionnement suivi a minima pendant 18 mois pour les b\u00e2timents neufs ou r\u00e9nov\u00e9s, et sur la dur\u00e9e du p\u00e9rim\u00e8tre temporel pour les b\u00e2timents en exploitation. | Pour un b\u00e2timent en exploitation qui initie un recommissionnement ou un r\u00e9trocommissionnement, ceci peut entrainer quelques travaux ou l\u2019installation de composants (dont le temps de retour sur investissement ne d\u00e9passe pas 2 ans si possible). | Les r\u00e9sultats et performances associ\u00e9es sont v\u00e9rifi\u00e9s, les ajustements n\u00e9cessaires sont r\u00e9alis\u00e9s. | Le fonctionnement du b\u00e2timent et de ses \u00e9quipements est adapt\u00e9/ajust\u00e9 \u00e0 son usage r\u00e9el. | Un rapport est r\u00e9dig\u00e9 par l\u2019agent de commissionnement, \u00e0 approuver par le demandeur. | Rappel : Les 18 mois d\u00e9butent lorsqu\u2019a minima 20% des surfaces (hors parties communes du b\u00e2timent) sont occup\u00e9es. | Rappel : il n\u2019est pas n\u00e9cessaire de mettre en place une mission sp\u00e9cifique de commissionnement pour cette exigence. L\u2019exploitant du b\u00e2timent peut la r\u00e9aliser.",notation:"Non applicable | Non atteint : 0 point | Atteint : 5 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs d\u2019un plan de r\u00e9glage / optimisation des performances</td><td>Sans objet</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>D\u00e9finition des missions de r\u00e9glage / optimisation des performances.</td><td>Sans objet</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Int\u00e9gration des tests d\u00e9finis dans la mission des acteurs concern\u00e9s, ou \u00e0 d\u00e9faut preuve qu\u2019un contrat sera pass\u00e9.<br>Plan de suivi de r\u00e9glages.</td><td>Sans objet</td></tr></table>"}
,
"ADAP1":{intro:"D\u00e9finition, classification et organisation des espaces",context:"Ce sous-th\u00e8me \u00e9value la d\u00e9finition des dur\u00e9es de vie du b\u00e2timent et des zones \u00e0 adaptation fr\u00e9quente, ainsi que la classification des espaces et l\u2019organisation des espaces structurants pour faciliter les adaptations futures."},
"ADAP1.1":{intro:"D\u00e9finition et classification des espaces",context:"Ce bloc couvre la d\u00e9finition des dur\u00e9es de vie du b\u00e2timent et des zones \u00e0 adaptation fr\u00e9quente, ainsi que la classification des espaces en zones \u00e0 adaptation fr\u00e9quente / occasionnelle / n\u2019ayant pas vocation \u00e0 \u00eatre adapt\u00e9es. | Cas de non-applicabilit\u00e9 : L\u2019op\u00e9ration est en exploitation axe Gestion seul, ou l\u2019op\u00e9ration n\u2019a pas de besoins d\u2019adaptation occasionnelle, ou de zone ayant vocation \u00e0 \u00eatre adapt\u00e9e de par son usage. Dans ces cas, les points des exigences ADAP1.1.1 et ADAP1.1.2 ne sont pas pris en compte."},
"ADAP1.1.1":{attendu:"D\u00e9finir la dur\u00e9e de vie pr\u00e9visionnelle de l\u2019ouvrage et la dur\u00e9e de vie \u00ab courte \u00bb des zones \u00e0 adaptation fr\u00e9quente, conform\u00e9ment \u00e0 la norme ISO 15686.",definition:"Le ma\u00eetre d\u2019ouvrage doit d\u00e9terminer : | La dur\u00e9e de vie pr\u00e9visionnelle pour l\u2019ouvrage (dur\u00e9e de vie totale pour laquelle le Ma\u00eetre d\u2019Ouvrage pr\u00e9voit de construire). Pour les b\u00e2timents existants, il s\u2019agit de la dur\u00e9e de vie pour laquelle le b\u00e2timent reste exploitable. | La dur\u00e9e de vie \u00ab courte \u00bb des zones \u00e0 adaptation fr\u00e9quente repr\u00e9sente l\u2019intervalle de dur\u00e9e de vie permettant une r\u00e9flexion sur l\u2019adaptation des locaux en fonction des usages et des besoins fonctionnels. Elle peut se r\u00e9p\u00e9ter plusieurs fois sur la dur\u00e9e de vie pr\u00e9visionnelle. Les solutions techniques et architecturales choisies doivent \u00eatre en ad\u00e9quation avec cette dur\u00e9e de vie courte, notamment pour les syst\u00e8mes techniques et les lots architecturaux de second \u0153uvre.",reglementation:"Norme ISO 15686",non_applicabilite:"L\u2019op\u00e9ration est en exploitation axe Gestion seul. | L\u2019op\u00e9ration n\u2019a pas de besoins d\u2019adaptation occasionnelle, ou de zone ayant vocation \u00e0 \u00eatre adapt\u00e9e de par son usage. | Dans ces cas, les points des exigences ADAP1.1.1 et ADAP1.1.2 ne sont pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre sur le d\u00e9coupage possible des espaces.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Document d\u00e9crivant les adaptations possibles, visite in situ (en r\u00e9alisation).</td><td></td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Document d\u00e9finissant la dur\u00e9e de vie pour laquelle le b\u00e2timent reste exploitable (Dur\u00e9e de validit\u00e9 du mode de preuve : Illimit\u00e9e tant que le b\u00e2timent n\u2019a pas \u00e9t\u00e9 modifi\u00e9 par rapport aux hypoth\u00e8ses de la preuve). Visite in situ.</td><td>Dur\u00e9e de vie pr\u00e9visionnelle du b\u00e2timent avec le d\u00e9tail des adaptations possibles.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td></td></tr></table>"},
"ADAP1.1.2":{attendu:"Classer les espaces en zones \u00e0 adaptation fr\u00e9quente / occasionnelle / n\u2019ayant pas vocation \u00e0 \u00eatre adapt\u00e9es.",definition:"Il s\u2019agit de classer les locaux en zones selon l\u2019adaptation attendue. Cette adaptation se comprend en termes de fr\u00e9quence et d\u2019ampleur : zones \u00e0 adaptation fr\u00e9quente / occasionnelle / n\u2019ayant pas vocation \u00e0 \u00eatre adapt\u00e9es. | Exemple de zones pour un b\u00e2timent de bureau : Zone \u00e0 adaptation fr\u00e9quente : Les plateaux de bureau, les circulations horizontales int\u00e9gr\u00e9es aux espaces de bureaux. Zone \u00e0 adaptation occasionnelle : Les zones de restauration, les circulations horizontales non int\u00e9gr\u00e9es aux espaces de bureaux. Zones n\u2019ayant pas vocation \u00e0 \u00eatre adapt\u00e9es : Les sanitaires, les circulations verticales, etc. | Exemple de zones pour un b\u00e2timent de commerce : Zone \u00e0 adaptation fr\u00e9quente : Cellules commerciales. Zone \u00e0 adaptation occasionnelle : Les zones de restauration, les circulations horizontales non int\u00e9gr\u00e9es aux espaces de commerce. Zones n\u2019ayant pas vocation \u00e0 \u00eatre adapt\u00e9es : Les sanitaires, les circulations verticales, etc.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation axe Gestion seul. | L\u2019op\u00e9ration n\u2019a pas de besoins d\u2019adaptation occasionnelle, ou de zone ayant vocation \u00e0 \u00eatre adapt\u00e9e de par son usage. | Dans ces cas, les points des exigences ADAP1.1.1 et ADAP1.1.2 ne sont pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre sur la classification des espaces et les dispositions prises.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Document d\u00e9crivant la classification des diff\u00e9rentes zones du b\u00e2timent avec d\u00e9tail des adaptations possibles.</td><td>Classification des espaces.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Document d\u00e9crivant la classification des diff\u00e9rentes zones du b\u00e2timent avec d\u00e9tail des adaptations possibles, visite in situ.</td><td>Classification des espaces et coh\u00e9rence lors de la visite in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Document pr\u00e9cisant et justifiant la classification des diff\u00e9rents espaces du projet selon leur niveau d\u2019adaptabilit\u00e9 (Dur\u00e9e de validit\u00e9 du mode de preuve : 1 an). Visite in situ.</td><td>Classification des espaces et coh\u00e9rence lors de la visite in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP1.2":{intro:"Organisation des espaces structurants",context:"Ce bloc \u00e9value les dispositions prises sur les locaux structurants du b\u00e2timent : divisibilit\u00e9 du b\u00e2timent en unit\u00e9s divisibles potentielles."},
"ADAP1.2.1":{attendu:"Assurer la divisibilit\u00e9 du b\u00e2timent en unit\u00e9s divisibles potentielles par l\u2019implantation des dessertes verticales.",definition:"Il s\u2019agit de s\u2019assurer que l\u2019implantation des dessertes verticales permet une adaptabilit\u00e9 la plus fine possible. Les surfaces (SDP) mentionn\u00e9es concernent la surface du b\u00e2timent accessible par une circulation verticale (escalier, ascenseur ou noyau d\u2019ascenseur). | Ces surfaces maximales permettent de diviser le b\u00e2timent en \u00ab unit\u00e9s divisibles potentielles \u00bb. | D\u00e9finition de \u00ab Unit\u00e9 divisible potentielle \u00bb : Une unit\u00e9 divisible potentielle est une surface du b\u00e2timent pouvant fonctionner de fa\u00e7on autonome. Par exemple pour un b\u00e2timent de bureau : Les espaces de bureaux + leurs dessertes verticales + leurs issues de secours + leurs sanitaires. | L\u2019exigence est atteinte si l\u2019implantation des sanitaires, dessertes verticales, et issues de secours permet de diviser le b\u00e2timent en surfaces maximales (m\u00b2 SDP) selon le secteur d\u2019activit\u00e9. | Remarques : Si le b\u00e2timent est en RdC le crit\u00e8re de desserte verticale n\u2019est pas \u00e0 prendre en compte. Les autres crit\u00e8res (surfaces, sanitaires, issues de secours) restent valables. | Il n\u2019est pas n\u00e9cessaire que chaque unit\u00e9 divisible potentielle dispose de sa propre sortie de secours, mais seulement qu\u2019elle dispose d\u2019une sortie de secours, conform\u00e9ment \u00e0 la r\u00e9glementation. | Rappel de la d\u00e9finition de la surface de plancher (SDP) : \u00ab La surface de plancher (SDP) est \u00e9gale \u00e0 la somme des surfaces de plancher de chaque niveau clos et couvert, calcul\u00e9e \u00e0 partir du nu int\u00e9rieur des fa\u00e7ades apr\u00e8s d\u00e9duction des \u00e9paisseurs des murs, portes et fen\u00eatres, des vides et tr\u00e9mies, des surfaces de hauteur de plafond inf\u00e9rieure \u00e0 1m80, des aires de stationnement, des zones non am\u00e9nageables et des locaux techniques. \u00bb | A l\u2019international, cette surface peut \u00eatre remplac\u00e9e par la surface utilis\u00e9e localement se rapprochant le plus de la d\u00e9finition ci-dessus.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation axe B\u00e2timent ou Gestion. | En construction neuve ou r\u00e9novation, cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. Dans ces cas, les points de l\u2019exigence ADAP1.2.1 ne sont pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre sur le d\u00e9coupage possible des espaces.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plan d\u2019architecture et note de calcul justifiant les surfaces.</td><td>Coh\u00e9rence entre les plans et le calcul.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, et mise \u00e0 jour de la note de calcul justifiant les surfaces si le projet a \u00e9t\u00e9 modifi\u00e9.</td><td>Coh\u00e9rence entre les plans et le calcul et visite in situ des possibilit\u00e9s de partition et de l\u2019emplacement des locaux.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2":{intro:"Dispositions facilitant les adaptations dans un m\u00eame volume b\u00e2ti",context:"Ce sous-th\u00e8me \u00e9value les dispositions facilitant l\u2019adaptabilit\u00e9 du b\u00e2timent pour un m\u00eame usage (principes structurels, locaux et syst\u00e8mes techniques, second \u0153uvre) et les dispositions facilitant la transformabilit\u00e9, la r\u00e9versibilit\u00e9 et la d\u00e9montabilit\u00e9 (diagnostic, \u00e9tude, circulations, r\u00e9versibilit\u00e9, structure, enveloppe, locaux et r\u00e9seaux, am\u00e9nagements int\u00e9rieurs, ind\u00e9pendance des 4 couches, d\u00e9montabilit\u00e9)."},
"ADAP2.1.1":{attendu:"Prendre des dispositions structurelles facilitant les adaptations futures du b\u00e2timent pour un m\u00eame usage.",definition:"En construction et r\u00e9novation : Des dispositions satisfaisantes doivent \u00eatre prises sur la structure pour permettre de recloisonner, de percer les planchers, ou de faciliter le cheminement horizontal des r\u00e9seaux techniques afin d\u2019adapter les locaux aux \u00e9ventuelles \u00e9volutions de besoins. | En exploitation, axe B\u00e2timent : Il s\u2019agit d\u2019avoir une r\u00e9flexion globale et de rendre compte des dispositions (structure, r\u00e9seaux, etc.) permettant de donner de l\u2019adaptabilit\u00e9 \u00e0 l\u2019ouvrage par le biais de solutions architecturales et techniques de gros \u0153uvre. | Les lots potentiellement concern\u00e9s sont : Fondations et infrastructure, Superstructure - Ma\u00e7onnerie, Couverture \u2013 Etanch\u00e9it\u00e9 - Charpente - Zinguerie, Fa\u00e7ades et menuiseries ext\u00e9rieures.",reglementation:"JRC (Joint Research Center de l\u2019UE) 2015 : \u00ab Nouvelles r\u00e8gles techniques europ\u00e9ennes pour l\u2019\u00e9valuation et la modernisation des structures existantes \u00bb. | Norme ISO 2394 \u00ab Principes g\u00e9n\u00e9raux de la fiabilit\u00e9 des constructions \u00bb de 2015.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation axe Gestion seul. | L\u2019op\u00e9ration est en r\u00e9novation, avec impossibilit\u00e9 d\u2019agir sur les \u00e9l\u00e9ments demand\u00e9s (exemple : b\u00e2timent class\u00e9), ou du fait que la r\u00e9novation ne concerne pas ces \u00e9l\u00e9ments. | Attention : si la correspondance taxinomie est vis\u00e9e en r\u00e9novation, cette exigence est applicable et doit \u00eatre atteinte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans de structure.</td><td rowspan=\"3\">V\u00e9rification de la coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, calepin de surcharge des planchers, note de calcul de descente de charge.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE, ou tout autre document permettant de faire \u00e9tat des principes structurels, r\u00e9seaux, installations techniques ; photos (Dur\u00e9e de validit\u00e9 du mode de preuve : Illimit\u00e9e tant que le b\u00e2timent n\u2019a pas \u00e9t\u00e9 modifi\u00e9 par rapport aux hypoth\u00e8ses de la preuve).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.1.2":{attendu:"Mettre en \u0153uvre des dispositions sur les locaux et syst\u00e8mes techniques (CVC, CFO-CFA, eau) facilitant les adaptations futures.",definition:"Des dispositions satisfaisantes organisationnelles et de dimensionnement doivent \u00eatre prises sur les syst\u00e8mes techniques. Les lots concern\u00e9s sont : CVC (Chauffage \u2013 Ventilation \u2013 Refroidissement - eau chaude sanitaire), Installations sanitaires, R\u00e9seaux d\u2019\u00e9nergie (courant fort), R\u00e9seaux de communication (courant faible), \u00c9quipement de production locale d\u2019\u00e9lectricit\u00e9. | Dispositions pouvant \u00eatre prises : Surdimensionnement des locaux techniques, R\u00e9seaux (CVC, CFO-CFA, eau) sectorisables et \u00e9volutifs, Surdimensionnement des r\u00e9seaux CFO, CFA (VDI), Eau, Surdimensionnement des r\u00e9seaux CVC. | En France, compl\u00e9ment sur les produits \u00e9quipements mat\u00e9riaux (PEM) disposant d\u2019une \u00e9valuation environnementale de la circularit\u00e9 comme Ecoscale ou tout autre \u00e9quivalent. | D\u00e9finition : Produit d\u00e9montable : \u00e0 l\u2019\u00e9chelle du produit mais \u00e9galement de son incorporation dans l\u2019ouvrage. Un produit est dit \u00ab d\u00e9montable \u00bb s\u2019il peut \u00eatre d\u00e9mont\u00e9 sans endommagement afin de faciliter son r\u00e9emploi ou son recyclage. | Tous les PEM identifi\u00e9s comme d\u00e9montables permettront de faciliter la v\u00e9rification de cette exigence.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation axe Gestion seul. | L\u2019op\u00e9ration est en r\u00e9novation, avec impossibilit\u00e9 d\u2019agir sur les \u00e9l\u00e9ments demand\u00e9s, ou du fait que la r\u00e9novation ne concerne pas ces \u00e9l\u00e9ments. | Dans ces cas, les points ne sont pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans, plans techniques.</td><td>V\u00e9rification de l\u2019identification des zones r\u00e9serv\u00e9es \u00e0 l\u2019ajout de nouveaux \u00e9quipements pour les locaux techniques ; Description des objectifs de sectorisation et de surdimensionnement des r\u00e9seaux.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td rowspan=\"2\">V\u00e9rification de l\u2019identification des zones r\u00e9serv\u00e9es \u00e0 l\u2019ajout de nouveaux \u00e9quipements pour les locaux techniques ; Identification/visite in situ des dispositions prises pour la sectorisation et le surdimensionnement des r\u00e9seaux.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE ou tout autre document permettant de faire \u00e9tat des dispositions prises, visite in situ, photos (dur\u00e9e de validit\u00e9 du mode de preuve : illimit\u00e9e tant que le b\u00e2timent n\u2019a pas \u00e9t\u00e9 modifi\u00e9 par rapport aux hypoth\u00e8ses de la preuve). (V\u00e9rification des zones r\u00e9serv\u00e9es \u00e0 l\u2019ajout de nouveaux \u00e9quipements pour les locaux techniques ; Identification/visite in situ des dispositions prises pour la sectorisation et le surdimensionnement des r\u00e9seaux).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.1.3":{attendu:"Mettre en \u0153uvre des dispositions sur le second \u0153uvre facilitant les adaptations futures.",definition:"Des dispositions satisfaisantes doivent \u00eatre prises sur le second \u0153uvre pour permettre d\u2019adapter ces zones aux \u00e9ventuelles \u00e9volutions de besoins. Les lots concern\u00e9s sont : Cloisonnement - Doublage - Plafonds suspendus - Menuiseries int\u00e9rieures, Rev\u00eatements des sols, murs et plafonds - Chape. | Normes : EN 15643-3, EN16309, ISO 20887:2020. | Il convient de d\u00e9montrer que les choix de syst\u00e8mes de second \u0153uvre (lots architecturaux, cloisonnement, plafonds, distribution) permettent une adaptabilit\u00e9 dans le temps des espaces au-del\u00e0 de leur simple organisation ou de leur simple surdimensionnement. | En France, compl\u00e9ment sur les PEM disposant d\u2019une \u00e9valuation environnementale de la circularit\u00e9 comme Ecoscale ou tout autre \u00e9quivalent. | D\u00e9finition : Produit d\u00e9montable : \u00e0 l\u2019\u00e9chelle du produit mais \u00e9galement de son incorporation dans l\u2019ouvrage. Un produit est dit \u00ab d\u00e9montable \u00bb s\u2019il peut \u00eatre d\u00e9mont\u00e9 sans endommagement afin de faciliter son r\u00e9emploi ou son recyclage. Tous les PEM identifi\u00e9s comme d\u00e9montables permettront de faciliter la v\u00e9rification de cette exigence.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation axe Gestion seul. | L\u2019op\u00e9ration est en r\u00e9novation, avec impossibilit\u00e9 d\u2019agir sur les \u00e9l\u00e9ments demand\u00e9s, ou du fait que la r\u00e9novation ne concerne pas ces \u00e9l\u00e9ments. | Dans ces cas, les points ne sont pas pris en compte. | Attention : si la correspondance taxinomie est vis\u00e9e en r\u00e9novation, cette exigence est applicable et doit \u00eatre atteinte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, note de calcul justifiant du pourcentage atteint.</td><td>V\u00e9rification de la pr\u00e9sence d\u2019une description du syst\u00e8me de cloisons modulaires, fiches techniques du syst\u00e8me de cloisons, des r\u00e9seaux.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, fiches techniques des r\u00e9seaux et du syst\u00e8me de cloisons, visite in situ, photos, mise \u00e0 jour de la note de calcul justifiant du pourcentage atteint si le projet a \u00e9t\u00e9 modifi\u00e9.</td><td rowspan=\"2\">V\u00e9rification des caract\u00e9ristiques de modularit\u00e9 des r\u00e9seaux, et des cloisons pos\u00e9es et constat in situ des typologies de cloisons pos\u00e9es.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE ou tout autre document permettant de faire \u00e9tat des dispositions prises, photos, visite in situ, note de calcul justifiant du pourcentage atteint pour les cloisons (dur\u00e9e de validit\u00e9 du mode de preuve : Illimit\u00e9e tant que le b\u00e2timent n\u2019a pas \u00e9t\u00e9 modifi\u00e9 par rapport aux hypoth\u00e8ses de la preuve).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2":{intro:"Dispositions facilitant la transformabilit\u00e9, la r\u00e9versibilit\u00e9 et la d\u00e9montabilit\u00e9",context:"Ce bloc \u00e9value les dispositions prises pour faciliter le changement d\u2019usage du b\u00e2timent (transformabilit\u00e9), la r\u00e9versibilit\u00e9 des espaces, et la d\u00e9montabilit\u00e9 en fin de vie. | Cas de non-applicabilit\u00e9 du sous-th\u00e8me ADAP2.2 : les non-applicabilit\u00e9 passent \u00e0 chaque exigence ADAP2.2.x. Non-applicabilit\u00e9 potentielle en exploitation axe Gestion seul et non plus obligatoire. Possibilit\u00e9 de non-applicabilit\u00e9 ajout\u00e9e en r\u00e9novation en cas d\u2019impossibilit\u00e9 d\u2019appliquer les exigences. Attention : si la correspondance taxinomie est vis\u00e9e en r\u00e9novation, ce bloc d\u2019exigences est applicable."},
"ADAP2.2.1":{attendu:"R\u00e9aliser un diagnostic de transformabilit\u00e9 (changement d\u2019usage) du b\u00e2timent.",definition:"Un diagnostic des besoins potentiels de transformabilit\u00e9 du b\u00e2timent vers d\u2019autres usages que ceux du programme initial (ou de l\u2019usage du b\u00e2timent existant) est men\u00e9. Ce diagnostic d\u00e9bouche sur un sc\u00e9nario de transformabilit\u00e9 du b\u00e2timent. | Ce sc\u00e9nario se base sur : Le contexte socio-urbain et administratif de l\u2019op\u00e9ration, montrant les usages futurs qui seraient pertinents et probables dans la zone d\u2019implantation du b\u00e2timent. | Les possibilit\u00e9s techniques de r\u00e9aliser une transformabilit\u00e9 du b\u00e2timent vers un autre usage, en fonction notamment des trames, hauteurs, volumes. | Remarque : La transformabilit\u00e9 est la possibilit\u00e9 donn\u00e9e, quand elle est pertinente, \u00e0 un b\u00e2timent de pouvoir changer ais\u00e9ment d\u2019usage par l\u2019anticipation lors de la conception. La r\u00e9versibilit\u00e9 permet de changer de programme \u00e0 court, moyen ou long terme.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion), cette exigence est non applicable. | En r\u00e9novation, cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable si le demandeur n\u2019a pas la possibilit\u00e9 d\u2019agir sur les \u00e9l\u00e9ments demand\u00e9s, ou du fait que la r\u00e9novation ne concerne pas ces \u00e9l\u00e9ments. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme, Conception et R\u00e9alisation</strong></td><td>Diagnostic de transformabilit\u00e9, \u00e9l\u00e9ments de contexte socio-urbain. Sc\u00e9nario retenu. Ces \u00e9l\u00e9ments sont si n\u00e9cessaire mis \u00e0 jour \u00e0 chaque phase.</td><td>Justification des usages potentiels en fonction du contexte socio-urbain.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.2":{attendu:"R\u00e9aliser une \u00e9tude de la transformabilit\u00e9 (changement d\u2019usage) du b\u00e2timent.",definition:"Une \u00e9tude de la transformabilit\u00e9 (changement d\u2019usage) du b\u00e2timent est demand\u00e9e, bas\u00e9e sur les r\u00e9sultats du diagnostic et du sc\u00e9nario issus de l\u2019exigence pr\u00e9c\u00e9dente. | Il s\u2019agit de d\u00e9terminer les solutions possibles \u00e0 mettre en place pour rendre possible cette transformabilit\u00e9. L\u2019exigence est atteinte si les dispositions \u00e0 prendre sont list\u00e9es dans une \u00e9tude de faisabilit\u00e9 (technique et \u00e9conomique). | D\u00e9finitions : ERP : Les \u00e9tablissements recevant du public. ICPE : Installations Class\u00e9es pour l\u2019Environnement.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion), cette exigence est non applicable. | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou document identifiant les transformabilit\u00e9s possibles (si ces \u00e9l\u00e9ments ne figurent pas d\u00e9j\u00e0 dans le diagnostic).</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>\u00c9tude de faisabilit\u00e9 de la transformabilit\u00e9 avec a minima : plans proc\u00e9d\u00e9s constructifs (structure, fa\u00e7ade) et notices de d\u00e9montabilit\u00e9, principes fonctionnels, plans sch\u00e9matiques des r\u00e9seaux techniques, description globale des syst\u00e8mes, principes des am\u00e9nagements int\u00e9rieurs, faisabilit\u00e9 \u00e9conomique.</td><td>Les modes de preuves devront permettre de v\u00e9rifier la prise en compte des dispositions architecturales, urbaines, structurelles, de stabilit\u00e9 au feu, d\u2019isolement acoustique et de dimensionnement des dispositions incendie relatives \u00e0 la transformabilit\u00e9.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.3":{attendu:"Mener une r\u00e9flexion sur le positionnement des circulations horizontales afin de faciliter les futurs changements d\u2019usages.",definition:"Une r\u00e9flexion est men\u00e9e sur le positionnement des circulations horizontales : Circulations \u00e0 l\u2019int\u00e9rieur, au c\u0153ur du b\u00e2timent en noyau central. Circulations report\u00e9es en bordure ou \u00e0 l\u2019ext\u00e9rieur du b\u00e2timent. | Cette r\u00e9flexion permet d\u2019indiquer en quoi le positionnement des circulations permet de faciliter un futur changement d\u2019usage du b\u00e2timent.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion), cette exigence est non applicable. | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 et les plans/CCTP.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, plans, visite in situ, photos</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 et les plans/DOE.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.4":{attendu:"Mener une r\u00e9flexion sur la r\u00e9versibilit\u00e9 possible des espaces particuliers (RdC, derniers niveaux, parkings en sous-sol).",definition:"Il convient de montrer que ces espaces peuvent changer d\u2019usage, par exemple possibilit\u00e9 de transformer un parking semi-enterr\u00e9 en espaces \u00e0 occupation autre que passag\u00e8re. Pour cela des dispositions conservatoires doivent \u00eatre d\u00e9montr\u00e9es (exemple : possibilit\u00e9 d\u2019\u00e9clairage naturel suffisant dans les parkings).",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion). | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 et les plans/CCTP.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, plans, visite in situ, photos</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 et les plans/DOE.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.5":{attendu:"Prendre des dispositions sur la structure (Gros \u0152uvre) pour permettre la transformabilit\u00e9 et la r\u00e9versibilit\u00e9 du b\u00e2timent.",definition:"Des dispositions satisfaisantes doivent \u00eatre prises sur la structure pour permettre la transformabilit\u00e9 et la r\u00e9versibilit\u00e9 du b\u00e2timent. Les lots potentiellement concern\u00e9s sont : Fondations et infrastructure, Superstructure - Ma\u00e7onnerie. | Il convient de montrer que la structure choisie permet potentiellement les changements d\u2019usages. | Exemples : Epaisseur du b\u00e2timent suffisante, Hauteur entre niveaux suffisante, Stabilisation de la structure permettant un changement d\u2019usage, Solidit\u00e9 et continuit\u00e9 structurelles y compris des fondations, Trames structurelles permettant le changement d\u2019usage. | R\u00e9f\u00e9rences : ISO 20887:2020, JRC 2015, ISO 2394.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion). | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Attention : si la correspondance taxinomie est vis\u00e9e en r\u00e9novation, cette exigence est applicable et doit \u00eatre atteinte. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans et calculs de structure.</td><td rowspan=\"2\">Coh\u00e9rence des descriptifs, plans et notes de calculs.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, visite in situ, calculs, photos</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.6":{attendu:"Prendre des dispositions sur l\u2019enveloppe pour permettre la transformabilit\u00e9 et la r\u00e9versibilit\u00e9 du b\u00e2timent.",definition:"Des dispositions satisfaisantes doivent \u00eatre prises sur l\u2019enveloppe pour permettre la transformabilit\u00e9 et la r\u00e9versibilit\u00e9 du b\u00e2timent. Les lots potentiellement concern\u00e9s : Couverture \u2013 Etanch\u00e9it\u00e9 - Charpente - Zinguerie, Fa\u00e7ades et menuiseries ext\u00e9rieures. | Exemples : Trames porteuses et ouvertures en fa\u00e7ade permettant une transformabilit\u00e9 des usages, Composants de fa\u00e7ade interchangeables si possible plusieurs fois, Utilisation de panneaux pr\u00e9fabriqu\u00e9s avec structure similaire et de trames r\u00e9p\u00e9titives (module de fa\u00e7ade). | R\u00e9f\u00e9rences : Level(s) indicator 2.2, Level(s) indicator 2.4, ISO 20887:2020.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion). | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies, et constat in situ des dispositions prises.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.7":{attendu:"D\u00e9montrer que les locaux et syst\u00e8mes techniques choisis permettent une transformabilit\u00e9/r\u00e9versibilit\u00e9 du b\u00e2timent.",definition:"Il convient de d\u00e9montrer que les locaux et syst\u00e8mes techniques choisis permettent une transformabilit\u00e9/r\u00e9versibilit\u00e9 du b\u00e2timent. Le caract\u00e8re ais\u00e9ment d\u00e9montable des r\u00e9seaux est donc ici essentiel. | Exemples de dispositions conservatoires : Locaux techniques suffisamment dimensionn\u00e9s, Assemblages et connexions r\u00e9versibles permettant d\u00e9montages et remontages successifs (en s\u00e9curit\u00e9), R\u00e9servations pour gaines et tr\u00e9mies, Facilit\u00e9 d\u2019acc\u00e8s aux composants. | R\u00e9f\u00e9rences : Level(s) indicator 2.2, Level(s) indicator 2.4, ISO 20887:2020. | En France, compl\u00e9ment sur les PEM disposant d\u2019une \u00e9valuation environnementale de la circularit\u00e9 comme Ecoscale. | D\u00e9finition : Produit d\u00e9montable : peut \u00eatre d\u00e9mont\u00e9 sans endommagement afin de faciliter son r\u00e9emploi ou son recyclage. Tous les PEM identifi\u00e9s comme d\u00e9montables permettront de faciliter la v\u00e9rification de cette exigence.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion). | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans, plans techniques.</td><td>Coh\u00e9rence des descriptifs et plans avec l\u2019\u00e9tude de faisabilit\u00e9.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, fiches techniques des syst\u00e8mes + bons de livraison correspondants.</td><td>V\u00e9rification de la coh\u00e9rence des plans et notes de calculs avec l\u2019\u00e9tude de faisabilit\u00e9, et constat in situ des dispositions prises (adaptabilit\u00e9 des locaux et r\u00e9seaux techniques).</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.8":{attendu:"Prendre des dispositions sur les am\u00e9nagements int\u00e9rieurs pour permettre une transformabilit\u00e9/r\u00e9versibilit\u00e9 du b\u00e2timent.",definition:"Il convient de d\u00e9montrer que les choix de syst\u00e8mes de second \u0153uvre (lots architecturaux, cloisonnement, plafonds, distribution) permettent une transformabilit\u00e9/r\u00e9versibilit\u00e9 du b\u00e2timent. Le caract\u00e8re d\u00e9montable des produits est donc ici essentiel. | Exemples de dispositions conservatoires : Utilisation de rev\u00eatements de sols facilement d\u00e9montables, continuit\u00e9 des rev\u00eatements de sols, Syst\u00e8mes de plafonds permettant une adaptabilit\u00e9 des espaces, Tramage pertinent des barri\u00e8res acoustiques, Cloisons d\u00e9posables sans intervention sur les planchers/plafonds, Facilit\u00e9 d\u2019acc\u00e8s aux composants, Assemblages et connexions r\u00e9versibles. | R\u00e9f\u00e9rences : Level(s) indicator 2.2, Level(s) indicator 2.4, ISO 20887:2020. | En France, compl\u00e9ment sur les PEM disposant d\u2019une \u00e9valuation environnementale de la circularit\u00e9 comme Ecoscale. Tous les PEM identifi\u00e9s comme d\u00e9montables permettront de faciliter la v\u00e9rification de cette exigence.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion). | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies, et constat in situ des dispositions prises.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.9":{attendu:"D\u00e9montrer l\u2019ind\u00e9pendance des 4 couches (structure, enveloppe, syst\u00e8mes, am\u00e9nagements int\u00e9rieurs).",definition:"Le but de cette exigence est de valoriser les projets qui permettent de s\u2019assurer que le fait d\u2019agir sur une couche (structure, enveloppe, syst\u00e8mes, am\u00e9nagements int\u00e9rieurs) n\u2019affecte pas les autres couches, en particulier celle qui la supporte, dans une optique de rendre possible la s\u00e9paration des \u00e9l\u00e9ments lors du d\u00e9montage, r\u00e9duire l\u2019impact ou les risques de d\u00e9gradations sur les \u00e9l\u00e9ments adjacents, et dans l\u2019optique de changement d\u2019usage futur. | Exemples : Les fa\u00e7ades rapport\u00e9es sont par d\u00e9finition ind\u00e9pendantes de la structure sur le plan de l\u2019\u00e9volutivit\u00e9, Rev\u00eatement ext\u00e9rieur ind\u00e9pendant des panneaux pr\u00e9fabriqu\u00e9s, Am\u00e9nagements int\u00e9rieurs d\u00e9solidarisables ais\u00e9ment de la structure et de la fa\u00e7ade, R\u00e9seaux techniques d\u00e9montables, Gaines de r\u00e9seaux techniques accessibles et modulables. | R\u00e9f\u00e9rences : Level(s) indicator 2.2, Level(s) indicator 2.4, ISO 20887:2020. | En France, compl\u00e9ment sur les PEM disposant d\u2019une \u00e9valuation environnementale de la circularit\u00e9 comme Ecoscale. Tous les PEM identifi\u00e9s comme d\u00e9montables permettront de faciliter la v\u00e9rification de cette exigence.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion). | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies, et constat in situ des dispositions prises.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP2.2.10":{attendu:"Prendre des dispositions pour la d\u00e9montabilit\u00e9 du b\u00e2timent en fin de vie et une conception plus \u00e9conome en ressources.",definition:"Des dispositions satisfaisantes doivent \u00eatre prises sur l\u2019ensemble du b\u00e2timent pour permettre sa d\u00e9montabilit\u00e9 en fin de vie. Les lots potentiellement concern\u00e9s : La structure (Gros \u0152uvre), L\u2019enveloppe (Fa\u00e7ades et menuiseries ext\u00e9rieures), Les locaux et r\u00e9seaux techniques, Les am\u00e9nagements int\u00e9rieurs. | En r\u00e9f\u00e9rence \u00e0 la norme ISO 20887:2020, les dispositions \u00e0 prendre en compte a minima sont : La facilit\u00e9 d\u2019acc\u00e8s aux composants et aux diff\u00e9rents services, L\u2019ind\u00e9pendance des 4 lots, L\u2019\u00e9vitement des traitements et finitions inutiles, La simplicit\u00e9 et normalisation de montage, La s\u00e9curit\u00e9 du d\u00e9montage, Le soutien des mod\u00e8les commerciaux d\u2019\u00e9conomie circulaire. | D\u00e9finitions : Produit d\u00e9montable, Produit r\u00e9employable, Produit recyclable. | Tous les PEM identifi\u00e9s comme d\u00e9montables, r\u00e9employables et/ou recyclables permettront de faciliter la v\u00e9rification de cette exigence.",non_applicabilite:"L\u2019op\u00e9ration est en exploitation (axes B\u00e2timent et Gestion). | En r\u00e9novation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | Attention : si la correspondance taxinomie est vis\u00e9e en r\u00e9novation, cette exigence est applicable et doit \u00eatre atteinte. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plans de d\u00e9montage/d\u00e9construction y compris informations de s\u00e9quen\u00e7age du d\u00e9montage conform\u00e9ment \u00e0 l\u2019ISO 20887:2020. Cahier de charges.</td><td>Conformit\u00e9 de la conception avec l\u2019ISO 20887:2020.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Inventaire tra\u00e7able des mat\u00e9riaux (incluant le cas \u00e9ch\u00e9ant les informations directement accessibles concernant les fournisseurs, l\u2019identification, les garanties, la dur\u00e9e de vie, la d\u00e9montabilit\u00e9, les codes-barres et/ou les \u00e9tiquettes RFID).</td><td>Coh\u00e9rence entre le cahier de charges et les mat\u00e9riaux utilis\u00e9s pour justifier de la conception \u00e9conome en ressources et de la d\u00e9montabilit\u00e9 en fin de vie.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP3":{intro:"Dispositions facilitant les extensions vers un volume b\u00e2ti plus important",context:"Ce sous-th\u00e8me \u00e9value les dispositions prises sur la structure et les syst\u00e8mes techniques pour permettre des extensions vers un volume b\u00e2ti plus important. | Cas de non-applicabilit\u00e9 du sous-th\u00e8me ADAP3 : Ce sous-th\u00e8me est non applicable en exploitation axes B\u00e2timent et Gestion. Il peut \u00eatre consid\u00e9r\u00e9 comme non-applicable en construction neuve ou r\u00e9novation, sans extensions verticales ou horizontales possibles sur l\u2019op\u00e9ration. Dans ces deux cas, les exigences du pr\u00e9sent sous-th\u00e8me sont consid\u00e9r\u00e9es comme non-applicables et leurs points ne seront alors pas pris en compte dans l\u2019\u00e9valuation."},
"ADAP3.1":{intro:"Dispositions facilitant les extensions vers un volume b\u00e2ti plus important",context:"Ce bloc \u00e9value les dispositions prises sur la structure (descentes de charges et extensions horizontales) et les syst\u00e8mes techniques (lots techniques) pour permettre des extensions."},
"ADAP3.1.1":{attendu:"Prendre des dispositions sur la descente de charges pour une extension verticale et/ou prendre des dispositions pour l\u2019extension horizontale.",definition:"Des dispositions sont prises sur la structure pour permettre des extensions vers un volume b\u00e2ti plus important. Il s\u2019agit de prendre des dispositions sur la descente de charge (toiture, \u00e9l\u00e9ments porteurs, fondations, contreventement), et/ou de prendre des dispositions pour l\u2019extension horizontale. | Les points sont attribu\u00e9s en fonction du pourcentage de descente de charge sup\u00e9rieure possible et des extensions horizontales possibles. | En construction ou r\u00e9novation, cela doit \u00eatre justifi\u00e9 par rapport aux documents locaux d\u2019urbanisme.",non_applicabilite:"Ce sous-th\u00e8me est non applicable en exploitation axes B\u00e2timent et Gestion. | Il peut \u00eatre consid\u00e9r\u00e9 comme non-applicable en construction neuve ou r\u00e9novation, sans extensions verticales ou horizontales possibles sur l\u2019op\u00e9ration.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans de structure, calculs de structure avec marge pour les extensions / charges.</td><td rowspan=\"2\">Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies, identification des marges prises pour les extensions / charges dans le calcul de structure. V\u00e9rifications des seuils de charges / surfaces.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE, calepin de surcharge des planchers, note de calcul de descente de charge avec marges prises pour les extensions / charges.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP3.1.2":{attendu:"Prendre des dispositions sur les syst\u00e8mes (lots techniques) pour permettre de futures extensions.",definition:"Des dispositions satisfaisantes sont prises sur les syst\u00e8mes techniques. La n\u00e9cessit\u00e9 de dimensionnements sup\u00e9rieurs doit \u00eatre justifi\u00e9e : Augmentation de la capacit\u00e9 d\u2019accueil, \u00e9volution du process h\u00e9berg\u00e9, \u00e9volutions du quartier, changement d\u2019usage pr\u00e9vu, etc. | Les lots concern\u00e9s sont : CVC, Installations sanitaires, R\u00e9seaux d\u2019\u00e9nergie (courant fort), R\u00e9seaux de communication (courant faible), Appareils \u00e9l\u00e9vateurs et autres \u00e9quipements de transport int\u00e9rieur, \u00c9quipement de production locale d\u2019\u00e9lectricit\u00e9. | Niveau 1 \u00ab Productions et alimentations \u00bb : Dispositions prises sur les productions et alimentations principales du b\u00e2timent (chauffage, climatisation, ventilation, \u00e9lectricit\u00e9, eau). | Niveau 2 \u00ab Productions, alimentations et distributions \u00bb : Niveau 1 + Dispositions prises sur la distribution des r\u00e9seaux techniques.",non_applicabilite:"Ce sous-th\u00e8me est non applicable en exploitation axes B\u00e2timent et Gestion. | Il peut \u00eatre consid\u00e9r\u00e9 comme non-applicable en construction neuve ou r\u00e9novation, sans extensions verticales ou horizontales possibles sur l\u2019op\u00e9ration.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>Objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans techniques.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td>Coh\u00e9rence entre l\u2019argumentaire d\u00e9velopp\u00e9 pour justifier de l\u2019atteinte de l\u2019objectif et les preuves fournies, et constat in situ des dispositions prises dans les locaux techniques et les r\u00e9seaux.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4":{intro:"Dispositions facilitant l\u2019interop\u00e9rabilit\u00e9 et l\u2019adaptabilit\u00e9 num\u00e9rique",context:"Ce sous-th\u00e8me \u00e9value l\u2019interop\u00e9rabilit\u00e9 (interface de programmation API) et l\u2019adaptabilit\u00e9 num\u00e9rique (R\u00e9seau Smart : p\u00e9rim\u00e8tre, rattachement, redondance, capacit\u00e9 d\u2019extension, parcours de distribution, locaux de r\u00e9partition, redondance des liaisons)."},
"ADAP4.1":{intro:"Interop\u00e9rabilit\u00e9",context:"Ce bloc \u00e9value la capacit\u00e9 du b\u00e2timent \u00e0 communiquer ses donn\u00e9es au travers d\u2019interfaces de programmation (API)."},
"ADAP4.1.1":{attendu:"Disposer d\u2019une ou plusieurs interfaces de programmation (API) pour communiquer les donn\u00e9es du b\u00e2timent.",definition:"Cette exigence \u00e9value la capacit\u00e9 d\u2019un b\u00e2timent \u00e0 communiquer des donn\u00e9es au travers d\u2019une ou plusieurs interfaces de programmation. Les donn\u00e9es doivent correspondre a minima au p\u00e9rim\u00e8tre suivant : T\u00e9l\u00e9m\u00e9trie des fluides (\u00e9lectricit\u00e9, calories, d\u00e9bit d\u2019eau\u2026), R\u00e9gulation centrale du chauffage et de la climatisation (CVC). | Une API (Application Programming Interface) est une interface logicielle qui permet de \u2019connecter\u2019 un logiciel ou un service \u00e0 un autre logiciel ou service afin d\u2019\u00e9changer des donn\u00e9es et des fonctionnalit\u00e9s. | La documentation de l\u2019API doit \u00eatre consultable au format num\u00e9rique \u00e0 l\u2019aide d\u2019un outil informatique (exemple Swagger). | R\u00e9f\u00e9rence : \u00ab Cadre de r\u00e9f\u00e9rence des API du b\u00e2timent \u00bb r\u00e9dig\u00e9 par la Smart Buildings Alliance.",non_applicabilite:"L\u2019exigence est non applicable si l\u2019op\u00e9ration ne dispose pas de T\u00e9l\u00e9m\u00e9trie des fluides ou de R\u00e9gulation centrale du chauffage et de la climatisation (CVC). Et si l\u2019op\u00e9ration n\u2019est pas \u00e9quip\u00e9e d\u2019un Syst\u00e8me de chauffage ou de climatisation, combin\u00e9 ou non avec un syst\u00e8me de ventilation dont la puissance nominale utile est sup\u00e9rieure \u00e0 70kW. | Dans ce cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges qui d\u00e9crit les API des cat\u00e9gories mentionn\u00e9es dans l\u2019exigence.</td><td>Description de(s) API mise(s) en place.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>API document\u00e9es au format num\u00e9rique (accessible avec un logiciel type swagger).</td><td>V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4.2":{intro:"Adaptabilit\u00e9 num\u00e9rique",context:"Ce bloc \u00e9value les dispositions prises pour le R\u00e9seau Smart du b\u00e2timent : p\u00e9rim\u00e8tre, pr\u00e9disposition au rattachement, redondance, capacit\u00e9 d\u2019extension, parcours de distribution des c\u00e2blages, locaux de r\u00e9partition g\u00e9n\u00e9rale, et redondance des liaisons."},
"ADAP4.2.1":{attendu:"D\u00e9finir le p\u00e9rim\u00e8tre du R\u00e9seau Smart du projet et disposer d\u2019un R\u00e9seau Smart utilisant le protocole IP et le standard Ethernet.",definition:"Les b\u00e2timents disposent traditionnellement de plusieurs r\u00e9seaux informatiques (CVC, s\u00fbret\u00e9, bureautique\u2026) qui peuvent \u00eatre physiquement s\u00e9par\u00e9s ou mutualis\u00e9s. L\u2019objectif est de d\u00e9finir le p\u00e9rim\u00e8tre du r\u00e9seau qui fera l\u2019objet de l\u2019\u00e9valuation, ce r\u00e9seau est nomm\u00e9 le \u00ab R\u00e9seau Smart \u00bb. | Le R\u00e9seau Smart est le r\u00e9seau f\u00e9d\u00e9rateur d\u2019un b\u00e2timent orient\u00e9 services (SOA) et utilisant le protocole IP. Il est s\u00e9curis\u00e9 et utilise exclusivement le standard Ethernet sur le r\u00e9seau local et le standard Internet depuis l\u2019ext\u00e9rieur du b\u00e2timent. | Le p\u00e9rim\u00e8tre doit inclure a minima : T\u00e9l\u00e9m\u00e9trie des fluides (\u00e9lectricit\u00e9, calories, d\u00e9bit d\u2019eau\u2026), R\u00e9gulation centrale du chauffage et de la climatisation (CVC).",non_applicabilite:"L\u2019exigence est non applicable si l\u2019op\u00e9ration ne dispose pas de T\u00e9l\u00e9m\u00e9trie des fluides ou de R\u00e9gulation centrale du chauffage et de la climatisation (CVC). Et si l\u2019op\u00e9ration n\u2019est pas \u00e9quip\u00e9e d\u2019un Syst\u00e8me de chauffage ou de climatisation, combin\u00e9 ou non avec un syst\u00e8me de ventilation dont la puissance nominale utile est sup\u00e9rieure \u00e0 70kW. | Dans ce cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges d\u00e9crivant le R\u00e9seau Smart avec son architecture OU synoptique pr\u00e9cisant ces m\u00eames informations. Exemples : CCTP, sch\u00e9ma et descriptif du R\u00e9seau Smart.</td><td>Pr\u00e9sence de ces documents.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dossier technique de r\u00e9colement et fiches techniques d\u00e9montrant la r\u00e9alisation des ouvrages d\u00e9crits dans les exigences.</td><td rowspan=\"2\">V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Rapport d\u2019inspection datant de plus de cinq ans justifiant du maintien en exploitabilit\u00e9 des ouvrages d\u00e9crits dans les exigences.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4.2.2":{attendu:"Pr\u00e9disposer le b\u00e2timent au rattachement \u00e0 tout type de liaison filaire externe.",definition:"Cette exigence vise \u00e0 ce que le b\u00e2timent soit pr\u00e9dispos\u00e9 \u00e0 accueillir les r\u00e9seaux des op\u00e9rateurs, du domaine public jusqu\u2019aux locaux techniques du b\u00e2timent. | Niveau 1 : Capacit\u00e9 de rattachement aux r\u00e9seaux externes et locaux centraux. Le b\u00e2timent doit disposer de : une adduction op\u00e9rateur depuis le domaine public, un cheminement jusqu\u2019au local op\u00e9rateur, un local op\u00e9rateur adapt\u00e9 (4m\u00b2 par baie ou 2m\u00b2 par coffret mural), une gaine verticale d\u00e9di\u00e9e, un cheminement entre local op\u00e9rateur et local de r\u00e9partition g\u00e9n\u00e9rale, un local r\u00e9partiteur g\u00e9n\u00e9ral adapt\u00e9 (4m\u00b2 par baie). | Niveau 2 : Qualit\u00e9 de l\u2019ouvrage. Le local op\u00e9rateur et le local r\u00e9partiteur g\u00e9n\u00e9ral disposent chacun d\u2019une surface de plancher de 8m\u00b2 ou plus avec 2,4 m\u00e8tres de largeur minimum. Les deux types de locaux doivent \u00eatre d\u00e9di\u00e9s \u00e0 leur usage et non mutualis\u00e9s.",non_applicabilite:"L\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable si l\u2019op\u00e9ration est en exploitation axe b\u00e2timent. | Dans les autres cas, elle n\u2019est pas applicable si l\u2019op\u00e9ration dispose d\u2019une surface de plancher (SDP) inf\u00e9rieur \u00e0 1000m\u00b2. | Dans ce cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges et documents requis d\u00e9montrant l\u2019int\u00e9gration dans le dossier de conception des exigences.</td><td>Taille des locaux techniques et rattachement aux r\u00e9seaux externes.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dossier technique de r\u00e9colement et fiches techniques d\u00e9montrant la r\u00e9alisation des ouvrages d\u00e9crits dans les exigences.</td><td rowspan=\"2\">V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Rapport d\u2019inspection datant de plus de cinq ans justifiant du maintien en exploitabilit\u00e9 des ouvrages d\u00e9crits dans les exigences.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4.2.3":{attendu:"Mettre en \u0153uvre une redondance de rattachement du b\u00e2timent aux r\u00e9seaux externes.",definition:"L\u2019objectif est de disposer de mesures conservatoires \u00e0 la mise en \u0153uvre d\u2019une redondance de rattachement du c\u00e2blage du b\u00e2timent du domaine public jusqu\u2019aux locaux op\u00e9rateurs, pour une continuit\u00e9 de services en cas de probl\u00e8me. | Niveau 1 : Cr\u00e9ation d\u2019un second ouvrage VRD distant de 8 m ou plus du premier. | Niveau 2 : Existence d\u2019un second local op\u00e9rateur avec surface correspondant au niveau 1 de ADAP4.2.2. | Niveau 3 : Qualit\u00e9 de l\u2019ouvrage, respect des deux niveaux pr\u00e9c\u00e9dents + l\u2019\u00e9loignement de 8m doit \u00eatre maintenu sur l\u2019ensemble des parcours redondants (compris locaux techniques).",non_applicabilite:"L\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable si l\u2019op\u00e9ration est en exploitation axe b\u00e2timent. | Dans les autres cas, elle n\u2019est pas applicable si l\u2019op\u00e9ration dispose d\u2019une surface de plancher (SDP) inf\u00e9rieur \u00e0 1000m\u00b2. | Dans ce cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges et documents requis d\u00e9montrant l\u2019int\u00e9gration dans le dossier de conception des exigences.</td><td>Taille des locaux techniques et rattachement aux r\u00e9seaux externes.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dossier technique de r\u00e9colement et fiches techniques d\u00e9montrant la r\u00e9alisation des ouvrages d\u00e9crits dans les exigences.</td><td rowspan=\"2\">V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Rapport d\u2019inspection datant de plus de cinq ans justifiant du maintien en exploitabilit\u00e9 des ouvrages d\u00e9crits dans les exigences.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4.2.4":{attendu:"Disposer d\u2019une capacit\u00e9 d\u2019extension pour l\u2019ajout de prises r\u00e9seau sur le R\u00e9seau Smart.",definition:"Cette exigence concerne la capacit\u00e9 d\u2019ajout de prises dans le b\u00e2timent. Elle requiert une capacit\u00e9 d\u2019extension non \u00e9quip\u00e9e de minimum 30% pour l\u2019ajout ult\u00e9rieur de prises r\u00e9seau sur le R\u00e9seau Smart. Cette r\u00e9serve doit porter a minima sur : les cheminements de c\u00e2bles entre le c\u0153ur de r\u00e9seau et les \u00e9quipements actifs d\u2019acc\u00e8s, les contenants recevant les \u00e9quipements actifs d\u2019acc\u00e8s, les arriv\u00e9es d\u00e9di\u00e9es \u00e0 l\u2019alimentation \u00e9lectrique et au traitement climatique des locaux techniques recevant les \u00e9quipements actifs du R\u00e9seau Smart. | L\u2019exigence ne porte pas sur le c\u00e2blage ni sur les \u00e9quipements actifs.",non_applicabilite:"L\u2019exigence est non applicable pour les op\u00e9rations \u00e9valu\u00e9es en phase exploitation axe B\u00e2timent et axe Gestion. | Dans les autres cas, elle n\u2019est pas applicable si ADAP4.2.1 n\u2019est pas applicable. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges d\u00e9montrant l\u2019int\u00e9gration dans le dossier de conception des exigences. Exemples : CCTP du syst\u00e8me de c\u00e2blage, synoptique du c\u00e2blage, plan d\u2019implantation des gaines techniques, fiches techniques des contenants.</td><td>R\u00e9serves sur les cheminements de c\u00e2bles, les contenants recevant les \u00e9quipements actifs d\u2019acc\u00e8s et les arriv\u00e9es d\u00e9di\u00e9es \u00e0 l\u2019alimentation \u00e9lectrique.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Documents d\u2019ex\u00e9cution qui permettent de v\u00e9rifier la capacit\u00e9 d\u2019extension effective.</td><td rowspan=\"2\">V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Rapport d\u2019inspection datant de plus de cinq ans justifiant du maintien en exploitabilit\u00e9 des ouvrages d\u00e9crits dans les exigences.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4.2.5":{attendu:"Disposer de deux parcours de distribution des c\u00e2blages dans le b\u00e2timent.",definition:"Le but est de valoriser la pr\u00e9disposition du b\u00e2timent \u00e0 recevoir un c\u00e2blage redondant. Chaque b\u00e2timent est dot\u00e9 de deux gaines techniques verticales, espac\u00e9es d\u2019au moins 8 m\u00e8tres (ou 2 m\u00e8tres avec un coupe-feu sur toutes les faces sur au moins une gaine). Ces gaines sont \u00e9quip\u00e9es de cheminements d\u00e9di\u00e9s aux liaisons de communication, permettant ainsi de disposer de deux parcours distincts pour distribuer chacun des niveaux du b\u00e2timent \u00e0 partir du ou des locaux de r\u00e9partition g\u00e9n\u00e9rale. | Nota bene : Ces gaines verticales peuvent \u00eatre partag\u00e9es avec d\u2019autres r\u00e9seaux VDI/CFA.",non_applicabilite:"L\u2019exigence peut \u00eatre d\u00e9clar\u00e9 comme non applicable si l\u2019op\u00e9ration est en exploitation axe b\u00e2timent. | Dans les autres cas, elle n\u2019est pas applicable si l\u2019op\u00e9ration dispose d\u2019une surface de plancher (SDP) inf\u00e9rieur \u00e0 1000m\u00b2. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges et documents requis d\u00e9montrant l\u2019int\u00e9gration dans le dossier de conception des exigences.</td><td>Pr\u00e9sence de 2 gaines techniques espac\u00e9es d\u2019au moins 8 m\u00e8tres (ou 2m avec coupe-feu).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dossier technique de r\u00e9colement et fiches techniques. Exemples : CCTP du syst\u00e8me de c\u00e2blage, synoptique du c\u00e2blage, plan d\u2019implantation des gaines techniques.</td><td rowspan=\"2\">V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Rapport d\u2019inspection datant de plus de cinq ans justifiant du maintien en exploitabilit\u00e9 des ouvrages d\u00e9crits dans les exigences.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4.2.6":{attendu:"Disposer de deux locaux ou espaces de r\u00e9partition g\u00e9n\u00e9rale pour assurer la redondance des \u00e9quipements centraux.",definition:"Il est demand\u00e9 la pr\u00e9sence dans le b\u00e2timent d\u2019un second local de r\u00e9partition g\u00e9n\u00e9rale pr\u00e9sentant des caract\u00e9ristiques identiques au premier. Il en est espac\u00e9 du premier d\u2019au moins 8 m\u00e8tres (ou 2 m\u00e8tres avec un coupe-feu). En cas de multiplicit\u00e9 des parcours de distribution des c\u00e2blages (exigence ADAP4.2.5), ils sont dispos\u00e9s sur des verticalit\u00e9s diff\u00e9rentes. Des cheminements de capacit\u00e9 adapt\u00e9e \u00e0 la quantit\u00e9 de c\u00e2bles \u00e0 installer interconnectent ce second local aux cheminements de distribution des c\u00e2bles dans le b\u00e2timent, au 1er local de r\u00e9partition g\u00e9n\u00e9rale, et au(x) local(aux) ou espaces des op\u00e9rateurs. | Nota bene : Le second local de r\u00e9partition g\u00e9n\u00e9rale peut \u00eatre mutualis\u00e9 avec d\u2019autres locaux li\u00e9s au courant faible, \u00e0 l\u2019exception du premier local r\u00e9partiteur g\u00e9n\u00e9ral.",non_applicabilite:"L\u2019exigence peut \u00eatre d\u00e9clar\u00e9 comme non applicable si l\u2019op\u00e9ration est en exploitation axe b\u00e2timent. | Dans les autres cas, elle n\u2019est pas applicable si l\u2019op\u00e9ration dispose d\u2019une surface de plancher (SDP) inf\u00e9rieur \u00e0 1000m\u00b2. | Dans ces cas, les points ne sont alors pas pris en compte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges et documents requis d\u00e9montrant l\u2019int\u00e9gration dans le dossier de conception des exigences.</td><td>Pr\u00e9sence de ces documents.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dossier technique de r\u00e9colement et fiches techniques. Exemples : CCTP du syst\u00e8me de c\u00e2blage, synoptique du c\u00e2blage, plan d\u2019implantation des gaines techniques.</td><td rowspan=\"2\">V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Rapport d\u2019inspection datant de plus de cinq ans justifiant du maintien en exploitabilit\u00e9 des ouvrages d\u00e9crits dans les exigences.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"ADAP4.2.7":{attendu:"Assurer la redondance des liaisons desservant les n\u0153uds de connexion du R\u00e9seau Smart.",definition:"Cette exigence a pour objet de v\u00e9rifier que le R\u00e9seau Smart est fiabilis\u00e9 par une redondance du c\u00e2blage interconnectant les r\u00e9partiteurs g\u00e9n\u00e9raux et les points de sous-r\u00e9partition. | Elle n\u00e9cessite la redondance des liaisons entre les r\u00e9partiteurs g\u00e9n\u00e9raux et les points de sous-r\u00e9partition. En cas de multiplicit\u00e9 des parcours de distribution des c\u00e2blages (exigence ADAP4.2.5), les liaisons doivent \u00eatre r\u00e9parties dans les diff\u00e9rents parcours.",non_applicabilite:"L\u2019exigence est non applicable si ADAP4.2.1 n\u2019est pas applicable. | Dans ce cas, les points seront d\u00e9duits du total disponible.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Extrait de cahier des charges et documents requis d\u00e9montrant l\u2019int\u00e9gration dans le dossier de conception des exigences.</td><td>Pr\u00e9sence de ces documents.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dossier technique de r\u00e9colement et fiches techniques. Exemples : CCTP du syst\u00e8me de c\u00e2blage, synoptique du c\u00e2blage, plan d\u2019implantation des gaines techniques.</td><td rowspan=\"2\">V\u00e9rification in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Rapport d\u2019inspection datant de plus de cinq ans justifiant du maintien en exploitabilit\u00e9 des ouvrages d\u00e9crits dans les exigences.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},"CHAN1":{intro:"Organisation du chantier",context:"La pr\u00e9paration et le suivi du chantier constituent des \u00e9l\u00e9ments majeurs pour limiter l\u2019impact environnemental du projet en phase de r\u00e9alisation. Cela consiste \u00e0 : r\u00e9diger une charte de chantier pr\u00e9cisant l\u2019ensemble des engagements environnementaux et de s\u00e9curit\u00e9 ; sensibiliser et former les entreprises aux enjeux environnementaux ; organiser le suivi de la charte du chantier ; d\u00e9finir les responsabilit\u00e9s de chacun. Ces actions permettent de mettre en place une vraie d\u00e9marche environnementale : r\u00e9duction \u00e0 la source des d\u00e9chets, limitation des nuisances et des pollutions, ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau, respect de la biodiversit\u00e9, communication et relations avec les riverains."},"CHAN1.1":{intro:"Engagement et d\u00e9finition des responsabilit\u00e9s des entreprises",context:"Un document d\u2019engagement est r\u00e9dig\u00e9 par la ma\u00eetrise d\u2019ouvrage en phase de conception ou programme pour fixer les obligations aux entreprises en mati\u00e8re de gestion environnementale du chantier. Ce document reprend les points essentiels de la charte de chantier (exigence CHAN1.2.1) et demande \u00e0 chaque entreprise d\u2019identifier un r\u00e9f\u00e9rent environnement et un responsable environnement par phase du chantier."},"CHAN1.1.1":{attendu:"La ma\u00eetrise d\u2019ouvrage r\u00e9dige un document d\u2019engagement \u00e0 destination des entreprises en lien contractuel direct et de leurs sous-traitants de rang 1. Ce document reprend l\u2019ensemble des points de la charte chantier r\u00e9dig\u00e9e en suivant l\u2019exigence CHAN1.2.1, et demande \u00e0 chaque entreprise de d\u00e9signer un r\u00e9f\u00e9rent environnement et un responsable environnement par phase du chantier.",definition:"Le document d\u2019engagement doit \u00eatre diffus\u00e9 \u00e0 toutes les entreprises en lien contractuel direct avec le ma\u00eettre d\u2019ouvrage et leurs sous-traitants de rang 1. En cas de modification de la charte chantier, il doit \u00eatre r\u00e9vis\u00e9 et rediffus\u00e9. | La d\u00e9signation des r\u00e9f\u00e9rents environnement pour chaque entreprise et du responsable environnement doit \u00eatre d\u00e9finie par \u00e9crit. | R\u00f4les : le r\u00e9f\u00e9rent environnement collecte les informations environnementales et sensibilise les ouvriers. Le responsable environnement assure le contr\u00f4le des engagements communs et tient \u00e0 jour l\u2019ensemble des documents n\u00e9cessaires sur le chantier.",non_applicabilite:"Si l\u2019op\u00e9ration est en exploitation axe B\u00e2timent, les exigences CHAN1.1 sont non applicables.",important:"Cette exigence doit obligatoirement \u00eatre atteinte.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou engagement \u00e0 produire une charte de chantier</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Document d\u2019engagement dat\u00e9 et sign\u00e9 par la ma\u00eetrise d\u2019ouvrage ; Preuve de la diffusion de cet engagement aux entreprises ; D\u00e9signation des r\u00e9f\u00e9rents environnement</td><td>Contenu, date et signature du document d\u2019engagement ; Diffusion du document d\u2019engagement ; D\u00e9signation pour chaque phase des r\u00e9f\u00e9rents environnement.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9e</td><td>Sans objet.</td></tr></table>"},"CHAN1.1.2":{attendu:"Un d\u00e9lai de pr\u00e9paration de chantier est fix\u00e9 contractuellement, en pr\u00e9cisant s\u2019il est compris ou non dans le d\u00e9lai d\u2019ex\u00e9cution.",definition:"La planification de cette \u00e9tape est \u00e9tablie afin de tirer au mieux parti de ce d\u00e9lai et d\u2019anticiper les r\u00e9ponses aux exigences environnementales du chantier. | Ce d\u00e9lai est \u00e0 appr\u00e9cier selon le contexte du projet : en g\u00e9n\u00e9ral de 1 \u00e0 3 mois selon sa complexit\u00e9 et le jeu de contraintes.",non_applicabilite:"Si l\u2019op\u00e9ration est en exploitation axe B\u00e2timent, les exigences CHAN1.1 sont non applicables.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Contrat mentionnant le d\u00e9lai de pr\u00e9paration de chantier ; Document de planification du chantier</td><td>Contrat mentionnant le d\u00e9lai et pr\u00e9cisant s\u2019il est compris ou non dans le d\u00e9lai d\u2019ex\u00e9cution ; Planification de la pr\u00e9paration de chantier ; Pertinence du d\u00e9lai choisi.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9e</td><td>Sans objet.</td></tr></table>"},"CHAN1.2":{intro:"Pilotage et surveillance du chantier",context:"Le suivi r\u00e9gulier de l\u2019application de la charte du chantier et la mise en \u0153uvre de mesures correctives si besoin garantissent que les engagements environnementaux sont respect\u00e9s tout au long des travaux. Ce suivi concerne tous les domaines environnementaux : gestion des d\u00e9chets, limitation des nuisances et pollutions, ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau."},"CHAN1.2.1":{attendu:"Pour le premier niveau (Charte chantier sans SOGED) : une charte chantier est r\u00e9dig\u00e9e au cours de la phase conception, incluant la gestion des d\u00e9chets, la limitation des nuisances et des pollutions, le suivi et la ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau. Elle est incluse dans le DCE. | Pour le deuxi\u00e8me niveau (Charte chantier avec SOGED) : un SOGED est r\u00e9alis\u00e9 et int\u00e9gr\u00e9 au plan d\u2019installation de chantier.",definition:"La charte contient : rappel des obligations r\u00e9glementaires, gestion des d\u00e9chets, nuisances, protection de l\u2019environnement, sant\u00e9 et s\u00e9curit\u00e9 des compagnons, modalit\u00e9s d\u2019application. | S\u2019il y a des locaux livr\u00e9s \u00ab en blanc \u00bb, une charte d\u00e9di\u00e9e aux preneurs doit \u00eatre r\u00e9dig\u00e9e. | Le SOGED d\u00e9crit l\u2019organisation technique de la gestion des d\u00e9chets (responsable \u00ab d\u00e9chets \u00bb, sensibilisation personnel, modalit\u00e9s de collecte, degr\u00e9 de d\u00e9tail du tri, logistique, tra\u00e7abilit\u00e9, fili\u00e8res de valorisation ou d\u2019\u00e9limination).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou engagement \u00e0 produire une charte de chantier</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Dispositions pr\u00e9paratoires prises (notamment sur la gestion des d\u00e9chets) ; Charte chantier ; Inclusion dans le DCE et les documents de march\u00e9 ; Charte chantier \u00ab preneurs \u00bb (si concern\u00e9) ; Plan d\u2019installation de chantier ; SOGED ou plan de gestion des d\u00e9chets de chantier (si concern\u00e9)</td><td>Points \u00e0 inclure a minima dans la charte chantier ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Points \u00e0 inclure a minima dans la charte chantier \u00ab preneurs \u00bb (si concern\u00e9) ; Contenu du SOGED (si concern\u00e9) ; Int\u00e9gration du SOGED au plan d\u2019installation de chantier (si concern\u00e9) ; Communication du SOGED \u00e0 tous les intervenants du chantier (si concern\u00e9).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises (notamment sur la gestion des d\u00e9chets) ; + \u00e9l\u00e9ments identiques aux items cit\u00e9s en phase Conception.</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier ; Points \u00e0 inclure a minima dans la charte chantier.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Charte chantier pr\u00e9visionnelle ; Dispositions pr\u00e9paratoires prises notamment sur : la gestion des d\u00e9chets, le plan d\u2019installation de chantier, SOGED (si concern\u00e9), int\u00e9gration du SOGED, communication du SOGED</td><td>Points \u00e0 inclure a minima dans la charte chantier ; Points \u00e0 inclure a minima dans la charte chantier \u00ab preneurs \u00bb (voir le SMR) (si concern\u00e9).</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent (Gestion)</strong></td><td>Non concern\u00e9e</td><td>Sans objet.</td></tr></table>"},"CHAN1.2.2":{attendu:"Pour le premier niveau (Ma\u00eetrise du suivi de chantier) : le suivi du chantier et le respect des exigences de la charte, y compris les mesures correctives si besoin, sont assur\u00e9s r\u00e9guli\u00e8rement (fr\u00e9quence > 1 mois). | Pour le deuxi\u00e8me niveau (Optimisation du suivi de chantier) : le suivi et le respect des exigences de la charte sont assur\u00e9s en continu (fr\u00e9quence \u2264 1 mois).",definition:"Le suivi couvre : la gestion des d\u00e9chets de chantier et leur valorisation, la limitation des nuisances et de la pollution, la ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau, la sant\u00e9 et la s\u00e9curit\u00e9 des compagnons.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en Exploitation axe B\u00e2timent, cette exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigence CHAN1.2.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Documents attestant du suivi et du respect de la charte chantier (ex : comptes rendus de r\u00e9unions de chantier, plan d\u2019installation de chantier, rapport mensuel de suivi des d\u00e9chets de chantier, Borderaux de Suivi des D\u00e9chets, planning des op\u00e9rations bruyantes, suivi des r\u00e9clamations...)</td><td>Documents attestant du suivi et du respect de la charte chantier.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN1.3":{intro:"Formation et sensibilisation des entreprises",context:"La sensibilisation et la formation des entreprises aux enjeux environnementaux et aux dispositions de la charte de chantier constituent un \u00e9l\u00e9ment cl\u00e9 pour assurer l\u2019engagement de tous les acteurs du chantier dans une d\u00e9marche environnementale."},"CHAN1.3.1":{attendu:"Les entreprises sont sensibilis\u00e9es et form\u00e9es (si besoin) au respect des exigences environnementales de la charte chantier.",definition:"Les contenus sont adapt\u00e9s selon la nature des travaux. Une attention particuli\u00e8re est port\u00e9e aux entreprises des \u00ab corps d\u2019\u00e9tat secondaires \u00bb. | La formation / sensibilisation suit de pr\u00e8s l\u2019arriv\u00e9e des entreprises, et est renouvel\u00e9e en cours de chantier si n\u00e9cessaire (interventions longues, changements d\u2019\u00e9quipes, etc.). | Cette exigence s\u2019applique pour les entreprises en lien contractuel direct avec le ma\u00eettre d\u2019ouvrage mais aussi pour leurs sous-traitants de rang 1.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en Exploitation axe B\u00e2timent, cette exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigence CHAN1.2.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Supports de formation ; Feuille d\u2019\u00e9margement ; Tableau de suivi des formations / sensibilisations</td><td>Planning des formations et sensibilisation des entreprises ; Contenu des formations et sensibilisation ; Documents attestant la r\u00e9alisation de ces formations / sensibilisations.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN2":{intro:"Gestion des d\u00e9chets de chantier",context:"La r\u00e9duction \u00e0 la source et l\u2019optimisation de la collecte, du tri et de la valorisation des d\u00e9chets de chantier permettent de limiter l\u2019impact environnemental des travaux. Cela passe par une organisation technique rigoureuse (SOGED) et des techniques constructives optimis\u00e9es."},"CHAN2.1":{intro:"R\u00e9duction \u00e0 la source des d\u00e9chets de chantier",context:"L\u2019optimisation des syst\u00e8mes constructifs et l\u2019adoption de dispositions techniques et organisationnelles permettent de r\u00e9duire consid\u00e9rablement la production de d\u00e9chets sur le chantier."},"CHAN2.1.1":{attendu:"Prendre des dispositions techniques et/ou organisationnelles et des dispositions sur les techniques constructives pour r\u00e9duire \u00e0 la source la production de d\u00e9chets de chantier.",definition:"Cat\u00e9gorie 1 \u00ab Dispositions techniques et/ou organisationnelles \u00bb : pr\u00e9parer le chantier, mettre en place des proc\u00e9dures et des plans de r\u00e9servation, utiliser des outils formels, d\u00e9velopper la coordination modulaire. Exemples : plans de r\u00e9servation pour \u00e9viter les repiquages, optimiser les conditionnements, sensibiliser les compagnons, g\u00e9n\u00e9raliser les coffrages m\u00e9talliques, ferraillage optimis\u00e9, dispositions contractuelles pour limiter les emballages. | Cat\u00e9gorie 2 \u00ab Dispositions prises sur les techniques constructives \u00bb : privil\u00e9gier la fabrication hors site, optimiser les syst\u00e8mes constructifs avec composants pr\u00e9fabriqu\u00e9s, recourir au calepinage, remplacer le polystyr\u00e8ne par des solutions limitant les d\u00e9chets.",attention:"Les techniques mises en place d\u00e9coulent des dispositions pr\u00e9vues dans le SOGED.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou engagement \u00e0 produire une charte de chantier</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Charte chantier \u00e0 destination de l\u2019entreprise sp\u00e9cifiant les dispositions \u00e0 prendre pour r\u00e9duire \u00e0 la source la production de d\u00e9chets de chantier ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Charte chantier \u00ab preneurs \u00bb (si concern\u00e9) ; Estimation de la r\u00e9duction de la masse de d\u00e9chets g\u00e9n\u00e9r\u00e9s par la mise en \u0153uvre de mode de construction sp\u00e9cifique ; Dispositions pr\u00e9paratoires prises pour r\u00e9duire \u00e0 la source les d\u00e9chets de chantier</td><td>Contenu de la charte chantier ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Contenu de la charte chantier \u00ab preneurs \u00bb ; Note de calcul.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour r\u00e9duire \u00e0 la source les d\u00e9chets de chantier et enregistrements associ\u00e9s (contrats fournisseurs, d\u00e9tails des plans de r\u00e9servation, pr\u00e9sentation des modes de construction, r\u00e9duction de la masse totale de d\u00e9chets g\u00e9n\u00e9r\u00e9s) ; Note de calcul</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier ; Note de calcul.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Charte chantier pr\u00e9visionnelle ; Dispositions pr\u00e9paratoires prises notamment sur la r\u00e9duction des d\u00e9chets \u00e0 la source et la mise en \u0153uvre de mode de construction ou de sp\u00e9cificit\u00e9s GER</td><td>Points \u00e0 inclure a minima dans la charte chantier ; Points \u00e0 inclure a minima dans la charte chantier \u00ab preneurs \u00bb (voir le SMR) (si concern\u00e9).</td></tr><tr><td><strong>Phase Exploitation Gestion</strong></td><td>Non concern\u00e9e</td><td>Sans objet.</td></tr></table>"},"CHAN2.2":{intro:"Optimisation de la collecte, du tri et du regroupement des d\u00e9chets de chantier",context:"Une s\u00e9paration rigoureuse des diff\u00e9rentes familles de d\u00e9chets et une valorisation optimale en aval du chantier constituent des objectifs majeurs de la gestion environnementale."},"CHAN2.2.1":{attendu:"Prendre des dispositions simples afin de faciliter le respect de la r\u00e9glementation en mati\u00e8re d\u2019\u00e9limination des d\u00e9chets en aval du chantier.",definition:"Identifier les d\u00e9chets produits par les travaux et les classer par familles : d\u00e9chets inertes (fractions min\u00e9rales), DIB (papier, m\u00e9tal, plastique, verre, bois, pl\u00e2tre, textiles), emballages, d\u00e9chets dangereux, d\u00e9chets \u00e9lectriques, etc. | Assurer une s\u00e9paration physique des d\u00e9chets conform\u00e9ment \u00e0 la r\u00e9glementation, notamment ne pas m\u00e9langer les d\u00e9chets dangereux et les emballages avec les autres typologies. | En site occup\u00e9 (exploitation axe B\u00e2timent lors de travaux de r\u00e9novation) : optimiser les flux de d\u00e9chets et la s\u00e9curit\u00e9 li\u00e9e aux flux, \u00e9tudier la logistique pour le stockage et l\u2019\u00e9vacuation fr\u00e9quente, minimiser les nuisances pour les occupants.",non_applicabilite:"S\u2019il n\u2019existe pas de sch\u00e9ma d\u2019organisation et de gestion des d\u00e9chets (SOGED) au sens de l\u2019exigence CHAN1.2.1 et si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, l\u2019exigence est non applicable.",attention:"Dans le cas d\u2019un tri hors site, l\u2019extrapolation des donn\u00e9es de la plateforme sera admise comme mode de preuve. | Une signalisation claire des bennes par le biais de pictogrammes ou de logotypes lorsque le tri est r\u00e9alis\u00e9 sur le chantier.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou engagement \u00e0 produire une charte de chantier</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Charte chantier \u00e0 destination de l\u2019entreprise sp\u00e9cifiant les dispositions \u00e0 prendre pour optimiser la collecte, le tri et le regroupement des d\u00e9chets de chantier ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Charte chantier \u00ab preneurs \u00bb (si concern\u00e9) ; Dispositions pr\u00e9paratoires prises</td><td>Contenu de la charte chantier ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Contenu de la charte chantier \u00ab preneurs \u00bb.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour optimiser la collecte, le tri et le regroupement des d\u00e9chets de chantier et enregistrements associ\u00e9s (comptes rendus, plan d\u2019installation, rapport mensuel, Borderaux de Suivi des D\u00e9chets, extrapolation des donn\u00e9es de la plateforme de tri, planning, suivi des r\u00e9clamations...) ; Plan d\u2019installation de chantier visualisant les zones de tri des d\u00e9chets ou photographies</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Charte chantier pr\u00e9visionnelle ; Dispositions pr\u00e9paratoires prises sur la collecte, le tri et le regroupement des d\u00e9chets de chantier</td><td>Points \u00e0 inclure a minima dans la charte chantier ; Points \u00e0 inclure a minima dans la charte chantier \u00ab preneurs \u00bb (voir le SMR) (si concern\u00e9).</td></tr><tr><td><strong>Phase Exploitation Gestion</strong></td><td>Non concern\u00e9e</td><td>Sans objet.</td></tr></table>"},"CHAN2.2.2":{attendu:"Si l\u2019op\u00e9ration dispose d\u2019un SOGED au sens de l\u2019exigence CHAN1.2.1, alors il est demand\u00e9 de s\u2019assurer de son suivi et de son respect de fa\u00e7on r\u00e9guli\u00e8re afin d\u2019optimiser les conditions de collecte et de tri des d\u00e9chets pour favoriser au maximum une valorisation en aval.",non_applicabilite:"S\u2019il n\u2019existe pas de sch\u00e9ma d\u2019organisation et de gestion des d\u00e9chets (SOGED) au sens de l\u2019exigence CHAN1.2.1 ou si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, l\u2019exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigence CHAN1.2.1 en cas de pr\u00e9sence d\u2019un SOGED</td><td>Sans objet.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>SOGED ; Int\u00e9gration du SOGED au plan d\u2019installation de chantier ; Documents attestant du suivi du et du respect du SOGED (rapport mensuel de suivi de chantier, plan d\u2019installation de chantier visualisant les zones de tri des d\u00e9chets ou photographies, preuve de la reprise des d\u00e9chets par le fournisseur ou entreprise, Borderaux de Suivi des D\u00e9chets)</td><td>Contenu du SOGED ; Enregistrements associ\u00e9s au suivi et au respect du SOGED.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN3":{intro:"Limitation des nuisances et des pollutions",context:"La limitation des nuisances (bruit, vibrations, visuelles, olfactives, trafic) et des pollutions (air, eau, sol) pendant la phase chantier constitue un enjeu environnemental majeur pour le respect du voisinage et l\u2019am\u00e9nagement du territoire."},"CHAN3.1":{intro:"Limitation des nuisances et des pollutions (anticipation)",context:"En phase de conception, il est demand\u00e9 d\u2019identifier l\u2019ensemble des nuisances et pollutions potentielles du chantier et d\u2019laborer une strat\u00e9gie de limitation adapt\u00e9e au contexte du projet."},"CHAN3.1.1":{attendu:"Apr\u00e8s une identification des caract\u00e9ristiques du site et une analyse des atouts et contraintes, anticiper le plus possible toutes les nuisances et pollutions potentielles vis-\u00e0-vis des riverains, des occupants (si chantier en site occup\u00e9) et du personnel de chantier.",definition:"Cela concerne : les nuisances sonores et vibratoires, les nuisances visuelles (dont propret\u00e9 et palissade de chantier), les nuisances olfactives et dues au trafic, la pollution de l\u2019air, de l\u2019eau, du sol, la pr\u00e9servation de la valeur \u00e9cologique du site et sa biodiversit\u00e9. | La r\u00e9flexion se d\u00e9compose en deux phases : une \u00e9valuation des risques de nuisances et de pollutions (est-ce que les nuisances et pollutions existent ?) et une strat\u00e9gie de limitation des nuisances et des pollutions \u00e0 mettre en \u0153uvre sur le chantier (comment limiter les nuisances et pollutions qui existent ?).",non_applicabilite:"Si l\u2019op\u00e9ration est en phase r\u00e9alisation (en construction ou r\u00e9novation), cette exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou engagement \u00e0 produire une charte de chantier</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Charte chantier \u00e0 destination de l\u2019entreprise sp\u00e9cifiant les dispositions \u00e0 prendre pour limiter les nuisances et pollutions ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Charte chantier \u00ab preneurs \u00bb (si concern\u00e9) ; Analyse du site et diagnostic initial de l\u2019ouvrage ; \u00c9valuation des risques de nuisances et de pollutions sur le chantier ; Strat\u00e9gie de limitation des nuisances et des pollutions</td><td>Contenu de la charte chantier ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Contenu de la charte chantier \u00ab preneurs \u00bb concernant la limitation des nuisances et pollutions.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec les exigences CHAN3.2.1, CHAN3.2.2, CHAN3.2.3 et CHAN3.3.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Charte chantier pr\u00e9visionnelle ; Dispositions pr\u00e9paratoires prises pour limiter les nuisances et pollutions</td><td>Points \u00e0 inclure a minima dans la charte chantier ; Points \u00e0 inclure a minima dans la charte chantier \u00ab preneurs \u00bb (voir le SMR) (si concern\u00e9).</td></tr><tr><td><strong>Phases Exploitation axe Gestion</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN3.2":{intro:"Limitation des nuisances",context:"En phase r\u00e9alisation, la mise en place de dispositions techniques et organisationnelles permet de limiter les nuisances sonores et vibratoires, visuelles, olfactives et de trafic aupr\u00e8s des riverains et occupants."},"CHAN3.2.1":{attendu:"Pour le premier niveau (Dispositions organisationnelles et/ou techniques) : limiter les nuisances sonores et vibratoires par la mise en place de dispositions techniques et/ou organisationnelles. | Pour le deuxi\u00e8me niveau (Mesures acoustiques) : mettre en place le suivi acoustique d\u00e9fini dans l\u2019\u00e9valuation des risques de g\u00eane acoustique ou vibratoire r\u00e9alis\u00e9e en amont (voir CHAN3.1.1).",definition:"Exemples de dispositions techniques/organisationnelles : planification des t\u00e2ches pour minimiser l\u2019impact sur le voisinage, limitation du nombre de camions de livraison, r\u00e9flexions sur les horaires du trafic des v\u00e9hicules, positionnement des postes fixes ou bruyants, remplacement des engins pneumatiques par leur \u00e9quivalent \u00e9lectrique ou hydraulique, choix d\u2019engins insonoris\u00e9s, utilisation de banches \u00e0 cl\u00e9s de serrage, limitation des d\u00e9coupes de mat\u00e9riaux, plan de circulation des engins, r\u00e9servations suffisantes pour \u00e9viter les per\u00e7ages ult\u00e9rieurs, suivi acoustique lors des r\u00e9unions de chantier, autocontr\u00f4les acoustiques internes.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, les exigences du bloc CHAN3.2 sont non applicables.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour limiter les nuisances sonores et vibratoires, et enregistrements associ\u00e9s (identification des origines de bruit, fiches produit du mat\u00e9riel et des engins, sch\u00e9ma de chantier avec la position des engins et du mat\u00e9riel, compte-rendu de chantier, planning des phases bruyantes, notice acoustique, preuve de l\u2019installation du dispositif de suivi des niveaux de bruits et/ou vibrations, suivi des enregistrements des niveaux de bruits et/ou vibrations, suivi des dispositions correctives le cas \u00e9ch\u00e9ant, recueil des r\u00e9clamations des riverains et des occupants (si chantier en site occup\u00e9), feuilles d\u2019\u00e9margement pour des formations \u00ab bonnes pratiques environnementales \u00bb des compagnons...)</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier concernant la limitation des nuisances sonores et vibratoires.</td></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigence CHAN3.1.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN3.2.2":{attendu:"Mettre en \u0153uvre des bonnes pratiques en mati\u00e8re de limitation des nuisances visuelles (dont propret\u00e9 et palissade de chantier) vis-\u00e0-vis des riverains, des occupants (si chantier en site occup\u00e9) et du personnel de chantier.",definition:"Au-del\u00e0 d\u2019un entretien r\u00e9gulier du chantier et de ses abords et du respect de la r\u00e9glementation quant \u00e0 la limitation de l\u2019impact visuel du chantier (voir le R\u00e8glement Sanitaire D\u00e9partemental), il est demand\u00e9 de prendre des dispositions pour limiter les nuisances visuelles. | Exemples : entretien r\u00e9gulier des palissades et des installations de chantier, arrosage r\u00e9gulier du sol, installation d\u2019un d\u00e9poussi\u00e9reur, nettoyage des zones int\u00e9rieures du chantier, empierrement des voiries, aire de lavage pour les roues des camions, am\u00e9nagement du chantier avec grillage autour de l\u2019aire de stockage des d\u00e9chets, r\u00e9flexions sur la hauteur des palissades, respect des espaces verts existants, mise en \u0153uvre des protections sur les cl\u00f4tures du chantier pour \u00e9viter les projections.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, les exigences du bloc CHAN3.2 sont non applicables.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour limiter les nuisances visuelles et enregistrements associ\u00e9s (photographies de l\u2019\u00e9tat de propret\u00e9 du chantier et de ses abords, compte-rendu de chantier, recueil des r\u00e9clamations des riverains et des occupants, protocoles de nettoyage du chantier et/ou des engins, rapport de fin de chantier avec proc\u00e9dure de nettoyage de fin de chantier, feuilles d\u2019\u00e9margement pour des formations \u00ab bonnes pratiques environnementales \u00bb des compagnons...)</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier concernant la limitation des nuisances visuelles.</td></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigence CHAN3.1.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN3.2.3":{attendu:"Mettre en \u0153uvre des bonnes pratiques en mati\u00e8re de limitation des nuisances olfactives et dues au trafic des v\u00e9hicules vis-\u00e0-vis des riverains, des occupants (si chantier en site occup\u00e9) et du personnel de chantier.",definition:"Nuisances olfactives : respect de l\u2019interdiction de br\u00falage des d\u00e9chets, contr\u00f4le de l\u2019usage et du stockage de produits odorants (peintures, solvants, huiles, colles), attention au ravitaillement des engins en fluides et carburants, r\u00e9duction des \u00e9missions polluantes et des odeurs des postes d\u2019enrobage, choix de produits peu odorants, application \u00e0 chaud, etc. | Nuisances dues au trafic des v\u00e9hicules : limitation du stationnement \u00ab moteur en marche \u00bb des engins, gestion des apports de mat\u00e9riel et des enl\u00e8vements de d\u00e9chets, planification des rotations des camions, r\u00e9flexions sur la signalisation des acc\u00e8s au chantier, optimisation du stationnement des v\u00e9hicules du personnel.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, les exigences du bloc CHAN3.2 sont non applicables.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour limiter les nuisances olfactives et dues au trafic et enregistrements associ\u00e9s (photographies du chantier et de sa signalisation, compte-rendu de chantier, recueil des r\u00e9clamations, planification des mouvements de v\u00e9hicules, feuilles d\u2019\u00e9margement pour des formations \u00ab bonnes pratiques environnementales \u00bb des compagnons, fiche mat\u00e9riel, justificatif d\u2019achat, plans de coffrage, fiches des produits...)</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier concernant la limitation des nuisances olfactives et dues au trafic.</td></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigence CHAN3.1.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN3.3":{intro:"Limitation des pollutions (air, eau, sols) et pr\u00e9servation de la valeur \u00e9cologique du site et de sa biodiversit\u00e9",context:"La protection du sol, de l\u2019air et de l\u2019eau constitue un enjeu essentiel pendant le chantier. La pr\u00e9servation ou l\u2019am\u00e9lioration de la biodiversit\u00e9 et des \u00e9cosyst\u00e8mes rep\u00e9r\u00e9s sur le site contribuent \u00e0 la qualit\u00e9 environnementale du projet."},"CHAN3.3.1":{attendu:"Pour le premier niveau (Dispositions pour limiter les pollutions de l\u2019air et celles de l\u2019eau ou du sol) : prendre des dispositions pour limiter la pollution de l\u2019air et au moins un type de pollutions parmi la pollution de l\u2019eau et la pollution du sol. | Pour le deuxi\u00e8me niveau (Dispositions pour limiter les pollutions (air, eau et sol) et pr\u00e9server la valeur \u00e9cologique) : prendre des dispositions non seulement pour limiter les pollutions (air, eau et sol), mais aussi pour pr\u00e9server la valeur \u00e9cologique du site et sa biodiversit\u00e9.",definition:"Pollution de l\u2019air : arrosage r\u00e9gulier ou humidification des sols et des surfaces, aspiration des poussi\u00e8res, mise en place de filtres, mise en place de sondes d\u2019empoussi\u00e9rement, confinement des r\u00e9seaux/\u00e9quipements/mat\u00e9riel/rev\u00eatements, choix d\u2019outils manuels ou motoris\u00e9s \u00e0 vitesse lente, etc. | Pollution des eaux et du sol : \u00e9tiquetage r\u00e9glementaire des cuves/f\u00fbts/bidons/pots, identification et stockage des produits potentiellement polluants, interdiction d\u2019enfouissement des d\u00e9chets en place, pr\u00e9sence de protections adapt\u00e9es pour les zones de stockage des produits, dispositifs de r\u00e9cup\u00e9ration des eaux de lavage, pr\u00e9sence d\u2019un kit de d\u00e9pollution, etc. | Pr\u00e9servation de la valeur \u00e9cologique : effarouchement d\u2019esp\u00e8ces, d\u00e9placement d\u2019esp\u00e8ces, plan de gestion visant l\u2019am\u00e9lioration des habitats pr\u00e9serv\u00e9s, cr\u00e9ation d\u2019habitats, balisage et pr\u00e9servation des \u00e9l\u00e9ments existants, cr\u00e9ation d\u2019un corridor \u00e9cologique, adaptation de la palette v\u00e9g\u00e9tale, r\u00e9duction de la pollution lumineuse, cr\u00e9ation de zones humides, etc.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, cette exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour limiter les pollutions (air, eau, sols) et pr\u00e9server la valeur \u00e9cologique du site et enregistrements associ\u00e9s (photographies du chantier, compte-rendu de chantier, recueil des r\u00e9clamations, feuilles d\u2019\u00e9margement pour des formations \u00ab bonnes pratiques environnementales \u00bb des compagnons, fiche mat\u00e9riel, justificatif d\u2019achat, plans de coffrage, plan de gestion visant l\u2019am\u00e9lioration des habitats pr\u00e9serv\u00e9s, fiches des produits...)</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier concernant la limitation des pollutions (air, eau, sols) et pr\u00e9servation de la valeur \u00e9cologique du site et de sa biodiversit\u00e9.</td></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigence CHAN3.1.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN3.4":{intro:"Communication interactive avec les riverains ou occupants (si chantier en site occup\u00e9)",context:"\u00c9tablir un dialogue permanent avec les riverains et les occupants permet de cr\u00e9er une relation de confiance, d\u2019identifier les pr\u00e9occupations et de mettre en place des solutions adapt\u00e9es aux contextes locaux."},"CHAN3.4.1":{attendu:"Pour le premier niveau (Recueil et gestion des r\u00e9clamations ou suggestions) : recueillir et g\u00e9rer les r\u00e9clamations ou suggestions des riverains et occupants tout au long du chantier. Ce premier niveau doit obligatoirement \u00eatre atteint. | Pour le deuxi\u00e8me niveau (Relations proactives) : aller au-del\u00e0 du recueil et de la gestion des r\u00e9clamations, en ayant des relations proactives avec les riverains et les occupants.",definition:"Pr\u00e9cision : la parenth\u00e8se \u00ab (si chantier en site occup\u00e9) \u00bb ne s\u2019adresse qu\u2019aux occupants. L\u2019exigence est donc applicable m\u00eame en cas de chantier en site non occup\u00e9. | Les vecteurs de communication \u00e0 privil\u00e9gier diff\u00e8rent en fonction du public vis\u00e9, de la phase du projet, du contexte du projet ainsi que son ampleur. Exemples : mise en place d\u2019une ligne t\u00e9l\u00e9phonique et/ou d\u2019un site internet permettant aux riverains et occupants de faire part de leurs r\u00e9clamations ou suggestions. | Pour les relations proactives : r\u00e9unions de quartier, r\u00e9unions de chantier avec les entreprises/riverains/associations, d\u00e9signation de riverains b\u00e9n\u00e9voles/habitants/travailleurs qui veillent au bon d\u00e9roulement du chantier, visites de chantier, comit\u00e9 de liaison des riverains ou occupants, envoi p\u00e9riodique d\u2019un formulaire d\u2019\u00e9valuation des points \u00e0 am\u00e9liorer, etc.",important:"Le premier niveau doit obligatoirement \u00eatre atteint pour \u00eatre certifi\u00e9.",attention:"Attention renforc\u00e9e \u00e0 la sant\u00e9 et s\u00e9curit\u00e9 des compagnons, par des actions de pr\u00e9vention, sensibilisation et suivi.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou engagement \u00e0 produire une charte de chantier</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Charte chantier \u00e0 destination de l\u2019entreprise sp\u00e9cifiant les dispositions \u00e0 prendre pour communiquer de fa\u00e7on interactive avec les riverains ou occupants ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Charte chantier \u00ab preneurs \u00bb (si concern\u00e9) ; Dispositions pr\u00e9paratoires prises pour communiquer de fa\u00e7on interactive</td><td>Contenu de la charte chantier concernant la communication interactive avec les riverains ou occupants ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Contenu de la charte chantier \u00ab preneurs \u00bb concernant la communication interactive.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour communiquer de fa\u00e7on interactive avec les riverains ou occupants (recueil des r\u00e9clamations / suggestions, proc\u00e9dure de suivi et de traitement, courrier de r\u00e9ponse, courrier d\u2019information sur la mise en place d\u2019une ligne t\u00e9l\u00e9phonique et/ou d\u2019un site internet, CR r\u00e9union de quartier, CR r\u00e9union de chantier associant les riverains ou occupants, photographies lors des visites de chantier, CR comit\u00e9 de liaison des riverains...)</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier concernant la communication interactive avec les riverains ou occupants (si chantier en site occup\u00e9).</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Charte chantier pr\u00e9visionnelle ; Dispositions pr\u00e9paratoires prises pour communiquer de fa\u00e7on interactive</td><td>Points \u00e0 inclure a minima dans la charte chantier ; Points \u00e0 inclure a minima dans la charte chantier \u00ab preneurs \u00bb (voir le SMR) (si concern\u00e9).</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e</td><td>Sans objet.</td></tr></table>"},"CHAN4":{intro:"Suivi et ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau",context:"La ma\u00eetrise des ressources (eau et \u00e9nergie) constitue un enjeu environnemental majeur. Il s\u2019agit non seulement de conna\u00eettre et de suivre les consommations au plus pr\u00e8s, mais aussi de mettre en place des dispositions pour les r\u00e9duire."},"CHAN4.1":{intro:"Conna\u00eetre, suivre et ma\u00eetrise les consommations d\u2019\u00e9nergie et d\u2019eau (Phases Programme, Conception, Exploitation axe B\u00e2timent)",context:"Dans les phases amont, il s\u2019agit de d\u00e9finir les objectifs et les dispositions visant \u00e0 conna\u00eetre, suivre et ma\u00eetrise les consommations du chantier."},"CHAN4.1.1":{attendu:"Conna\u00eetre, suivre et ma\u00eetrise les consommations d\u2019\u00e9nergie et d\u2019eau. Il est demand\u00e9 non seulement de conna\u00eetre et de suivre les consommations au plus pr\u00e8s des usages, mais aussi de ma\u00eetrise et limiter les consommations d\u2019\u00e9nergie et d\u2019eau.",definition:"Cela peut se traduire par : la pr\u00e9sence de dispositifs pour assurer le suivi des consommations d\u2019\u00e9nergie pour chaque type d\u2019\u00e9nergie (lectricit\u00e9, gaz, mazout...), la pr\u00e9sence de dispositifs pour assurer le suivi des consommations d\u2019\u00e9nergie et/ou d\u2019eau sur certains postes (notamment les bases de vie du chantier), la pr\u00e9sence de compteurs d\u2019\u00e9nergie et/ou d\u2019eau sur les engins les plus consommateurs (fixes ou mobiles), le choix de mat\u00e9riel et d\u2019engins moins consommateurs d\u2019\u00e9nergie et/ou d\u2019eau, la mise en place d\u2019un syst\u00e8me de coupure de l\u2019alimentation \u00e9lectrique et/ou en eau du chantier contr\u00f4l\u00e9 par une horloge, la mise en place d\u2019une programmation horaire et/ou d\u2019un zonage des installations d\u2019\u00e9clairage du chantier, la mise en place de lampes basse consommation, la mise en place de dispositifs pour limiter les consommations d\u2019eau \u00e0 la source (r\u00e9cup\u00e9ration d\u2019eau de pluie, r\u00e9cup\u00e9ration des eaux de lavage des centrales \u00e0 b\u00e9ton...), la mise en place de dispositifs permettant une \u00e9conomie d\u2019eau dans les bungalows (chasses d\u2019eau double commande, limiteurs de d\u00e9bits, etc.), la mise en place de proc\u00e9dures organisationnelles pour limiter les consommations d\u2019eau, la sensibilisation du personnel de chantier, la communication des consommations sur le site.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase r\u00e9alisation (en construction ou r\u00e9novation), cette exigence est non applicable.",attention:"L\u2019exigence est valid\u00e9e si et seulement si le suivi des consommations au plus pr\u00e8s des usages est prescrit pour l\u2019\u00e9nergie ET l\u2019eau, et si la ma\u00eetrise des consommations concerne l\u2019\u00e9nergie ET l\u2019eau.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme ou engagement \u00e0 produire une charte de chantier</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Charte chantier \u00e0 destination de l\u2019entreprise sp\u00e9cifiant les dispositions \u00e0 prendre pour suivre et ma\u00eetrise les consommations d\u2019\u00e9nergie et d\u2019eau ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Dispositions pr\u00e9paratoires prises pour le suivi et la ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau ; Charte chantier \u00ab preneurs \u00bb (si concern\u00e9)</td><td>Contenu de la charte chantier concernant le suivi et la ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau ; Inclusion de la charte chantier dans le DCE et les documents de march\u00e9 ; Contenu de la charte chantier \u00ab preneurs \u00bb concernant le suivi et la ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Charte chantier pr\u00e9visionnelle ; Dispositions pr\u00e9paratoires prises pour suivre et ma\u00eetrise les consommations d\u2019\u00e9nergie et d\u2019eau</td><td>Points \u00e0 inclure a minima dans la charte chantier ; Points \u00e0 inclure a minima dans la charte chantier \u00ab preneurs \u00bb (voir le SMR) (si concern\u00e9).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec les exigences CHAN4.2.1 et CHAN4.3.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN4.2":{intro:"Conna\u00eetre et suivre les consommations d\u2019\u00e9nergie et d\u2019eau (Phase R\u00e9alisation)",context:"Le suivi effectif des consommations d\u2019\u00e9nergie et d\u2019eau sur le chantier constitue un pr\u00e9alable \u00e0 toute ma\u00eetrise."},"CHAN4.2.1":{attendu:"Pour le premier niveau (Suivi des consommations au plus pr\u00e8s des usages) : conna\u00eetre et suivre les consommations d\u2019\u00e9nergie et d\u2019eau au plus pr\u00e8s des usages. La r\u00e9alisation d\u2019un sch\u00e9ma de comptage est aussi attendue. | Pour le deuxi\u00e8me niveau (Analyse des consommations) : interpr\u00e9ter les diff\u00e9rents relev\u00e9s des consommations d\u2019\u00e9nergie et d\u2019eau, les analyser et les comparer avec d\u2019autres projets (par exemple via des indicateurs de suivi des consommations) ou avec des valeurs guide.",definition:"Dispositifs pour le suivi des consommations : compteurs d\u2019\u00e9nergie pour chaque type d\u2019\u00e9nergie, dispositifs de suivi sur certains postes (bases de vie), compteurs sur les engins les plus consommateurs.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, cette exigence est non applicable.",attention:"Le premier niveau de points est valid\u00e9 si et seulement si le suivi des consommations au plus pr\u00e8s des usages est effectif pour l\u2019\u00e9nergie ET l\u2019eau. Le deuxi\u00e8me niveau est valid\u00e9 si et seulement si l\u2019analyse des consommations est r\u00e9alis\u00e9e pour l\u2019\u00e9nergie ET l\u2019eau.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour suivre et analyser les consommations d\u2019\u00e9nergie et d\u2019eau, et enregistrements associ\u00e9s (Tableau / graphique de suivi des consommations, sch\u00e9ma de comptage des compteurs d\u2019\u00e9nergie et d\u2019eau, factures d\u2019\u00e9nergie et d\u2019eau, fiche mat\u00e9riel, justificatif d\u2019achat, indicateurs de suivi des consommations d\u2019\u00e9nergie et d\u2019eau...)</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier concernant le suivi et l\u2019analyse des consommations d\u2019\u00e9nergie et d\u2019eau.</td></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigences CHAN4.1.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN4.3":{intro:"Ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau (Phase R\u00e9alisation)",context:"La ma\u00eetrise des consommations pass par l\u2019adoption de dispositions appropri\u00e9es et par une gestion active des \u00e9ventuelles surconsommations."},"CHAN4.3.1":{attendu:"Pour le premier niveau (Ma\u00eetrise des consommations) : prendre des dispositions pour adopter une strat\u00e9gie de r\u00e9duction des consommations d\u2019\u00e9nergie et d\u2019eau pendant le chantier et ainsi limiter ces consommations au juste n\u00e9cessaire. | Pour le deuxi\u00e8me niveau (Dispositions en cas de surconsommation) : prendre des dispositions en cas de surconsommation d\u2019\u00e9nergie et d\u2019eau d\u00e9cel\u00e9e, c\u2019est-\u00e0-dire identifier les surconsommations, d\u00e9terminer leur(s) cause(s) et entreprendre des actions correctives et/ou pr\u00e9ventives.",definition:"Ma\u00eetrise : choix de mat\u00e9riel et d\u2019engins moins consommateurs, mise en place d\u2019un syst\u00e8me de coupure de l\u2019alimentation \u00e9lectrique et/ou en eau contr\u00f4l\u00e9 par une horloge, programmation horaire et/ou zonage des installations d\u2019\u00e9clairage, lampes basse consommation, dispositifs pour limiter les consommations d\u2019eau \u00e0 la source, dispositifs permettant une \u00e9conomie d\u2019eau dans les bungalows, proc\u00e9dures organisationnelles, sensibilisation du personnel, communication des consommations. | Surconsommation : proc\u00e9dures de suivi des consommations avec rep\u00e9rage des pics et actions correctives, proc\u00e9dures organisationnelles pour rep\u00e9rer les fuites d\u2019eau (analyse des consommations nocturnes, rondes techniques...).",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, cette exigence est non applicable.",attention:"Le premier niveau est valid\u00e9 si et seulement si la ma\u00eetrise des consommations concerne l\u2019\u00e9nergie ET l\u2019eau. Le deuxi\u00e8me niveau est valid\u00e9 si et seulement si les dispositions prises en cas de surconsommation concernent l\u2019\u00e9nergie ET l\u2019eau.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Dispositions prises pour ma\u00eetrise les consommations d\u2019\u00e9nergie et d\u2019eau et enregistrements associ\u00e9s (fiche mat\u00e9riel, justificatif d\u2019achat, photographies, programmation horaire, affichage des bonnes pratiques et/ou des consommations d\u2019\u00e9nergie et d\u2019eau, feuilles d\u2019\u00e9margement pour des formations \u00ab bonnes pratiques environnementales \u00bb des compagnons, proc\u00e9dure de suivi des consommations avec rep\u00e9rage des pics, tableau de suivi des actions correctives associ\u00e9es, \u00ab trace \u00bb des actions correctives engag\u00e9es, mesure de l\u2019efficacit\u00e9 des actions correctives...)</td><td>Enregistrements associ\u00e9s au suivi et au respect de la charte chantier concernant la ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau et les dispositions prises en cas de surconsommation.</td></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Non concern\u00e9es car \u00e9valu\u00e9es avec l\u2019exigences CHAN4.1.1</td><td>Sans objet.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},"CHAN5":{intro:"Bilan multith\u00e9matique du chantier",context:"Un bilan de fin de chantier permet d\u2019\u00e9valuer le respect des engagements environnementaux et d\u2019identifier les points forts et les axes d\u2019am\u00e9lioration pour les futurs chantiers."},"CHAN5.1":{intro:"Bilan multith\u00e9matique du chantier",context:"Ce bilan doit couvrir tous les th\u00e8mes environnementaux abourd\u00e9s pendant le chantier : g\u00e9estion des d\u00e9chets, limitation des nuisances et pollutions, ma\u00eetrise des consommations d\u2019\u00e9nergie et d\u2019eau, biodiversit\u00e9, relations avec les riverains."},"CHAN5.1.1":{attendu:"Pour le premier niveau (Bilan de fin de chantier) : r\u00e9aliser un bilan multith\u00e9matique \u00e0 la fin du chantier au regard des exigences de la charte chantier et des objectifs de performance \u00e0 atteindre. Ce bilan doit porter un regard critique sur tous les \u00e9l\u00e9ments du chantier ayant un impact sur les aspects environnementaux. | Pour le deuxi\u00e8me niveau (Bilan de fin de chantier et diffusion) : r\u00e9aliser un bilan de fin de chantier (comme le premier niveau) et le diffuser \u00e0 toutes les entreprises qui ont travaill\u00e9 sur le chantier.",definition:"Le bilan doit aller au-del\u00e0 de la simple compilation des r\u00e9sultats quantitatifs et qualitatifs, il doit d\u00e9terminer l\u2019atteinte ou non des objectifs propres \u00e0 cette phase et faire le point sur un certain nombre de crit\u00e8res majeurs parmi lesquels : les aspects \u00e9conomiques et financiers, les aspects techniques (gestion des d\u00e9chets, limitation des nuisances et pollutions), les aspects des ressources humaines, les aspects r\u00e9glementaires et la satisfaction des riverains et des occupants (si chantier en site occup\u00e9). Il doit mettre en \u00e9vidence les points forts et les points faibles du chantier, analyser les probl\u00e8mes rencontr\u00e9s, interroger les intervenants sur la mise en place de nouvelles techniques. | Si la ma\u00eetrise d\u2019ouvrage choisit de diffuser le bilan de fin de chantier via une r\u00e9union, alors il est demand\u00e9 de pr\u00e9voir de faire ce bilan dans les derniers mois de chantier.",non_applicabilite:"Si l\u2019op\u00e9ration est en phase programme ou conception (en construction ou r\u00e9novation), ou en axe B\u00e2timent, cette exigence est non applicable.",important:"Cette exigence doit obligatoirement \u00eatre atteinte a minima au premier niveau \u00ab Bilan de fin de chantier \u00bb.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Rapport de bilan du chantier ; Preuve de la diffusion de ce rapport aux entreprises (mails, courriers, CR de r\u00e9union...)</td><td>Contenu du rapport de bilan du chantier ; Diffusion du rapport de bilan du chantier.</td></tr><tr><td><strong>Phases Programme, Conception et Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Non concern\u00e9es</td><td>Sans objet.</td></tr></table>"},
"ACCL1":{intro:"Adaptation au changement climatique",context:"L\u2019adaptation au changement climatique d\u00e9signe les strat\u00e9gies, initiatives et mesures visant \u00e0 r\u00e9duire la vuln\u00e9rabilit\u00e9 des syst\u00e8mes naturels et humains contre les effets (pr\u00e9sents et attendus) des changements climatiques. (GIEC) | Globalement, trois types de strat\u00e9gies existent et peuvent se combiner pour lutter contre le changement climatique : Att\u00e9nuation (limiter la vitesse d\u2019augmentation des taux de gaz \u00e0 effet de serre dans l\u2019air), Adaptation (rendre les syst\u00e8mes ou territoires moins vuln\u00e9rables au d\u00e9r\u00e8glement climatique), Transition (l\u2019adaptation comme une politique de transition permanente sur le tr\u00e8s long terme). | Ce th\u00e8me traite de l\u2019adaptation des b\u00e2timents au changement climatique : \u00e9volution rapide mais limit\u00e9e des b\u00e2timents eux-m\u00eames pour les adapter \u00e0 ce changement climatique, mais aussi une adaptation plus structurante \u00e0 une \u00e9chelle plus grande (quartiers) pour adapter notamment l\u2019implantation de ceux-ci. | Rappel : L\u2019ensemble des exigences du th\u00e8me s\u2019applique sur le p\u00e9rim\u00e8tre spatial et des responsabilit\u00e9s du demandeur."},
"ACCL1.1":{intro:"Risques d\u00fbs au changement climatique et r\u00e9silience du b\u00e2timent",context:"Ce sous-th\u00e8me traite des mesures et dispositions prises pour g\u00e9rer les risques naturels d\u00fbs au changement climatique."},
"ACCL1.1.1":{attendu:"Mesures et dispositions prises pour g\u00e9rer les risques naturels d\u00fbs au changement climatique.",definition:"Il est demand\u00e9, notamment \u00e0 partir de l\u2019analyse de site : | De proc\u00e9der \u00e0 un examen visant \u00e0 d\u00e9terminer les risques naturels potentiels qui pourraient influer sur le site sur la base de projections climatiques de pointe sur les trente prochaines ann\u00e9es (profils RCP du GIEC RCP 2.6, RCP 4.5, RCP 6.0 et RCP 8.5). Les sc\u00e9narios SSP \u00ab Shared Socioeconomic Pathways \u00bb suivants (enveloppe m\u00e9diane) sont \u00e9galement accept\u00e9s : SSP1-2.6 (proche du RCP2.6), SSP2-4.5 (proche du RCP4.5 et du RCP6.0 jusqu\u2019\u00e0 2050), et SSP5-8.5 (proche du RCP8.5). Il est accept\u00e9 d\u2019utiliser l\u2019un de ces sc\u00e9narios seulement. | Les fichiers m\u00e9t\u00e9o utilis\u00e9s seront les fichiers correspondants aux sc\u00e9narios ci-dessus, \u00e0 l\u2019horizon 2050, avec les valeurs de temp\u00e9ratures et rayonnement maxima mensuelles. | De r\u00e9aliser une \u00e9valuation de la vuln\u00e9rabilit\u00e9 du futur b\u00e2timent li\u00e9e aux risques pr\u00e9c\u00e9demment identifi\u00e9s. | D\u2019int\u00e9grer lors de la conception et de la construction, les solutions d\u2019adaptation r\u00e9duisant les risques climatiques physiques les plus significatifs. | De s\u2019assurer de l\u2019exhaustivit\u00e9 des al\u00e9as pris en compte dans le cadre de l\u2019examen ainsi que lors de l\u2019utilisation des outils, en compl\u00e9tant avec d\u2019autres outils si n\u00e9cessaire.",non_applicabilite:"L\u2019exigence est non applicable en exploitation axe Gestion.",reglementation:"En France, les zones concern\u00e9es sont indiqu\u00e9es dans l\u2019Arr\u00eat\u00e9 du 22 juillet 2020 d\u00e9finissant les zones expos\u00e9es au ph\u00e9nom\u00e8ne de mouvement de terrain diff\u00e9rentiel cons\u00e9cutif \u00e0 la s\u00e9cheresse et \u00e0 la r\u00e9hydratation des sols argileux. L\u2019arr\u00eat\u00e9 cite l\u2019outil de cartographie \u2018G\u00e9orisque\u2019 accessible selon le lien suivant : https://www.georisques.gouv.fr. | En France, les PPRI (Plans de Pr\u00e9vention des Risques naturels d\u2019Inondation) (et plus g\u00e9n\u00e9ralement les PPRn - Plans de Pr\u00e9vention des Risques naturels) indiquent l\u2019appartenance du projet \u00e0 une zone \u00e0 risque et les contraintes qui s\u2019y appliquent dans ce cas. Dans le cas d\u2019un risque d\u2019inondation toutes les sources de risques doivent \u00eatre consid\u00e9r\u00e9s : d\u00e9bordement de cours d\u2019eau, submersion marine, violentes averses, etc. | La norme ISO 14091 de 2021 \u00ab Adaptation au changement climatique \u2014 Lignes directrices sur la vuln\u00e9rabilit\u00e9, les impacts et l\u2019\u00e9valuation des risques \u00bb fournit des pistes m\u00e9thodologiques. | La s\u00e9rie de norme EN 1991-1 donne des actions possibles \u00e0 prendre en compte pour certains risques naturels : EN 1991-1-1 (accroissement des pr\u00e9cipitations), EN 1991-1-3 (augmentation des chutes de neige), EN 1991-1-4 (charges de vent accrues), EN 1991-1-5 (stress thermique).",attention:"La mise en place uniquement de dispositions manag\u00e9riales ne permet pas d\u2019obtenir de points. Elles doivent donc \u00eatre accompagn\u00e9es de dispositions architecturales et/ou techniques. | Pour les contraintes li\u00e9es au sol, il ne s\u2019agit pas ici de traiter les contraintes structurelles classiques des sols (entra\u00eenant par exemple le choix de fondations profondes), mais de traiter les contraintes li\u00e9es au changement climatique, comme par exemple : alternance potentielle de p\u00e9riodes de s\u00e9cheresse et d\u2019apports pluvieux importants, entra\u00eenant des d\u00e9sordres structurels. | Dans le cas o\u00f9 aucune r\u00e9glementation ne s\u2019impose au b\u00e2timent, seule l\u2019analyse de risques est \u00e0 r\u00e9aliser. | Dans le cas o\u00f9 aucune r\u00e9glementation ne s\u2019impose au b\u00e2timent, une analyse de risques et la mise en place de dispositions sont \u00e0 r\u00e9aliser.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Analyse du site incluant les risques naturels (dont les contraintes li\u00e9es au sol). | R\u00e9sultats des simulations et /ou \u00e9valuations (exemple l\u2019\u00e9valuation BAT-ADAPT, LEVELS, et/ou autre). | Liste de solutions propos\u00e9es.</td><td>Pr\u00e9sence de l\u2019identification de tous les types de risque naturel.</td></tr><tr><td><strong>Phases Conception, R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Document d\u2019analyse des risques identifi\u00e9s. | R\u00e9sultats des simulations et /ou \u00e9valuations (exemple l\u2019\u00e9valuation BAT-ADAPT, LEVELS, et/ou autre). | Justification des sc\u00e9narios et fichiers m\u00e9t\u00e9o utilis\u00e9s. | Liste de solutions retenues et/ou les conditions de leur mise en place. | Liste d\u2019indicateurs propos\u00e9s pour le suivi de l\u2019efficacit\u00e9 des indicateurs avec une lettre d\u2019engagement du suivi de ces indicateurs.</td><td>Propositions de solutions, Incidences des solutions.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td colspan=\"2\">Non concern\u00e9e. Sans objet.</td></tr></table>"},
"ACCL1.2":{intro:"Adaptation des conditions de confort hygrothermique dans les locaux et sur la parcelle",context:"Ce sous-th\u00e8me traite de l\u2019adaptation des conditions de confort hygrothermique dans les locaux et de la r\u00e9duction de l\u2019effet d\u2019\u00eelot de chaleur sur la parcelle."},
"ACCL1.2.1":{attendu:"Adaptation des conditions de confort hygrothermique dans les locaux.",definition:"Il est demand\u00e9 dans cette exigence de calculer les conditions de confort dans les locaux en utilisant la m\u00eame m\u00e9thode de calcul que pour le th\u00e8me confort hygrothermique (exigences HYGR2.1.6b ou HYGR2.1.6c ou HYGR2.2.1-REU), et le m\u00eame d\u00e9coupage en Blocs Homog\u00e8nes (BH). Il s\u2019agit d\u2019un approfondissement de la simulation thermique dynamique utilis\u00e9e pour le th\u00e8me confort hygrothermique, dans le but de calculer la performance en se basant sur des projections m\u00e9t\u00e9orologiques pour 2050. Il s\u2019agit de simuler le b\u00e2timent sans syst\u00e8mes actifs de froid (m\u00eame s\u2019il en a). | Les syst\u00e8mes li\u00e9s au b\u00e2ti permettant la cr\u00e9ation de mouvements d\u2019air (exemple : brasseurs d\u2019air), s\u2019ils sont pr\u00e9vus, doivent \u00eatre inclus dans la simulation. | Un(des) syst\u00e8me(s) de refroidissement ou actif de froid (y compris s\u2019il fonctionne uniquement en appoint), est un \u00e9quipement de production de froid (Tour A\u00e9ror\u00e9frig\u00e9rante, groupe froid, r\u00e9seau de froid, syst\u00e8me d\u2019absorption) associ\u00e9 \u00e0 des \u00e9metteurs de froid, destin\u00e9 au confort des personnes.",non_applicabilite:"L\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable : | en Exploitation axe B\u00e2timent, | en R\u00e9novation si celle-ci ne concerne pas les lots/sous-lots suivants : 3. Superstructure & Ma\u00e7onnerie, 4. Couverture-Etanch\u00e9it\u00e9-Charpente-Zinguerie, 5.2 Doublages mur, mat\u00e9riaux de protection, isolants et membranes, 6. Fa\u00e7ades et menuiseries ext\u00e9rieures. | L\u2019exigence est non applicable en exploitation axe Gestion. | Dans ces cas, les points seront d\u00e9duits du total disponible. | Enfin, dans le cas o\u00f9 le projet est situ\u00e9 en climat polaire, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",reglementation:"La simulation doit \u00eatre r\u00e9alis\u00e9e avec un fichier m\u00e9t\u00e9o repr\u00e9sentatif du climat futur pour 2050 : | Fichiers de type GIEC (et cadre de r\u00e9f\u00e9rence LEVELS : document \u00ab Level(s) indicator 5.1: Protection of occupier health and thermal comfort \u00bb - Version 1.1 de janvier 2021) : La mod\u00e9lisation doit se fonder sur des fichiers m\u00e9t\u00e9o bas\u00e9s a minima sur les sc\u00e9narios du GIEC RCP 2.6, RCP 4.5, RCP 6.0 et RCP 8.5 (voir aussi le \u201cGuide de r\u00e9alisation de STD dans le cadre du r\u00e9f\u00e9rentiel HQE\u201d). Il est accept\u00e9 de faire un calcul avec l\u2019un de ces sc\u00e9narios seulement. | Les nouveaux sc\u00e9narios SSP \u00ab Shared Socioeconomic Pathways \u00bb suivants sont \u00e9galement accept\u00e9s : SSP1-2.6 (proche du RCP2.6), SSP2-4.5 (proche du RCP4.5 et du RCP6.0 jusqu\u2019\u00e0 2050), et SSP5-8.5 (proche du RCP8.5). | Les fichiers m\u00e9t\u00e9o utilis\u00e9s seront les fichiers correspondants aux sc\u00e9narios ci-dessus, \u00e0 l\u2019horizon 2050, avec les valeurs de temp\u00e9ratures et rayonnement maxima mensuelles. | Les donn\u00e9es m\u00e9t\u00e9o doivent \u00eatre a minima \u00e0 une maille de 50km : projections globales issues des sc\u00e9narios SSP, ou projections r\u00e9gionalis\u00e9es issues des sc\u00e9narios RCP (sauf le 6.0), pour l\u2019horizon 2041-2060 (correspondant par simplification \u00e0 2050). | En France : Le fichier m\u00e9t\u00e9o d\u00e9grad\u00e9 de la r\u00e9glementation thermique et/ou environnementale en vigueur (RE2020) peut \u00e9galement \u00eatre utilis\u00e9. | Plages de temp\u00e9ratures minimales \u00e0 respecter : Celles donn\u00e9es pour la Cat\u00e9gorie II, dans la norme EN ISO 16798-1. Ces plages permettent de d\u00e9terminer la zone de confort \u00e0 respecter. | Voir aussi le document \u00ab Level(s) indicator 4.2: Time outside of thermal comfort range \u00bb - Version 1.1 de janvier 2021. | Les valeurs \u00e0 respecter \u00ab sur l\u2019ann\u00e9e \u00bb correspondent \u00e0 des valeurs calcul\u00e9es sur la p\u00e9riode de refroidissement telle que d\u00e9finie dans la r\u00e9glementation thermique et/ou environnementale en vigueur.",attention:"Les effets des \u00eelots de chaleur locaux peuvent aussi \u00eatre int\u00e9gr\u00e9s aux fichiers utilis\u00e9s si un risque d\u2019\u00eelot de chaleur est identifi\u00e9 (cf. aussi l\u2019exigence ACCL1.2.2 ci-dessous). | Le cadre de r\u00e9f\u00e9rence europ\u00e9en LEVELS (document 5.1 cit\u00e9 ci-dessus) donne \u00e9galement des exemples de dispositions pouvant \u00eatre prises afin d\u2019am\u00e9liorer les performances du b\u00e2timent en climat d\u00e9grad\u00e9.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Justification des sc\u00e9narios et fichiers m\u00e9t\u00e9o utilis\u00e9s. | Simulation thermique dynamique ; CCTP ; Plans.</td><td>V\u00e9rification que les sc\u00e9narios d\u2019usage pris en compte correspondent aux sc\u00e9narios d\u00e9finis par le maitre d\u2019ouvrage ; V\u00e9rification des fichiers m\u00e9t\u00e9o utilis\u00e9s. Coh\u00e9rence entre le ficher m\u00e9t\u00e9o utilis\u00e9 et la localisation du projet (m\u00eame zone climatique) ; Coh\u00e9rence entre les hypoth\u00e8ses de la simulation thermique dynamique et les \u00e9l\u00e9ments du projet d\u00e9crits et dessin\u00e9s, notamment sur les points suivants : Caract\u00e9ristiques des parois opaques et vitr\u00e9es. Caract\u00e9ristiques et fonctionnement des protections solaires. Caract\u00e9ristiques et fonctionnement des \u00e9quipements techniques.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Justification des sc\u00e9narios et fichiers m\u00e9t\u00e9o utilis\u00e9s. | Mise \u00e0 jour de la simulation thermique dynamique en cas de modification du projet ; DOE.</td><td>V\u00e9rification que les sc\u00e9narios d\u2019usage pris en compte correspondent aux sc\u00e9narios d\u00e9finis par le maitre d\u2019ouvrage ; V\u00e9rification des fichiers m\u00e9t\u00e9o utilis\u00e9s.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Justification des sc\u00e9narios et fichiers m\u00e9t\u00e9o utilis\u00e9s. | Simulation thermique dynamique ; CCTP ; Plans.</td><td>V\u00e9rification que les sc\u00e9narios d\u2019usage pris en compte correspondent aux sc\u00e9narios d\u00e9finis par le maitre d\u2019ouvrage ; V\u00e9rification des fichiers m\u00e9t\u00e9o utilis\u00e9s.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td colspan=\"2\">Non concern\u00e9e. Sans objet.</td></tr></table>"},
"ACCL1.2.2":{attendu:"R\u00e9duction de l\u2019effet d\u2019\u00eelot de chaleur.",definition:"Il est demand\u00e9 au choix : | de prendre des dispositions pour am\u00e9liorer l\u2019albedo d\u2019au moins 10% par rapport \u00e0 la situation ant\u00e9rieure au projet, | ou de d\u00e9montrer que l\u2019alb\u00e9do du projet (b\u00e2timent et parcelle) est sup\u00e9rieur \u00e0 0,25. | L\u2019am\u00e9lioration de 10% signifie que l\u2019albedo passe de 0,2 \u00e0 0,3 par exemple, et non pas de 0,2 \u00e0 0,22. | Seules les surfaces horizontales sont \u00e0 prendre en compte.",non_applicabilite:"Si le projet est en r\u00e9novation ou exploitation (axe B\u00e2timent) sans possibilit\u00e9 de modifier son albedo (exemple : b\u00e2timent class\u00e9), cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. | L\u2019exigence est non applicable en exploitation axe Gestion. | Dans ces cas, les trois points seront d\u00e9duits du total de points disponibles.",reglementation:"On entend par \u00eelot de chaleur le ph\u00e9nom\u00e8ne d\u2019\u00e9l\u00e9vations plus ou moins localis\u00e9es des temp\u00e9ratures, particuli\u00e8rement des temp\u00e9ratures maximales diurnes et nocturnes, enregistr\u00e9es en milieu urbain par rapport aux zones rurales ou foresti\u00e8res voisines ou par rapport aux temp\u00e9ratures moyennes r\u00e9gionales. | L\u2019effet d\u2019\u00eelot de chaleur urbain (ICU) est un facteur suppl\u00e9mentaire \u00e0 prendre en compte pour mod\u00e9liser les caract\u00e9ristiques de l\u2019air ext\u00e9rieur et les temp\u00e9ratures du rayonnement thermique autour d\u2019un b\u00e2timent. En effet, les temp\u00e9ratures dans les zones urbaines peuvent \u00eatre plus \u00e9lev\u00e9es que dans les zones rurales du fait de l\u2019association des facteurs suivants : les gaz d\u2019\u00e9chappement des v\u00e9hicules, les rejets de chaleur provenant des syst\u00e8mes de climatisation des b\u00e2timents, la g\u00e9om\u00e9trie des canyons urbains, la faible \u00e9vapotranspiration v\u00e9g\u00e9tale, l\u2019absorption et le r\u00e9fl\u00e9chissement de la chaleur par les routes, les sols et les structures. | Cet effet peut avoir lieu dans l\u2019ensemble d\u2019une zone urbaine ou peut \u00eatre tr\u00e8s localis\u00e9, en fonction de la combinaison des facteurs en cause, dans un quartier ou \u00e0 des points particuliers.",attention:"L\u2019effet d\u2019ICU peut \u00eatre \u00e9valu\u00e9 et justifi\u00e9 avec des outils de type \u201cSCORE ICU\u201d (d\u00e9velopp\u00e9 par NEPSEN Transition et ILO Paysages) ou \u00e9quivalent, qui permettent de d\u00e9terminer si les dispositions prises sur le projet am\u00e9liorent l\u2019impact sur les \u00eelots de Chaleur Urbains. Si le score obtenu est conforme au niveau absolu d\u2019alb\u00e9do demand\u00e9 ou am\u00e9lior\u00e9 au moins de 10%, alors l\u2019exigence est atteinte. | L\u2019effet d\u2019ICU peut \u00eatre mod\u00e9lis\u00e9 par une \u00e9tude a\u00e9raulique. Dans ce cas, les r\u00e9sultats de l\u2019\u00e9tude peuvent \u00eatre apport\u00e9s en justification. Les hypoth\u00e8ses de l\u2019\u00e9tude doivent \u00eatre coh\u00e9rentes avec les autres \u00e9tudes men\u00e9es sur l\u2019op\u00e9ration. Il n\u2019est pas n\u00e9cessaire de mod\u00e9liser la v\u00e9g\u00e9tation finement dans l\u2019\u00e9tude.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Analyse du site. | Taux de v\u00e9g\u00e9talisation, facteurs de r\u00e9flexion, albedo des sols, plans.</td><td>Exposition des objectifs.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plan masse, CCTP, masques. Etude ou score ICU. | Taux de v\u00e9g\u00e9talisation, facteurs de r\u00e9flexion, albedo des sols, plans.</td><td>Positionnement, surfaces et valeurs d\u2019albedo des espaces v\u00e9g\u00e9talis\u00e9s, rev\u00eatements de sol, etc.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE ou tout autre document. Etude ou score ICU. | Taux de v\u00e9g\u00e9talisation, facteurs de r\u00e9flexion, albedo des sols, plans.</td><td>Positionnement, surfaces et valeurs d\u2019albedo des espaces v\u00e9g\u00e9talis\u00e9s, rev\u00eatements de sol, etc.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>Taux de v\u00e9g\u00e9talisation, facteurs de r\u00e9flexion, albedo des sols, plans.</td><td>Positionnement, surfaces et valeurs d\u2019albedo des espaces v\u00e9g\u00e9talis\u00e9s, rev\u00eatements de sol. Visite in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td colspan=\"2\">Non concern\u00e9e. Sans objet.</td></tr></table>"},
"ACV1":{intro:"Analyse en Cycle de Vie (ACV)",context:"L\u2019exigence de ce th\u00e8me est de r\u00e9aliser un calcul ACV centr\u00e9 sur l\u2019op\u00e9ration concern\u00e9e, en construction neuve et en r\u00e9novation. Il n\u2019est pas apparu pertinent de demander une ACV en exploitation. | L\u2019objectif est d\u2019inciter \u00e0 anticiper les futurs niveaux r\u00e9glementaires (pour les b\u00e2timents concern\u00e9s), et d\u2019inciter \u00e0 concevoir les b\u00e2timents neufs et r\u00e9nov\u00e9s en fonction de plusieurs indicateurs environnementaux. | Ainsi, il est demand\u00e9 de r\u00e9aliser un calcul ACV : en construction neuve (pour les b\u00e2timents soumis \u00e0 la RE2020 selon la m\u00e9thode de la r\u00e9glementation en vigueur, pour les autres b\u00e2timents ou \u00e0 l\u2019international selon la norme EN 15978), en r\u00e9novation (m\u00e9thode TRC de l\u2019Alliance HQE-GBC ou m\u00e9thode inspir\u00e9e de la norme EN 15978). | Dans le cas de la r\u00e9novation, il conviendra de choisir uniquement une des deux exigences (ACV1.1.1 ou ACV1.2.1). | Pour les pays \u00e0 l\u2019international hors d\u2019Europe ou un calcul ACV n\u2019est pas possible, les exigences ACV1.3.1-Int, ACV1.3.2-Int et ACV1.3.3-Int valorisent les efforts faits pour limiter l\u2019impact carbone."},
"ACV1.1":{intro:"Calcul des impacts environnementaux de l\u2019op\u00e9ration",context:"Ce sous-th\u00e8me traite du calcul des indicateurs environnementaux de l\u2019op\u00e9ration selon la m\u00e9thode applicable (RE2020 pour les b\u00e2timents soumis en construction neuve, TRC pour la r\u00e9novation)."},
"ACV1.1.1":{attendu:"Calculer les impacts environnementaux de l\u2019op\u00e9ration selon la m\u00e9thode applicable (RE2020 pour construction neuve soumise, TRC pour r\u00e9novation).",definition:"Cette exigence est applicable en construction neuve uniquement pour les projets soumis \u00e0 la r\u00e9glementation environnementale 2020 (RE2020) en France m\u00e9tropolitaine, et en r\u00e9novation. | Les projets non soumis \u00e0 cette r\u00e9glementation environnementale (RE2020) et les projets internationaux ne sont pas soumis \u00e0 cette exigence. | En construction neuve : calcul des impacts environnementaux et \u00e9nerg\u00e9tiques selon la r\u00e9glementation environnementale en vigueur. Cette exigence valorise les projets qui pr\u00e9sentent des valeurs sur les indicateurs Ic Construction et Ic Energie inf\u00e9rieures aux valeurs Ic Construction Max et Ic Energie Max d\u00e9finies selon la m\u00e9thode de calcul RE2020, et en fonction des paliers temporels pr\u00e9vus dans l\u2019arr\u00eat\u00e9 de cette r\u00e9glementation. Ces paliers r\u00e9glementaires sont pr\u00e9vus en 2022, 2025 et 2028. | En r\u00e9novation : pour les projets en r\u00e9novation, il convient de calculer le TRC (Temps de Retour Carbone). Cet indicateur a \u00e9t\u00e9 d\u00e9fini dans le cadre du projet NZC de l\u2019Alliance HQE-GBC. Ce temps de retour carbone correspond au rapport entre l\u2019effort de r\u00e9novation (EGES PCE neuf) et le gain annuel \u00e9nerg\u00e9tique et environnemental li\u00e9 \u00e0 la r\u00e9novation ((EGES\u00e9nergie avant - EGES\u00e9nergie apr\u00e8s)/50 ans).",non_applicabilite:"Les projets non soumis \u00e0 la RE2020 et les projets internationaux prennent l\u2019exigence ACV1.2.1. Non applicable en exploitation.",notation:"Non Applicable | Pas de calcul | Niveau 1 : 6 points | Niveau 2 : 9 points | Niveau 3 : 12 points",attention:"En r\u00e9novation, il conviendra de choisir uniquement une des deux exigences (ACV1.1.1 ou ACV1.2.1).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs vis\u00e9s.</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des indicateurs (calcul r\u00e9glementaire RE2020). Rapport du Bureau d\u2019\u00e9tude phase conception avec prise en compte des paliers temporels r\u00e9glementaires. CCTP, Plans de conception.</td><td>Nombre de b\u00e2timents, surfaces des b\u00e2timents, nombre de places de parking, \u00e9quipements inscrits aux CCTP, sc\u00e9nario et usages. + pour Ic \u00e9nergie : Type d\u2019\u00e9nergie, Contenu CO\u2082 des RCU, potentiel Titre V RCU. + pour Ic parcelle : quantit\u00e9s inscrites dans les \u00e9tudes, CCTP, Bonne attribution au lot \u00ab Parcelle \u00bb, Plans. + pour Cep et pour Cep,nr : \u00e9quipements inscrits aux CCTP, sc\u00e9nario et usages, Tableaux quantitatifs (Lots).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des indicateurs (calcul r\u00e9glementaire RE2020). Rapport du Bureau d\u2019\u00e9tude phase r\u00e9alisation avec prise en compte des paliers temporels r\u00e9glementaires. DOE, Plans de r\u00e9alisation.</td><td>Nombre de b\u00e2timents, surfaces des b\u00e2timents, \u00e9quipements mis en \u0153uvre, sc\u00e9nario et usages. Coh\u00e9rence des \u00e9l\u00e9ments mis en \u0153uvre sur le chantier avec les DOE / \u00e9tude r\u00e9glementaire. + pour Ic \u00e9nergie, + pour Ic parcelle, + pour Cep et Cep,nr.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td colspan=\"2\">Non concern\u00e9e</td></tr></table>"},
"ACV1.2":{intro:"Indicateurs environnementaux",context:"Ce sous-th\u00e8me traite de l\u2019analyse et du traitement d\u2019un ou plusieurs indicateurs environnementaux, applicable aux projets internationaux, aux projets non soumis \u00e0 la RE2020, et en r\u00e9novation."},
"ACV1.2.1":{attendu:"Analyser et traiter un ou plusieurs indicateurs environnementaux.",definition:"Cette exigence est applicable \u00e0 tous les projets internationaux neufs ou r\u00e9nov\u00e9s. Elle est \u00e9galement applicable \u00e0 tous les projets non soumis \u00e0 la R\u00e9glementation Environnementale (RE2020), situ\u00e9s en France M\u00e9tropolitaine. | Cette exigence valorise les projets qui travaillent \u00e0 r\u00e9duire un ou plusieurs impacts environnementaux de r\u00e9f\u00e9rence tels que d\u00e9finis dans la norme EN 15978. | En construction neuve : r\u00e9aliser un calcul ACV selon la norme EN 15978 (utilis\u00e9e par le cadre d\u2019\u00e9valuation europ\u00e9en Level(s) et l\u2019exp\u00e9rimentation E+C-). En r\u00e9novation : r\u00e9aliser un calcul ACV selon la m\u00e9thode d\u00e9finie par l\u2019Alliance HQE-GBC pour la r\u00e9novation, tr\u00e8s similaire \u00e0 la m\u00e9thode norm\u00e9e europ\u00e9enne EN 15978. | Pour les projets internationaux hors Europe, les donn\u00e9es environnementales issues de banques de donn\u00e9es bas\u00e9es sur des normes et/ou r\u00e9glementations locales peuvent \u00eatre utilis\u00e9es.",non_applicabilite:"Non applicable en exploitation.",notation:"Non Applicable | Non atteint | Niveau 1 : 4 points | Niveau 2 : 8 points",attention:"Pour les projets internationaux hors Europe, les donn\u00e9es environnementales issues de banques de donn\u00e9es bas\u00e9es sur des normes et/ou r\u00e9glementations locales peuvent \u00eatre utilis\u00e9es.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs vis\u00e9s.</td><td>Objectifs vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des \u00e9missions de gaz \u00e0 effet de serre (calcul normatif EN 15978 ou selon la m\u00e9thode de calcul de l\u2019Alliance HQE-GBC). Rapport du Bureau d\u2019\u00e9tude phase conception. CCTP, Plans de conception.</td><td>Nombre de b\u00e2timents, surfaces des b\u00e2timents, nombre de places de parking, \u00e9quipements inscrits aux CCTP, sc\u00e9nario et usages, \u2026</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des \u00e9missions de gaz \u00e0 effet de serre (calcul normatif EN 15978 ou selon la m\u00e9thode de calcul de l\u2019Alliance HQE-GBC). Rapport du Bureau d\u2019\u00e9tude phase r\u00e9alisation. DOE, Plans de r\u00e9alisation.</td><td>Nombre de b\u00e2timents, surfaces des b\u00e2timents, \u00e9quipements mis en \u0153uvre, sc\u00e9nario et usages. Coh\u00e9rence des \u00e9l\u00e9ments mises en \u0153uvre sur le chantier avec les DOE/\u00e9tude r\u00e9glementaire.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td colspan=\"2\">Non concern\u00e9e</td></tr></table>"},
"ACV1.2.1.a":{attendu:"Renseigner la valeur de l\'impact sur le changement climatique total en kgCO₂/m²SU.",definition:"Cet indicateur est issu du calcul ACV réalisé selon la norme EN 15978. Il représente l\'impact sur le changement climatique total du bâtiment, exprimé en kgCO₂/m² de surface utile."},
"ACV1.3-Int":{intro:"Optimisation de l\u2019ACV sur l\u2019impact carbone",context:"Ce sous-th\u00e8me s\u2019applique \u00e0 l\u2019international dans les pays hors d\u2019Europe qui ne peuvent pas r\u00e9aliser d\u2019ACV. Il convient pour cela de justifier qu\u2019une ACV n\u2019est pas r\u00e9alisable par exemple par manque de donn\u00e9es, ou impossibilit\u00e9 d\u2019utiliser un outil de calcul ACV."},
"ACV1.3.1-Int":{attendu:"Objectiver l\u2019impact carbone des \u00e9l\u00e9ments les plus impactants sur l\u2019analyse du cycle de vie du projet. \u00c9tudier des variantes pour d\u00e9gager des \u00e9conomies potentielles importantes en \u00e9missions de CO\u2082 \u00e0 l\u2019\u00e9chelle du projet.",definition:"Cette exigence vise \u00e0 objectiver l\u2019impact carbone des \u00e9l\u00e9ments les plus impactants sur l\u2019analyse du cycle de vie du projet. Elle doit permettre de d\u00e9gager des \u00e9conomies potentielles importantes en \u00e9missions de CO\u2082 \u00e0 l\u2019\u00e9chelle du projet.",notation:"Non atteint | Niveau 1 : \u00e9tude de variantes sur l\u2019\u00e9l\u00e9ment le plus impactant de chaque lot architectural : 2 points | Niveau 2 : \u00e9tude de variantes sur l\u2019\u00e9l\u00e9ment le plus impactant de chaque lot y compris sur les lots techniques : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des \u00e9missions de gaz \u00e0 effet de serre sur le cycle de vie. Rapport du Bureau d\u2019\u00e9tude phase conception avec d\u00e9tail des variantes. CCTP, Plans de conception.</td><td>Coh\u00e9rence des donn\u00e9es environnementales (source, hypoth\u00e8ses\u2026), \u00e9missions totales, produits/mat\u00e9riaux les plus \u00e9metteurs, variantes propos\u00e9es et leur pertinence.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td colspan=\"2\">Idem phase Conception, pas de mise \u00e0 jour demand\u00e9e.</td></tr></table>"},
"ACV1.3.2-Int":{attendu:"Retenir et mettre en \u0153uvre des variantes r\u00e9duisant le potentiel de r\u00e9chauffement climatique.",definition:"Cette exigence valorise les projets qui travaillent \u00e0 r\u00e9duire le potentiel de r\u00e9chauffement climatique.",notation:"Non atteint | Niveau 1 : 30 kg CO\u2082/m\u00b2SDP \u00e9conomis\u00e9s : 1 point | Niveau 2 : 60 kg CO\u2082/m\u00b2SDP \u00e9conomis\u00e9s : 2 points | Niveau 3 : 100 kg CO\u2082/m\u00b2SDP \u00e9conomis\u00e9s : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des \u00e9missions de gaz \u00e0 effet de serre sur le cycle de vie. Rapport du Bureau d\u2019\u00e9tude phase conception avec d\u00e9tail des variantes. CCTP, Plans de conception.</td><td>Coh\u00e9rence des donn\u00e9es environnementales (source, hypoth\u00e8ses\u2026), \u00e9missions totales, gain sur les \u00e9missions des diff\u00e9rentes variantes.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des \u00e9missions de gaz \u00e0 effet de serre sur le cycle de vie. Rapport du Bureau d\u2019\u00e9tude phase r\u00e9ception. DOE, Plans de r\u00e9alisation. Visite in situ.</td><td>Coh\u00e9rence entre les variantes prises en compte dans l\u2019ACV et les \u00e9l\u00e9ments pr\u00e9sents sur site.</td></tr></table>"},
"ACV1.3.3-Int":{attendu:"Introduire des mat\u00e9riaux biosourc\u00e9s.",definition:"Cette exigence valorise les projets qui travaillent \u00e0 introduire des mat\u00e9riaux biosourc\u00e9s.",notation:"Non atteint | Niveau 1 : 2,5 kg/m\u00b2SDP de stockage biog\u00e9nique : 1 point | Niveau 2 : 5 kg/m\u00b2SDP de stockage biog\u00e9nique : 2 points | Niveau 3 : 9 kg/m\u00b2SDP de stockage biog\u00e9nique : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul du stockage carbone biog\u00e9nique. Rapport du Bureau d\u2019\u00e9tude phase conception. CCTP, Plans de conception.</td><td>Coh\u00e9rence des \u00e9l\u00e9ments biosourc\u00e9s avec les plans et les CCTP.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul du stockage carbone biog\u00e9nique. Rapport du Bureau d\u2019\u00e9tude phase r\u00e9ception. DOE, Plans de r\u00e9alisation. Visite in situ.</td><td>Coh\u00e9rence entre les \u00e9l\u00e9ments biosourc\u00e9s pris en compte et les \u00e9l\u00e9ments pr\u00e9sents sur site.</td></tr></table>"},
"BIOD1":{intro:"Respecter l\'environnement, c\'est prendre en compte la nature qui nous entoure et la biodiversité qui nous est vitale. La planète est un tissu vivant sur lequel le bâtiment a un impact à l\'échelle de la parcelle, du quartier mais aussi au niveau global. | La biodiversité traite des espèces (Homme, faune et flore, champignons, bactéries…) et des milieux qu\'ils soient « ordinaires » ou « remarquables » et parfois protégés. La diversité biologique est indispensable à la survie de l\'Homme tant par son besoin de nature que par les services dont il profite (production de nourriture, régulation du ruissellement, pollinisation…).",context:"Potentiel écologique : recouvre les notions de capacité et qualité écologiques. | La capacité correspond aux supports d\'accueil de la biodiversité offert par les surfaces au contact du vivant (toitures, façades, aménagements extérieurs et intérieurs, etc.) et les équipements pour accueillir faune et flore (nichoirs, gîtes, ruches, etc.). | La qualité écologique dépend de la diversité des habitats, des strates végétales, des gênes, de la maturité des écosystèmes, de la rareté des espèces, qualité des sols, etc. | Le potentiel écologique concerne le site d\'implantation du bâtiment ou les sites de productions des produits, équipements et services qu\'ils consomment. Son amélioration doit permettre aux écosystèmes de bien fonctionner (bouclage des cycles, fonction refuge, reproduction, alimentation, production de biomasse, etc.). | Continuité écologique : assurer la continuité des trames vertes et bleues, des corridors écologiques tant sur les sites de production que pour le bâtiment dont les formes, la volumétrie et les aménagements extérieurs peuvent limiter, voire éviter les effets de coupure ou de barrière, etc. | Innocuité envers le vivant : il s\'agit ici de limiter les sources de danger et nuisance sur les toitures, façades et aménagements extérieurs (étalement urbain, imperméabilité des sols, pollution lumineuse, collisions d\'oiseaux sur les façades vitrées, etc.)."},
"BIOD1.1":{intro:"Dans le cas où la biodiversité est traitée et gérée au niveau d\'une zone plus large que la seule parcelle du projet (zone d\'aménagement dépassant le cadre de la parcelle de l\'opération, parcelle avec plusieurs bâtiments dont le bâtiment objet de la demande de certification, etc.), les dispositions prises à cette échelle plus large peuvent permettre de justifier de l\'atteinte du niveau de performance visé. Le niveau sera considéré également comme atteint si les prescriptions demandées à l\'échelle de cette zone plus large (zone d\'aménagement par exemple) sont respectées.",context:"Rappel : L\'ensemble des exigences s\'appliquent sur le périmètre spatial et des responsabilités du demandeur de la certification."},
"BIOD1.1.1":{attendu:"Réaliser un diagnostic écologique complet du site initial, comprenant une pré-identification des habitats naturels et artificialisés, la détermination des supports potentiels de biodiversité, et une visite terrain exhaustive.",definition:"Le diagnostic du site initial comporte les étapes suivantes : Une pré-identification des habitats naturels et artificialisés. | Détermination des supports potentiels de biodiversité : Lors de la première étape de « pré-identification des habitats naturels et artificialisés », les milieux artificialisés doivent être mieux encadrés car ce sont des supports de biodiversité. La biodiversité ne s\'apprécie pas uniquement dans les « espaces extérieurs » mais aussi sur le bâti et à proximité directe d\'un site. La présence d\'un habitat artificialisé ne dédouane pas le demandeur de la certification de risques réglementaires. Dans le cas où il n\'y a pas d\'espaces végétalisés, une inspection du/des bâtiments doit être effectuée. Si la parcelle est entièrement bâtie, les enveloppes du bâtiment constituent également des habitats en milieu urbain et peuvent être des supports spontanés de sites de nidification par exemple. Certaines espèces sont totalement adaptées au milieu urbain, protégées nationalement et nicheuses en façades (anfractuosités, corniches, bas-reliefs, balcons, etc) et en toitures (cheminées, lucarnes, corniches, combles, etc) et parkings souterrains avec puits de lumière ouverts. Que ce soit sur des bâtiments modernes en toitures terrasses ou sur du Haussmannien toitures zinc, il existe de nombreux projets soutenant de la biodiversité urbaine. Il convient donc à cette première étape de déterminer, selon la typologie de façades et de toitures, les éléments plus ou moins propices à la nidification d\'oiseaux et mammifères protégés. Si le risque est existant, une observation doit être effectuée avec reportage photographique a minima. Dans le cas où il existe des indices de présence (survol, chant/cris, plumes, poils, cadavres, coquilles d\'œufs, fientes, etc.), l\'écologue doit réaliser un diagnostic plus approfondi. | Le diagnostic complet du site initial lors d\'une visite terrain qui comprend : L\'identification de l\'occupation des sols à l\'aide de la liste des habitats selon la classification CORINE biotope ou une autre classification. Le relevé des strates végétales par habitat. L\'identification des éléments remarquables et leur localisation (bois mort, zone humide, tas de pierres...). Le relevé des espèces végétales invasives et leur localisation. La cartographie des habitats du site initial. La présence et la localisation de la faune : nidifications, reproduction, alimentation. | Ce diagnostic est réalisé par un écologue, ou une personne compétente sur ce thème. Cette compétence s\'apprécie au travers des justifications suivantes : En France : qualification OPQIBI 07.01 (Etude de la biodiversité et des écosystèmes) ou 21.05 (Ingénierie des écosystèmes) ou équivalent. A défaut, sera pris en compte la formation initiale (≥ Master en écologie ou biologie – Niveau 1 de l\'éducation nationale en France) et l\'expérience (réalisation de diagnostics écologiques sur au moins deux opérations).",non_applicabilite:"Lorsque le site initial ne dispose pas d\'espaces extérieurs (végétalisés ou non), ou ne comporte pas de supports potentiels de biodiversité (sur les espaces extérieurs ou le bâti) cette exigence peut être déclarée comme non-applicable. Lorsque seul l\'axe Gestion est visé, cette exigence est non applicable.",reglementation:"En France : qualification OPQIBI 07.01 (Etude de la biodiversité et des écosystèmes) ou 21.05 (Ingénierie des écosystèmes) ou équivalent. A défaut : formation initiale (≥ Master en écologie ou biologie – Niveau 1) et expérience (réalisation de diagnostics écologiques sur au moins deux opérations).",important:"Ce diagnostic écologique du site peut être réalisé pour tous les types d\'opération, que ce soit une construction neuve, un bâtiment en rénovation ou en exploitation.",attention:"Définition : « Espaces extérieurs » : Espaces accessibles aux usagers du bâtiment et soumis aux intempéries.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>La mission d\'un écologue contenant les éléments et supports documentaires indiqués dans l\'exigence doit être prévue et planifiée, une vue aérienne du site.</td><td>Dimensionnement de la mission au regard des espaces extérieurs disponibles sur le site.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Un document présentant les données du diagnostic du site initial. La liste des habitats utilisée. CV de l\'écologue, qualifications, diplômes, opérations réalisées, ou attestation OPQIBI.</td><td>Cartographie des habitats et des éléments remarquables sur le site, identifiés lors du diagnostic initial, date de réalisation de la visite terrain.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Rapport de visite in situ avec notamment : L\'emplacement et l\'angle de la prise de vue des photographies prises pendant la visite terrain. Les photographies numérotées prises pendant la visite terrain. CV de l\'écologue, qualifications, diplômes, opérations réalisées, ou attestation OPQIBI.</td><td>Cartographie des habitats et des éléments remarquables sur le site, identifiés lors du diagnostic initial, date de réalisation de la visite terrain.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.1.2":{attendu:"Réaliser un diagnostic écologique du projet tenant compte de la mise en place des recommandations de l\'écologue pour améliorer le potentiel écologique du site.",definition:"Le diagnostic du projet comporte les étapes suivantes :<ul><li>La projection de l\'occupation du sol à l\'aide de la liste des habitats après la construction pour les bâtiments neufs, après la réalisation des travaux de rénovation, et après la mise en œuvre des préconisations de l\'écologue en vue d\'améliorer le potentiel écologique du site pour les bâtiments existants.</li><li>L\'identification des éléments remarquables conservés et leur localisation (bois mort, zone humide, tas de pierres...).</li><li>Le relevé des espèces végétales invasives et leur localisation.</li><li>La présence et la localisation de la faune : nidifications, reproduction, alimentation, afin de déterminer les éventuelles incidences réglementaires, d\'anticiper la phase chantier (repérage des nids à conserver en chantier) et les consignes pour la phase d\'exploitation.</li><li>La cartographie des habitats du projet.</li></ul> | Ce diagnostic est réalisé par un écologue, ou une personne compétente sur ce thème. Cette compétence s\'apprécie au travers des justifications suivantes : En France : qualification OPQIBI 07.01 (Etude de la biodiversité et des écosystèmes) ou 21.05 (Ingénierie des écosystèmes) ou équivalent. A défaut, sera pris en compte la formation initiale (≥ Master) en écologie ou biologie – Niveau 1 de l\'éducation nationale en France) et l\'expérience (réalisation de diagnostics écologiques sur au moins deux opérations).",non_applicabilite:"Lorsque seul l\'axe Gestion est visé, cette exigence est non applicable.",reglementation:"En France : qualification OPQIBI 07.01 (Etude de la biodiversité et des écosystèmes) ou 21.05 (Ingénierie des écosystèmes) ou équivalent. A défaut : formation initiale (≥ Master en écologie ou biologie) et expérience (réalisation de diagnostics écologiques sur au moins deux opérations).",important:"Ce diagnostic écologique du site peut être réalisé pour tous les types d\'opération, que ce soit une construction neuve, un bâtiment en rénovation ou en exploitation.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>La mission d\'un écologue contenant les éléments et supports documentaires indiqués dans l\'exigence doit être prévue et planifiée.</td><td>Dimensionnement de la mission de l\'écologue au regard des espaces extérieurs disponibles sur le site.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Un document présentant les données du diagnostic du projet. La liste des habitats utilisée. CV de l\'écologue, qualifications, diplômes, opérations réalisées, ou attestation OPQIBI.</td><td>Cartographie des habitats et des éléments remarquables sur le site, identifiés lors du diagnostic initial, date de réalisation de la visite terrain.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Un document présentant les données du diagnostic du projet. Un document détaillant la méthodologie d\'inventaire employée. Tableau récapitulatif désignant espèce par espèce, la réglementation applicable. Rapport de visite in situ avec notamment : L\'emplacement et l\'angle de la prise de vue des photographies prises pendant la visite terrain. Les photographies numérotées prises pendant la visite terrain. CV de l\'écologue, qualifications, diplômes, opérations réalisées, ou attestation OPQIBI.</td><td>Comparaison des cartographies du diagnostic initial et du diagnostic écologique du projet, mis à jour suite à la réalisation du projet de construction, rénovation ou la prise en compte des recommandations de l\'écologue.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.1.3":{attendu:"Mettre en œuvre les recommandations de l\'écologue, hiérarchisées en trois niveaux (prioritaires, importantes, facultatives), afin d\'améliorer le potentiel écologique du site.",non_applicabilite:"Lorsque seul l\'axe Gestion est visé, cette exigence est non applicable. Dans ce cas, les cinq points de l\'exigence seront déduits du total de points disponibles.",definition:"Suite au diagnostic écologique réalisé, l\'écologue formulera des recommandations hiérarchisées afin d\'améliorer le potentiel écologique du site a minima sur les aspects suivants :<table class=\"list-tbl\"><tr><td>La superficie des espaces végétalisés.</td></tr><tr><td>La diversité des strates et des habitats.</td></tr><tr><td>Les continuités écologiques intra et extra site.</td></tr><tr><td>La préservation des espèces et habitats présents sur le site initial.</td></tr><tr><td>La protection et l\'innocuité envers la faune.</td></tr><tr><td>La temporalité de mise en place des éléments paysagers sur le projet afin de s\'assurer de leur plantation optimale. Sur ce point, il est donc possible, voire souhaitable pour la bonne plantation des espèces envisagées, que la plantation ou l\'aménagement des espaces paysagers soient réalisés après l\'audit réalisation (en construction ou rénovation) ou après l\'audit exploitation concerné. Dans ce cas, il doit être apporté la preuve que la levée de garantie de reprise végétale sera bien effectuée, afin de s\'assurer que les végétaux sont en place, les pertes remplacées et que tous les aménagements sont en place.</td></tr></table>Ces recommandations seront hiérarchisées a minima sur trois niveaux (prioritaires, importantes, facultatives) en fonction du diagnostic réalisé. | Cette exigence vise à vérifier la mise en œuvre des recommandations de l\'écologue.",attention:"Dans le cas de toiture ou terrasse végétalisée, les indicateurs Biodiversité du Référentiel GreenRoofScore peuvent alimenter l\'analyse et la hiérarchisation des recommandations.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>La mission d\'un écologue contenant les éléments et supports documentaires indiqués dans l\'exigence doit être prévue et planifiée.</td><td>Dimensionnement de la mission de l\'écologue au regard des espaces extérieurs disponibles sur le site.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CV de l\'écologue, qualifications, diplômes, opérations réalisées, ou attestation OPQIBI, document de recommandations hiérarchisées sur l\'opération (prioritaires, importantes, facultatives), CCTP et documents graphiques (plan masse, plans toitures, photos…) comportant les recommandations formulées.</td><td>Cohérence entre les recommandations et les enjeux écologiques identifiés sur le site lors du diagnostic initial.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>CV de l\'écologue, qualifications, diplômes, opérations réalisées, ou attestation OPQIBI, DOE, documents graphiques de présentation des recommandations mises en œuvre (plan masse, plans toitures, photos…). Procès-verbal de levée de garantie de reprise végétale ou contrat indiquant sa réalisation future.</td><td>Cohérence entre les enjeux écologiques identifiés sur le site et les préconisations de l\'écologue mises en œuvre.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.1.4":{attendu:"S\'assurer que la construction n\'est pas érigée sur une zone sensible identifiée : terres arables de haute fertilité, terrains de haute valeur écologique reconnue ou terres forestières.",definition:"La construction n\'est pas érigée sur une des zones suivantes : Terres arables et terres de culture dont le niveau de fertilité du sol et de biodiversité souterraine est moyen à élevé, tel que visé dans l\'Enquête statistique aréolaire sur l\'utilisation/l\'occupation des sols de l\'Union (LUCAS). | Terrains vierges de haute valeur reconnue pour la biodiversité et terres servant d\'habitat d\'espèces menacées (flore et faune) figurant sur la liste rouge européenne ou la liste rouge de l\'UICN. | Terres répondant à la définition de la forêt établie dans la législation nationale et utilisée dans l\'inventaire national de gaz à effet de serre ou, lorsque cette définition n\'est pas disponible, répondant à la définition de la forêt donnée par la FAO.",non_applicabilite:"En Rénovation et en Exploitation (axes Bâtiment et Gestion), cette exigence est non-applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phases Programme, Conception, Réalisation, Exploitation axe Bâtiment</strong></td><td>Plan de situation par rapport au plan local d\'urbanisme.</td><td>Construction non érigée sur une zone sensible.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2":{intro:"Dans le cas où la biodiversité est traitée et gérée au niveau d\'une zone plus large que la seule parcelle du projet (zone d\'aménagement dépassant le cadre de la parcelle de l\'opération, parcelle avec plusieurs bâtiments dont le bâtiment objet de la demande de certification, etc.), les dispositions prises à cette échelle plus large peuvent permettre de justifier de l\'atteinte du niveau de performance visé. Le niveau sera considéré également comme atteint si les prescriptions demandées à l\'échelle de cette zone plus large (zone d\'aménagement par exemple) sont respectées.",context:"Cas de non-applicabilité : Lorsque seul l\'axe Gestion est visé, le bloc d\'exigences est non applicable."},
"BIOD1.2.1":{attendu:"Calculer et améliorer le Coefficient de Biotope par Surface (CBS) du projet par rapport à la valeur imposée localement ou atteindre un CBS minimal.",definition:"Il s\'agit ici de calculer le CBS (Coefficient de Biotope par Surface) et de s\'assurer que le projet : améliore le coefficient imposé localement par les documents d\'urbanisme s\'ils existent, respecte une valeur minimale. | Le CBS est un coefficient qui décrit la proportion des surfaces favorables à la biodiversité (surface écoaménageable) par rapport à la surface totale d\'une parcelle. Le calcul du CBS permet d\'évaluer la qualité environnementale d\'une parcelle, d\'un ilot, d\'un quartier, ou d\'un plus vaste territoire. | Exiger l\'atteinte d\'un CBS dans un projet d\'aménagement ou de renouvellement urbain permet de s\'assurer globalement de la qualité d\'un projet, en réponse à plusieurs enjeux : amélioration du microclimat, infiltration des eaux pluviales et alimentation de la nappe phréatique, création et valorisation d\'espace vital pour la faune et la flore. | Le CBS est une valeur qui se calcule de la manière suivante : CBS = surface écoaménageable / surface de la parcelle. La surface écoaménageable est calculée à partir des différents types de surfaces qui composent la parcelle : Surface écoaménageable = (surface de type A x coef. A) + (surface de type B x coef. B) + … + (surface de type N x coef. N) | Chaque type de surface est multiplié par un coefficient compris entre 0 et 1, qui définit son potentiel. Les surfaces verticales lorsqu\'elles sont végétalisées sont à prendre en compte. | Les coefficients à considérer suivant les 9 types de surface sont :<table class=\"list-tbl\"><tr><th>Type de surface</th><th>Coefficient</th></tr><tr><td>1. Surfaces imperméables</td><td>0</td></tr><tr><td>2. Surfaces semi-perméables (air/eau), sans végétation</td><td>0,3</td></tr><tr><td>3. Surfaces semi-ouvertes perméables (air/eau), sans végétation</td><td>0,5</td></tr><tr><td>4. Espaces verts sur dalles (terre végétale &lt; 80 cm)</td><td>0,5</td></tr><tr><td>5. Espaces verts sur dalles (terre végétale &gt; 80 cm)</td><td>0,7</td></tr><tr><td>6. Espaces verts en pleine terre</td><td>1</td></tr><tr><td>7. Toiture classique</td><td>0,2</td></tr><tr><td>8. Mur végétalisé</td><td>0,5</td></tr><tr><td>9. Toiture végétalisée (extensif/intensif)</td><td>0,7</td></tr></table>",attention:"La méthode décrite ici est celle de l\'ADEME (fiche outil n°11 de l\'ADEME). En France, en alternative à la méthode décrite ci-dessus le CBSh (Coefficient de Biotope Surfacique harmonisé) développé au sein du projet CAP2030 peut être utilisé. Les mêmes niveaux de performance sont visés.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs de CBS.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans spécifiant : les surfaces aménagées et leurs superficies.</td><td>Cohérence entre les hypothèses du calcul du CBS et les CCTP (ou équivalent) du projet.</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, visite in situ.</td><td>Cohérence entre les hypothèses du calcul de CBS et les surfaces mises en œuvre sur le projet.</td></tr><tr><td><strong>Phase Exploitation (axes Bâtiment)</strong></td><td>Visite in situ, plans.</td><td>Cohérence entre les hypothèses du calcul de CBS et les surfaces mises en œuvre sur le projet.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2.2":{attendu:"Créer ou maintenir un nombre minimal de types d\'habitats pertinents sur la parcelle.",definition:"Il convient de déterminer le nombre de types d\'habitats présents sur la parcelle à partir du diagnostic écologique du projet. Ces habitats doivent être pertinents vis-à-vis du contexte écologique et des espèces cibles environnantes. | Les points peuvent être obtenus des deux façons suivantes : Dans le cas où un diagnostic écologique n\'a pas été réalisé par un écologue : si le nombre de types d\'habitats est compris dans les différentes fourchettes proposées (2 à 4, 5 à 6, >6), et si ce nombre est au moins égal au nombre de types d\'habitats présents à l\'origine sur le site. Ces types d\'habitats peuvent être ceux présents à l\'origine sur le site ou être différents. Si les types d\'habitats sont différents, une justification doit être fournie, pour s\'assurer de leur compatibilité avec les habitats présents sur le site. Ainsi, les habitats créés doivent répondre à des enjeux et aux besoins des espèces susceptibles de parvenir jusqu\'au site. Il faut également que les habitats recréés soient compatibles avec le biotope et les espèces cibles environnantes. | Dans le cas où un diagnostic écologique a été réalisé par un écologue : si le nombre de type d\'habitats présents sur le projet atteint un pourcentage minimum par rapport au nombre potentiel maximal d\'habitats pertinents sur le projet, déterminé lors du diagnostic écologique (≥30%, ≥50%, ≥75%). | Proposition de liste de types d\'habitats :<table class=\"list-tbl\"><tr><th style=\"width:40px;text-align:center\">N°</th><th style=\"text-align:left\">Type d\'habitat</th></tr><tr><td style=\"text-align:center\">1</td><td>Espaces naturels non gérés (bois, pelouse, etc.)</td></tr><tr><td style=\"text-align:center\">2</td><td>Espaces agricoles gérés intensivement</td></tr><tr><td style=\"text-align:center\">3</td><td>Autres espaces agricoles, aménagements d\'agriculture urbaine</td></tr><tr><td style=\"text-align:center\">4</td><td>Massifs et parterres ornementaux, prairie plantée, gazons</td></tr><tr><td style=\"text-align:center\">5</td><td>Gazons de terrain sportif</td></tr><tr><td style=\"text-align:center\">6</td><td>Parcs boisés, alignements d\'arbres, haies arborées, arbres isolés sur herbacées hautes</td></tr><tr><td style=\"text-align:center\">7</td><td>Parcs boisés, alignements d\'arbres, haies, noues plantées, arbres isolés sur gazon</td></tr><tr><td style=\"text-align:center\">8</td><td>Alignements d\'arbres, arbres isolés sur sol artificialisé, patios arborés</td></tr><tr><td style=\"text-align:center\">9</td><td>Surfaces minérales végétalisées</td></tr><tr><td style=\"text-align:center\">10</td><td>Toitures muscinales</td></tr><tr><td style=\"text-align:center\">11</td><td>Toitures herbacées</td></tr><tr><td style=\"text-align:center\">12</td><td>Toitures arbustives/arborées</td></tr><tr><td style=\"text-align:center\">13</td><td>Milieux aquatiques</td></tr><tr><td style=\"text-align:center\">14</td><td>Berges semi-naturelles</td></tr><tr><td style=\"text-align:center\">15</td><td>Composts</td></tr><tr><td style=\"text-align:center\">16</td><td>Parois minérales (murets, murs, façades)</td></tr></table> | Si une autre liste d\'habitats est utilisée, elle devra être transmise en mode de preuve. La classification CORINE biotope peut aussi être utilisée. | Il est attendu a minima en justification pour justifier de la pertinence des habitats : Un tableau avec le listing des habitats, leur descriptif, leur localisation, leur classification (CORINE Biotope ou autre), et les espèces cibles identifiées.",attention:"Habitats pertinents à considérer : Espaces naturels non gérés, Espaces agricoles, Aménagements agricoles urbains, Ornementaux, Terrains sportifs, Parcs et alignements d\'arbres, Alignements et arbres en milieu urbain, Surfaces minérales végétalisées, Toitures muscinales, herbacées, arbustives/arborées, Milieux aquatiques, Berges, Composts, Parois minérales.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs de nombre d\'habitats pertinents sur l\'opération.</td><td>Objectifs visés.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans.</td><td>Nombre de types d\'habitat ou pourcentage minimal d\'habitats pertinents atteint.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Visite in situ, inventaire des habitats, photos, liste des habitats utilisée.</td><td>Nombre de types d\'habitats ou pourcentage minimal d\'habitats pertinents atteint. Identification de ces habitats à l\'aide des photos réalisées sur site.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2.3":{attendu:"Créer ou maintenir au minimum 3 à 4 types de strates végétales sur la parcelle.",definition:"En lien avec le diagnostic initial du site (s\'il est réalisé), il convient de déterminer le nombre de types de strates végétales présentes sur la parcelle. | Les points sont obtenus si le nombre de types de strates végétales est au moins égal à 3 ou 4, et si ce nombre est au moins égal au nombre de types de strates végétales présentes à l\'origine sur le site. | Ces types de strates végétales peuvent être celles présentes à l\'origine sur le site ou être différentes. Si les types de strates sont différentes, une justification doit être fournie, pour s\'assurer de leur compatibilité avec les types de strates présentes sur le site. Il faut en effet que les types de strates recréés soient compatibles avec le biotope. | A minima, les quatre types de strates suivants sont pris en compte dans cette exigence : La strate cryptogamique ou muscinale composée de lichens et mousses, jusqu\'à quelques millimètres de hauteur. | La strate herbacée composée d\'herbacées (dont notamment herbes, prairies, etc.), jusqu\'à 1m, 1,50m de hauteur à maturité. | La strate arbustive composée d\'arbustes ou buissons (mesurant de 0,3m à 2m à l\'état adulte pour la strate arbustive basse, de 2 à 7m pour la strate arbustive haute). | La strate arborée composée d\'arbres dont la hauteur débute vers les 8m.",attention:"Le type de strate s\'évalue selon la hauteur projetée à maturité des végétaux. Les espèces dites couvre-sols et espèces à très faible développement, dans le cas où elles ne constituent pas une strate spécifique, peuvent être considérées dans la strate cryptogamique ou muscinale. Les plantes grimpantes dans le cas où elles ne constituent pas une strate spécifique, peuvent être considérées dans la strate arbustive. | Pour le territoire de La Réunion : Couvrante/Rampante (Strate herbacées jusqu\'à 1m, 1m50 à maturité) | Arbustif basse (0,3m à 2m) | Arbustif haut (2 à 7m) | Arborée (à partir de 8m). Pour les autres territoires français ultra-marins et à l\'international : Une adaptation des strates végétales peut être proposée et justifiée en fonction du contexte. Cette adaptation doit comporter a minima 4 strates.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs de nombre de strates sur l\'opération.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans, coupes.</td><td>Nombre de strates par rapport aux strates préexistantes.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Visite in situ, inventaire des strates, photos.</td><td>Nombre de strates par rapport aux strates préexistantes.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2.4":{attendu:"Sélectionner des espèces végétales locales à hauteur d\'au moins 50% et assurer qu\'aucune espèce envahissante n\'est introduite.",definition:"Il convient de s\'assurer que les espèces sont non invasives, et adaptées au climat et au terrain. Pour ce faire, il est demandé de : veiller à ce qu\'au moins 50% des espèces plantées soient d\'origine locale, s\'assurer que les espèces introduites sont non invasives. | Une justification a minima documentaire est attendue, en s\'appuyant sur les espèces répertoriées par les autorités locales. | En France, le réseau des Conservatoires Botaniques Nationaux (CBN) répertorie les espèces, dans l\'une de ses 12 listes rattachées à la zone biogéographique adaptée (une liste par CBN, le nombre de CBN étant amené à croître).",attention:"Espèce locale (ou de nos régions ou espèce indigène ou autochtone) : Se dit d\'une plante ayant colonisé le territoire considéré (la région) par des moyens naturels, ou bien à la faveur de déplacements humains, mais dont la présence est dans tous les cas attestée avant 1500 après JC. | Espèce invasive : Une espèce exotique envahissante est une espèce allochtone dont l\'introduction par l\'Homme (volontaire ou fortuite), l\'implantation et la propagation menacent les écosystèmes, les habitats ou les espèces indigènes avec des conséquences écologiques ou économiques ou sanitaires négatives (UICN 2000). | Pour le territoire de La Réunion : Proscrire l\'introduction d\'espèces exotiques envahissantes ou potentiellement envahissantes. Privilégier une sélection d\'essences selon la liste d\'espèces indigènes DAUPI. Aménager les espaces paysagers tenant compte de la Stratégie de Lutte contre les espèces invasives à La Réunion.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectif de choix d\'espèces locales.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Essences choisies dans le CCTP, label (Végétal local ou autre), plans, fiches techniques, bons de commande et/ou bons de livraison des éléments prévus au CCTP.</td><td>Cohérence entre le choix des essences et le contexte local.</td></tr><tr><td><strong>Phase Réalisation</strong></td><td>DOE, visite in situ, label, bons de commande, bons de livraison, factures.</td><td>Cohérence entre le choix des essences et le contexte local.</td></tr><tr><td><strong>Phase Exploitation (axes Bâtiment)</strong></td><td>Visite in situ, plans, label. Documents complémentaires : Plan d\'entretien et de maintenance, présentation de la préservation/amélioration de la biodiversité.</td><td>Cohérence entre les essences plantées et le contexte local.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2.5":{attendu:"Minimiser l\'impact sanitaire lié à la palette végétale en ne dépassant pas 40% d\'espèces à fort potentiel allergisant.",definition:"Il est demandé de minimiser l\'introduction d\'espèces allergènes (la palette végétale du site ne devra pas comporter plus de 40% d\'espèces végétales ayant un potentiel allergisant fort), en particulier les espèces dont le potentiel allergisant est fort (cyprès, bouleau, graminées, ambroisie, aulne, chêne, charme, pariétaire, armoise, etc). | Le potentiel allergisant d\'une espèce végétale est la capacité de son pollen à provoquer une allergie pour une partie non négligeable de la population. | Les classes de potentiel allergisant, dépendent du type de pollen, de sa concentration dans l\'air, de son retentissement chimique. | L\'objectif n\'est pas ici de proscrire certaines essences, mais bien d\'offrir un haut niveau de qualité sanitaire des espaces extérieurs tout en favorisant l\'accroissement de la biodiversité sur la parcelle. Il est donc tout à fait envisageable d\'introduire des essences à potentiel allergène élevé, à condition par exemple que celles-ci soient minoritaires en densité ou que leur localisation ait été spécifiquement déterminée pour minimiser les risques sanitaires pour les usagers (éloignés des locaux sensibles et absents des espaces confinés de type cour fermée).",attention:"En France, les classes de potentiel allergisant sont établies par le RNSA - Réseau National de Surveillance Aérobiologique (RNSA) – http://www.pollens.fr/accueil.php. Les espèces allergènes à considérer sont à adapter géographiquement suivant informations répertoriées par les autorités locales. | Pour le territoire de La Réunion : La liste des principales espèces allergènes est donnée par les données ATMO Réunion.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectif de choix des espèces végétales.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plans et localisation des espèces à risque. CCTP. Notice d\'intégration paysagère. Fiches techniques présentant le classement allergène des essences plantées.</td><td>Les fiches techniques présentant le classement allergène des essences plantées.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Visite in situ, inventaire des espèces, photos.</td><td>Conformité avec l\'objectif du maximum 40% d\'espèces allergènes fortes.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2.6":{attendu:"Justifier de la reconstitution/amélioration d\'habitats et des conditions de vie de la faune en cohérence avec le diagnostic écologique réalisé.",definition:"En lien avec le diagnostic initial du site (s\'il est réalisé), et en cohérence avec les autres exigences du thème, il est demandé ici de : Justifier des espèces implantées, dans une optique de reconstitution des habitats sur le site. | Mener à la période adéquate une étude avec des méthodes de recensement appropriées, ces éléments devant être justifiés relativement au contexte. | Prendre en compte l\'influence du bâtiment sur la faune de la parcelle. Il s\'agit de prendre les dispositions nécessaires pour limiter les sources de danger et nuisance sur les toitures, façades et aménagements extérieurs (imperméabilité des sols, pollution lumineuse, collisions d\'oiseaux sur les façades vitrées, etc.).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectif pour l\'amélioration/la reconstitution de l\'habitat et des conditions de vie de la faune sur la parcelle.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plans, CCTP. Dispositions prises pour la reconstitution d\'habitats et pour limiter les sources de danger et de nuisance pour la faune (amélioration de la qualité du sol, choix des structures végétales, création de refuges, etc.).</td><td>Cohérence entre l\'objectif et le contexte existant.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Visite in situ, inventaire des dispositions, photos.</td><td>Mise en place des dispositions prévues à la phase conception.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2.7":{attendu:"Assurer la connexion des espaces végétalisés à l\'intérieur du site et avec les espaces extérieurs voisins, en respectant la séquence ERC.",definition:"Il convient donc ici d\'apprécier le nombre d\'espaces végétalisés (au sens des d\'habitats identifiés) de l\'opération, ainsi que la qualité de leurs connexions. | Connexion intra site : Il s\'agit de faire en sorte, sur le projet, que la majorité des espaces végétalisés soient connectés entre eux de façon satisfaisante. En fonction du nombre d\'habitats identifiés sur l\'opération, le nombre de connexion selon le mode de déplacement des espèces cibles sera évalué. Un corridor assure des connexions entre des réservoirs de biodiversité, offrant aux espèces des conditions favorables à leur déplacement et à l\'accomplissement de leur cycle de vie. Il existe différents type de corridors : Linéaires (haies, chemins et bords de chemins, ripisylves, bandes enherbées le long des cours d\'eau…). | Discontinus (ponctuation d\'espaces-relais ou d\'îlots-refuges, mares permanentes ou temporaires, bosquets…). | La fragmentation est une des causes majeures de l\'érosion de la biodiversité. Les « corridors » sont des éléments paysagers linéaires qui permettent la dispersion d\'espèces animales ou végétales entre deux habitats, au sein d\'un environnement plus ou moins hostile. | Connexion extra site : Il convient aussi d\'évaluer si le projet permet d\'assurer une continuité des espaces créés avec les espaces végétalisés existants sur les parcelles voisines. | Les continuités écologiques correspondent à l\'ensemble formé par : Des réservoirs de biodiversité (zones vitales, riches en biodiversité, où les individus peuvent réaliser l\'ensemble de leur cycle de vie). | Des corridors écologiques (voies de déplacements empruntées par la faune et la flore qui relient les réservoirs de biodiversité). | Et les cours d\'eau et canaux. | Les éléments et espaces participants à la trame écologique peuvent être les suivants : espaces agricoles isolés, espaces verts, couloirs verts liés aux modes doux, cours d\'eau, mares, ripisylve, jardins, alignements d\'arbres, etc… Il y a continuité écologique lorsqu\'il existe une liaison et/ou une contiguïté entre des milieux de même nature. Cette liaison peut être de nature structurale (ex : 2 prairies isolées reliées par une bande enherbée), ou de nature fonctionnelle, c\'est-à-dire lorsque les organismes vivants se déplacent d\'un milieu à l\'autre. La continuité écologique n\'est pas obligatoirement une continuité spatiale. | Il est donc important de : Limiter les fragmentations de la continuité écologique par la création d\'obstacles tels que des barrières, des clôtures, un lieu de stockage des déchets, ou des obstacles (immatériels) tels que le bruit, la lumière, des pollutions ou certaines pratiques de gestion des espaces verts. | Identifier la nature de la fragmentation et le niveau de vulnérabilité. Pour cela, la méthodologie des incidences de projet d\'aménagement du volet faune-flore d\'étude d\'impact peut être repris. | Les différents points ci-dessus sont mis en place en appliquant la séquence ERC : Éviter si besoin en modifiant le projet, Réduire les impacts potentiels et, Compenser s\'il reste des impacts résiduels. | Pour déterminer si l\'exigence est atteinte, il convient de procéder comme suit : Sur la base des habitats pertinents identifiés en BIOD1.2.2, présenter un plan et une coupe avec la connectivité des habitats selon le mode de déplacement des espèces cibles. Cela doit permettre de se rendre compte des obstacles entre deux habitats mais aussi des différences de niveaux entre deux habitats (RDC/R+3 par exemple). En effet, avec l\'étagement, l\'attractivité des habitats diminue fortement pour bon nombre de cortèges. | Un cortège désigne un ensemble d\'espèces ayant des caractéristiques écologiques ou biologiques communes. Les espèces cibles peuvent ainsi être regroupées en cortèges : passereaux cavernicoles, passereaux des milieux ouverts, oiseaux des milieux fermés, invertébrés du sol, insectes pollinisateurs, rapaces, mammifères, etc. | Il convient de déterminer le nombre de cortèges présents sur le site et le nombre de cortèges favorisés par le projet en termes de connectivité (sans obstacles). | L\'exigence est atteinte si le nombre de cortèges favorisés (connectivité des habitats du site aux espèces cibles du secteur) est supérieur à la moitié des cortèges inventoriés.",non_applicabilite:"Dans le cas où le projet ne présente pas d\'espaces extérieurs pouvant être en connexion avec l\'aménagement urbain, l\'exigence peut être considérée comme non-applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectif pour les connexions intra et extra site.</td><td>Définition des objectifs à atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plans, CCTP. Scénarios de connexions mises en place et justification que le scénario retenu a bien respecté la séquence ERC.</td><td>Cohérence entre l\'objectif et le contexte existant.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Visite in situ, inventaire des dispositions prises, photos.</td><td>Mise en place des connexions prévues, vérification de l\'absence d\'obstacles.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"BIOD1.2.8":{attendu:"Mettre en œuvre des mesures compensatoires volontaires appliquant la séquence ERC (Éviter, Réduire, Compenser) pour la perte de biodiversité.",definition:"Cette exigence a pour objectif de pousser à la compensation volontaire, au-delà des compensations réglementairement applicables. | Pour la biodiversité ordinaire, prendre des dispositions pour éviter au maximum sa destruction, et compenser la perte de biodiversité en rétablissant les surfaces et habitats détruits. | Pour mener à bien ces mesures, il convient d\'appliquer la séquence ERC, décrite ci-dessous. | Définition de la « séquence ERC » : Les questions environnementales doivent faire partie des données de conception des projets au même titre que les autres éléments techniques, financiers, etc. Cette conception doit tout d\'abord s\'attacher à éviter les impacts sur l\'environnement, y compris au niveau des choix fondamentaux liés au projet (nature du projet, localisation, voire opportunité). Cette phase est essentielle et préalable à toutes les autres actions consistant à minimiser les impacts environnementaux des projets, c\'est-à-dire à réduire au maximum ces impacts et en dernier lieu, si besoin, à compenser les impacts résiduels après évitement et réduction. C\'est en ce sens et compte tenu de cet ordre que l\'on parle de « séquence Éviter, Réduire, Compenser ». | Ainsi, dans la conception et la mise en œuvre de leurs projets, les maîtres d\'ouvrage doivent définir les mesures adaptées pour éviter, réduire et, lorsque c\'est nécessaire et possible compenser leurs impacts négatifs significatifs sur l\'environnement. Cette compensation peut se faire également par mutualisation sur un site à proximité. | En France : La séquence ERC est décrite dans le document « Lignes directrices nationales sur la séquence éviter, réduire et compenser les impacts sur les milieux naturels » - MEDDE, Octobre 2013. La participation au programme Nature 2050, ou équivalent, permet également d\'inscrire le projet dans une démarche de compensation de la biodiversité. Nature 2050 est un programme pilote d\'actions concrètes favorisant la restauration de la biodiversité et l\'adaptation des territoires agricoles, naturels et forestiers français, recourant à des solutions basées sur la nature.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points vérifiés a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectif de mesures compensatoires.</td><td>Objectif d\'Evitement de Réduction et de Compensation des impacts sur la biodiversité.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plans, CCTP. Classements des espèces. Document de synthèse des mesures d\'évitement en amont du projet, de réduction en conception, de compensation en réalisation, puis de suivi en exploitation (ce document peut être issu d\'un rapport d\'un écologue).</td><td>Mesures prises pour éviter, réduire et, lorsque c\'est nécessaire et possible, compenser leurs impacts négatifs significatifs sur l\'environnement.</td></tr><tr><td><strong>Phases Réalisation et Exploitation axe Bâtiment</strong></td><td>Visite in situ, inventaire des mesures ERC prises à cette phase, photos.</td><td>Mise en place des mesures ERC prévues à la conception.</td></tr><tr><td><strong>Phase Exploitation (axe Gestion)</strong></td><td colspan=\"2\">Sans objet - Non concernée</td></tr></table>"},
"CARB1":{intro:"Emissions de CO\u2082",context:"Le changement climatique est en partie d\u00fb aux \u00e9missions de gaz \u00e0 effet de serre. Par convention, on se limitera ici aux six gaz pris en compte par le protocole de Kyoto, \u00e0 savoir : CO\u2082 (Dioxyde de carbone), N\u2082O (Protoxyde d\u2019azote), CH\u2084 (M\u00e9thane), HFC (Hydrofluorocarbures), PFC (Perfluorocarbures), SF\u2086 (Hexafluorure de soufre). | Les \u00e9missions de gaz \u00e0 effet de serre peuvent s\u2019\u00e9valuer sur l\u2019ensemble du cycle de vie du b\u00e2timent. Elles peuvent donc \u00e9galement \u00eatre calcul\u00e9es, pendant la phase d\u2019utilisation du b\u00e2timent, \u00e0 partir des consommations d\u2019\u00e9nergie en utilisant des facteurs de conversion. C\u2019est l\u2019objectif de ce th\u00e8me. | D\u2019autre part, le th\u00e8me traite \u00e9galement les \u00e9missions de CO\u2082 li\u00e9es aux d\u00e9placements des usagers du b\u00e2timent. Pour le moment elles sont trait\u00e9es de fa\u00e7on simplifi\u00e9e en tenant compte des usagers principaux et du motif de d\u00e9placement \u00ab b\u00e2timent-domicile \u00bb uniquement. Seul un affichage de la valeur calcul\u00e9e est propos\u00e9. Il a \u00e9t\u00e9 consid\u00e9r\u00e9 en effet qu\u2019il \u00e9tait trop t\u00f4t pour pouvoir proposer une classification sur cet indicateur. | Ce th\u00e8me se d\u00e9compose donc en deux blocs d\u2019exigences : Emissions de CO\u2082 li\u00e9es aux consommations d\u2019\u00e9nergie en phase d\u2019utilisation du b\u00e2timent, et Emissions de CO\u2082 li\u00e9es aux d\u00e9placements. Le premier bloc d\u2019exigences attribue sa note au th\u00e8me."},
"CARB1.1":{intro:"Emissions de CO\u2082 pendant la phase d\u2019utilisation du b\u00e2timent",context:"Ce sous-th\u00e8me traite des \u00e9missions de CO\u2082 pendant la phase d\u2019utilisation du b\u00e2timent, exprim\u00e9es en kgCO\u2082eq/m\u00b2SDP.an."},
"CARB1.1.1":{attendu:"Emissions de CO\u2082 pendant la phase d\u2019utilisation du b\u00e2timent (kgCO\u2082/m\u00b2SDP.an).",definition:"Le but est d\u2019\u00e9valuer les \u00e9missions de gaz \u00e0 effet de serre (GES) effectives du b\u00e2timent pendant sa phase d\u2019utilisation. Un facteur d\u2019\u00e9mission en kilogramme \u00e9quivalent CO\u2082 par kilowattheure PCI d\u2019\u00e9nergie finale permet de passer d\u2019une consommation d\u2019\u00e9nergie \u00e0 une \u00e9mission de GES. | Se reporter au chapitre \u00ab Valeurs d\u2019\u00e9missions de carbone \u00bb pour consulter les valeurs-seuils requises pour chaque type d\u2019activit\u00e9. | Le p\u00e9rim\u00e8tre concern\u00e9 par cette exigence est l\u2019ensemble des postes de consommation \u00e9nerg\u00e9tique du b\u00e2timent (en France : postes r\u00e9glementaires, immobiliers non r\u00e9glementaires et mobiliers). | Nota : les consommations li\u00e9es aux IRVE ne sont pas \u00e0 prendre en compte dans le cas d\u2019une Conception ou R\u00e9novation. En phase Exploitation, elles seront d\u00e9duites sur la base des consommations relev\u00e9es \u00e0 un point de livraison (PDL) sp\u00e9cifique (n\u00b0 de PDL) ou gr\u00e2ce \u00e0 un sous-comptage sp\u00e9cifique. | *Note : Les classes de l\u2019usage Aires de service sont construites en prenant l\u2019hypoth\u00e8se d\u2019un mix 100% \u00e9lectrique, une demande de principe d\u2019\u00e9quivalence peut \u00eatre r\u00e9alis\u00e9e dans le cas o\u00f9 le mix serait diff\u00e9rent et les classes inadapt\u00e9es.",attention:"Pour \u00e9valuer cette exigence, il convient de reporter dans l\u2019exigence CARB1.1.1.a dans ISIA la classe des \u00e9missions carbone atteinte, calcul\u00e9e dans le fichier Excel fourni en IDEN1.1.3."},
"CARB1.1.1.a":{attendu:"Classe correspondante aux \u00e9missions de CO\u2082 pendant la phase d\u2019utilisation du b\u00e2timent.",definition:"L\u2019indicateur \u00e0 calculer est l\u2019\u00e9mission de gaz \u00e0 effet de serre (GES) en phase d\u2019utilisation en kg eq. CO\u2082/m\u00b2SDP.an. | Les consommations \u00e9nerg\u00e9tiques \u00e0 prendre en compte sont celles calcul\u00e9es pour la phase d\u2019utilisation du b\u00e2timent dans le th\u00e8me Energie : La consommation effective du b\u00e2timent dans le cas o\u00f9 les factures \u00e9nerg\u00e9tiques sont exploitables, ou la consommation pr\u00e9visionnelle du b\u00e2timent dans le cas o\u00f9 les factures \u00e9nerg\u00e9tiques n\u2019existent pas ou ne sont pas exploitables. | Les facteurs d\u2019\u00e9mission de CO\u2082 des \u00e9nergies consomm\u00e9es sont exprim\u00e9s en kilogramme de CO\u2082 par kilowattheure d\u2019\u00e9nergie finale. Ils sont d\u00e9finis dans les tableaux ci-dessous pour les projets en France m\u00e9tropolitaine (extrait de la r\u00e9glementation environnementale 2020).",reglementation:"Coefficients de conversion : 1 kWhEF \u21d4 2,58 kWhEP pour l\u2019\u00e9lectricit\u00e9. | 1 kWhEF \u21d4 1 kWhEP pour les autres \u00e9nergies (gaz, r\u00e9seaux de chaleur, bois, etc.). | 1 kWhEF \u21d4 (1 - taux ENR en %) kWhEP pour les r\u00e9seaux de chaleur. | Pour l\u2019Ile de La R\u00e9union : 1 kWhEF \u21d4 2,8 kWhEP pour l\u2019\u00e9lectricit\u00e9 (ADEME). | L\u2019\u00e9nergie finale (kWhEF) est la quantit\u00e9 d\u2019\u00e9nergie disponible pour l\u2019utilisateur final. L\u2019\u00e9nergie primaire (kWhEP) est la consommation n\u00e9cessaire \u00e0 la production de cette \u00e9nergie finale. | Pour l\u2019international, les coefficients de conversion locaux sont \u00e0 prendre en compte. S\u2019il n\u2019en existe pas, par d\u00e9faut les coefficients ci-dessus s\u2019appliquent. | Pour les b\u00e2timents reli\u00e9s \u00e0 un r\u00e9seau de chaleur, le taux d\u2019ENR et le contenu CO\u2082 de l\u2019\u00e9nergie consomm\u00e9e est celui d\u00e9clar\u00e9 par le r\u00e9seau de chaleur (en France ce contenu CO2 est publi\u00e9 par arr\u00eat\u00e9). | Pour les b\u00e2timents multi-\u00e9nergie, il sera indispensable de quantifier les consommations d\u2019\u00e9nergie du b\u00e2timent durant son utilisation, par sources \u00e9nerg\u00e9tiques. | Pour les projets internationaux, les facteurs d\u2019\u00e9missions de CO2 sont \u00e0 adapter et justifier localement, pour cela il est notamment possible d\u2019utiliser les donn\u00e9es fournies sur le site de l\u2019agence internationale de l\u2019\u00e9nergie (IEA). S\u2019il n\u2019est pas possible de d\u00e9terminer les parts relatives de consommation \u00e9lectrique li\u00e9es \u00e0 chaque poste, alors le coefficient d\u2019\u00e9mission \u00e0 prendre en compte est le plus d\u00e9favorable. | Pour l\u2019Ile de La R\u00e9union, la valeur actualis\u00e9e des Emissions de CO\u2082 sera consid\u00e9r\u00e9e. | Il est possible de d\u00e9duire la production photovolta\u00efque export\u00e9e des \u00e9missions, dans ce cas, il convient d\u2019utiliser le facteur d\u2019\u00e9mission de l\u2019\u00e9lectricit\u00e9 autres usages (important, il convient de veiller \u00e0 ne pas comptabiliser plusieurs fois la production photovolta\u00efque autoconsomm\u00e9e, car celle-ci est d\u00e9duite des consommations \u00e9nerg\u00e9tiques). | Pour les combustibles, la donn\u00e9e environnementale de mise \u00e0 disposition de l\u2019\u00e9nergie i couvre la mise \u00e0 disposition du combustible jusqu\u2019au b\u00e2timent (par unit\u00e9 d\u2019\u00e9nergie finale) et les donn\u00e9es de combustion (par unit\u00e9 d\u2019\u00e9nergie finale). | De plus, en France : S\u2019il n\u2019est pas possible de d\u00e9terminer les parts relatives de consommation \u00e9lectrique li\u00e9es \u00e0 chaque poste, alors le coefficient d\u2019\u00e9mission \u00e0 prendre en compte est celui du chauffage en France m\u00e9tropolitaine (0,079 kgCO\u2082eq/kWhEF). Pour les autres usages non r\u00e8glementaires, il sera n\u00e9cessaire d\u2019utiliser les facteurs d\u2019\u00e9mission provenant de sources officielles (Exemple : Base Carbone en France).",attention:"P\u00e9rim\u00e8tre fonctionnel : Dans le cas o\u00f9 le nombre de sous-objets d\u00e9fini dans le seuil ne serait pas en ad\u00e9quation avec les sous-objets du projet, il est possible d\u2019effectuer une p\u00e9r\u00e9quation en fonction de celui-ci. Cette p\u00e9r\u00e9quation devra \u00eatre dument motiv\u00e9e et justifi\u00e9e (par une note de calcul) et n\u2019est pas n\u00e9cessairement lin\u00e9aire au nombre de sous-objets du projet. | P\u00e9rim\u00e8tre spatial : Seules les \u00e9missions dans le p\u00e9rim\u00e8tre de responsabilit\u00e9s du demandeur et relatives \u00e0 l\u2019activit\u00e9 du sous-objet certifi\u00e9 sont prises en compte. Par exemple, pour un b\u00e2timent d\u2019enseignement, des locaux d\u2019enseignement, des locaux administratifs, un internat, une cantine et un gymnase, il convient de retirer les \u00e9missions de ces trois derniers usages (cantine, internat, gymnase) des \u00e9missions totales de l\u2019\u00e9tablissement, mais \u00e9galement les surfaces des b\u00e2timents/espaces concern\u00e9s par ces usages, pour exprimer les \u00e9missions ou les flux en valeurs absolues, mais rapport\u00e9es au m\u00b2 de SDP du sous-objet \u00ab enseignement \u00bb concern\u00e9. En effet, ces autres activit\u00e9s doivent \u00eatre consid\u00e9r\u00e9es comme des sous-objets s\u00e9par\u00e9s. | La surface de plancher (SDP) peut \u00eatre remplac\u00e9e par la surface utilis\u00e9e localement se rapprochant le plus de la d\u00e9finition suivante : \u00ab La surface de plancher (SDP) est \u00e9gale \u00e0 la somme des surfaces de plancher de chaque niveau clos et couvert, calcul\u00e9e \u00e0 partir du nu int\u00e9rieur des fa\u00e7ades apr\u00e8s d\u00e9duction des \u00e9paisseurs des murs, portes et fen\u00eatres, des vides et tr\u00e9mies, des surfaces de hauteur de plafond inf\u00e9rieure \u00e0 1m80, des aires de stationnement, des zones non am\u00e9nageables et des locaux techniques. \u00bb",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration. | D\u00e9finition justifi\u00e9e d\u2019un objectif d\u2019\u00e9missions r\u00e9elles.</td><td>D\u00e9finition des objectifs \u00e0 atteindre. | D\u00e9finition des sc\u00e9narios d\u2019usage notamment sur les points suivants : nombre d\u2019occupants, consignes de temp\u00e9rature, horaires de fonctionnement. | Coh\u00e9rence entre le fichier m\u00e9t\u00e9o utilis\u00e9 et la localisation du projet (m\u00eame zone climatique).</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des \u00e9missions r\u00e9elles. | CCTP. | Plans.</td><td>V\u00e9rification que les sc\u00e9narios d\u2019usage pris en compte correspondent aux sc\u00e9narios d\u00e9finis par le ma\u00eetre d\u2019ouvrage, notamment sur les points suivants : nombre d\u2019occupants, consignes de temp\u00e9rature, horaires de fonctionnement, apports internes li\u00e9s aux consommations mobili\u00e8res. | Coh\u00e9rence entre les hypoth\u00e8ses de calcul et les \u00e9l\u00e9ments mis en \u0153uvre du projet, notamment sur les points suivants : caract\u00e9ristiques des parois opaques et vitr\u00e9es, puissance de l\u2019\u00e9clairage, caract\u00e9ristiques et hypoth\u00e8ses d\u2019usage des \u00e9quipements techniques, d\u00e9bits de ventilation, nombre et caract\u00e9ristiques des ascenseurs et monte-charge, caract\u00e9ristiques des parkings, nombre de DJU \u00e9t\u00e9 et hiver. | Coh\u00e9rence entre le fichier m\u00e9t\u00e9o utilis\u00e9 et la localisation du projet (m\u00eame zone climatique).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des \u00e9missions r\u00e9elles. | DOE.</td><td>Coh\u00e9rence entre les hypoth\u00e8ses de calcul et les \u00e9l\u00e9ments mis en \u0153uvre du projet, notamment sur les points suivants : caract\u00e9ristiques des parois opaques et vitr\u00e9es, puissance de l\u2019\u00e9clairage, caract\u00e9ristiques et hypoth\u00e8ses d\u2019usage des \u00e9quipements techniques, d\u00e9bits de ventilation, nombre et caract\u00e9ristiques des ascenseurs et monte-charge, caract\u00e9ristiques des parkings, nombre de DJU \u00e9t\u00e9 et hiver. | Coh\u00e9rence entre le fichier m\u00e9t\u00e9o utilis\u00e9 et la localisation du projet (m\u00eame zone climatique).</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td colspan=\"2\">SANS factures : (M\u00e9thode d\u00e9taill\u00e9e, idem phase R\u00e9alisation). | AVEC Factures, m\u00e9thode simplifi\u00e9e : Relev\u00e9 des consommations d\u2019\u00e9nergie ; D\u00e9finition des sc\u00e9nariis d\u2019occupation nominale ; Mod\u00e8le de calcul math\u00e9matique correctif. Points v\u00e9rifi\u00e9s : Coh\u00e9rence entre le p\u00e9rim\u00e8tre d\u2019\u00e9valuation et celui des factures ; Transformation en \u00e9missions de CO\u2082. | AVEC Factures, m\u00e9thode d\u00e9taill\u00e9e : D\u00e9finition des sc\u00e9nariis d\u2019occupation nominale ; Calcul th\u00e9orique de consommation r\u00e9ajust\u00e9e par rapport \u00e0 des conditions d\u2019usages nominales. Points v\u00e9rifi\u00e9s : Coh\u00e9rence entre les hypoth\u00e8ses de calcul et les \u00e9l\u00e9ments mis en \u0153uvre du projet, notamment sur les points suivants : caract\u00e9ristiques des parois opaques et vitr\u00e9es, caract\u00e9ristiques et hypoth\u00e8ses d\u2019usage des \u00e9quipements techniques, puissance de l\u2019\u00e9clairage. Coh\u00e9rence entre le fichier m\u00e9t\u00e9o utilis\u00e9 et la localisation du projet (m\u00eame zone climatique).</td></tr></table>"},
"CARB1.2":{intro:"Emissions de CO\u2082 li\u00e9es aux d\u00e9placements",context:"Ce sous-th\u00e8me traite des \u00e9missions de CO\u2082 li\u00e9es aux d\u00e9placements des usagers du b\u00e2timent."},
"CARB1.2.1":{attendu:"Emissions de CO\u2082 li\u00e9es aux d\u00e9placements (kgCO\u2082eq/m\u00b2SDP.an).",definition:"L\u2019\u00e9valuation des \u00e9missions de CO\u2082 li\u00e9es aux d\u00e9placements pendant la phase d\u2019utilisation du b\u00e2timent, tient compte des impacts des principaux usagers (cf. tableau indiqu\u00e9 en fin d\u2019exigence) du b\u00e2timent, induits par la localisation de celui-ci. L\u2019\u00e9valuation n\u2019inclut donc pas l\u2019activit\u00e9 h\u00e9berg\u00e9e par le b\u00e2timent. Ainsi par exemple, les livraisons ou transports de d\u00e9chets ou marchandises ne sont pas pris en compte*. | Les trois groupes d\u2019usagers principaux suivants se rencontrent sur la quasi-totalit\u00e9 des typologies : les salari\u00e9s, les visiteurs ou clients, les prestataires (agents de maintenance/entretien, etc.). | Pour l\u2019\u00e9valuation, nous retenons uniquement les deux premiers groupes : les salari\u00e9s et les visiteurs ou clients. Le troisi\u00e8me groupe a en effet un impact beaucoup plus n\u00e9gligeable. | Pour s\u2019approcher au plus des motifs de d\u00e9placements associ\u00e9s aux b\u00e2timents tertiaires, nous proposons de retenir le motif principal des trajets domicile-b\u00e2timent, concernant les salari\u00e9s et les \u00ab visiteurs ou clients \u00bb. | Chaque typologie de b\u00e2timent tertiaire est concern\u00e9e par ce motif de d\u00e9placement. Il est donc tr\u00e8s important de le prendre en compte. | *Note : Pour tous les b\u00e2timents, il est \u00e9galement possible de tenir compte des \u00e9missions de CO\u2082 li\u00e9es aux transports de marchandises (poids lourds par exemple). Cette cat\u00e9gorie de transports peut en effet avoir un impact tr\u00e8s important sur les \u00e9missions globales li\u00e9es aux d\u00e9placements. C\u2019est notamment le cas pour les secteurs \u00ab logistique \u00bb ou \u00ab commerce \u00bb. Dans ce cas, le demandeur ajoute cette valeur \u00e0 celle des \u00e9missions li\u00e9es aux d\u00e9placements des usagers.",evaluation:"Il n\u2019y a pas d\u2019\u00e9valuation li\u00e9e \u00e0 ce sous-th\u00e8me \u00ab Emissions de CO\u2082 li\u00e9es aux d\u00e9placements \u00bb. Les valeurs calcul\u00e9es ne seront pas int\u00e9gr\u00e9es au calcul global sur le th\u00e8me \u00ab Carbone \u00bb. | Aucune classe ne sera associ\u00e9e dans cette version du r\u00e9f\u00e9rentiel car il est difficile aujourd\u2019hui d\u2019en d\u00e9finir. Le positionnement sur une \u00e9chelle d\u2019\u00e9valuation ne sera possible que dans un second temps, apr\u00e8s plusieurs retours d\u2019exp\u00e9riences. | Les indicateurs de sortie seront exprim\u00e9s en kg CO\u2082eq/m\u00b2.an.",attention:"Le renseignement des distances cumul\u00e9es parcourues par l\u2019ensemble des usagers et par part modale est \u00e0 r\u00e9aliser par le demandeur de la certification. En France, celui-ci peut s\u2019aider de l\u2019outil Effinergie-Ecomobilit\u00e9 pour identifier les distances domicile-travail moyenne par contexte urbain. | Il n\u2019est pas obligatoire d\u2019avoir des donn\u00e9es r\u00e9elles des d\u00e9placements, car celles-ci sont parfois difficiles \u00e0 obtenir. Des valeurs conventionnelles ou ratios peuvent ainsi \u00eatre utilis\u00e9s. Il appartient au demandeur de la certification de fournir ces ratios et valeurs par d\u00e9faut et de les justifier. | Note : concernant la surface de plancher : Cf. CARB.1.1.1",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Calcul des \u00e9missions de CO\u2082 li\u00e9es aux d\u00e9placements.</td><td rowspan=\"3\">Coh\u00e9rence du calcul avec les hypoth\u00e8ses d\u2019usage du b\u00e2timent notamment sur les points suivants : localisation du b\u00e2timent, nombre d\u2019occupant, niveau d\u2019accessibilit\u00e9 du b\u00e2timent, enqu\u00eate de mobilit\u00e9 si existante..</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Mise \u00e0 jour du calcul des \u00e9missions de CO\u2082 li\u00e9es aux d\u00e9placements.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Calcul des \u00e9missions de CO\u2082 li\u00e9es aux d\u00e9placements.</td></tr></table>"},
"COUT1":{intro:"Ma\u00eetrise des charges de fonctionnement",context:"Ce sous-th\u00e8me \u00e9value la connaissance des charges li\u00e9es aux fluides et d\u00e9chets, ainsi que l\u2019optimisation des installations de suivi des consommations."},
"COUT1.1":{intro:"Charges li\u00e9es aux fluides et aux d\u00e9chets",context:"Ce bloc \u00e9value la connaissance des charges \u00e9nerg\u00e9tiques, des charges li\u00e9es \u00e0 l\u2019eau et des charges de gestion des d\u00e9chets."},
"COUT1.1.1":{attendu:"Cette exigence requiert, sur le p\u00e9rim\u00e8tre spatial et des responsabilit\u00e9s du demandeur, la connaissance ou l\u2019estimation pr\u00e9visionnelle des charges et recettes annuelles associ\u00e9es (TTC - Toutes Taxes Comprises) aux consommations \u00e9nerg\u00e9tiques tous usages et \u00e0 la production d\u2019\u00e9nergie in situ.",definition:"Les charges et recettes renseign\u00e9es doivent correspondre aux consommations \u00e9nerg\u00e9tiques tous usages, correspondant \u00e0 l\u2019ensemble des postes de consommations \u00e9nerg\u00e9tiques (postes mobiliers et immobiliers). | Les \u00ab charges associ\u00e9es aux consommations \u00e9nerg\u00e9tiques annuelles \u00bb correspondent : au co\u00fbt total de l\u2019\u00e9nergie consomm\u00e9e par l\u2019immeuble (consommations immobili\u00e8res et mobili\u00e8res) ; \u00e0 l\u2019annualisation des co\u00fbts d\u2019abonnements au fournisseur d\u2019\u00e9nergie ; aux taxes associ\u00e9es (en France : TURPE, CSPE, CTA, TCFE et TVA). Les co\u00fbts des installations techniques pour la production et la distribution d\u2019\u00e9nergie ne sont pas inclus. | Les \u00ab recettes annuelles associ\u00e9es \u00e0 la revente d\u2019\u00e9nergie produite in situ \u00bb correspondent aux recettes li\u00e9es \u00e0 la revente d\u2019\u00e9lectricit\u00e9, de froid ou de chaleur \u00e0 un r\u00e9seau d\u2019\u00e9nergie externe au b\u00e2timent et \u00e0 sa parcelle. | Les indicateurs doivent \u00eatre renseign\u00e9s en euro TTC par surface de plancher (SDP) par an (\u20acTTC/m\u00b2SDP/an) pour les types d\u2019\u00e9nergie suivants : \u00c9lectricit\u00e9 du r\u00e9seau, Gaz naturel, R\u00e9seau de chaleur, R\u00e9seau de froid, Fioul, Biomasse, \u00c9nergie renouvelable produite in situ, Autres. | En phase exploitation depuis plus de 2 ans, le niveau de connaissance est valoris\u00e9, notamment la connaissance \u00e0 partir de donn\u00e9es r\u00e9elles plut\u00f4t que l\u2019estimation \u00e0 partir de simulations. Le recours \u00e0 des donn\u00e9es estim\u00e9es ne permet pas l\u2019obtention de la totalit\u00e9 des points. | P\u00e9riode de r\u00e9f\u00e9rence : Les charges et recettes doivent \u00eatre \u00e9tablies au choix sur une p\u00e9riode continue de 12 mois cons\u00e9cutifs les plus proches de la date de demande d\u2019entr\u00e9e en certification.",reglementation:"En France : ordonnance n\u00b02011-1539 du 16 novembre 2011 relative \u00e0 la d\u00e9finition des surfaces de plancher. | Art. R. 131-41-1 du D\u00e9cret \u00ab Tertiaire \u00bb. | D\u00e9cret BACS relatif au syst\u00e8me d\u2019automatisation et de contr\u00f4le des b\u00e2timents non r\u00e9sidentiels.",notation:"Non atteint : 0 point | Les charges sont connues pour au moins deux types d\u2019\u00e9nergie : 1 point | Les charges sont connues pour tous les types d\u2019\u00e9nergie, et les recettes sont connues pour l\u2019\u00e9nergie renouvelable produite : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Document sur les conditions tarifaires.</td><td>Pr\u00e9sence du document.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des consommations et productions \u00e9nerg\u00e9tiques ainsi que des charges et recettes associ\u00e9es avec pr\u00e9cisions sur les hypoth\u00e8ses tarifaires utilis\u00e9es + plans et CCTP.</td><td>En cas de calcul th\u00e9orique : V\u00e9rification que les sc\u00e9narios d\u2019usage pris en compte correspondent aux sc\u00e9narios d\u00e9finis par le demandeur. Coh\u00e9rence entre les hypoth\u00e8ses de calcul et les \u00e9l\u00e9ments du projet d\u00e9crits et dessin\u00e9s (parois, protections solaires, \u00e9quipements techniques, fichier m\u00e9t\u00e9o, hypoth\u00e8ses tarifaires).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des consommations et productions \u00e9nerg\u00e9tiques ainsi que des charges et recettes associ\u00e9es avec pr\u00e9cisions sur les hypoth\u00e8ses tarifaires utilis\u00e9es + DOE.</td><td>Idem phase Conception.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Calcul des consommations et productions \u00e9nerg\u00e9tiques ainsi que des charges et recettes associ\u00e9es avec pr\u00e9cisions sur les hypoth\u00e8ses tarifaires utilis\u00e9es + DOE. OU Relev\u00e9s de compteurs et pr\u00e9cisions sur les hypoth\u00e8ses tarifaires utilis\u00e9es. OU Facture des consommations et recettes issues de la revente. Dur\u00e9e de validit\u00e9 des modes de preuve : 1 an.</td><td>En cas de calcul th\u00e9orique ou de calculs bas\u00e9s sur des relev\u00e9s de compteur : Idem phases Conception et R\u00e9alisation. En cas de relev\u00e9 de factures : Coh\u00e9rence des factures avec l\u2019ann\u00e9e de r\u00e9f\u00e9rence choisie.</td></tr></table>"},
"COUT1.1.2":{attendu:"Ma\u00eetrise des charges au travers de la coh\u00e9rence entre puissances souscrites et puissances atteintes.",definition:"Cette exigence vise, sur le p\u00e9rim\u00e8tre spatial et des responsabilit\u00e9s du demandeur, la ma\u00eetrise des charges au travers de l\u2019optimisation des puissances appel\u00e9es et souscrites. Cette optimisation a plusieurs avantages \u00e9conomiques : la r\u00e9duction des co\u00fbts de raccordement et d\u2019abonnement aux r\u00e9seaux ; l\u2019am\u00e9lioration des conditions tarifaires au travers d\u2019une r\u00e9duction des consommations en heures pleines et en heures de pointe ; des gains d\u2019investissement sur les installations de courants forts li\u00e9s \u00e0 la possibilit\u00e9 de diminuer le dimensionnement de ces installations ; des gains d\u2019exploitation sur les installations de production d\u2019\u00e9nergie li\u00e9s \u00e0 une utilisation de ces \u00e9quipements dans des conditions de meilleur rendement. | Cette exigence requiert une optimisation des puissances souscrites pour au moins un des r\u00e9seaux (r\u00e9seau \u00e9lectrique, r\u00e9seau de chaud ou de froid) au regard des besoins du b\u00e2timent. | Pour les b\u00e2timents en construction et/ou r\u00e9novation : il est demand\u00e9 une r\u00e9flexion sur les puissances \u00e0 souscrire par rapport aux courbes de charges et au coefficient de foisonnement pour l\u2019\u00e9lectricit\u00e9. | Pour les b\u00e2timents existants : il est demand\u00e9 une optimisation des puissances souscrites par rapport aux puissances appel\u00e9es en les confrontant aux puissances maximales atteintes (r\u00e9seau d\u2019\u00e9lectricit\u00e9, de chaud ou de froid). | Le choix de puissance souscrite doit \u00eatre coh\u00e9rent avec cette analyse des puissances maximales atteintes. Une note justificative doit pr\u00e9ciser la coh\u00e9rence des puissances souscrites au regard de ces puissances maximales atteintes.",attention:"Ces strat\u00e9gies d\u2019optimisation des contrats bas\u00e9es sur une r\u00e9duction des puissances appel\u00e9es en heures pleines et des puissances souscrites peut se traduire par une augmentation des consommations d\u2019\u00e9nergie en p\u00e9riode creuse. Il est alors n\u00e9cessaire de v\u00e9rifier si l\u2019\u00e9ventuelle surconsommation g\u00e9n\u00e9r\u00e9e en p\u00e9riode creuse est compens\u00e9e par une \u00e9conomie sur le contrat d\u2019acc\u00e8s au r\u00e9seau.",notation:"Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Pr\u00e9sence des objectifs dans le programme.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Justificatif de l\u2019optimisation des puissances \u00e0 souscrire aupr\u00e8s des fournisseurs d\u2019\u00e9nergie + Plans et CCTP.</td><td>En cas de calcul des courbes de charges : Pour le chaud et le froid : coh\u00e9rence entre le justificatif de puissance \u00e0 souscrire/souscrite et les courbes de charges calcul\u00e9es. Pour l\u2019\u00e9lectricit\u00e9 : coh\u00e9rence entre le justificatif et les coefficients de foisonnement utilis\u00e9s pour le dimensionnement.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Justificatif de l\u2019optimisation des puissances \u00e0 souscrire aupr\u00e8s des fournisseurs d\u2019\u00e9nergie + Contrat de fourniture d\u2019\u00e9nergie + DOE.</td><td>Idem phase Conception.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Courbes d\u2019appel de puissance + contrat de fourniture d\u2019\u00e9nergie. Dur\u00e9e de validit\u00e9 des modes de preuve : 1 an.</td><td>En cas d\u2019utilisation des courbes de charges transmises par le fournisseur : Coh\u00e9rence des puissances souscrites au regard des puissances maximales atteintes.</td></tr></table>"},
"COUT1.1.3":{attendu:"Valorisation du recours \u00e0 des solutions de flexibilit\u00e9 \u00e9nerg\u00e9tique (lissage des appels de puissance, effacement\u2026).",definition:"Cette exigence valorise, sur le p\u00e9rim\u00e8tre spatial et des responsabilit\u00e9s du demandeur, le recours \u00e0 des solutions de flexibilit\u00e9 \u00e9nerg\u00e9tique (lissage des appels de puissance, effacement\u2026). Elle porte sur l\u2019appel aux r\u00e9seaux ainsi que sur l\u2019appel aux installations de production d\u2019\u00e9nergie pr\u00e9sentes dans le b\u00e2timent (chaudi\u00e8re, pompe \u00e0 chaleur, groupe \u00e9lectrog\u00e8ne, panneaux photovolta\u00efques, etc.). | Cette exigence est justifi\u00e9e d\u2019un point de vue \u00e9conomique par : la r\u00e9duction des d\u00e9penses d\u2019investissement sur les installations de courants forts ; des gains d\u2019exploitation sur les installations de production d\u2019\u00e9nergie li\u00e9s \u00e0 une utilisation de ces \u00e9quipements dans des conditions de meilleur rendement. | Pour l\u2019atteinte de l\u2019exigence, il est n\u00e9cessaire de prouver que le(s) dispositif(s) technique(s) est(sont) pr\u00e9sent(s) et que les solutions retenues ont bien un impact pour lisser les profils d\u2019appel de puissance au travers d\u2019une comparaison de courbes de charges avec et sans le(s) dispositif(s) en question. | D\u00e9finition : Les solutions de lissage et d\u2019effacement permettant de valider l\u2019exigence incluent notamment : l\u2019optimisation des strat\u00e9gies de relance des installations, l\u2019effacement des appels sur le r\u00e9seau en p\u00e9riode de surcharge, le recours \u00e0 des dispositifs de stockage d\u2019\u00e9nergie pour redistribution en heures pleines ou de pointe (stockage d\u2019\u00e9lectricit\u00e9, de chaud ou de froid). | Ne sont pas comptabilis\u00e9s dans cette cat\u00e9gorie les dispositifs de programmation horaire des \u00e9quipements visant uniquement \u00e0 adapter leur fonctionnement \u00e0 l\u2019occupation effective des locaux.",attention:"Ces strat\u00e9gies d\u2019optimisation des contrats bas\u00e9es sur une r\u00e9duction des puissances appel\u00e9es en heures pleines et des puissances souscrites peut se traduire par une augmentation des consommations d\u2019\u00e9nergie en p\u00e9riode creuse. Il est alors n\u00e9cessaire de v\u00e9rifier si l\u2019\u00e9ventuelle surconsommation g\u00e9n\u00e9r\u00e9e en p\u00e9riode creuse est compens\u00e9e par une \u00e9conomie sur le contrat d\u2019acc\u00e8s au r\u00e9seau.",notation:"Non atteint : 0 point | Pr\u00e9sence d\u2019une solution et analyse de son impact : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Pr\u00e9sence des objectifs dans le programme.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Documentation technique sur solutions pr\u00e9vues + Plans et CCTP. ET courbes d\u2019appel de puissance comment\u00e9es avec l\u2019impact de la strat\u00e9gie adopt\u00e9e pour le second niveau de l\u2019exigence.</td><td>Coh\u00e9rence entre les dispositions d\u00e9crites pour optimiser les appels de puissance et les \u00e9l\u00e9ments dessin\u00e9s/mis en \u0153uvre.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Documentation technique sur solutions pr\u00e9vues + DOE. ET courbes d\u2019appel de puissance comment\u00e9es avec l\u2019impact de la strat\u00e9gie adopt\u00e9e pour le second niveau de l\u2019exigence. Dur\u00e9e de validit\u00e9 des modes de preuve : 2 ans.</td><td>Idem phase Conception.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Idem phase R\u00e9alisation.</td><td>Coh\u00e9rence entre les dispositions d\u00e9crites pour optimiser les appels de puissance et les \u00e9l\u00e9ments mis en \u0153uvre. R\u00e9duction des pics d\u2019appel de puissance par rapport \u00e0 la situation sans les dispositifs de flexibilit\u00e9 pour le second niveau de points.</td></tr></table>"},
"COUT1.1.4":{attendu:"Connaissance ou estimation pr\u00e9visionnelle des charges annuelles associ\u00e9es au service de l\u2019eau.",definition:"Cette exigence requiert, sur le p\u00e9rim\u00e8tre spatial et des responsabilit\u00e9s du demandeur, la connaissance ou l\u2019estimation pr\u00e9visionnelle des charges annuelles associ\u00e9es au service de l\u2019eau. Les charges renseign\u00e9es doivent correspondre aux consommations d\u2019eau tous usages. | L\u2019indicateur doit \u00eatre renseign\u00e9 en euro (ou monnaie locale \u00e0 l\u2019international) TTC par surface de plancher (\u20acTTC/m\u00b2SDP/an). | D\u00e9finition : Les charges associ\u00e9es aux services de l\u2019eau doivent inclure trois types de postes : les co\u00fbts li\u00e9s \u00e0 l\u2019achat d\u2019eau potable (incluant l\u2019abonnement au r\u00e9seau et la consommation d\u2019eau potable tous usages) ; les co\u00fbts li\u00e9s \u00e0 la collecte et au traitement des eaux us\u00e9es (dont l\u2019abonnement au service de collecte et de traitement et le volume d\u2019eau rejet\u00e9e) ; les redevances et taxes per\u00e7ues par les organismes publics (en France : redevances aux agences de l\u2019eau et TVA). Les co\u00fbts des installations techniques pour la production, le traitement et la distribution d\u2019eau dans le b\u00e2timent ne sont pas inclus. | En phase exploitation depuis plus de 2 ans, le niveau de connaissance est valoris\u00e9, notamment la connaissance \u00e0 partir de donn\u00e9es r\u00e9elles plut\u00f4t que l\u2019estimation \u00e0 partir de simulations. | P\u00e9riode de r\u00e9f\u00e9rence : Les charges et recettes doivent \u00eatre \u00e9tablies sur une p\u00e9riode continue de 12 mois cons\u00e9cutifs les plus proches de la date de demande d\u2019entr\u00e9e en certification.",notation:"Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Document sur les conditions tarifaires de l\u2019op\u00e9rateur de gestion des eaux (adduction et assainissement).</td><td>Pr\u00e9sence des conditions.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Calcul des consommations d\u2019eau et de rejet d\u2019eaux us\u00e9es ainsi que des charges associ\u00e9es (taxes comprises) + Plans et CCTP.</td><td>En cas de calcul th\u00e9orique : Coh\u00e9rence des hypoth\u00e8ses de calcul avec les \u00e9l\u00e9ments mis en \u0153uvre ET coh\u00e9rence des hypoth\u00e8ses tarifaires par rapport aux conditions de l\u2019op\u00e9rateur de gestion des eaux.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Calcul des consommations d\u2019eau et de rejet d\u2019eaux us\u00e9es ainsi que des charges associ\u00e9es (taxes comprises) + DOE.</td><td>Idem phase Conception. En cas de calculs bas\u00e9s sur des relev\u00e9s de compteur : Coh\u00e9rence des hypoth\u00e8ses tarifaires par rapport au prix des op\u00e9rateurs de gestion des eaux.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Calcul des consommations d\u2019eau et de rejet d\u2019eaux us\u00e9es ainsi que des charges associ\u00e9es (taxes comprises) avec pr\u00e9cisions sur les hypoth\u00e8ses tarifaires utilis\u00e9es + DOE. OU Relev\u00e9s de compteurs et pr\u00e9cisions sur les hypoth\u00e8ses tarifaires utilis\u00e9es. OU Factures. Dur\u00e9e de validit\u00e9 des modes de preuve : 1 an.</td><td>En cas de calcul th\u00e9orique ou de calculs bas\u00e9s sur des relev\u00e9s de compteurs : idem phase R\u00e9alisation. En cas de relev\u00e9 de factures : Coh\u00e9rence des factures avec l\u2019ann\u00e9e de r\u00e9f\u00e9rence choisie.</td></tr></table>"},
"COUT1.1.4.a":{attendu:"Indicateur de charges d\u2019eau",definition:"Valeur en \u20acTTC/m\u00b2SDP/an.",notation:"Information \u00e0 renseigner"},
"COUT1.1.5":{attendu:"Connaissance ou estimation pr\u00e9visionnelle des charges annuelles associ\u00e9es \u00e0 la gestion des d\u00e9chets.",definition:"Cette exigence requiert, sur le p\u00e9rim\u00e8tre spatial et des responsabilit\u00e9s du demandeur, la connaissance ou l\u2019estimation pr\u00e9visionnelle des charges annuelles associ\u00e9es \u00e0 la gestion des d\u00e9chets. Sont distingu\u00e9s : les d\u00e9chets d\u2019activit\u00e9s d\u2019une part ; et les d\u00e9chets d\u2019entretien/maintenance d\u2019autre part. | Les charges associ\u00e9es \u00e0 la gestion des d\u00e9chets correspondent au co\u00fbt total de la collecte, de l\u2019enl\u00e8vement et de l\u2019\u00e9ventuel traitement des d\u00e9chets de l\u2019op\u00e9ration. Ces co\u00fbts incluent les \u00e9ventuelles taxes et redevances associ\u00e9es \u00e0 l\u2019enl\u00e8vement des d\u00e9chets par les collectivit\u00e9s, les co\u00fbts d\u2019enl\u00e8vement et de traitement par d\u2019\u00e9ventuels prestataires priv\u00e9s, les co\u00fbts de location d\u2019une benne, ainsi que les co\u00fbts internes li\u00e9s au personnel et mat\u00e9riel d\u00e9di\u00e9s \u00e0 la gestion des d\u00e9chets (manutention, tri interne). | Les d\u00e9chets d\u2019activit\u00e9s correspondent aux d\u00e9chets produits par les occupants dans le cadre de leurs activit\u00e9s : papier/carton, DIB, verre, cartouches d\u2019encre, d\u00e9chets putrescibles (dont d\u00e9chets de restauration), DEEE\u2026 | Les d\u00e9chets d\u2019entretien/maintenance correspondent aux d\u00e9chets produits dans le cadre des interventions d\u2019entretien et de maintenance : d\u00e9chets d\u2019emballage, DIB, d\u00e9chets de maintenance (filtres, lampes, a\u00e9rosols\u2026), d\u00e9chets espaces verts si pr\u00e9sence d\u2019espaces verts\u2026 | Les indicateurs doivent \u00eatre renseign\u00e9s en euro TTC par surface de plancher (\u20acTTC/m\u00b2SDP/an). | P\u00e9riode de r\u00e9f\u00e9rence : Les charges et recettes doivent \u00eatre \u00e9tablies sur une p\u00e9riode continue de 12 mois cons\u00e9cutifs les plus proches de la date de demande d\u2019entr\u00e9e en certification.",notation:"Non atteint : 0 point | D\u00e9chets d\u2019activit\u00e9s OU d\u2019entretien/maintenance : 1 point | D\u00e9chets d\u2019activit\u00e9s ET d\u2019entretien/maintenance : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Document sur les conditions tarifaires de l\u2019op\u00e9rateur de gestion des d\u00e9chets d\u2019activit\u00e9s et/ou d\u2019entretien/maintenance (par typologie de d\u00e9chets).</td><td>Pr\u00e9sence du document.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Calcul du volume des d\u00e9chets d\u2019activit\u00e9s et/ou d\u2019entretien/maintenance et des charges associ\u00e9es (taxes comprises).</td><td>En cas de calcul th\u00e9orique : Coh\u00e9rence des hypoth\u00e8ses de calcul avec les typologies de d\u00e9chets. Coh\u00e9rence des hypoth\u00e8ses tarifaires par rapport aux conditions des op\u00e9rateurs de gestion des d\u00e9chets.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Calcul du volume des d\u00e9chets d\u2019activit\u00e9s et/ou d\u2019entretien/maintenance et des charges associ\u00e9es (taxes comprises) + DOE. Facture des consommations du traitement des d\u00e9chets d\u2019activit\u00e9s et/ou d\u2019entretien/maintenance. Dur\u00e9e de validit\u00e9 des modes de preuve : 1 an.</td><td>En cas de facture : Coh\u00e9rence des factures avec les typologies de d\u00e9chets.</td></tr></table>"},
"COUT1.1.5.a":{attendu:"Indicateur de charges d\u00e9chets d\u2019activit\u00e9s",definition:"Valeur en \u20acTTC/m\u00b2SDP/an.",notation:"Information \u00e0 renseigner"},
"COUT1.1.5.b":{attendu:"Indicateur de charges d\u00e9chets d\u2019entretien/maintenance",definition:"Valeur en \u20acTTC/m\u00b2SDP/an.",notation:"Information \u00e0 renseigner"},
"COUT​1.2":{intro:"Optimisation des installations",context:"Ce bloc \u00e9value les moyens de suivi des consommations d\u2019\u00e9nergie et d\u2019eau, ainsi que la d\u00e9tection d\u2019anomalies."},
"COUT1.2.1":{attendu:"Mise \u00e0 disposition des moyens de suivi n\u00e9cessaires \u00e0 une analyse des consommations \u00e9nerg\u00e9tiques par type d\u2019\u00e9nergie et par poste de mani\u00e8re coh\u00e9rente sur le b\u00e2timent.",definition:"Cette exigence a pour but la mise \u00e0 disposition des moyens de suivi n\u00e9cessaires \u00e0 une analyse des consommations \u00e9nerg\u00e9tiques par type d\u2019\u00e9nergie et par poste de mani\u00e8re coh\u00e9rente sur le b\u00e2timent. Cette analyse permet entre autres d\u2019identifier les sources d\u2019\u00e9ventuelles surconsommations et donc de mieux ma\u00eetriser les charges \u00e9nerg\u00e9tiques. Les exigences peuvent \u00eatre valid\u00e9es par la pr\u00e9sence de compteurs ainsi que la mise en place de manchettes d\u2019attente (pour les b\u00e2timents livr\u00e9s en blanc \u00e0 la condition que le positionnement des manchettes permette au futur preneur d\u2019atteindre l\u2019exigence). | Le premier niveau (\u00ab Suivi par type d\u2019\u00e9nergie uniquement \u00bb) requiert la pr\u00e9sence de dispositifs permettant le suivi des consommations d\u2019\u00e9nergie pour chaque type d\u2019\u00e9nergie utilis\u00e9e. Par type d\u2019\u00e9nergie, on entend la source d\u2019\u00e9nergie utilis\u00e9e : l\u2019\u00e9lectricit\u00e9 ; un combustible ; un r\u00e9seau de froid urbain ; une auto-production de chauffage et/ou de froid. En pr\u00e9sence d\u2019une \u00e9nergie renouvelable, un compteur sp\u00e9cifique au type d\u2019\u00e9nergie consid\u00e9r\u00e9 doit \u00eatre pr\u00e9sent. | Le deuxi\u00e8me niveau (\u00ab Suivi par type d\u2019\u00e9nergie et par poste: chauffage, froid, ECS, ventilation, \u00e9clairage et auxiliaires \u00bb) requiert de prendre des dispositions pour assurer le suivi des consommations d\u2019\u00e9nergie pour chaque type d\u2019\u00e9nergie sur les cinq postes suivants : chauffage, refroidissement (hors process), ECS, \u00e9clairage (hors \u00e9clairage ext\u00e9rieur, de s\u00e9curit\u00e9, des parkings et de mise en valeur des objets), ventilation et auxiliaires de fonctionnement. | Le dernier niveau (\u00ab Suivi par type d\u2019\u00e9nergie et par postes : postes pr\u00e9c\u00e9dents + 2 autres postes \u00bb) requiert de prendre des dispositions pour assurer le suivi des consommations pour chaque type d\u2019\u00e9nergie sur les cinq postes pr\u00e9c\u00e9dents ainsi que pour au moins deux autres postes immobiliers ou mobiliers : \u00e9quipements \u00e9lectrom\u00e9caniques, production de froid (process), \u00e9clairage des parkings, \u00e9clairage ext\u00e9rieur, bureautique, cuisine, blanchisserie, etc. ET d\u00e8s 2022 en France, une GTB doit \u00eatre mise en place et r\u00e9pondre aux caract\u00e9ristiques du \u00ab D\u00e9cret BACS \u00bb.",notation:"Non atteint : 0 point | Suivi par type d\u2019\u00e9nergie uniquement : 1 point | Suivi par type d\u2019\u00e9nergie et par poste : chauffage, froid, ECS, ventilation, \u00e9clairage et auxiliaires : 2 points | Suivi par type d\u2019\u00e9nergie et par postes : postes pr\u00e9c\u00e9dents + 2 autres postes : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Pr\u00e9sence des objectifs.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Sch\u00e9mas de comptage OU fiches/plans techniques des \u00e9l\u00e9ments de comptage mis en place et arborescence de comptage + CCTP.</td><td>Coh\u00e9rence entre le niveau de comptage \u00e9valu\u00e9 et les compteurs dessin\u00e9s.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Sch\u00e9mas de comptage OU fiches/plans techniques des \u00e9l\u00e9ments de comptage mis en place et arborescence de comptage + DOE. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Coh\u00e9rence entre le niveau de comptage \u00e9valu\u00e9 et les compteurs dessin\u00e9s ET constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT1.2.2":{attendu:"Mise \u00e0 disposition des moyens de comptage n\u00e9cessaires \u00e0 une analyse des consommations d\u2019eau par poste de mani\u00e8re coh\u00e9rente sur le b\u00e2timent.",definition:"Cette exigence a pour but de mettre \u00e0 disposition les moyens de comptage n\u00e9cessaires \u00e0 une analyse des consommations d\u2019eau par poste de mani\u00e8re coh\u00e9rente sur le b\u00e2timent. Cette analyse permet entre autres d\u2019identifier les sources d\u2019\u00e9ventuelles surconsommations et donc de mieux ma\u00eetriser les charges li\u00e9es \u00e0 l\u2019eau. Les exigences peuvent \u00eatre valid\u00e9es par la pr\u00e9sence de compteurs ainsi que la mise en place de manchettes d\u2019attente. | Le premier niveau (\u00ab Suivi par usages principaux uniquement \u00bb) requiert la pr\u00e9sence de dispositifs permettant le suivi des consommations d\u2019eau pour chacun des usages principaux selon une arborescence de comptage \u00e0 justifier. Un usage est identifi\u00e9 essentiellement par deux facteurs : l\u2019activit\u00e9 des espaces et la pr\u00e9sence d\u2019\u00e9quipements sp\u00e9cifiques consommant de l\u2019eau (blanchisserie, \u00e9quipements de cuisines, piscine, etc.). Exemples d\u2019usages : Sanitaires et douches, Restaurant, Piscine-SPA, Blanchisserie, Arrosage, S\u00e9curit\u00e9 incendie, Eaux techniques, etc. | Le deuxi\u00e8me niveau (\u00ab Suivi par sous-comptage de premier niveau \u00bb) requiert la mise en place d\u2019un premier niveau de sous-comptage. \u00c0 partir du sch\u00e9ma de comptage \u00ab de base \u00bb, pour les usages qui se pr\u00eatent au sous-comptage, il est demand\u00e9 la mise en \u0153uvre d\u2019une arborescence de sous-comptage permettant le suivi sp\u00e9cifique des consommations d\u2019eau par zone et/ou type d\u2019eau via un premier niveau de sous-comptage. | Le dernier niveau (\u00ab Suivi par sous-comptage de premier et deuxi\u00e8me niveau \u00bb) requiert la mise en place d\u2019un deuxi\u00e8me niveau de sous-comptage permettant un suivi plus sp\u00e9cifique des consommations d\u2019eau.",notation:"Non atteint : 0 point | Suivi par usages principaux uniquement : 1 point | Suivi par sous-comptage de premier niveau : 2 points | Suivi par sous-comptage de premier et deuxi\u00e8me niveau : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Pr\u00e9sence des objectifs.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Sch\u00e9mas de comptage OU fiches/plans techniques des \u00e9l\u00e9ments de comptage mis en place et arborescence de comptage + CCTP.</td><td>Coh\u00e9rence entre le niveau de comptage \u00e9valu\u00e9 et les compteurs dessin\u00e9s.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Sch\u00e9mas de comptage OU fiches/plans techniques des \u00e9l\u00e9ments de comptage mis en place et arborescence de comptage + DOE. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Coh\u00e9rence entre le niveau de comptage \u00e9valu\u00e9 et les compteurs dessin\u00e9s ET constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT1.2.3":{attendu:"D\u00e9tection d\u2019anomalies de fonctionnement des installations et d\u00e9clenchement d\u2019alertes centralis\u00e9es.",definition:"Cette exigence examine les dispositions prises pour permettre la d\u00e9tection d\u2019anomalies de fonctionnement des installations et le d\u00e9clenchement d\u2019alertes centralis\u00e9es. Une d\u00e9tection rapide de ces anomalies permet notamment de limiter les surconsommations et surco\u00fbts d\u2019entretien et de maintenance qu\u2019aurait g\u00e9n\u00e9r\u00e9s l\u2019anomalie si elle n\u2019avait pas \u00e9t\u00e9 d\u00e9tect\u00e9e. Il est demand\u00e9 la pr\u00e9sence de moyens de contr\u00f4le permettant la d\u00e9tection de d\u00e9fauts et/ou d\u2019anomalies avec la g\u00e9n\u00e9ration d\u2019alarmes. | Cela concerne les d\u00e9tections et alertes pour les types de syst\u00e8mes suivants : Syst\u00e8me pour les installations de chauffage, refroidissement, ventilation et distribution d\u2019air ; Syst\u00e8me pour les installations de courants faibles/forts (transformateurs, groupes \u00e9lectrog\u00e8nes\u2026) ; Syst\u00e8me pour les installations de distribution et gestion de l\u2019eau. | Exemples de d\u00e9tection : Pics de surconsommation, appel de puissance anormal, d\u00e9tection de fuite, perte de charges dans un r\u00e9seau de distribution d\u2019air, \u00e9cart \u00e0 une temp\u00e9rature de consigne, d\u00e9rives des d\u00e9bits d\u2019air\u2026",reglementation:"D\u00e9cret BACS relatif au syst\u00e8me d\u2019automatisation et de contr\u00f4le des b\u00e2timents non r\u00e9sidentiels et \u00e0 la r\u00e9gulation automatique de la chaleur.",notation:"Non atteint : 0 point | Un type de syst\u00e8me : 1 point | Deux types de syst\u00e8mes : 2 points | Trois types de syst\u00e8mes : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Pr\u00e9sence des objectifs.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP + documentation sur le syst\u00e8me de gestion technique et/ou pilotage.</td><td>Coh\u00e9rence avec les \u00e9l\u00e9ments du projet d\u00e9crits dans les CCTP.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>DOE, documentation sur le syst\u00e8me de gestion technique et/ou pilotage. Analyse fonctionnelle de la GTB. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Coh\u00e9rence avec les \u00e9l\u00e9ments du projet mis en \u0153uvre et constat in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2":{intro:"Ma\u00eetrise des charges d\u2019exploitation",context:"Ce sous-th\u00e8me \u00e9value la connaissance des charges d\u2019exploitation et la facilit\u00e9 d\u2019entretien de l\u2019enveloppe, des \u00e9quipements et des terminaux."},
"COUT2.1":{intro:"Charges d\u2019exploitation",context:"Ce bloc \u00e9value la connaissance des charges annuelles d\u2019exploitation du b\u00e2timent."},
"COUT2.1.1":{attendu:"Connaissance ou estimation pr\u00e9visionnelle des charges annuelles d\u2019exploitation pour les b\u00e2timents en exploitation.",definition:"Cette exigence requiert, sur le p\u00e9rim\u00e8tre spatial et des responsabilit\u00e9s du demandeur, la connaissance ou l\u2019estimation pr\u00e9visionnelle des charges annuelles d\u2019exploitation pour les b\u00e2timents en exploitation. L\u2019analyse doit \u00eatre mise en regard des niveaux de prestations attendus et/ou r\u00e9alis\u00e9s. | Les indicateurs de charges suivants sont consid\u00e9r\u00e9s : Assurance du b\u00e2timent ; Entretien et maintenance m\u00e9caniques et \u00e9lectriques ; Entretien et maintenance de la structure externe ; Entretien et maintenance int\u00e9rieures ; Nettoyage ; Entretien des surfaces ext\u00e9rieures ; S\u00e9curit\u00e9/s\u00fbret\u00e9. | Les charges annuelles d\u2019exploitation correspondent aux co\u00fbts annuels associ\u00e9s aux actions d\u2019entretien des surfaces int\u00e9rieures et ext\u00e9rieures, de maintenance des installations techniques et de nettoyage. Ces co\u00fbts incluent les co\u00fbts relatifs \u00e0 la main d\u2019\u0153uvre employ\u00e9e pour ces interventions mais aussi les co\u00fbts associ\u00e9s \u00e0 l\u2019achat du mat\u00e9riel et des petits composants. \u00c0 l\u2019inverse, ces co\u00fbts excluent les co\u00fbts des gros travaux et remplacements majeurs (gros travaux amortissables). | Les indicateurs doivent \u00eatre renseign\u00e9s en euro HT par surface de plancher (\u20acHT/m\u00b2SDP/an). | Pour les projets de construction ou de r\u00e9novation ou les b\u00e2timents en exploitation depuis moins de deux ans : Les charges demand\u00e9es correspondent \u00e0 des co\u00fbts annuels moyens estim\u00e9s en fonction des caract\u00e9ristiques du b\u00e2ti et des \u00e9quipements pr\u00e9sents. | Pour les b\u00e2timents en exploitation depuis plus de deux ans : Les donn\u00e9es demand\u00e9es correspondent aux charges r\u00e9elles sur 12 mois cons\u00e9cutifs proches de la date de certification.",notation:"Non atteint : 0 point | Un indicateur connu : 2 points | Entre 2 et 4 indicateurs connus : 4 points | Au moins 5 indicateurs connus : 6 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Documents d\u00e9terminant les hypoth\u00e8ses de gestion des op\u00e9rations d\u2019entretien et de maintenance (internalis\u00e9es ou externalis\u00e9es) ainsi que les co\u00fbts de main d\u2019\u0153uvre internes.</td><td>Pr\u00e9sence du document.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Estimation pr\u00e9visionnelle des charges annuelles d\u2019exploitation + CCTP et plans.</td><td>En cas de calcul pr\u00e9visionnel : Coh\u00e9rence des hypoth\u00e8ses de calcul et du fonctionnement pr\u00e9visionnel du demandeur sur les sujets suivants : op\u00e9rations d\u2019entretien et de maintenance internalis\u00e9es ou externalis\u00e9es, co\u00fbts de main d\u2019\u0153uvre internes.</td></tr><tr><td><strong>Phase Exploitation axes B\u00e2timent et Gestion</strong></td><td>Estimation pr\u00e9visionnelle des charges annuelles d\u2019exploitation + DOE. OU Contrats d\u2019entretien et de maintenance externalis\u00e9s, ET factures pour interventions. Dur\u00e9e de validit\u00e9 des modes de preuve : 1 an.</td><td>En cas de calcul pr\u00e9visionnel : Idem. En cas de recours \u00e0 des donn\u00e9es r\u00e9elles : Couverture des contrats, prise en compte des interventions hors contrat et autres co\u00fbts internes.</td></tr></table>"},
"COUT2.2":{intro:"Facilit\u00e9 d\u2019entretien de l\u2019enveloppe du b\u00e2ti",context:"Ce bloc \u00e9value les dispositions prises pour faciliter l\u2019entretien de l\u2019enveloppe du b\u00e2timent.",non_applicabilite:"Ce bloc d\u2019exigences est non applicable pour les op\u00e9rations demandant un axe Gestion seul. Dans ce cas les points relatifs aux exigences COUT2.2.x seront d\u00e9duits du total de points disponibles."},
"COUT2.2.1":{attendu:"Interventions faciles et s\u00e9curis\u00e9es sur les principaux \u00e9l\u00e9ments de l\u2019enveloppe.",definition:"Le but de cette exigence est de s\u2019assurer que la facilit\u00e9 d\u2019entretien a \u00e9t\u00e9 prise en compte lors de la conception de l\u2019enveloppe du b\u00e2timent. En effet, la possibilit\u00e9 d\u2019acc\u00e8s \u00e0 l\u2019enveloppe et la facilit\u00e9 d\u2019entretien des surfaces associ\u00e9es permettent de r\u00e9duire les d\u00e9lais d\u2019intervention et donc les co\u00fbts associ\u00e9s. | Il est demand\u00e9 d\u2019identifier et de justifier la facilit\u00e9 et la s\u00e9curit\u00e9 des conditions d\u2019acc\u00e8s aux principaux \u00e9l\u00e9ments de l\u2019enveloppe pour les familles suivantes : Fa\u00e7ades ; Toitures ; Protections solaires ; Fen\u00eatres, menuiseries et vitrages ; Autres \u00e9l\u00e9ments de l\u2019enveloppe (par exemple panneaux photovolta\u00efques ou ECS solaire). | Les dispositions mises en place pour faciliter les conditions d\u2019acc\u00e8s peuvent inclure des \u00e9l\u00e9ments architecturaux fixes (passerelles s\u00e9curis\u00e9es, escaliers d\u2019acc\u00e8s aux toitures, etc.) ou des \u00e9l\u00e9ments techniques qui seront utiles \u00e0 la mise en place de certains \u00e9quipements d\u2019entretien (dispositifs d\u2019accroche permettant l\u2019utilisation de nacelle, d\u2019\u00e9chelles, etc.). | En outre, tous ces acc\u00e8s doivent pouvoir \u00eatre assur\u00e9s en toute s\u00e9curit\u00e9.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Coh\u00e9rence des objectifs avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP et plans + Etude de l\u2019accessibilit\u00e9 des \u00e9l\u00e9ments de l\u2019enveloppe ET/OU DIUO provisoire.</td><td>Coh\u00e9rence des hypoth\u00e8ses de l\u2019\u00e9tude d\u2019accessibilit\u00e9 ou du DIUO avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>DOE + Etude de l\u2019accessibilit\u00e9 des \u00e9l\u00e9ments de l\u2019enveloppe et/ou DIUO. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Constat in situ des dispositions d\u00e9crites.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2.2.2":{attendu:"Surfaces d\u2019au moins 4 familles de l\u2019enveloppe faciles \u00e0 entretenir.",definition:"Le but de cette exigence est de s\u2019assurer que la facilit\u00e9 d\u2019entretien a \u00e9t\u00e9 prise en compte lors de la conception de l\u2019enveloppe du b\u00e2timent. En effet, la possibilit\u00e9 d\u2019acc\u00e8s \u00e0 l\u2019enveloppe et la facilit\u00e9 d\u2019entretien des surfaces associ\u00e9es permettent de r\u00e9duire les d\u00e9lais d\u2019intervention et donc les co\u00fbts associ\u00e9s. | Le recours \u00e0 des mat\u00e9riaux faciles \u00e0 nettoyer (en \u00e9vitant notamment les surfaces granuleuses, poreuses, etc.) ou ne n\u00e9cessitant pas d\u2019op\u00e9rations d\u2019entretien/nettoyage r\u00e9guli\u00e8res pour les \u00e9l\u00e9ments de l\u2019enveloppe du b\u00e2ti (rev\u00eatements de toiture, de fa\u00e7ades et de menuiseries ext\u00e9rieures) permet de r\u00e9duire les co\u00fbts d\u2019entretien et de nettoyage associ\u00e9s. Les mat\u00e9riaux autonettoyants peuvent \u00e9galement \u00eatre valoris\u00e9s dans cette exigence. | Pour valider l\u2019exigence, il est demand\u00e9 d\u2019identifier les mat\u00e9riaux utilis\u00e9s et de justifier leur facilit\u00e9 d\u2019entretien et de nettoyage, pour les quatre familles suivantes : Fa\u00e7ades ; Toitures ; Protections solaires ; Fen\u00eatres, et vitrages.",attention:"La r\u00e9duction des co\u00fbts associ\u00e9s \u00e0 l\u2019entretien des surfaces de l\u2019enveloppe ne doit pas se faire au d\u00e9triment de l\u2019hygi\u00e8ne. Il est ici question de r\u00e9duire les co\u00fbts d\u2019entretien futur par un choix pertinent de syst\u00e8mes et de mat\u00e9riaux pour un niveau de services rendus donn\u00e9.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Coh\u00e9rence des objectifs avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP et plans + Document identifiant les mat\u00e9riaux de l\u2019enveloppe et leurs caract\u00e9ristiques d\u2019entretien/nettoyage.</td><td>Coh\u00e9rence entre les \u00e9l\u00e9ments du projet et les types de surfaces d\u00e9clar\u00e9es.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>DOE + Document identifiant les mat\u00e9riaux de l\u2019enveloppe et leurs caract\u00e9ristiques d\u2019entretien/nettoyage. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Coh\u00e9rence entre le constat in situ et les types de surfaces d\u00e9clar\u00e9es.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2.3":{intro:"Facilit\u00e9 d\u2019entretien des \u00e9quipements de production et des syst\u00e8mes \u00e9lectrom\u00e9caniques",context:"Ce bloc \u00e9value les dispositions prises pour faciliter et s\u00e9curiser l\u2019entretien des \u00e9quipements techniques.",non_applicabilite:"Ce bloc d\u2019exigences est non applicable pour les op\u00e9rations demandant un axe Gestion seul. Dans ce cas les points relatifs aux exigences COUT2.3.x seront d\u00e9duits du total de points disponibles."},
"COUT2.3.1":{attendu:"Interventions faciles et s\u00e9curis\u00e9es sur les \u00e9quipements de production et les syst\u00e8mes \u00e9lectrom\u00e9caniques.",definition:"Cette exigence vise \u00e0 s\u2019assurer que la conception technique et architecturale permet une intervention s\u00e9curis\u00e9e et facilit\u00e9e pour les op\u00e9rations d\u2019entretien/maintenance du b\u00e2timent, relativement aux \u00e9quipements de production (g\u00e9n\u00e9rateurs de chauffage/rafra\u00eechissement, centrale de traitement d\u2019air, transformateurs, groupes \u00e9lectrog\u00e8nes, syst\u00e8mes de gestion de l\u2019eau) des syst\u00e8mes suivants : Syst\u00e8mes de chauffage/rafra\u00eechissement ; Syst\u00e8mes de ventilation ; Syst\u00e8mes relatifs aux courants faibles/forts (transformateurs, groupes \u00e9lectrog\u00e8nes, syst\u00e8me de production d\u2019\u00e9nergie) ; Syst\u00e8mes de gestion de l\u2019eau ; Ainsi que les syst\u00e8mes \u00e9lectrom\u00e9caniques (\u00e9l\u00e9vateurs, ascenseurs, monte-charges, etc.) s\u2019il y en a. | Il est demand\u00e9 de v\u00e9rifier la possibilit\u00e9 d\u2019intervention sur les \u00e9quipements techniques y compris les \u00e9l\u00e9ments primaires (organes d\u2019isolement, volets de r\u00e9glage, filtres des CTA, organes de coupure, vannes hydrauliques, etc.). L\u2019exigence est v\u00e9rifi\u00e9e si la conception technique et architecturale permet des interventions s\u00e9curis\u00e9es et facilit\u00e9es, avec des locaux techniques de taille suffisante pour les \u00e9quipes de maintenance. | Note : Les remplacements des \u00e9quipements ou de leurs \u00e9l\u00e9ments les plus encombrants ne sont pas consid\u00e9r\u00e9s ici.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Coh\u00e9rence des objectifs avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans justifiant l\u2019accessibilit\u00e9 aux \u00e9quipements de production et aux syst\u00e8mes \u00e9lectrom\u00e9caniques.</td><td>Coh\u00e9rence des hypoth\u00e8ses de l\u2019\u00e9tude d\u2019accessibilit\u00e9 ou du DIUO avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>DIUO, DOE justifiant l\u2019accessibilit\u00e9 aux \u00e9quipements de production et aux syst\u00e8mes \u00e9lectrom\u00e9caniques. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Constat in situ des dispositions d\u00e9crites.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2.3.2":{attendu:"Remplacement de tous les \u00e9quipements de production ou syst\u00e8mes \u00e9lectrom\u00e9caniques, y compris les plus encombrants, possible sans d\u00e9gradation du b\u00e2ti.",definition:"Il est demand\u00e9 que les interventions d\u2019entretien et de maintenance, y compris pour le remplacement de tous les \u00e9quipements, m\u00eame les plus encombrants, puissent \u00eatre effectu\u00e9es sans d\u00e9gradation majeure et structurelle du b\u00e2ti. Le but de cette exigence est de s\u2019assurer que la conception technique et architecturale permet une r\u00e9duction des d\u00e9lais d\u2019intervention et des co\u00fbts associ\u00e9s. | Cette question peut se traiter par : la mise en \u0153uvre de \u00ab murs fusibles \u00bb ; le dimensionnement ad\u00e9quat des acc\u00e8s (portes, couloirs, escaliers, etc.) ; la mise en place de trappes d\u2019acc\u00e8s ; l\u2019installation en toiture avec un acc\u00e8s r\u00e9fl\u00e9chi pour le remplacement de tous les \u00e9quipements ; etc.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Coh\u00e9rence des objectifs avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>\u00c9tudes d\u2019accessibilit\u00e9 aux \u00e9quipements techniques de production + CCTP, plans.</td><td>Coh\u00e9rence entre l\u2019\u00e9tude d\u2019accessibilit\u00e9 et les \u00e9l\u00e9ments du projet notamment sur les points suivants : v\u00e9rification de l\u2019encombrement des \u00e9quipements techniques par rapport aux sections des portes ; v\u00e9rification de la prise en compte du poids des \u00e9quipements dans le dimensionnement structurel des cheminements envisag\u00e9s.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>\u00c9tudes d\u2019accessibilit\u00e9 aux \u00e9quipements techniques de production + DOE. Justification du remplacement sans d\u00e9gradation majeure ni structurelle du b\u00e2ti. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Constat in situ et coh\u00e9rence entre l\u2019\u00e9tude d\u2019accessibilit\u00e9 et les \u00e9l\u00e9ments du projet notamment sur les points suivants : v\u00e9rification de l\u2019encombrement des \u00e9quipements techniques par rapport aux sections des portes ; v\u00e9rification de la prise en compte du poids des \u00e9quipements dans le dimensionnement structurel des cheminements envisag\u00e9s.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2.3.3":{attendu:"Interventions possibles sur les \u00e9quipements de production ou syst\u00e8mes \u00e9lectrom\u00e9caniques sans g\u00eane majeure pour les occupants.",definition:"Cette exigence valorise la possibilit\u00e9 d\u2019intervention sur les \u00e9quipements soit : pendant les heures d\u2019occupation sans que l\u2019intervention n\u2019occasionne de g\u00eane pour les occupants dans les locaux \u00e0 occupation autre que passag\u00e8re (c\u2019est-\u00e0-dire un local qui par destination implique une dur\u00e9e de s\u00e9jour pour un occupant sup\u00e9rieure \u00e0 une demi-heure) ; en dehors des heures d\u2019occupation du b\u00e2timent. | Le but de cette exigence est de s\u2019assurer que la conception technique et architecturale permet une r\u00e9duction des d\u00e9lais d\u2019intervention et des co\u00fbts associ\u00e9s. | Les \u00e9quipements techniques consid\u00e9r\u00e9s sont les \u00e9quipements de production suivants : Syst\u00e8mes de chauffage/rafra\u00eechissement ; Syst\u00e8mes de ventilation ; Syst\u00e8mes relatifs aux courants faibles/forts (transformateurs, groupes \u00e9lectrog\u00e8nes, syst\u00e8me de production d\u2019\u00e9nergie, etc.) ; Syst\u00e8mes de gestion de l\u2019eau ; Ainsi que pour les syst\u00e8mes \u00e9lectrom\u00e9caniques (\u00e9l\u00e9vateurs, ascenseurs, monte-charges, etc.). | Cette question peut se traiter par exemple par : la pr\u00e9sence d\u2019un local technique centralis\u00e9 ; la planification des interventions en l\u2019absence des occupants (Note : les interventions de nuit ou le week-end hors contrat \u00ab principal \u00bb avec l\u2019exploitant ne peuvent \u00eatre valoris\u00e9es dans cette exigence visant \u00e0 r\u00e9duire les co\u00fbts li\u00e9s \u00e0 ces interventions) ; etc.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Coh\u00e9rence des objectifs avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans justifiant l\u2019accessibilit\u00e9 aux \u00e9quipements de production et au syst\u00e8me \u00e9lectrom\u00e9canique.</td><td>Coh\u00e9rence des hypoth\u00e8ses d\u2019intervention avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>DIUO, DOE justifiant l\u2019accessibilit\u00e9 aux \u00e9quipements de production et au syst\u00e8me \u00e9lectrom\u00e9canique. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Constat in situ des dispositions d\u00e9crites.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2.3.4":{attendu:"Pr\u00e9sence de locaux de stockage des produits et mat\u00e9riels d\u2019entretien et de maintenance.",definition:"Cette exigence demande de garantir la pr\u00e9sence de locaux de stockage pour l\u2019entretien et la maintenance du b\u00e2timent. Il peut s\u2019agir de locaux s\u00e9par\u00e9s (a minima un pour l\u2019entretien et un pour la maintenance) ou d\u2019un local commun permettant les deux. | Il est demand\u00e9 que : Ce(s) local(aux) soi(en)t s\u00e9par\u00e9(s) de la zone de stockage de d\u00e9chets ; Ce(s) local(aux) permette(nt) l\u2019entreposage des produits et mat\u00e9riels pour l\u2019entretien et la maintenance du b\u00e2timent (filtres, produits de remplacement, d\u2019entretien et de maintenance\u2026).",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans.</td><td>Coh\u00e9rence entre les justificatifs et les \u00e9l\u00e9ments saisis dans ISIA.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE.</td><td>V\u00e9rification / visite in situ.</td></tr><tr><td><strong>Phase Exploitation axe B\u00e2timent</strong></td><td>DOE ou tout autre document permettant de justifier l\u2019exigence (plans, etc) (dur\u00e9e de validit\u00e9 illimit\u00e9e sauf modification du projet), visite in situ.</td><td>V\u00e9rification / visite in situ.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2.4":{intro:"Facilit\u00e9 d\u2019entretien des terminaux et organes de r\u00e9glages, vidange et secours",context:"Ce bloc \u00e9value les dispositions prises pour faciliter et s\u00e9curiser l\u2019entretien des terminaux et des organes de r\u00e9glage, vidange et secours.",non_applicabilite:"Ce bloc d\u2019exigences est non applicable pour les op\u00e9rations demandant un axe Gestion seul. Dans ce cas les points relatifs aux exigences COUT2.4 seront d\u00e9duits du total de points disponibles."},
"COUT2.4.1":{attendu:"Interventions faciles et s\u00e9curis\u00e9es sur les terminaux et sur les organes de r\u00e9glage, vidange et secours.",definition:"La facilit\u00e9 d\u2019acc\u00e8s aux terminaux ainsi qu\u2019aux organes de r\u00e9glage, vidange et secours par les intervenants d\u2019entretien et de maintenance permet de r\u00e9duire les d\u00e9lais d\u2019intervention et donc les co\u00fbts associ\u00e9s. Ce dernier \u00e9l\u00e9ment est en particulier tr\u00e8s sensible pour les composants nombreux dans le b\u00e2ti dont les co\u00fbts sont alors d\u00e9multipli\u00e9s (exemple : luminaires, filtres d\u2019a\u00e9ration, etc.). | Pour les terminaux : Il est demand\u00e9 de justifier la facilit\u00e9 et la s\u00e9curit\u00e9 d\u2019intervention de l\u2019op\u00e9rateur de maintenance sur les terminaux des \u00e9quipements des locaux \u00e0 occupation autre que passag\u00e8re. Les dispositions prises pour faciliter ces interventions incluent notamment : la localisation adapt\u00e9e des moyens d\u2019acc\u00e8s en hauteur ; le dimensionnement ad\u00e9quat des moyens d\u2019acc\u00e8s (trappes en faux plafond assez grandes) ; la simplicit\u00e9 de conception des terminaux permettant des interventions ais\u00e9es si possible standardis\u00e9es (composants standards, gestes simples, etc.). | Pour les organes de r\u00e9glage, vidange et secours : Il est demand\u00e9 que des dispositions architecturales et techniques soient prises pour faciliter et s\u00e9curiser l\u2019acc\u00e8s aux organes de r\u00e9glage, vidange et secours. La r\u00e9alisation des interventions de maintenance des terminaux doit \u00eatre possible sans d\u00e9gradation du b\u00e2ti et doit \u00eatre facilit\u00e9e pour l\u2019op\u00e9rateur.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Coh\u00e9rence des objectifs avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>CCTP, plans justifiant l\u2019accessibilit\u00e9 aux terminaux et organes de r\u00e9glage, vidange et secours.</td><td>Coh\u00e9rence des hypoth\u00e8ses de l\u2019\u00e9tude d\u2019accessibilit\u00e9 ou du DIUO avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>DIUO, DOE justifiant l\u2019accessibilit\u00e9 aux terminaux et organes de r\u00e9glage, vidange et secours. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Constat in situ des dispositions d\u00e9crites.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT2.4.2":{attendu:"Interventions possibles sur une majeure partie des terminaux et sur les organes de r\u00e9glage, vidange de secours sans g\u00eane majeure pour les occupants.",definition:"La possibilit\u00e9 d\u2019intervention sur les terminaux ainsi que sur les organes de r\u00e9glage, vidange et secours sans g\u00eane majeure pour les occupants permet de r\u00e9duire les d\u00e9lais d\u2019intervention et donc les co\u00fbts associ\u00e9s. Ce dernier \u00e9l\u00e9ment est en particulier tr\u00e8s sensible pour les composants nombreux dans le b\u00e2ti dont les co\u00fbts sont alors d\u00e9multipli\u00e9s (exemple : luminaires, filtres d\u2019a\u00e9ration, etc.). | Pour les terminaux : Il est demand\u00e9 que la majeure partie des terminaux des \u00e9quipements soit accessible depuis un local non fr\u00e9quent\u00e9 par les occupants de mani\u00e8re prolong\u00e9e (occupation de plus d\u2019une demi-heure par la m\u00eame personne) ou que les terminaux ne n\u00e9cessitent pas d\u2019intervention de maintenance r\u00e9guli\u00e8re (6 mois) ou des interventions n\u00e9cessitant l\u2019interruption de l\u2019activit\u00e9 normale de l\u2019occupant. | Les dispositions techniques ou architecturales prises doivent permettre de couvrir les quatre syst\u00e8mes suivants : Syst\u00e8mes de chauffage/rafra\u00eechissement ; Syst\u00e8mes de ventilation ; Syst\u00e8mes relatifs aux courants faibles/forts ; Syst\u00e8mes de gestion de l\u2019eau. | Pour les organes de r\u00e9glage, vidange et secours : Il s\u2019agit de s\u2019assurer que la majeure partie des organes de r\u00e9glage, vidange et secours sont accessibles depuis un local non fr\u00e9quent\u00e9 par les occupants de mani\u00e8re prolong\u00e9e.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Objectifs pr\u00e9cis\u00e9s dans le programme de l\u2019op\u00e9ration.</td><td>Coh\u00e9rence des objectifs avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Liste des terminaux n\u00e9cessitant une maintenance r\u00e9guli\u00e8re + CCTP et plans techniques.</td><td>Coh\u00e9rence de la liste des terminaux avec les \u00e9l\u00e9ments du projet.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation axe B\u00e2timent</strong></td><td>Liste des terminaux n\u00e9cessitant une maintenance r\u00e9guli\u00e8re + DIUO, DOE. Justification de l\u2019absence de n\u00e9cessit\u00e9 d\u2019entretien r\u00e9gulier des terminaux. En phase Exploitation : Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9.</td><td>Coh\u00e9rence de la liste des terminaux avec les \u00e9l\u00e9ments du projet et constat in situ des dispositions d\u00e9crites.</td></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Non concern\u00e9e.</td><td>Sans objet</td></tr></table>"},
"COUT3":{intro:"Ma\u00eetrise des co\u00fbts de gros remplacement",context:"Ce sous-th\u00e8me \u00e9value l\u2019estimation des dur\u00e9es de vie pr\u00e9visionnelles et co\u00fbts de remplacements, ainsi que l\u2019\u00e9laboration d\u2019un plan pluriannuel de travaux."},
"COUT3.1":{intro:"Co\u00fbts de remplacements et de gros renouvellements",context:"Ce bloc \u00e9value la planification des remplacements et gros renouvellements des principaux \u00e9quipements et \u00e9l\u00e9ments du b\u00e2ti."},
"COUT3.1.1":{attendu:"Estimation des dur\u00e9es de vie pr\u00e9visionnelles et co\u00fbts de remplacement des principaux \u00e9quipements et \u00e9l\u00e9ments du b\u00e2ti.",definition:"Cette exigence vise \u00e0 \u00e9valuer l\u2019estimation d\u00e9taill\u00e9e des co\u00fbts de remplacement majeurs pour au moins 2 lots min imum. Sont consid\u00e9r\u00e9s comme lots \u00e9ligibles : couverture, fa\u00e7ade, menuiseries, chaudi\u00e8res, chauffage, climatisation, plomberie, \u00e9lectricit\u00e9, ascenseurs, escaliers, structures porteuses, ITE, syst\u00e8mes VMC, syst\u00e8mes sant\u00e9, chauffage, r\u00e9seaux.",notation:"Non applicable | Non atteint : 0 point | Co\u00fbts estim\u00e9s sur 2 lots : 2 points | Co\u00fbts estim\u00e9s sur 4 lots : 4 points | Co\u00fbts estim\u00e9s sur 6 lots : 5 points | Co\u00fbts estim\u00e9s sur 8 lots : 6 points",non_applicabilite:"Non applicable pour les op\u00e9rations en axe Gestion seul ou en axe Programme/Conception sans \u00e9bauche d\u2019architecture. Dans ce cas les points seront d\u00e9duits du total de points disponibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>Sch\u00e9ma directeur de maintenance \u00e0 long terme. Estimations co\u00fbts remplacement.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Plan pluriannuel de travaux avec budg\u00e9tisation.</td></tr></table>"},
"COUT3.1.2":{attendu:"Elaboration d\u2019un plan pluriannuel de travaux de gros renouvellements.",definition:"Cette exigence vise \u00e0 v\u00e9rifier la mise en place d\u2019un plan pr\u00e9visionnel couvrant au moins 5 ou 10 ans, planifiant les travaux majeurs et remplacements d\u2019\u00e9quipements.",notation:"Non applicable | Non atteint : 0 point | Pr\u00e9sence d\u2019un plan pluriannuel \u00e0 5 ans : 1 point | Pr\u00e9sence d\u2019un plan pluriannuel \u00e0 10 ans : 2 points",non_applicabilite:"Non applicable pour les op\u00e9rations en axe Gestion seul ou en axe Programme/Conception sans \u00e9bauche d\u2019architecture. Dans ce cas les points seront d\u00e9duits du total de points disponibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>Plan pr\u00e9visionnel d\u2019entretien et remplacements majeurs.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>Plan pluriannuel de travaux mis \u00e0 jour r\u00e9guli\u00e8rement.</td></tr></table>"},
"COUT4":{intro:"Approches en co\u00fbt global",context:"Ce sous-th\u00e8me \u00e9value la r\u00e9alisation d\u2019analyses en co\u00fbt global pour le choix de solutions techniques ou d\u2019exploitation."},
"COUT4.1":{intro:"Approches en co\u00fbt global",context:"Ce bloc \u00e9value les analyses en co\u00fbt global \u00e9l\u00e9mentaires et d\u00e9taill\u00e9es r\u00e9alis\u00e9es sur le b\u00e2timent."},
"COUT4.1.1":{attendu:"Analyse en co\u00fbt global \u00e9l\u00e9mentaire pour le choix de solutions techniques ou d\u2019exploitation.",definition:"Cette exigence \u00e9value la r\u00e9alisation d\u2019analyses \u00e9l\u00e9mentaires en co\u00fbt global (LCC simple) pour justifier le choix de solutions techniques ou d\u2019exploitation. Une analyse doit couvrir au minimum l\u2019investissement initial et les co\u00fbts d\u2019exploitation sur une p\u00e9riode d\u00e9finie.",notation:"Non applicable | Non atteint : 0 point | Analyse a minima pour un type de solution : 3 points | Analyse a minima pour 2 types de solution : 4 points | Analyse a minima pour 3 types de solution : 5 points",non_applicabilite:"Non applicable pour les op\u00e9rations en axe Gestion seul ou pour lesquelles aucune solution technique altern ative n\u2019est envisag\u00e9e. Dans ce cas les points seront d\u00e9duits du total de points disponibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>Analyses co\u00fbt global \u00e9l\u00e9mentaires. Justifications des choix techniques ou exploitation.</td></tr></table>"},
"COUT4.1.2":{attendu:"Analyse en co\u00fbt global d\u00e9taill\u00e9e du b\u00e2timent ou de l\u2019exploitation.",definition:"Cette exigence \u00e9value la r\u00e9alisation d\u2019une analyse d\u00e9taill\u00e9e et compl\u00e8te du co\u00fbt global du b\u00e2timent sur toute sa dur\u00e9e de vie, ou de l\u2019exploitation. Cette \u00e9tude doit couvrir : tous les lots d\u2019\u00e9quipements, tous les postes de co\u00fbts (investissement, op\u00e9ration, maintenance, renouvellement), une p\u00e9riode suffisamment longue (30 ans minimum ou dur\u00e9e de vie du b\u00e2timent). Les m\u00e9thodes de r\u00e9f\u00e9rence incluent VAN, ISO 15686-5, NF EN 16627.",notation:"Non applicable | Non atteint : 0 point | Etude en co\u00fbt global d\u00e9taill\u00e9e : 10 points",non_applicabilite:"Non applicable pour les op\u00e9rations en axe Gestion seul ou pour lesquelles une \u00e9tude d\u00e9taill\u00e9e n\u2019est pas pertinente. Dans ce cas les points seront d\u00e9duits du total de points disponibles.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Conception</strong></td><td>\u00c9tude d\u00e9taill\u00e9e en co\u00fbt global du b\u00e2timent. Donn\u00e9es utilis\u00e9es, m\u00e9thodologie appliqu\u00e9e.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td>\u00c9tude de co\u00fbt global d\u00e9taill\u00e9e de l\u2019exploitation. M\u00e9thodologie appliqu\u00e9e, donn\u00e9es utilis\u00e9es.</td></tr></table>"},
"DEVT1":{intro:"Contribution \u00e0 l\u2019attractivit\u00e9 des territoires",context:"Le b\u00e2timent est facteur de d\u00e9veloppement \u00e9conomique, de cr\u00e9ation d\u2019emplois, et d\u2019attractivit\u00e9 du territoire. Il induit de nouvelles charges mais surtout de nouvelles recettes pour la collectivit\u00e9. Le b\u00e2timent par son implantation, les activit\u00e9s qu\u2019il g\u00e9n\u00e8re ou qu\u2019il h\u00e9berge ainsi que par ses relations avec le tissu \u00e9conomique local, contribue concr\u00e8tement au dynamisme et au d\u00e9veloppement des territoires. | L\u2019\u00e9valuation de ce th\u00e8me est organis\u00e9e comme suit : | Contribution au dynamisme et \u00e0 l\u2019attractivit\u00e9 des territoires : Justifier l\u2019ad\u00e9quation entre le projet et les besoins du territoire est une premi\u00e8re \u00e9tape. Elle permet de garantir que le b\u00e2timent r\u00e9pond bien \u00e0 une demande locale. La contribution au dynamisme du territoire est ensuite analys\u00e9e par le biais de dispositions favorisant une \u00e9conomie de partage, la promotion de clauses d\u2019insertion sociale par l\u2019emploi et d\u2019actions de formation, le transfert de comp\u00e9tences, et les partenariats. | Choix de fili\u00e8res locales, r\u00e9emploi et \u00e9conomie circulaire : L\u2019\u00e9valuation s\u2019attache \u00e0 analyser dans quelle mesure le projet promeut le r\u00e9emploi, et le recours \u00e0 des fili\u00e8res locales (en termes de ressources, de sources d\u2019\u00e9nergie, de recyclage de d\u00e9chets et de comp\u00e9tences) dans une optique d\u2019\u00e9conomie circulaire."},
"DEVT1.1":{intro:"Contribution \u00e0 l\u2019ancrage local",context:"Ce sous-th\u00e8me traite de la contribution du b\u00e2timent \u00e0 l\u2019ancrage local : analyse du contexte, appartenance \u00e0 une zone prioritaire, et dispositions pour l\u2019\u00e9conomie de partage."},
"DEVT1.1.1":{attendu:"Analyse des relations entre le b\u00e2timent et son contexte local.",definition:"L\u2019enjeu de cette exigence est de comprendre comment le b\u00e2timent se situe dans son contexte local afin d\u2019\u00e9ventuellement pouvoir identifier des synergies avec d\u2019autres acteurs du territoire.",non_applicabilite:"Cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable pour : les op\u00e9rations des secteurs \u00ab p\u00e9nitentiaire \u00bb et \u00ab data center \u00bb ; sur justifications, les op\u00e9rations qui ne peuvent mettre en place de synergies pour des raisons de s\u00e9curit\u00e9 ou d\u2019acc\u00e8s r\u00e9glement\u00e9. Si l\u2019exigence est non applicable, les points seront alors d\u00e9duits du total de points disponibles.",notation:"Non applicable | Non atteint : 0 point | Analyse du contexte uniquement : 1 point | Analyse du contexte ET identification de potentiels de synergie : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme, Conception et R\u00e9alisation</strong></td><td>Pour le premier niveau : Synth\u00e8se des documents strat\u00e9giques du territoire (Exemples en France : PLU, SCOT, Sch\u00e9mas Directeurs, etc.) OU Document de pr\u00e9sentation du projet \u00e0 la collectivit\u00e9 et tra\u00e7abilit\u00e9 associ\u00e9e (PPT, CR de r\u00e9union, etc.) OU Document de pr\u00e9sentation du projet reprenant les \u00e9l\u00e9ments demand\u00e9s. Pour le deuxi\u00e8me niveau : Documents attestant de la tra\u00e7abilit\u00e9 d\u2019une concertation avec les parties prenantes (PPT, CR de r\u00e9union, etc.) OU Document attestant d\u2019une r\u00e9flexion sur la recherche de synergies pour les activit\u00e9s \u00e9tudi\u00e9es.</td><td>Coh\u00e9rence des informations avec les caract\u00e9ristiques du projet.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td colspan=\"2\">Non concern\u00e9es.</td></tr></table>"},
"DEVT1.1.2":{attendu:"Appartenance du b\u00e2timent \u00e0 une zone prioritaire pour le renouvellement urbain OU b\u00e2timent correspondant \u00e0 une r\u00e9habilitation de b\u00e2timent d\u00e9saffect\u00e9.",definition:"L\u2019exigence vise \u00e0 valoriser les projets (ou b\u00e2timents existants) issus d\u2019une volont\u00e9 de redynamisation du territoire, se situant donc dans une zone d\u2019am\u00e9nagement prioritaire et r\u00e9pondant \u00e0 une priorit\u00e9 pour le d\u00e9veloppement \u00e9conomique local. | Elle peut \u00eatre atteinte de deux mani\u00e8res diff\u00e9rentes : | Option 1 : Le b\u00e2timent appartient \u00e0 une zone consid\u00e9r\u00e9e comme prioritaire pour le renouvellement urbain (ancienne friche industrielle, zone \u00e9conomiquement d\u00e9favoris\u00e9e, zone franche urbaine, requalification urbaine, etc.). Les zones consid\u00e9r\u00e9es comme \u00ab prioritaires \u00bb pour le d\u00e9veloppement territorial sont par exemple les suivantes : site appartenant \u00e0 un projet de r\u00e9habilitation d\u2019une friche industrielle. Plus sp\u00e9cifiquement en France : site appartenant au p\u00e9rim\u00e8tre ANRU, site couvert par une Convention du PNRQAD, site appartenant \u00e0 une Zone Franche Urbaine (ZFU), site appartenant \u00e0 un programme de revitalisation des centres-bourgs de l\u2019ANAH. | Option 2 : Le b\u00e2timent correspond \u00e0 une r\u00e9habilitation de b\u00e2timent d\u00e9saffect\u00e9. Un b\u00e2timent est consid\u00e9r\u00e9 comme d\u00e9saffect\u00e9 s\u2019il a perdu son activit\u00e9 d\u2019origine et n\u2019abrite plus aucune activit\u00e9 depuis, la p\u00e9riode d\u2019inoccupation devant avoir \u00e9t\u00e9 prolong\u00e9e. Exemples : requalification d\u2019anciens b\u00e2timents industriels en bureaux ou mus\u00e9e, ancien dock transform\u00e9 en restaurant ou salle de spectacle, etc.",non_applicabilite:"Cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable si le b\u00e2timent n\u2019est pas dans une zone prioritaire pour le renouvellement urbain. Si l\u2019exigence est non applicable, les points seront alors d\u00e9duits du total de points disponibles.",notation:"Non applicable | Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme, Conception et R\u00e9alisation</strong></td><td>Document prouvant l\u2019appartenance \u00e0 une zone prioritaire OU document prouvant que le b\u00e2timent correspond \u00e0 une r\u00e9habilitation de b\u00e2timent d\u00e9saffect\u00e9. Dur\u00e9e de validit\u00e9 des modes de preuve : Illimit\u00e9e (sauf modification du projet).</td><td>Localisation du projet ou dernier historique du site.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td colspan=\"2\">Non concern\u00e9es.</td></tr></table>"},
"DEVT1.1.3":{attendu:"Dispositions prises pour favoriser l\u2019\u00e9conomie de partage au sein du b\u00e2timent ou entre le b\u00e2timent et son voisinage.",definition:"Pour un projet de construction, l\u2019enjeu de cette exigence est de concevoir des b\u00e2timents ouverts sur le quartier ou proposant des activit\u00e9s mutualis\u00e9es au sein de diff\u00e9rentes entit\u00e9s du b\u00e2timent (dans une optique d\u2019\u00e9conomie de partage). Les espaces concern\u00e9s doivent obligatoirement appartenir au p\u00e9rim\u00e8tre certifi\u00e9. | Les dispositions (programmatiques, architecturales ou d\u2019exploitation) validant cette exigence peuvent \u00eatre de deux types : | Ouverture d\u2019espaces ou de services pourvus par le b\u00e2timent \u00e0 son voisinage : il s\u2019agit ici de pr\u00e9voir que certains espaces/services puissent \u00eatre \u00ab ouverts \u00bb et fr\u00e9quent\u00e9s par le voisinage (habitants, riverains, etc.), dans une optique d\u2019\u00e9conomie de partage. Il ne s\u2019agit pas de la pr\u00e9sence de ces services, \u00e9valu\u00e9s dans un autre objectif du pr\u00e9sent r\u00e9f\u00e9rentiel. Il s\u2019agit bien de rendre ces services/espaces ouverts sur le quartier. | Mutualisation de certains espaces pour des activit\u00e9s ou des usagers diff\u00e9rents, par exemple : RIE pouvant \u00eatre utilis\u00e9 en salle de r\u00e9union en dehors des heures de repas, cellules logistiques pouvant \u00eatre utilis\u00e9es par plusieurs preneurs, etc.",non_applicabilite:"Cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable pour : les op\u00e9rations des secteurs \u00ab p\u00e9nitentiaire \u00bb et \u00ab data center \u00bb ; sur justifications, les op\u00e9rations qui ne peuvent mettre en place de la mutualisation d\u2019activit\u00e9s pour des raisons de s\u00e9curit\u00e9 ou d\u2019acc\u00e8s r\u00e9glement\u00e9. Si l\u2019exigence est non applicable, les deux points seront alors d\u00e9duits du total de points disponibles.",notation:"Non applicable | Aucune disposition : 0 point | A minima 1 type de disposition : 1 point | A minima 2 types de disposition : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme int\u00e9grant les \u00e9l\u00e9ments demand\u00e9s.</td><td>Intentions concernant l\u2019\u00e9conomie de partage.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Plans d\u2019am\u00e9nagement. CCTP / DCE int\u00e9grant les dispositions architecturales.</td><td>Coh\u00e9rence des dispositions avec les plans.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DOE int\u00e9grant les am\u00e9nagements r\u00e9alis\u00e9s. Photos/sch\u00e9mas de circulation. Visite du site. Contrats et convention li\u00e9s au partage/entretien/s\u00e9curit\u00e9 de ces espaces prouvant leur mutualisation effective. Dur\u00e9e de validit\u00e9 : 1 an.</td><td>Mutualisation effective des espaces.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td colspan=\"2\">Non concern\u00e9es.</td></tr></table>"},
"DEVT1.2":{intro:"Promotion de l\u2019emploi et de l\u2019insertion sociale",context:"Ce sous-th\u00e8me traite de la promotion de l\u2019emploi et de l\u2019insertion sociale : estimation des emplois g\u00e9n\u00e9r\u00e9s, clauses d\u2019insertion dans les march\u00e9s, et respect de seuils d\u2019heures en insertion."},
"DEVT1.2.1":{attendu:"Estimation des emplois g\u00e9n\u00e9r\u00e9s par le projet (\u00e9tudes et chantier sur un projet de construction/r\u00e9novation, exploitation sur un b\u00e2timent existant).",definition:"Il s\u2019agit d\u2019avoir une tra\u00e7abilit\u00e9 des emplois g\u00e9n\u00e9r\u00e9s par le projet de construction/r\u00e9novation (phases \u00e9tudes et travaux) ou par l\u2019exploitation du b\u00e2timent (pour un b\u00e2timent existant), et ce pour l\u2019ensemble des prestations. | P\u00e9rim\u00e8tre de l\u2019indicateur : A minima, le calcul doit reposer sur une estimation bas\u00e9e sur les diff\u00e9rentes entreprises intervenant dans le projet pour un b\u00e2timent en construction ou r\u00e9novation, ou sur les diff\u00e9rents contrats pour un b\u00e2timent en exploitation. | Le r\u00e9sultat doit \u00eatre fourni sous forme d\u2019\u00e9quivalent temps plein (\u00ab ETP \u00bb) d\u2019emplois g\u00e9n\u00e9r\u00e9s par le projet (CDI, CDD, int\u00e9rim, contrat d\u2019apprentissage, stages, etc.). | En construction ou en r\u00e9novation, les ETP doivent \u00eatre calcul\u00e9s en fonction des effectifs mobilis\u00e9s pendant la dur\u00e9e du projet de construction ou r\u00e9novation. | Pour un b\u00e2timent existant, les ETP doivent \u00eatre calcul\u00e9s en fonction des effectifs mobilis\u00e9s annuellement pour l\u2019exploitation du b\u00e2timent.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Calcul des emplois avec source des donn\u00e9es et m\u00e9thode utilis\u00e9e, faisant appara\u00eetre le nombre d\u2019emplois en \u00e9quivalent ETP. Dur\u00e9e de validit\u00e9 des modes de preuve : 2 ans.</td><td>Prise en compte de l\u2019ensemble des prestataires intervenant directement dans le projet. Calcul mis \u00e0 jour \u00e0 chaque phase.</td></tr></table>"},
"DEVT1.2.2":{attendu:"Utilisation d\u2019une clause d\u2019insertion dans les march\u00e9s de construction ou d\u2019exploitation.",definition:"L\u2019enjeu est de favoriser l\u2019emploi d\u2019insertion en utilisant les clauses d\u2019insertion sociale dans les march\u00e9s de construction ou d\u2019exploitation (pour un b\u00e2timent existant). | Une clause d\u2019insertion est d\u00e9finie comme un article sp\u00e9cifique introduit dans les march\u00e9s, appels d\u2019offre ou contrats destin\u00e9 \u00e0 favoriser l\u2019emploi de personnes en difficult\u00e9 (personnes en situation de handicap, \u00c9SAT, ch\u00f4meurs de longue dur\u00e9e, personnes en r\u00e9insertion professionnelle, jeunes sans qualification, apprentis, etc.) par les entreprises qui vont obtenir lesdits march\u00e9s. Une clause d\u2019insertion est g\u00e9n\u00e9ralement formul\u00e9e sous forme d\u2019engagement sur un nombre minimal d\u2019heures d\u2019insertion que l\u2019entreprise retenue devra justifier avoir r\u00e9alis\u00e9es au b\u00e9n\u00e9fice des personnes en difficult\u00e9 vis\u00e9es par la clause.",notation:"Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme int\u00e9grant l\u2019engagement \u00e0 utiliser la clause d\u2019insertion.</td><td>Pr\u00e9sence d\u2019une clause d\u2019insertion.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Clause d\u2019insertion (g\u00e9n\u00e9rale ou particuli\u00e8re) visible dans le DCE.</td><td>Pr\u00e9sence d\u2019une clause d\u2019insertion dans le DCE.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Clause d\u2019insertion (g\u00e9n\u00e9rale ou particuli\u00e8re) visible dans le DOE.</td><td>Pr\u00e9sence d\u2019une clause d\u2019insertion dans le DOE.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Clause d\u2019insertion visible dans le(les) contrat(s) d\u2019exploitation concern\u00e9s. Dur\u00e9e de validit\u00e9 : Dur\u00e9e du(des) contrat(s).</td><td>Pr\u00e9sence d\u2019une clause d\u2019insertion dans le(les) contrat(s).</td></tr></table>"},
"DEVT1.2.3":{attendu:"Respect d\u2019un seuil minimum d\u2019heures en insertion (en %) par rapport au nombre total d\u2019heures de main d\u2019\u0153uvre (chantier ou exploitation).",definition:"Pour les op\u00e9rations de construction ou de r\u00e9novation : Il s\u2019agit de s\u2019assurer du suivi de la clause d\u2019insertion et de parvenir \u00e0 l\u2019atteinte d\u2019un certain quota d\u2019heures en insertion pendant le chantier, parmi le nombre total d\u2019heures de main d\u2019\u0153uvre. Un bilan final des heures d\u2019insertion est \u00e9galement demand\u00e9 une fois le chantier achev\u00e9. | Pour les contrats en exploitation : Il s\u2019agit de s\u2019assurer du respect d\u2019un nombre minimum d\u2019heures en insertion pour la main d\u2019\u0153uvre employ\u00e9e sur le b\u00e2timent. | Le taux d\u2019insertion est \u00e0 calculer en fonction du nombre d\u2019heures d\u2019insertion par rapport au nombre total d\u2019heures de main d\u2019\u0153uvre globale (y compris celle qui n\u2019avait pas de clauses d\u2019insertion dans leur contrat).",notation:"Non atteint : 0 point | Taux < 5% : 1 point | 5% \u2264 taux < 8% : 2 points | \u2265 8% : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme int\u00e9grant les \u00e9l\u00e9ments demand\u00e9s.</td><td>Taux d\u2019insertion vis\u00e9s.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Seuils et demande de suivi/bilan visibles dans le DCE.</td><td>Taux d\u2019insertion et respect des seuils demand\u00e9s.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Document de tra\u00e7abilit\u00e9 attestant du suivi des heures d\u2019insertion sur chantier. Calcul justifiant de l\u2019atteinte des seuils minimums demand\u00e9s.</td><td>Taux d\u2019insertion et respect des seuils demand\u00e9s. Tra\u00e7abilit\u00e9 des heures d\u2019insertion.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Seuils et demande de suivi/bilan visibles dans les contrats d\u2019exploitation. Document de tra\u00e7abilit\u00e9 attestant du suivi des heures d\u2019insertion pour les contrats d\u2019exploitation. Calcul justifiant de l\u2019atteinte des seuils minimums demand\u00e9s.</td><td>Taux d\u2019insertion et respect des seuils demand\u00e9s. Tra\u00e7abilit\u00e9 des heures d\u2019insertion.</td></tr></table>"},
"DEVT1.3":{intro:"Participation \u00e0 une mont\u00e9e en comp\u00e9tence des acteurs",context:"Ce sous-th\u00e8me traite des dispositions prises pour la formation et la mont\u00e9e en comp\u00e9tence des acteurs du projet et des acteurs locaux."},
"DEVT1.3.1":{attendu:"Dispositions prises pour la formation et la mont\u00e9e en comp\u00e9tence des acteurs participant au projet ou intervenant sur le b\u00e2timent.",definition:"L\u2019enjeu est de faire monter en comp\u00e9tence les acteurs de l\u2019op\u00e9ration au travers d\u2019actions de sensibilisation ou de formation. | Ces actions sont \u00e0 destination des acteurs du projet (ma\u00eetrise d\u2019ouvrage, ma\u00eetrise d\u2019\u0153uvre, entreprises de travaux, exploitant, autres prestataires) ou des personnes intervenant sur le b\u00e2timent (prestataire d\u2019entretien, de nettoyage, d\u2019accueil, de maintenance...). Elles doivent porter sur des probl\u00e9matiques environnementales dans la conception, construction ou gestion du b\u00e2timent ou sur des pratiques, techniques ou produits sp\u00e9cifiques utilis\u00e9s sur le projet ou dans l\u2019exploitation du b\u00e2timent. | Le premier niveau de points (\u00ab Mise en place de r\u00e9unions de sensibilisation uniquement \u00bb) peut \u00eatre atteint par la mise en place de r\u00e9unions de sensibilisation. | Le second niveau de points (\u00ab Recours ou mise en place de formations \u00bb) n\u00e9cessite le recours \u00e0 des formations plus formalis\u00e9es mises en place par le demandeur directement ou par des organismes prestataires ou partenaires.",notation:"Non atteint : 0 point | Mise en place de r\u00e9unions de sensibilisation uniquement : 1 point | Recours ou mise en place de formations : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Note d\u2019intention sur la mise en place de r\u00e9unions de sensibilisation ou de formations.</td><td>Intentions concernant la formation et la comp\u00e9tence des acteurs.</td></tr><tr><td><strong>Phases Conception, R\u00e9alisation et Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Preuves de l\u2019organisation de r\u00e9unions de sensibilisation (supports ou compte-rendu) OU preuve de la formation des acteurs (pr\u00e9sentation de la formation et document synth\u00e9tisant les nombres d\u2019heures de formation d\u00e9livr\u00e9es et le nombre de personnes form\u00e9es). Dur\u00e9e de validit\u00e9 : 3 ans.</td><td>Contenu des actions de sensibilisation ou de formation cibl\u00e9 sur des probl\u00e9matiques environnementales et/ou des pratiques, produits ou techniques innovants. Public des actions cibl\u00e9 sur des acteurs du projet ou des personnes intervenant sur le b\u00e2timent.</td></tr></table>"},
"DEVT1.3.2":{attendu:"Dispositions prises pour la mont\u00e9e en comp\u00e9tence des acteurs locaux.",definition:"L\u2019enjeu est de faire monter en comp\u00e9tence les acteurs locaux par rapport \u00e0 des pratiques, techniques, produits ou syst\u00e8mes innovants mis en place sur l\u2019op\u00e9ration, par le biais d\u2019actions de formation ou sensibilisation. | Ces actions sont \u00e0 destination des acteurs locaux (ma\u00eetre d\u2019ouvrage, ma\u00eetre d\u2019\u0153uvre, entreprises de travaux, exploitant, autres prestataires) susceptibles \u00e0 l\u2019avenir de mettre en place ces pratiques, techniques, produits ou syst\u00e8mes localement. | Une pratique, une technique, un produit, ou un syst\u00e8me sont ici consid\u00e9r\u00e9s comme \u00ab innovant \u00bb lorsqu\u2019ils ne sont pas mis en place couramment dans la r\u00e9gion d\u2019implantation, ou lorsqu\u2019il apporte pour la premi\u00e8re fois au march\u00e9, ou int\u00e8gre, ou comporte en retour un b\u00e9n\u00e9fice, une efficacit\u00e9 ou une solution que n\u2019apportent pas ou mal les pratiques, techniques, produits, ou syst\u00e8mes existants.",non_applicabilite:"Si l\u2019op\u00e9ration ne comporte pas de pratiques, techniques, produits ou syst\u00e8mes innovants, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable. Les points seront alors d\u00e9duits du total de points disponibles.",notation:"Non applicable | Non atteint : 0 point | Atteint : 2 points",attention:"Pour l\u2019\u00cele de la R\u00e9union, Mayotte, la Martinique, la Guadeloupe, Saint-Barth\u00e9lemy, Saint-Martin, la Guyane, la Nouvelle Cal\u00e9donie, la Polyn\u00e9sie fran\u00e7aise, Wallis et Futuna : sont appel\u00e9s \u00ab locaux \u00bb, les acteurs \u00e0 l\u2019\u00e9chelle de chaque territoire.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Note d\u2019intention sur la mise en place de r\u00e9unions de sensibilisation ou de formations.</td><td>Intentions concernant la formation et la comp\u00e9tence des acteurs locaux.</td></tr><tr><td><strong>Phases Conception, R\u00e9alisation et Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Preuves de l\u2019organisation de sensibilisation (supports ou compte-rendu) OU de formation des acteurs locaux. Dur\u00e9e de validit\u00e9 : 3 ans.</td><td>Contenu des sensibilisations ou formations sur les pratiques, techniques, produits ou syst\u00e8mes innovants. Public de ces actions cibl\u00e9 sur des acteurs locaux susceptibles de les mettre en place.</td></tr></table>"},
"DEVT2":{intro:"\u00c9conomie circulaire, r\u00e9emploi et choix de fili\u00e8res locales",context:"Ce sous-th\u00e8me traite du recours \u00e0 des composants assembl\u00e9s localement, du r\u00e9emploi et de la r\u00e9utilisation, de la s\u00e9lection de fili\u00e8res locales participant \u00e0 une \u00e9conomie circulaire, et du recours \u00e0 des comp\u00e9tences locales."},
"DEVT2.1":{intro:"S\u00e9lection de composants assembl\u00e9s localement",context:"Ce sous-th\u00e8me traite du recours \u00e0 un seuil minimum de composants assembl\u00e9s localement, \u00e9valu\u00e9 en pourcentage de co\u00fbt des achats par rapport au co\u00fbt total des travaux ou des budgets de Gros Entretien Renouvellement."},
"DEVT2.1.1":{attendu:"Recours \u00e0 un seuil minimum de composants assembl\u00e9s localement (en % de co\u00fbt des achats par rapport au co\u00fbt total des travaux ou des budgets de Gros Entretien Renouvellement pour un b\u00e2timent existant).",definition:"Est appel\u00e9e \u00ab locale \u00bb une implantation du lieu d\u2019assemblage du composant \u00e0 une distance \u2264 180 km ou dans la r\u00e9gion administrative du chantier (ou du b\u00e2timent). Le seuil est \u00e9valu\u00e9 en pourcentage de co\u00fbt des achats par rapport au co\u00fbt total des travaux ou des budgets de Gros Entretien Renouvellement pour b\u00e2timent existant. | L\u2019origine locale d\u2019un composant est \u00e9tablie \u00e0 partir du lieu o\u00f9 le composant acquiert ses caract\u00e9ristiques principales. Celui-ci correspond : \u00e0 l\u2019usine de fabrication et d\u2019assemblage pour des composants pr\u00eats \u00e0 \u00eatre utilis\u00e9s (par exemple pour les menuiseries, les panneaux de bois ou les rouleaux d\u2019isolants) ; au lieu de pr\u00e9paration pour les \u00e9l\u00e9ments mis en forme sur le chantier (par exemple, la centrale \u00e0 b\u00e9ton pour le b\u00e9ton).",notation:"< 15% du co\u00fbt d\u2019achat : 0 point | \u2265 15% du co\u00fbt d\u2019achat : 1 point | \u2265 25% du co\u00fbt d\u2019achat : 2 points | \u2265 40% du co\u00fbt d\u2019achat : 3 points",attention:"Pour l\u2019\u00cele de la R\u00e9union, Mayotte, la Martinique, la Guadeloupe, Saint-Barth\u00e9lemy, Saint-Martin, la Guyane, la Nouvelle Cal\u00e9donie, la Polyn\u00e9sie fran\u00e7aise, Wallis et Futuna : sont appel\u00e9s \u00ab assembl\u00e9s localement \u00bb, les composants assembl\u00e9s sur chaque territoire.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme et Conception</strong></td><td>Programme int\u00e9grant les \u00e9l\u00e9ments demand\u00e9s.</td><td>Intentions sur le recours \u00e0 un seuil minimal de composants assembl\u00e9s localement.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>DCE int\u00e9grant les \u00e9l\u00e9ments demand\u00e9s avec un paragraphe engageant l\u2019entreprise sur la localisation de l\u2019assemblage des composants. ET Note de calcul estimant le montant des travaux pour les principaux lots concern\u00e9s.</td><td>Provenance locale des composants pris en compte dans le calcul pour justifier l\u2019atteinte des seuils.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Contrat d\u2019exploitation li\u00e9 au Gros Entretien Renouvellement. Calcul du % du co\u00fbt + bordereaux de prix. Dur\u00e9e de validit\u00e9 : 5 ans.</td><td>Provenance locale des composants pour justifier l\u2019atteinte des seuils.</td></tr></table>"},
"DEVT2.2":{intro:"R\u00e9emploi et r\u00e9utilisation",context:"Ce sous-th\u00e8me traite du r\u00e9emploi et de la r\u00e9utilisation de mat\u00e9riaux et composants dans le cadre du projet. Non applicable pour les op\u00e9rations en exploitation axe B\u00e2timent ou Gestion."},
"DEVT2.2.1":{attendu:"\u00c9tude de faisabilit\u00e9 pour le r\u00e9emploi et la r\u00e9utilisation.",definition:"Cette exigence vise \u00e0 valoriser l\u2019\u00e9tude de faisabilit\u00e9 pour le r\u00e9emploi et la r\u00e9utilisation de mat\u00e9riaux issus de la d\u00e9construction. | L\u2019\u00e9tude de faisabilit\u00e9 comportera : un volet assurantiel et r\u00e9glementaire ; un diagnostic ressources. | Le diagnostic ressources conditionnera l\u2019optimisation du r\u00e9emploi/r\u00e9utilisation sur le projet. L\u2019enjeu du diagnostic ressources est de pr\u00e9parer le d\u00e9ploiement du r\u00e9emploi/r\u00e9utilisation de mat\u00e9riaux. Le but est ici d\u2019identifier le gisement de mat\u00e9riaux et de produits r\u00e9employables/r\u00e9utilisables. | Ce diagnostic consiste \u00e0 : caract\u00e9riser les gisements ; indiquer les nouveaux domaines d\u2019emploi ou d\u2019utilisation ; identifier les ouvrages du projet pouvant n\u00e9cessiter les mat\u00e9riaux de r\u00e9emploi/r\u00e9utilisation ; expliciter la d\u00e9pose, la pr\u00e9paration et la mise en \u0153uvre des mat\u00e9riaux ; v\u00e9rifier la faisabilit\u00e9 par une \u00e9tude d\u2019impact (\u00e9conomique, logistique et/ou environnementale).",non_applicabilite:"Cette exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable pour les op\u00e9rations en construction neuve.",reglementation:"LOI n\u00b0 2020-105 du 10 f\u00e9vrier 2020 relative \u00e0 la lutte contre le gaspillage et \u00e0 l\u2019\u00e9conomie circulaire. | D\u00e9cret n\u00b02021-821 du 25 juin 2021 relatif au diagnostic portant sur la gestion des produits \u00e9quipements, mat\u00e9riaux et d\u00e9chets issus de la d\u00e9molition ou de la r\u00e9novation significative de b\u00e2timents. | Arr\u00eat\u00e9 du 26 mars 2023 relatif au diagnostic portant sur la gestion des produits, \u00e9quipements, mat\u00e9riaux et d\u00e9chets issus de la d\u00e9molition ou de la r\u00e9novation significative de cat\u00e9gories de b\u00e2timents.",notation:"Non applicable | Non atteint : 0 point | Atteint : 4 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme de l\u2019op\u00e9ration.</td><td>D\u00e9finition des objectifs \u00e0 atteindre.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Le volet assurantiel et r\u00e9glementaire et le diagnostic ressources.</td><td>Coh\u00e9rence entre les \u00e9l\u00e9ments du justificatif.</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Mise \u00e0 jour du volet assurantiel et r\u00e9glementaire et du diagnostic ressources.</td><td>Coh\u00e9rence.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td colspan=\"2\">Non concern\u00e9es.</td></tr></table>"},
"DEVT2.2.2":{attendu:"R\u00e9emploi (HORS terres).",definition:"Cette exigence vise \u00e0 \u00e9valuer la part des produits : qui sont utilis\u00e9s sur le chantier concern\u00e9 et qui viennent du r\u00e9emploi (des plateformes de r\u00e9emploi par exemple) ; OU qui viennent du chantier concern\u00e9 et sont ensuite valoris\u00e9s ailleurs par du r\u00e9emploi. | Les terres ne sont pas concern\u00e9es par cette cat\u00e9gorie (elles sont comptabilis\u00e9es dans les exigences du th\u00e8me D\u00e9chets). | Le r\u00e9emploi est d\u00e9fini comme : \u00ab toute op\u00e9ration par laquelle des substances, mati\u00e8res ou produits qui ne sont pas des d\u00e9chets sont utilis\u00e9s de nouveau pour un usage identique \u00e0 celui pour lequel ils avaient \u00e9t\u00e9 con\u00e7us \u00bb.",notation:"Non atteint : 0 point | Niveau 1 : 1 point | Niveau 2 : 2 points | Niveau 3 : 3 points | Niveau 4 : 4 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Justificatif des quantit\u00e9s de produits valoris\u00e9s par le R\u00e9emploi par type de produits.</td><td>Coh\u00e9rence entre les \u00e9l\u00e9ments du justificatif et les \u00e9l\u00e9ments saisis dans l\u2019outil.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Mise \u00e0 jour du justificatif des quantit\u00e9s de produits valoris\u00e9s par le R\u00e9emploi.</td><td>Coh\u00e9rence.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td colspan=\"2\">Non concern\u00e9es.</td></tr></table>"},
"DEVT2.2.3":{attendu:"R\u00e9utilisation avec la garantie de site et d\u2019usage (HORS terre).",definition:"Cette exigence vise \u00e0 valoriser la r\u00e9utilisation avec la garantie de site et d\u2019usage. Cela permet la pr\u00e9vention \u00e0 la cr\u00e9ation de d\u00e9chets comme le r\u00e9emploi. | Garantie de site : Le mat\u00e9riau/composant est fabriqu\u00e9 et r\u00e9utilis\u00e9 in-situ (sur le m\u00eame site, le m\u00eame chantier) ; OU le site de r\u00e9utilisation et le ma\u00eetre d\u2019ouvrage r\u00e9cepteur sont garantis (Contrat de Cession entre ma\u00eetrises d\u2019ouvrage). | Garantie d\u2019usage : Le nouveau domaine d\u2019emploi du mat\u00e9riau/composant est garanti, notamment par un diagnostic technique qui fiabilise le nouveau domaine d\u2019emploi (diagnostic ressources).",notation:"Non atteint : 0 point | Au moins 1 type de composants dont le pourcentage de r\u00e9utilisation avec garantie \u2265 10% : 1 point | Au moins 1 type \u2265 30% OU au moins 2 types \u2265 10% : 2 points | Au moins 1 type \u2265 50% OU au moins 2 types \u2265 30% : 3 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Justificatif des quantit\u00e9s de produits valoris\u00e9s par la R\u00e9utilisation avec la garantie de site et d\u2019usage, le Diagnostic Ressource, et si besoin le Contrat de Cession.</td><td>Le Diagnostic Ressource, le Contrat de Cession et la coh\u00e9rence entre les \u00e9l\u00e9ments du justificatif.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>Mise \u00e0 jour du justificatif, du Diagnostic Ressource, et si besoin du Contrat de Cession.</td><td>Coh\u00e9rence.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td colspan=\"2\">Non concern\u00e9es.</td></tr></table>"},
"DEVT2.2.4":{attendu:"Utilisation d\u2019une partie du b\u00e2timent existant en tant que Base vie de chantier.",definition:"Cette exigence vise \u00e0 valoriser l\u2019utilisation de locaux et \u00e9quipements du b\u00e2timent existant comme base de vie. L\u2019utilisation doit concerner toute la dur\u00e9e du chantier et pas seulement une phase de celui-ci. Il s\u2019agit des \u00e9quipements et des locaux du b\u00e2timent existant qui sont mis \u00e0 disposition pour le personnel du chantier. Les bases vie de type \u00ab bungalow tout \u00e9quip\u00e9 \u00bb ne sont pas prises en compte pour cette exigence.",non_applicabilite:"Cas o\u00f9 aucune base vie de chantier n\u2019est obligatoire sur le chantier selon le Code du Travail. Cas des constructions neuves. Cas o\u00f9 il y a uniquement des bases vie de chantier de type \u00ab bungalow tout \u00e9quip\u00e9 \u00bb. Non applicable en exploitation axe B\u00e2timent et axe Gestion. Les points seront d\u00e9duits du total de points disponibles.",notation:"Non applicable | Non atteint : 0 point | Atteint : 1 point",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phases Programme, Conception et R\u00e9alisation</strong></td><td>Justificatif du r\u00e9emploi des bases-vies de chantier.</td><td>Coh\u00e9rence entre les \u00e9l\u00e9ments du justificatif.</td></tr><tr><td><strong>Phase Exploitation</strong></td><td colspan=\"2\">Non concern\u00e9es.</td></tr></table>"},
"DEVT2.3":{intro:"S\u00e9lection de fili\u00e8res locales ou participant \u00e0 une \u00e9conomie circulaire",context:"Ce sous-th\u00e8me traite de l\u2019identification de fili\u00e8res locales (mati\u00e8res premi\u00e8res, \u00e9nergie renouvelable, valorisation d\u00e9chets), du recours \u00e0 des composants issus de fili\u00e8res locales, et de l\u2019approvisionnement en \u00e9nergie renouvelable locale."},
"DEVT2.3.1":{attendu:"Identification de fili\u00e8res locales en termes de mati\u00e8res premi\u00e8res, de sources d\u2019\u00e9nergie renouvelable et de valorisation mati\u00e8re de d\u00e9chets.",definition:"Cette exigence vise \u00e0 v\u00e9rifier que les potentiels en mati\u00e8re de fili\u00e8res locales ont bien \u00e9t\u00e9 identifi\u00e9s. | On appelle \u00ab fili\u00e8re locale de mati\u00e8res premi\u00e8res \u00bb une cha\u00eene d\u2019\u00e9laboration de composants dont l\u2019extraction des principales mati\u00e8res premi\u00e8res (plus de 50% en volume), la transformation de ces mati\u00e8res et l\u2019assemblage sont r\u00e9alis\u00e9s \u00e0 proximit\u00e9 du projet (distance inf\u00e9rieure \u00e0 180 km du projet ou m\u00eame r\u00e9gion administrative). | On appelle \u00ab fili\u00e8re locale de valorisation mati\u00e8re de d\u00e9chets \u00bb une cha\u00eene de r\u00e9utilisation/valorisation des d\u00e9chets dont la r\u00e9cup\u00e9ration et la transformation \u00e9ventuelle en produits r\u00e9utilisables sont r\u00e9alis\u00e9es \u00e0 proximit\u00e9 du projet (distance inf\u00e9rieure \u00e0 180 km du projet ou m\u00eame r\u00e9gion administrative). | On appelle \u00ab source d\u2019\u00e9nergie renouvelable locale \u00bb : une source d\u2019\u00e9nergie finale dont le centre de production est \u00e0 moins de 25 km du projet ; une source d\u2019approvisionnement primaire situ\u00e9e \u00e0 une distance inf\u00e9rieure \u00e0 180 km ou dans la r\u00e9gion administrative du b\u00e2timent ; une production d\u2019\u00e9nergie renouvelable directement produite sur site.",notation:"Non atteint : 0 point | Atteint : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Toutes phases</strong></td><td>Document pr\u00e9sentant un \u00e9tat des lieux des fili\u00e8res locales. Analyse de site comprenant l\u2019\u00e9tat des lieux des fili\u00e8res locales. Dur\u00e9e de validit\u00e9 : 5 ans.</td><td>Existence d\u2019un \u00e9tat des lieux des fili\u00e8res locales.</td></tr></table>"},
"DEVT2.3.2":{attendu:"Recours \u00e0 un (des) composant(s) (chantier ou Gros Entretien Renouvellement) issu(s) d\u2019une fili\u00e8re locale de production (mati\u00e8res premi\u00e8res) ou une fili\u00e8re de valorisation/r\u00e9emploi.",definition:"L\u2019enjeu de cette exigence est de privil\u00e9gier le recours \u00e0 des composants dont l\u2019ensemble de la fili\u00e8re de production est local depuis l\u2019extraction de mati\u00e8res premi\u00e8res jusqu\u2019\u00e0 l\u2019assemblage final, ou issus d\u2019une fili\u00e8re locale de r\u00e9emploi de composants du b\u00e2timent. | Les composants sont consid\u00e9r\u00e9s comme \u00e9tant issus de fili\u00e8res locales de production ou de valorisation si leurs principaux produits (au moins 75% en volume) sont issus d\u2019une fili\u00e8re locale de production ou d\u2019une fili\u00e8re locale de valorisation ou r\u00e9emploi, et si l\u2019assemblage final est \u00e9galement local (distance \u2264 180 km du projet ou m\u00eame r\u00e9gion administrative).",notation:"Non atteint : 0 point | Au moins un composant : 1 point | Au moins 3 composants issus a minima de deux lots diff\u00e9rents : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme int\u00e9grant les \u00e9l\u00e9ments demand\u00e9s.</td><td>Intentions concernant le recours \u00e0 des fili\u00e8res locales.</td></tr><tr><td><strong>Phase Conception</strong></td><td>DCE int\u00e9grant les \u00e9l\u00e9ments demand\u00e9s ET \u00c9tude de faisabilit\u00e9 sur l\u2019approvisionnement local pour les composants \u00e9tudi\u00e9s.</td><td>Fili\u00e8re locale du/des composant(s).</td></tr><tr><td><strong>Phase R\u00e9alisation</strong></td><td>Justification de la provenance locale du (des) composant(s) \u00e9tudi\u00e9(s).</td><td>Fili\u00e8re locale du/des composant(s).</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Contrat d\u2019exploitation li\u00e9 au GER + justification de la provenance locale. Dur\u00e9e de validit\u00e9 : 5 ans.</td><td>Fili\u00e8re locale du/des composant(s) utilis\u00e9(s).</td></tr></table>"},
"DEVT2.3.3":{attendu:"Recours \u00e0 de l\u2019approvisionnement en \u00e9nergie renouvelable dont la production est locale ou issue d\u2019une mutualisation \u00e9nerg\u00e9tique \u00e0 l\u2019\u00e9chelle du quartier.",definition:"Cette exigence requiert qu\u2019au moins une partie de l\u2019approvisionnement en \u00e9nergie du b\u00e2timent soit assur\u00e9e par une \u00e9nergie renouvelable locale ou issue d\u2019une mutualisation \u00e9nerg\u00e9tique \u00e0 l\u2019\u00e9chelle du quartier. | Le premier niveau de l\u2019exigence (\u00ab Au moins un mode d\u2019approvisionnement \u00bb) est valid\u00e9 ind\u00e9pendamment des besoins couverts par cet approvisionnement. | Le second niveau (\u00ab A minima 50% de l\u2019\u00e9nergie finale (tous usages) pourvue par de l\u2019approvisionnement local \u00bb) requiert de justifier que ce(s) approvisionnement(s) permet(tent) de couvrir 50% de la consommation d\u2019\u00e9nergie finale tous usages du b\u00e2timent. | On appelle \u00ab mutualisation d\u2019\u00e9nergie \u00e0 l\u2019\u00e9chelle du quartier \u00bb le fait de r\u00e9cup\u00e9rer dans un p\u00e9rim\u00e8tre proche du b\u00e2timent des d\u00e9perditions \u00e9nerg\u00e9tiques qui seraient normalement perdues et les r\u00e9utiliser comme apport d\u2019\u00e9nergie sur le b\u00e2timent.",notation:"Non atteint : 0 point | Au moins un mode d\u2019approvisionnement : 1 point | A minima 50% de l\u2019\u00e9nergie finale (tous usages) pourvue par de l\u2019approvisionnement local : 2 points",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme int\u00e9grant l\u2019engagement \u00e0 recourir \u00e0 un approvisionnement local en \u00e9nergie. ET \u00c9tat des lieux des fili\u00e8res \u00e9nerg\u00e9tiques locales.</td><td>Intentions concernant le recours aux sources locales d\u2019\u00e9nergie renouvelable.</td></tr><tr><td><strong>Phases Conception et R\u00e9alisation</strong></td><td>\u00c9tat des lieux des fili\u00e8res \u00e9nerg\u00e9tiques locales. Estimation de la consommation en \u00e9nergie finale couverte par des \u00e9nergies renouvelables locales. Description des syst\u00e8mes \u00e9ventuels de mutualisation \u00e9nerg\u00e9tique.</td><td>Pour le premier niveau : Caract\u00e8re local de l\u2019approvisionnement. Pour le second niveau : Caract\u00e8re local + calcul pour le respect du seuil.</td></tr><tr><td><strong>Phase Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Contrat sur l\u2019approvisionnement local. ET/OU Factures. Dur\u00e9e de validit\u00e9 : 1 an.</td><td>Caract\u00e8re local de l\u2019approvisionnement + calcul pour le respect du seuil.</td></tr></table>"},
"DEVT2.4":{intro:"Recours \u00e0 des comp\u00e9tences locales",context:"Ce sous-th\u00e8me traite du recours \u00e0 une majorit\u00e9 de prestataires locaux dans les march\u00e9s de conception/construction ou d\u2019exploitation."},
"DEVT2.4.1":{attendu:"Recours \u00e0 une majorit\u00e9 de prestataires locaux dans les march\u00e9s de conception/construction ou d\u2019exploitation.",definition:"Cette exigence requiert que la majorit\u00e9 (en nombre) des prestataires et entreprises intervenant sur le projet (ou b\u00e2timent en exploitation) soit implant\u00e9e localement. | Est appel\u00e9 \u00ab local \u00bb un prestataire dont le si\u00e8ge ou une agence locale est implant\u00e9(e) \u00e0 une distance \u2264 180 km ou dans la r\u00e9gion administrative du chantier (ou du b\u00e2timent). | Les prestataires concern\u00e9s impliquent tous les niveaux de sous-traitance intervenant directement dans le projet. Ceci exclut notamment les fournisseurs de composants, mat\u00e9riaux, etc.",non_applicabilite:"Dans les cas o\u00f9 le type d\u2019op\u00e9ration ne permet pas d\u2019avoir recours explicitement \u00e0 des prestataires locaux (par exemple pour les march\u00e9s publics), cette exigence est consid\u00e9r\u00e9e comme non applicable. Les points seront d\u00e9duits du total de points disponibles.",notation:"Non applicable | Non atteint : 0 point | Atteint : 1 point",attention:"Pour l\u2019\u00cele de la R\u00e9union, Mayotte, la Martinique, la Guadeloupe, Saint-Barth\u00e9lemy, Saint-Martin, la Guyane, la Nouvelle Cal\u00e9donie, la Polyn\u00e9sie fran\u00e7aise, Wallis et Futuna : la limite locale est le territoire pour les prestataires.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Programme</strong></td><td>Programme int\u00e9grant l\u2019engagement \u00e0 recourir \u00e0 des prestataires locaux.</td><td>Intention d\u2019avoir recours \u00e0 des prestataires locaux.</td></tr><tr><td><strong>Phase Conception</strong></td><td>Clause favorisant le recours \u00e0 des prestataires locaux. ET/OU Note justificative prouvant le recours \u00e0 des prestataires locaux.</td><td>Caract\u00e8re local des prestataires.</td></tr><tr><td><strong>Phases R\u00e9alisation et Exploitation (axes B\u00e2timent et Gestion)</strong></td><td>Coordonn\u00e9es des prestataires s\u00e9lectionn\u00e9s prouvant leur caract\u00e8re local. Dur\u00e9e de validit\u00e9 : 1 an.</td><td>Caract\u00e8re local des prestataires justifiant le respect de l\u2019exigence.</td></tr></table>"}
,
"GD":{intro:"Le thème Gestion Durable évalue la qualité de la gestion et de l\'exploitation d\'un bâtiment en phase d\'exploitation. Il couvre la maintenance, le suivi des systèmes techniques, la relation avec les usagers et le suivi des performances environnementales.",context:"Ce thème est spécifique à l\'exploitation (axe Gestion). Il s\'applique aux bâtiments en exploitation et évalue la qualité des pratiques de gestion mises en œuvre par l\'exploitant."},
"GD1":{intro:"Ce sous-thème évalue la gestion de la maintenance au sens large : entretien, nettoyage, choix des produits, optimisation des méthodes, prestataires et fournisseurs, gestion des déchets.",context:"La maintenance englobe l\'ensemble des opérations d\'entretien et de nettoyage des espaces intérieurs et extérieurs, le choix des produits utilisés, les méthodes employées et la sélection des prestataires."},
"GD1.1":{intro:"Contrôle de la prestation d\'entretien et de nettoyage avec objectif de résultat.",context:"L\'objectif est de s\'assurer que les prestations d\'entretien et de nettoyage sont contrôlées et répondent à des critères de qualité définis."},
"GD1.2":{intro:"Achats responsables de produits d\'entretien et de nettoyage respectueux de l\'environnement et de la santé.",context:"Il s\'agit de privilégier les produits d\'entretien et de nettoyage éco-labellisés ou présentant un profil environnemental et sanitaire favorable."},
"GD1.3":{intro:"Utilisation et achats responsables de produits d\'entretien et de nettoyage respectueux de l\'environnement, et achats de produits phytosanitaires respectueux de l\'environnement.",context:"Ce bloc couvre le choix des produits d\'entretien avec écolabel et les produits phytosanitaires pour les espaces verts."},
"GD1.4":{intro:"Optimisation des méthodes d\'entretien et de nettoyage.",context:"L\'objectif est de privilégier l\'utilisation de matériels et techniques limitant la surconsommation de produits et ressources, et les impacts de l\'activité d\'entretien."},
"GD1.5":{intro:"Prestataires et fournisseurs : choix, formation et gestion des déchets.",context:"Ce bloc évalue l\'engagement environnemental des prestataires, leur formation et la gestion des déchets sur le site."},
"GD2":{intro:"Ce sous-thème couvre la définition de la maintenance des systèmes techniques, la gestion et le suivi des systèmes, et le renouvellement des produits intérieurs.",context:"Il s\'agit d\'évaluer la qualité de la maintenance technique (processus, gammes, résultats, maintenance préventive/curative), le commissioning, le suivi des systèmes et la pérennité des performances."},
"GD2.1":{intro:"Définition de la maintenance des systèmes techniques : processus, gammes, résultats, maintenance préventive et curative.",context:"Le périmètre d\'évaluation couvre l\'ensemble des équipements techniques du bâtiment, hors ceux directement sous la responsabilité des utilisateurs."},
"GD2.2":{intro:"Gestion et suivi des systèmes : commissioning, suivi, pérennité de l\'automatisation et des performances, équipements frigorifiques.",context:"Ce bloc évalue les pratiques de suivi des systèmes techniques en exploitation, le commissioning (ou rétrocommissioning), et la pérennité des systèmes."},
"GD2.3":{intro:"Renouvellement des produits de construction intérieurs.",context:"Ce bloc évalue la prise en compte des critères environnementaux et sanitaires lors du renouvellement des produits de construction intérieurs."},
"GD3":{intro:"Ce sous-thème évalue la relation avec les usagers : gestion des demandes d\'intervention, limitation des nuisances et concertation.",context:"La qualité de la relation entre l\'exploitant et les occupants du bâtiment est essentielle pour garantir le confort et la satisfaction des usagers."},
"GD3.1":{intro:"Gestion des demandes d\'intervention des occupants et suivi des demandes pour les systèmes techniques.",context:"Il s\'agit de mettre en place un processus de gestion et de suivi des demandes d\'intervention des occupants."},
"GD3.2":{intro:"Limiter les nuisances liées aux opérations d\'entretien, de maintenance, de tri et d\'enlèvement des déchets.",context:"Les opérations d\'entretien et de gestion des déchets peuvent générer des nuisances pour les occupants qu\'il convient de limiter."},
"GD3.3":{intro:"Concertation avec les occupants.",context:"La concertation avec les occupants permet d\'améliorer la qualité de la gestion et de répondre au mieux à leurs attentes."},
"GD4":{intro:"Ce sous-thème évalue le suivi des performances environnementales : consommations, réduction, efficacité énergétique, alertes, légionelles et reporting.",context:"Le suivi des performances environnementales est essentiel pour garantir l\'amélioration continue de la gestion du bâtiment."},
"GD4.1":{intro:"Suivi des consommations et de la qualité : énergie, eau, qualité de l\'air intérieur et qualité de l\'air dans les parkings.",context:"Le suivi des consommations est le préalable à toute démarche de réduction et d\'optimisation."},
"GD4.2":{intro:"Réduction des consommations, efficacité énergétique, alertes et prévention des légionelles.",context:"Après le suivi, l\'objectif est de réduire les consommations et de mettre en place des systèmes d\'alerte pour prévenir les dérives."},
"GD4.3":{intro:"Reporting global et carnet sanitaire.",context:"Le reporting permet de synthétiser et de communiquer les performances environnementales du bâtiment."},
"GD1.1.1":{attendu:"Contr\u00f4le de la prestation d\u2019entretien et de nettoyage, et objectif de r\u00e9sultat pour les espaces \u00e0 contrainte d\u2019hygi\u00e8ne.",definition:"Il est demand\u00e9 un contr\u00f4le de la prestation d\u2019entretien dans le cadre du contrat, de la charte ou du plan d\u2019actions. Ce contr\u00f4le comprend a minima un objectif de r\u00e9sultat dans le cahier des charges avec un protocole de contr\u00f4le de la prestation (par l\u2019exploitant ou l\u2019occupant) et un suivi du r\u00e9sultat. | Le premier niveau de l\u2019exigence concerne les espaces \u00e0 contraintes d\u2019hygi\u00e8ne (sanitaires, espaces de restauration, etc.). Le second niveau \u00e9tend ce contr\u00f4le \u00e0 l\u2019ensemble des espaces (y compris bureaux, circulations, etc.). Le troisi\u00e8me niveau ajoute des contr\u00f4les sp\u00e9cifiques : contr\u00f4le visuel organis\u00e9 des esp\u00e8ces ext\u00e9rieures et contr\u00f4le bact\u00e9riologique d\u2019au moins deux surfaces dans les locaux \u00e0 contraintes d\u2019hygi\u00e8ne.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Cahier des charges de la prestation d\u2019entretien et de nettoyage. | Protocole de contr\u00f4le de la prestation. | R\u00e9sultats des contr\u00f4les (visuels, bact\u00e9riologiques le cas \u00e9ch\u00e9ant).</td><td>Sans objet</td></tr></table>"},
"GD1.2.1":{attendu:"Utiliser des produits d\u2019entretien et de nettoyage \u00e9co-labellis\u00e9s ou respectueux de l\u2019environnement et de la sant\u00e9.",definition:"Dans tous les locaux, y compris ceux sans condition d\u2019hygi\u00e8ne sp\u00e9cifique, un pourcentage minimal des quantit\u00e9s annuelles de produits utilis\u00e9s (dont le papier) doit \u00eatre \u00e9co-labellis\u00e9 ou \u00e9quivalent (\u00c9colabel europ\u00e9en, NF Environnement, Nordic Swan, etc.). | \u25b8 Niveau 1 : < 30% des quantit\u00e9s annuelles de produits utilis\u00e9s (dont le papier) sont \u00e9co-labellis\u00e9s (ou \u00e9quivalent) | \u25b8 Niveau 2 : 30 \u00e0 60% des quantit\u00e9s annuelles de produits utilis\u00e9s (dont le papier) sont \u00e9co-labellis\u00e9s (ou \u00e9quivalent) | \u25b8 Niveau 3 : > 60% des quantit\u00e9s annuelles de produits utilis\u00e9s (dont le papier) sont \u00e9co-labellis\u00e9s (ou \u00e9quivalent) | \u25b8 Niveau 4 : 100% des quantit\u00e9s annuelles de produits utilis\u00e9s (dont le papier) sont \u00e9co-labellis\u00e9s (ou \u00e9quivalent) | La part des produits \u00e9co-labellis\u00e9s se calcule en nombre de r\u00e9f\u00e9rences par rapport au nombre total de r\u00e9f\u00e9rences utilis\u00e9es (ou en volume si tous les produits sont de m\u00eame nature).",attention:"Pour les produits utilis\u00e9s dans les locaux \u00e0 contraintes d\u2019hygi\u00e8ne sp\u00e9cifiques (sanitaires, espaces de restauration), il est admis que les produits ne soient pas \u00e9co-labellis\u00e9s si aucun produit \u00e9co-labellis\u00e9 ne r\u00e9pond \u00e0 la contrainte d\u2019hygi\u00e8ne. Dans ce cas, ces produits sont exclus du calcul.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Inventaire des produits d\u2019entretien et de nettoyage. | Fiches de donn\u00e9es s\u00e9curit\u00e9 et/ou certificats d\u2019\u00e9colabel des produits. | Justificatif du calcul du pourcentage de produits \u00e9co-labellis\u00e9s.</td><td>Sans objet</td></tr></table>"},
"GD1.3.1.- Utilisation et achats responsables de produits d\'entretien et de nettoyage respectueux de l\'environnement":{attendu:"Utiliser et acheter des produits d\u2019entretien et de nettoyage respectueux de l\u2019environnement.",definition:"Ce bloc \u00e9value la proportion de produits \u00e9co-labellis\u00e9s utilis\u00e9s pour l\u2019entretien et le nettoyage. La part des produits \u00e9co-labellis\u00e9s se calcule en nombre de r\u00e9f\u00e9rences.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Inventaire des produits. | Fiches de donn\u00e9es s\u00e9curit\u00e9 et certificats d\u2019\u00e9colabel.</td><td>Sans objet</td></tr></table>"},
"GD1.3.2":{attendu:"Acheter des produits phytosanitaires respectueux de l\u2019environnement.",definition:"Lorsque l\u2019ouvrage comporte des espaces verts, il s\u2019agit d\u2019utiliser des produits phytosanitaires utilisables en agriculture biologique ou de r\u00e9aliser l\u2019entretien par des techniques alternatives uniquement : d\u00e9sherbage m\u00e9canique, vapeur, infrarouge, paillage, mulching, etc. | L\u2019enjeu est de substituer les produits phytosanitaires \u00ab classiques \u00bb par des produits \u00e0 faible impact environnemental. | Le niveau 4 points valorise l\u2019absence totale de produit phytosanitaire et de pesticide.",reglementation:"R\u00e8glement (UE) 2018/848 du Parlement Europ\u00e9en et du Conseil du 30 mai 2018 relatif \u00e0 la production biologique. | R\u00e8glement europ\u00e9en 889/2008. | En France : plan ECOPHYTO national (version 2, 26/11/2015).",non_applicabilite:"S\u2019il n\u2019y a pas d\u2019espaces verts, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Recensement de l\u2019ensemble des produits. | Classement des produits en fonction des quantit\u00e9s et fr\u00e9quence d\u2019utilisation. | Fiches de donn\u00e9es s\u00e9curit\u00e9 des produits phytosanitaires. | Recensement de l\u2019ensemble des produits de traitements pr\u00e9ventifs et curatifs sur l\u2019ann\u00e9e (produits phytosanitaires). | Justification de l\u2019achat exclusif de produits phytosanitaires utilisables en agriculture biologique. | Justification de l\u2019absence de pesticides.</td><td>Sans objet</td></tr></table>"},
"GD1.4.1":{attendu:"Optimiser les m\u00e9thodes d\u2019entretien des espaces ext\u00e9rieurs (y compris espaces verts) et de nettoyage des espaces int\u00e9rieurs.",definition:"Privil\u00e9gier l\u2019utilisation de mat\u00e9riels/techniques limitant la surconsommation de produits et ressources, et les impacts de l\u2019activit\u00e9 d\u2019entretien : eau, produits d\u2019entretiens, \u00e9nergie, etc. | Pour le nettoyage des espaces int\u00e9rieurs : nettoyage par microfibre sans utilisation de produits d\u2019entretien, nettoyage \u00e0 sec, m\u00e9thodes \u00e9vitant les rejets particulaires et/ou limitant les rejets gazeux (filtration de l\u2019air rejet\u00e9 par les aspirateurs, nettoyage des moquettes par rotocleaner). | Pour les espaces ext\u00e9rieurs : plan de gestion diff\u00e9renci\u00e9e des espaces verts, techniques d\u2019entretien pr\u00e9servant les sols, choix des mat\u00e9riels limitant les consommations de carburants, optimisation de la gestion des d\u00e9chets verts. | Remarque : si plusieurs prestataires sont concern\u00e9s par une cat\u00e9gorie, le prestataire le plus impactant doit respecter les conditions pour obtenir le niveau correspondant.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Mat\u00e9riels et techniques employ\u00e9es. | Protocoles des diff\u00e9rentes op\u00e9rations d\u2019entretien ou de nettoyage (fiches d\u2019op\u00e9ration par exemple). | Cahier des charges du prestataire d\u2019entretien ou de nettoyage mentionnant les techniques mises en \u0153uvre. | Fiches techniques du mat\u00e9riel utilis\u00e9.</td><td>Sans objet</td></tr></table>"},
"GD1.5.1":{attendu:"S\u2019assurer que les prestataires d\u2019entretien et de nettoyage sont engag\u00e9s dans une d\u00e9marche environnementale.",definition:"Les prestataires charg\u00e9s de l\u2019entretien des espaces ext\u00e9rieurs, de l\u2019entretien du b\u00e2ti, et du nettoyage des espaces int\u00e9rieurs sont engag\u00e9s dans une d\u00e9marche environnementale (certification ISO 14001, d\u00e9finition d\u2019une charte environnementale, etc.). | Cet engagement doit comprendre : objectifs pr\u00e9cis d\u00e9finis, preuves de planification et de suivis de ces objectifs, r\u00e9visions annuelles si n\u00e9cessaire, actions engag\u00e9es en cons\u00e9quence. | Remarque : si plusieurs prestataires sont concern\u00e9s, le prestataire le plus impactant doit respecter les conditions. Si le nombre maximum de prestataires est de deux, le niveau maximum atteint est 3 points. Le dernier niveau (4 points) est accessible si l\u2019ensemble des prestataires (>1) r\u00e9pond \u00e0 l\u2019exigence.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Certificat du prestataire d\u2019entretien ou de nettoyage (ISO 14001 par exemple). | Charte environnementale du prestataire d\u2019entretien ou de nettoyage.</td><td>Sans objet</td></tr></table>"},
"GD1.5.2":{attendu:"S\u2019assurer que les prestataires d\u2019entretien et de nettoyage sont form\u00e9s aux bonnes pratiques environnementales.",definition:"Les prestataires charg\u00e9s de l\u2019entretien des espaces ext\u00e9rieurs, et du nettoyage des espaces int\u00e9rieurs ont mis en place un plan de formation visant \u00e0 communiquer sur : les pratiques d\u2019entretien environnementalement responsables, les conseils d\u2019utilisation et les doses appropri\u00e9es figurant sur l\u2019\u00e9tiquetage des produits. | La preuve de la mise en \u0153uvre des formations doit \u00eatre apport\u00e9e (causeries, formations approfondies, support, etc.). Tout nouvel intervenant doit avoir \u00e9t\u00e9 form\u00e9. | Remarque : si plusieurs prestataires sont concern\u00e9s, le prestataire le plus impactant doit respecter les conditions.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Plan de formation des agents d\u2019entretien ou de nettoyage. | Supports de formation. | Preuve que les formations ont bien eu lieu (attestations de pr\u00e9sence, par exemple).</td><td>Sans objet</td></tr></table>"},
"GD1.5.3":{attendu:"Mettre en place un protocole de tri des d\u00e9chets et choisir des prestataires et fili\u00e8res de traitement adapt\u00e9s.",definition:"Justification de la mise en place d\u2019un protocole de tri, et des prestataires d\u2019enl\u00e8vement des d\u00e9chets sur l\u2019ouvrage, en regard du contexte et des objectifs environnementaux, en privil\u00e9giant autant que possible la valorisation. | Cela concerne : les d\u00e9chets produits lors des travaux d\u2019entretien/maintenance, les d\u00e9chets issus des travaux de r\u00e9novation, les d\u00e9chets d\u2019activit\u00e9s produits par les utilisateurs. | Il est demand\u00e9 de choisir des prestataires et des fili\u00e8res de traitement en fonction du type de d\u00e9chets g\u00e9n\u00e9r\u00e9s, de respecter la r\u00e9glementation locale en mati\u00e8re d\u2019\u00e9limination des d\u00e9chets, de garantir la pr\u00e9sence d\u2019un protocole de tri (a minima pour les d\u00e9chets d\u2019entretien/maintenance), et de prendre des dispositions pour optimiser le tri et le stockage des d\u00e9chets avant enl\u00e8vement. | P\u00e9rim\u00e8tre : b\u00e2timent (p\u00e9rim\u00e8tre des responsabilit\u00e9s + parcelle) ; site (mutualis\u00e9 possible) ; parc (\u00e9chelle du parc). | Si l\u2019un des types n\u2019est pas trait\u00e9 dans le p\u00e9rim\u00e8tre, l\u2019\u00e9valuation au-del\u00e0 de la r\u00e9glementation se fait sur deux niveaux seulement : au moins un type (1 point) ou tous les types restant (4 points).",reglementation:"Se reporter \u00e0 l\u2019annexe du pr\u00e9sent th\u00e8me pour les rappels concernant la classification et la gestion des d\u00e9chets en France. | D\u00e9cret 5 flux (papier/carton, m\u00e9tal, plastique, verre, bois). | D\u00e9cret 7 flux (ajout fractions min\u00e9rales et pl\u00e2tre). | D\u00e9cret 8 flux (ajout textiles). | D\u00e9chets dangereux : r\u00e9glementation sp\u00e9cifique.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Contrats de prestation d\u2019enl\u00e8vement et traitement des d\u00e9chets. | Contrats entre le collecteur de d\u00e9chets et l\u2019entreprise de valorisation lorsque celles-ci sont distinctes, ou attestations de valorisation. | \u00c9tudes des fili\u00e8res.</td><td>Sans objet</td></tr></table>"},
"GD2.1.1":{attendu:"Optimiser la maintenance des \u00e9quipements techniques : d\u00e9finir un processus de maintenance et des gammes de maintenance adapt\u00e9es.",definition:"\u00c9valuation de la maintenance des quatre types de syst\u00e8mes suivants avec mise en place d\u2019un processus de maintenance et d\u00e9finition des gammes de maintenance : | \u25b8 Syst\u00e8me(s) de chauffage/refroidissement (hors \u00e9quipements g\u00e9r\u00e9s par l\u2019utilisateur) : production de chaleur, production de froid, distribution de chaleur, distribution de froid, terminaux. | \u25b8 Syst\u00e8me(s) de ventilation (et si pr\u00e9sents des syst\u00e8mes de traitement des rejets malodorants) : CTA, groupe d\u2019extraction, bouches d\u2019extraction/insufflation, modules d\u2019entr\u00e9es d\u2019air, ventilo-convecteurs, conduits de ventilation, filtres, humidificateurs, batteries d\u2019\u00e9changeurs. | \u25b8 Syst\u00e8me d\u2019\u00e9clairage : luminaires, dispositifs de gestion, dispositifs d\u2019allumage/extinction. | \u25b8 \u00c9quipements de gestion de l\u2019eau : plomberie, production d\u2019ECS, syst\u00e8mes de traitement, appareils de robinetterie. | Processus de maintenance : d\u00e9finition des exigences de maintenance, strat\u00e9gie de maintenance choisie, p\u00e9rim\u00e8tre du contrat, proc\u00e9dure curative. | Gammes de maintenance : issues de gammes g\u00e9n\u00e9riques adapt\u00e9es au contexte, ou d\u00e9finies sp\u00e9cifiquement. | Niveaux de maintenance (FDX 60-000 AFNOR) : Niveau I (actions simples), Niveau II (proc\u00e9dures simples), Niveau III (proc\u00e9dures complexes), Niveau IV (ma\u00eetrise technique particuli\u00e8re).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Contrat de prestation de maintenance du (des) syst\u00e8me(s) contenant : les \u00e9l\u00e9ments pris en charge et les niveaux de maintenance associ\u00e9s, les modes de reporting de la maintenance. | Les gammes de maintenance (op\u00e9rations, p\u00e9riodicit\u00e9, observations) adapt\u00e9es au contexte. | Document de reporting des op\u00e9rations de maintenance : rapports ou fiches d\u2019inspection, rapport mensuel d\u2019activit\u00e9 (RMA).</td><td>Sans objet</td></tr></table>"},
"GD2.1.2":{attendu:"D\u00e9finir des exigences de r\u00e9sultats de la maintenance et mettre en place une proc\u00e9dure de contr\u00f4le.",definition:"Pour les 4 types de syst\u00e8mes (Chauffage/refroidissement, \u00c9clairage, Ventilation, ECS), la maintenance a des exigences de r\u00e9sultat avec pr\u00e9cision des \u00e9l\u00e9ments suivants : indicateurs de r\u00e9sultat, niveau de qualit\u00e9 attendu, d\u00e9finition du crit\u00e8re de criticit\u00e9 de l\u2019intervention pour le curatif, processus de contr\u00f4le du r\u00e9sultat. | Pr\u00e9sence d\u2019une proc\u00e9dure de contr\u00f4le associ\u00e9e \u00e0 ces objectifs de r\u00e9sultat et dispositions pr\u00e9vues en cas de prestation non conforme. | La maintenance doit inclure des indicateurs de r\u00e9sultat : taux de cl\u00f4ture en curatif, taux de cl\u00f4ture en pr\u00e9ventif, et d\u2019autres indicateurs de r\u00e9sultat pour le curatif et le pr\u00e9ventif selon le niveau vis\u00e9. | Contrat de r\u00e9sultat : engagement d\u2019une entreprise ext\u00e9rieure \u00e0 r\u00e9aliser une prestation d\u00e9finie par des objectifs quantifi\u00e9s et \u00e0 apporter la preuve de l\u2019atteinte de ces objectifs.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Contrat de prestation de maintenance du (des) syst\u00e8me(s) contenant : les \u00e9l\u00e9ments pris en charge et les niveaux de maintenance associ\u00e9s, le(s) indicateur(s) de r\u00e9sultat et les objectifs de r\u00e9sultats associ\u00e9s \u00e0 ces indicateurs, les modes de reporting et le processus de contr\u00f4le associ\u00e9, les dispositions pr\u00e9vues en cas de prestation non conforme. | Les gammes de maintenance adapt\u00e9es au contexte. | Document de reporting pr\u00e9cisant l\u2019atteinte ou non des objectifs pour les indicateurs de r\u00e9sultats vis\u00e9s et en cas de non-atteinte, la trace des actions correctives engag\u00e9es. | Rapport mensuel d\u2019activit\u00e9 (RMA).</td><td>Sans objet</td></tr></table>"},
"GD2.1.3":{attendu:"Analyser p\u00e9riodiquement l\u2019efficacit\u00e9 de la maintenance d\u00e9ploy\u00e9e sur le site.",definition:"Au premier niveau, \u00ab Analyse mensuelle de l\u2019efficacit\u00e9 de la maintenance \u00bb, il est demand\u00e9 d\u2019effectuer a minima une fois par mois une analyse de l\u2019efficacit\u00e9 de la maintenance selon les crit\u00e8res d\u00e9finis dans l\u2019exigence pr\u00e9c\u00e9dente. G\u00e9n\u00e9ralement cette analyse est adjointe au rapport p\u00e9riodique d\u2019exploitation. | Au deuxi\u00e8me niveau, \u00ab Optimisation du suivi mensuel \u00bb, l\u2019analyse pr\u00e9c\u00e9dente doit \u00eatre optimis\u00e9e, avec en compl\u00e9ment la pr\u00e9sence de proc\u00e9dures associ\u00e9es aux indicateurs, coupl\u00e9es \u00e0 un seuil d\u2019alerte permettant le d\u00e9clenchement d\u2019actions correctives lorsque le seuil est d\u00e9pass\u00e9. | Le choix des indicateurs d\u00e9pend du processus de maintenance sur l\u2019ouvrage. Une proc\u00e9dure doit \u00eatre associ\u00e9e \u00e0 ces indicateurs pour d\u00e9finir \u00e0 partir de quel seuil une d\u00e9faillance est identifi\u00e9e.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Niveau \u00e0 0 point : justification de l\u2019analyse de l\u2019efficacit\u00e9 de la maintenance (a minima en pr\u00e9ventif, curatif, pr\u00e9sence d\u2019une proc\u00e9dure en cas de d\u00e9faillance identifi\u00e9e). | Niveau \u00e0 3 points : justification de l\u2019analyse optimis\u00e9e de l\u2019efficacit\u00e9 de la maintenance (a minima, suivi de 2 indicateurs de performance, diff\u00e9rents de ceux suivis au niveau pr\u00e9c\u00e9dent) ; justification du choix des indicateurs suivis.</td><td>Sans objet</td></tr></table>"},
"GD2.1.4":{attendu:"\u00c9valuer la mani\u00e8re dont est g\u00e9r\u00e9e la maintenance pr\u00e9ventive et curative sur l\u2019ouvrage.",definition:"Premier niveau : \u00ab Simple tra\u00e7abilit\u00e9 des op\u00e9rations de maintenance \u00bb \u2014 dispositions prises pour garantir la tra\u00e7abilit\u00e9 des op\u00e9rations de maintenance pr\u00e9ventive et curative (g\u00e9n\u00e9ration d\u2019OT, cl\u00f4ture d\u2019OT, enregistrement par exemple dans un tableur Excel). | Deuxi\u00e8me niveau : \u00ab Pr\u00e9sence d\u2019une proc\u00e9dure de suivi de la maintenance pr\u00e9ventive et curative \u00bb \u2014 suivi des ordres de travail (OT) en cours, d\u00e9clenchement des nouveaux OT, enregistrement des OT cl\u00f4tur\u00e9s. Cette proc\u00e9dure peut \u00eatre associ\u00e9e \u00e0 une GMAO. | Troisi\u00e8me niveau : \u00ab Gestion interactive de la maintenance via un outil sp\u00e9cifique permettant le suivi en direct des OT \u00bb \u2014 gestion via GMAO avec g\u00e9n\u00e9ration automatique des OT pr\u00e9ventifs, suivi des OT en cours de traitement, achats et commandes en direct, gestion des stocks en direct. | Quatri\u00e8me niveau : \u00ab Niveau pr\u00e9c\u00e9dent ET maintenance curative possible sur le site 24h/24 et 7j/7 \u00bb.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Niveau \u00e0 0 point : justification de la tra\u00e7abilit\u00e9 des op\u00e9rations de maintenance pr\u00e9ventive et curative. | Niveau \u00e0 2 points : justification de la tra\u00e7abilit\u00e9 optimis\u00e9e des op\u00e9rations de maintenance pr\u00e9ventive et curative (justification de la mise en \u0153uvre d\u2019une proc\u00e9dure de suivi, \u00e9ventuellement associ\u00e9e \u00e0 une GMAO). | Niveau \u00e0 3 points : justification de la tra\u00e7abilit\u00e9 optimis\u00e9e et de la mise en \u0153uvre d\u2019une proc\u00e9dure de suivi associ\u00e9e \u00e0 une GMAO. | Niveau \u00e0 4 points : justification de la possibilit\u00e9 d\u2019assurer la maintenance curative sur le site 24h/24 et 7j/7.</td><td>Sans objet</td></tr></table>"},
"GD2.2.1":{attendu:"Optimiser le suivi des syst\u00e8mes techniques par la r\u00e9alisation d\u2019un commissioning (ou r\u00e9trocommissioning).",definition:"Il s\u2019agit de passer en revue le fonctionnement des syst\u00e8mes techniques de l\u2019ouvrage et de les comparer aux objectifs de performance attendus. | D\u00e9signation d\u2019un agent de commissioning : une personne est missionn\u00e9e en tant qu\u2019agent de recommissionnement ou r\u00e9trocommissionnement. | \u25b8 Premier niveau (autocontr\u00f4le) : la personne est issue de l\u2019entit\u00e9 du demandeur ou de l\u2019exploitant. Formation minimale de 3 jours et exp\u00e9rience minimale finalis\u00e9e (essais fonctionnels) en recommissionnement sur au moins 2 op\u00e9rations du m\u00eame type. | \u25b8 Second niveau (contr\u00f4le tiers) : l\u2019agent de commissioning est une tierce partie ind\u00e9pendante. Comp\u00e9tence minimale de 5 jours de formation. Qualification/certification CBCP ou \u00e9quivalent. En France, l\u2019OPQIBI propose une qualification en ing\u00e9nierie du commissionnement. | Le commissioning porte sur les 4 types de syst\u00e8mes : chauffage/refroidissement, ventilation, \u00e9clairage, gestion de l\u2019eau.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Cahier des charges du commissioning. | D\u00e9signation de l\u2019agent de commissioning et justification de sa qualification (CV, attestation de formation, r\u00e9f\u00e9rences, certification CBCP/CBCF). | Plan de commissioning et rapports de commissioning pour chaque type de syst\u00e8me concern\u00e9. | Listes de d\u00e9fauts identifi\u00e9s et plans d\u2019actions correctives.</td><td>Sans objet</td></tr></table>"},
"GD2.2.2":{attendu:"Assurer le suivi des syst\u00e8mes techniques en exploitation.",definition:"Cette exigence compl\u00e8te le commissioning en assurant un suivi p\u00e9riodique des syst\u00e8mes techniques. Le suivi porte sur les 4 types de syst\u00e8mes (chauffage/refroidissement, ventilation, \u00e9clairage, gestion de l\u2019eau). | Il s\u2019agit de v\u00e9rifier p\u00e9riodiquement que les syst\u00e8mes fonctionnent conform\u00e9ment aux objectifs de performance d\u00e9finis lors du commissioning.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Rapports de suivi p\u00e9riodique des syst\u00e8mes. | Plans d\u2019actions correctives suite aux d\u00e9rives constat\u00e9es. | Preuves de la mise en \u0153uvre des actions correctives.</td><td>Sans objet</td></tr></table>"},
"GD2.2.3":{attendu:"Assurer la p\u00e9rennit\u00e9 de l\u2019automatisation et de la r\u00e9gulation des syst\u00e8mes techniques.",definition:"Il s\u2019agit de v\u00e9rifier p\u00e9riodiquement que les syst\u00e8mes de r\u00e9gulation et d\u2019automatisation (GTB, automates, etc.) fonctionnent correctement. | \u25b8 Premier niveau : test annuel des syst\u00e8mes de r\u00e9gulation et d\u2019automatisation. | \u25b8 Second niveau : tests plus r\u00e9guliers (a minima semestriels) avec tra\u00e7abilit\u00e9 des r\u00e9sultats.",non_applicabilite:"Si le b\u00e2timent ne dispose pas de syst\u00e8me d\u2019automatisation ou de r\u00e9gulation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Rapports de tests des syst\u00e8mes de r\u00e9gulation et d\u2019automatisation. | Tra\u00e7abilit\u00e9 des r\u00e9sultats des tests. | Plans d\u2019actions correctives le cas \u00e9ch\u00e9ant.</td><td>Sans objet</td></tr></table>"},
"GD2.2.4":{attendu:"Assurer la p\u00e9rennit\u00e9 des performances lors du renouvellement des \u00e9quipements techniques.",definition:"Lors du renouvellement d\u2019un \u00e9quipement technique, il est demand\u00e9 de remplacer l\u2019\u00e9quipement par un \u00e9quipement au moins \u00e9quivalent (remplacement \u00e0 l\u2019identique) ou plus performant. | \u25b8 Premier niveau : remplacement \u00e0 l\u2019identique. | \u25b8 Second niveau : remplacement par un \u00e9quipement plus performant.",non_applicabilite:"Si aucun renouvellement n\u2019a eu lieu sur la p\u00e9riode d\u2019\u00e9valuation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Justification des renouvellements effectu\u00e9s. | Fiches techniques des \u00e9quipements remplac\u00e9s et des nouveaux \u00e9quipements. | Comparaison des performances (ancien vs nouveau).</td><td>Sans objet</td></tr></table>"},
"GD2.2.5":{attendu:"Assurer le contr\u00f4le et la maintenance des \u00e9quipements frigorifiques contenant des fluides frigorig\u00e8nes.",definition:"Pr\u00e9requis (PR) : les \u00e9quipements frigorifiques contenant des fluides frigorig\u00e8nes doivent faire l\u2019objet d\u2019un contr\u00f4le et d\u2019une maintenance conform\u00e9ment \u00e0 la r\u00e9glementation en vigueur (r\u00e8glement europ\u00e9en F-Gas, Code de l\u2019environnement).",reglementation:"R\u00e8glement europ\u00e9en F-Gas. | Code de l\u2019environnement.",non_applicabilite:"Si le b\u00e2timent ne dispose pas d\u2019\u00e9quipements frigorifiques contenant des fluides frigorig\u00e8nes, l\u2019exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Registre des \u00e9quipements frigorifiques. | Attestations de contr\u00f4le d\u2019\u00e9tanch\u00e9it\u00e9. | Fiches d\u2019intervention sur les \u00e9quipements frigorifiques.</td><td>Sans objet</td></tr></table>"},
"GD2.3.1":{attendu:"Prendre en compte des crit\u00e8res environnementaux et sanitaires lors du renouvellement des produits de construction int\u00e9rieurs.",definition:"Lors du renouvellement de produits de construction int\u00e9rieurs (rev\u00eatements de sol, peintures, faux-plafonds, cloisons, etc.), il est demand\u00e9 de prendre en compte des crit\u00e8res environnementaux et sanitaires dans le choix des produits. | Le choix doit \u00eatre crois\u00e9 selon toutes les caract\u00e9ristiques suivantes : \u00e9missions de COV, contenu en substances dangereuses, durabilit\u00e9, recyclabilit\u00e9, impact environnemental (FDES ou \u00e9quivalent).",non_applicabilite:"Si aucun renouvellement de produits de construction int\u00e9rieurs n\u2019a eu lieu sur la p\u00e9riode d\u2019\u00e9valuation, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Justification des crit\u00e8res de choix des produits de construction int\u00e9rieurs renouvel\u00e9s. | Fiches techniques et/ou FDES des produits. | \u00c9tiquetage sanitaire des produits (\u00e9missions de COV).</td><td>Sans objet</td></tr></table>"},
"GD3.1.1":{attendu:"Mettre en place un processus de gestion des demandes d\u2019intervention des occupants.",definition:"Quatre niveaux de gestion des demandes d\u2019intervention : | \u25b8 Niveau 1 (0 point) : les demandes d\u2019intervention sont trait\u00e9es mais pas tra\u00e7\u00e9es. | \u25b8 Niveau 2 (1 point) : les demandes d\u2019intervention sont trait\u00e9es et tra\u00e7\u00e9es (num\u00e9ro d\u2019enregistrement, date, nature de la demande, lieu). | \u25b8 Niveau 3 (2 points) : niveau pr\u00e9c\u00e9dent ET pr\u00e9sence d\u2019une proc\u00e9dure d\u00e9finissant les d\u00e9lais cibles de prise en compte et de r\u00e9solution. | \u25b8 Niveau 4 (3 points) : niveau pr\u00e9c\u00e9dent ET retour d\u2019information \u00e0 l\u2019utilisateur sur la prise en compte de sa demande et sur le r\u00e9sultat de l\u2019intervention.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Registre des demandes d\u2019intervention. | Proc\u00e9dure de gestion des demandes (d\u00e9lais cibles, circuit de traitement). | Preuves de retour d\u2019information aux utilisateurs (e-mails, tickets, etc.).</td><td>Sans objet</td></tr></table>"},
"GD3.1.2":{attendu:"Assurer le suivi des demandes d\u2019intervention sur les syst\u00e8mes techniques.",definition:"Le suivi des demandes d\u2019intervention est \u00e9valu\u00e9 par type de syst\u00e8me technique (chauffage/refroidissement, ventilation, \u00e9clairage, gestion de l\u2019eau). | Le niveau de notation d\u00e9pend du nombre de types de syst\u00e8mes pour lesquels un suivi est mis en place.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Registre de suivi des demandes d\u2019intervention par type de syst\u00e8me. | Indicateurs de suivi (d\u00e9lais de traitement, taux de r\u00e9solution, etc.).</td><td>Sans objet</td></tr></table>"},
"GD3.2.1":{attendu:"Limiter les nuisances g\u00e9n\u00e9r\u00e9es par les op\u00e9rations d\u2019entretien et de maintenance pour les occupants.",definition:"\u25b8 Niveau 1 (1 point) : les op\u00e9rations d\u2019entretien/maintenance g\u00e9n\u00e9rant des nuisances sont r\u00e9alis\u00e9es en dehors des heures d\u2019occupation (interventions curatives planifi\u00e9es). | \u25b8 Niveau 2 (2 points) : en compl\u00e9ment, un planning de maintenance pr\u00e9ventive est d\u00e9fini et communiqu\u00e9 aux occupants, les interventions pr\u00e9ventives sont r\u00e9alis\u00e9es de mani\u00e8re \u00e0 minimiser la g\u00eane des occupants.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Planning de maintenance pr\u00e9ventive. | Preuve de communication du planning aux occupants. | Preuve que les interventions curatives sont planifi\u00e9es en dehors des heures d\u2019occupation.</td><td>Sans objet</td></tr></table>"},
"GD3.2.2":{attendu:"Limiter les nuisances li\u00e9es au tri et \u00e0 l\u2019enl\u00e8vement des d\u00e9chets pour les occupants.",definition:"Les op\u00e9rations de tri et d\u2019enl\u00e8vement des d\u00e9chets sont organis\u00e9es de mani\u00e8re \u00e0 limiter les nuisances pour les occupants (bruit, odeurs, encombrement des circulations, etc.).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Proc\u00e9dure de gestion des d\u00e9chets d\u00e9crivant les dispositions prises pour limiter les nuisances. | Planning de collecte des d\u00e9chets.</td><td>Sans objet</td></tr></table>"},
"GD3.3.1":{attendu:"Mettre en place une concertation avec les occupants sur la gestion du b\u00e2timent.",definition:"La concertation avec les occupants peut prendre diff\u00e9rentes formes : enqu\u00eates de satisfaction, r\u00e9unions p\u00e9riodiques, bo\u00eete \u00e0 id\u00e9es, comit\u00e9 de pilotage incluant des repr\u00e9sentants des occupants, etc. | L\u2019objectif est de recueillir les retours des occupants sur la qualit\u00e9 de la gestion et d\u2019en tenir compte dans les d\u00e9cisions d\u2019exploitation.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Comptes-rendus de r\u00e9unions de concertation ou r\u00e9sultats d\u2019enqu\u00eates de satisfaction. | Plans d\u2019actions suite aux retours des occupants.</td><td>Sans objet</td></tr></table>"},
"GD4.1.1":{attendu:"Mettre en place un suivi des consommations d\u2019\u00e9nergie.",definition:"Cinq niveaux de suivi des consommations d\u2019\u00e9nergie : | \u25b8 0 point : pas de suivi. | \u25b8 1 point : suivi global des consommations d\u2019\u00e9nergie (compteur g\u00e9n\u00e9ral). | \u25b8 2 points : suivi par sous-comptage des principaux postes de consommation. | \u25b8 3 points : suivi par sous-comptage avec analyse p\u00e9riodique et plan d\u2019actions. | \u25b8 5 points : suivi par GTB (Gestion Technique du B\u00e2timent) avec alertes automatis\u00e9es en cas de d\u00e9rive.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Relev\u00e9s de consommation d\u2019\u00e9nergie (factures, compteurs). | Description du syst\u00e8me de sous-comptage. | Analyses p\u00e9riodiques des consommations et plans d\u2019actions. | Description du syst\u00e8me GTB et param\u00e9trage des alertes le cas \u00e9ch\u00e9ant.</td><td>Sans objet</td></tr></table>"},
"GD4.1.2":{attendu:"Mettre en place un suivi des consommations d\u2019eau.",definition:"Cinq niveaux de suivi des consommations d\u2019eau : | \u25b8 0 point : pas de suivi. | \u25b8 1 point : suivi global des consommations d\u2019eau (compteur g\u00e9n\u00e9ral). | \u25b8 2 points : suivi par sous-comptage des principaux postes de consommation. | \u25b8 3 points : suivi par sous-comptage avec analyse p\u00e9riodique et plan d\u2019actions. | \u25b8 5 points : suivi par GTB avec alertes automatis\u00e9es en cas de d\u00e9rive.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Relev\u00e9s de consommation d\u2019eau (factures, compteurs). | Description du syst\u00e8me de sous-comptage. | Analyses p\u00e9riodiques des consommations et plans d\u2019actions. | Description du syst\u00e8me GTB et param\u00e9trage des alertes le cas \u00e9ch\u00e9ant.</td><td>Sans objet</td></tr></table>"},
"GD4.1.3":{attendu:"Mettre en place un suivi de la qualit\u00e9 de l\u2019air int\u00e9rieur (QAI).",definition:"Sept niveaux de suivi de la QAI, allant de la simple balise CO2 aux audits complets avec suivi des moisissures : | \u25b8 1 point : pr\u00e9sence d\u2019au moins une balise CO2 dans un local repr\u00e9sentatif. | \u25b8 2 points : pr\u00e9sence de balises CO2 dans les locaux \u00e0 forte occupation. | \u25b8 3 points : suivi en continu du CO2 avec alertes en cas de d\u00e9passement. | \u25b8 4 points : suivi en continu du CO2 et de la temp\u00e9rature avec analyse p\u00e9riodique. | \u25b8 5 points : audit QAI p\u00e9riodique (mesures de polluants). | \u25b8 6 points : audit QAI complet avec plan d\u2019actions correctives. | \u25b8 7 points : niveau pr\u00e9c\u00e9dent ET suivi des moisissures.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Description du syst\u00e8me de suivi QAI (type de capteurs, localisation). | Relev\u00e9s de mesures CO2, temp\u00e9rature, polluants. | Rapports d\u2019audits QAI. | Plans d\u2019actions correctives. | Rapports de suivi des moisissures le cas \u00e9ch\u00e9ant.</td><td>Sans objet</td></tr></table>"},
"GD4.1.4":{attendu:"Mettre en place un suivi de la qualit\u00e9 de l\u2019air dans les parkings souterrains.",definition:"\u25b8 0 point : suivi r\u00e9glementaire uniquement (CO). | \u25b8 1 point : suivi r\u00e9glementaire ET suivi d\u2019au moins un polluant suppl\u00e9mentaire (NO2, particules fines, etc.).",non_applicabilite:"Si le b\u00e2timent ne dispose pas de parking souterrain, l\u2019exigence est non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Relev\u00e9s de mesures de la qualit\u00e9 de l\u2019air dans les parkings. | Description du syst\u00e8me de suivi (capteurs, polluants mesur\u00e9s).</td><td>Sans objet</td></tr></table>"},
"GD4.2.1":{attendu:"R\u00e9duire les consommations d\u2019\u00e9nergie du b\u00e2timent.",definition:"Justification d\u2019une r\u00e9duction des consommations d\u2019\u00e9nergie par rapport \u00e0 une consommation de r\u00e9f\u00e9rence. Deux m\u00e9thodes sont possibles : | \u25b8 M\u00e9thode simplifi\u00e9e : comparaison des consommations r\u00e9elles sur deux p\u00e9riodes (avant/apr\u00e8s actions d\u2019am\u00e9lioration), avec correction climatique. | \u25b8 M\u00e9thode d\u00e9taill\u00e9e : comparaison par rapport \u00e0 une consommation de r\u00e9f\u00e9rence calcul\u00e9e (simulation \u00e9nerg\u00e9tique, annexe environnementale). | Niveaux de notation : NA/0/4/5/6/8/10 points selon le pourcentage de r\u00e9duction atteint (5% \u00e0 30%). | P\u00e9rim\u00e8tre : tous usages \u00e9nerg\u00e9tiques du b\u00e2timent (hors process sp\u00e9cifiques le cas \u00e9ch\u00e9ant).",non_applicabilite:"Si le b\u00e2timent est neuf ou r\u00e9cemment livr\u00e9 (moins de 2 ans d\u2019exploitation), l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Consommations de r\u00e9f\u00e9rence et consommations r\u00e9elles. | Description de la m\u00e9thode utilis\u00e9e (simplifi\u00e9e ou d\u00e9taill\u00e9e). | Justification de la correction climatique le cas \u00e9ch\u00e9ant. | Justification du pourcentage de r\u00e9duction atteint.</td><td>Sans objet</td></tr></table>"},
"GD4.2.2":{attendu:"R\u00e9duire les consommations d\u2019eau du b\u00e2timent.",definition:"Justification d\u2019une r\u00e9duction des consommations d\u2019eau par rapport \u00e0 une consommation de r\u00e9f\u00e9rence. | Niveaux de notation : NA/0/1-5 points selon le pourcentage de r\u00e9duction atteint (5% \u00e0 30%).",non_applicabilite:"Si le b\u00e2timent est neuf ou r\u00e9cemment livr\u00e9 (moins de 2 ans d\u2019exploitation), l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Consommations de r\u00e9f\u00e9rence et consommations r\u00e9elles d\u2019eau. | Justification du pourcentage de r\u00e9duction atteint. | Description des actions d\u2019\u00e9conomie d\u2019eau mises en \u0153uvre.</td><td>Sans objet</td></tr></table>"},
"GD4.2.3":{attendu:"Mettre en place un service d\u2019efficacit\u00e9 \u00e9nerg\u00e9tique ou un Contrat de Performance \u00c9nerg\u00e9tique (CPE).",definition:"Trois niveaux : | \u25b8 1 point : mise en place d\u2019un service d\u2019efficacit\u00e9 \u00e9nerg\u00e9tique avec suivi des consommations et recommandations d\u2019am\u00e9lioration. | \u25b8 2 points : mise en place d\u2019un CPE avec engagement contractuel de r\u00e9duction des consommations. | \u25b8 3 points : CPE avec clause d\u2019int\u00e9ressement (partage des \u00e9conomies r\u00e9alis\u00e9es). | D\u00e9finition du CPE : les Contrats de Performance \u00c9nerg\u00e9tique sont d\u00e9finis par la Directive Europ\u00e9enne 2012/27/UE comme un accord contractuel entre le b\u00e9n\u00e9ficiaire et le fournisseur d\u2019une mesure visant \u00e0 am\u00e9liorer l\u2019efficacit\u00e9 \u00e9nerg\u00e9tique. | Types de march\u00e9s : M.F. (forfait), M.T. (forfait climatique), M.C. (compteur), C.P. (combustible + entretien), P.F. (exploitation sans fourniture d\u2019\u00e9nergie).",reglementation:"Directive europ\u00e9enne 2012/27/UE relative \u00e0 l\u2019efficacit\u00e9 \u00e9nerg\u00e9tique. | Fascicule FDX 60 000 d\u2019AFNOR. | CEREMA - Fiche n\u00b0 02 (avril 2015).",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Contrat de service d\u2019efficacit\u00e9 \u00e9nerg\u00e9tique ou CPE. | Rapports de suivi des performances \u00e9nerg\u00e9tiques. | Justification du type de march\u00e9 et des clauses d\u2019int\u00e9ressement le cas \u00e9ch\u00e9ant.</td><td>Sans objet</td></tr></table>"},
"GD4.2.4":{attendu:"Mettre en place un syst\u00e8me d\u2019alertes sur les consommations d\u2019\u00e9nergie et d\u2019eau.",definition:"\u25b8 2 points : syst\u00e8me d\u2019alertes automatis\u00e9es sur les consommations d\u2019\u00e9nergie (d\u00e9passement de seuils, d\u00e9rives anormales). | \u25b8 3 points : syst\u00e8me d\u2019alertes automatis\u00e9es sur les consommations d\u2019\u00e9nergie ET d\u2019eau.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Description du syst\u00e8me d\u2019alertes (param\u00e9trage des seuils, destinataires des alertes). | Exemples d\u2019alertes g\u00e9n\u00e9r\u00e9es et actions correctives mises en \u0153uvre.</td><td>Sans objet</td></tr></table>"},
"GD4.2.5":{attendu:"Mettre en place des dispositions de pr\u00e9vention du risque l\u00e9gionelles.",definition:"\u25b8 0 point : non atteint. | \u25b8 1 point : suivi des temp\u00e9ratures de l\u2019eau chaude sanitaire aux points critiques (d\u00e9part production, retour de boucle, points d\u2019usage les plus d\u00e9favoris\u00e9s). | \u25b8 2 points : niveau pr\u00e9c\u00e9dent ET suivi en temps r\u00e9el des temp\u00e9ratures avec alertes en cas de d\u00e9rive. | \u25b8 3 points : niveau pr\u00e9c\u00e9dent ET mise en place d\u2019un carnet sanitaire avec analyse des risques li\u00e9s aux l\u00e9gionelles (r\u00e9seaux a\u00e9rauliques et hydrauliques). | R\u00e9glementation : analyses de l\u00e9gionelles une fois par an minimum aux points recommand\u00e9s. Seuils d\u2019alerte et d\u2019action d\u00e9finis par la r\u00e9glementation. Analyses par laboratoire accr\u00e9dit\u00e9 EA. Norme NF T 90-431.",reglementation:"Code de la sant\u00e9 publique (articles L. 1321-1 et suivants). | Arr\u00eat\u00e9 du 1er f\u00e9vrier 2010 relatif \u00e0 la surveillance des l\u00e9gionelles. | Circulaire DGS n\u00b0 2002/273 du 2 mai 2002. | Norme NF T 90-431 (ao\u00fbt 2017).",non_applicabilite:"Si le b\u00e2timent ne dispose pas de r\u00e9seau d\u2019eau chaude sanitaire, l\u2019exigence peut \u00eatre d\u00e9clar\u00e9e comme non applicable.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Relev\u00e9s de temp\u00e9ratures aux points critiques. | R\u00e9sultats d\u2019analyses de l\u00e9gionelles. | Description du syst\u00e8me de suivi en temps r\u00e9el le cas \u00e9ch\u00e9ant. | Carnet sanitaire avec analyse des risques le cas \u00e9ch\u00e9ant.</td><td>Sans objet</td></tr></table>"},
"GD4.3.1":{attendu:"Mettre en place un reporting global des performances environnementales du b\u00e2timent.",definition:"Production d\u2019un document de reporting global synth\u00e9tisant les performances environnementales du b\u00e2timent : consommations d\u2019\u00e9nergie et d\u2019eau, qualit\u00e9 de l\u2019air int\u00e9rieur, gestion des d\u00e9chets, satisfaction des occupants, etc.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Document de reporting global. | Indicateurs de performance suivis. | P\u00e9riodicit\u00e9 du reporting.</td><td>Sans objet</td></tr></table>"},
"GD4.3.2":{attendu:"Mettre en place un carnet sanitaire du b\u00e2timent.",definition:"\u25b8 1 point : carnet sanitaire r\u00e9glementaire couvrant les installations a\u00e9rauliques et hydrauliques du b\u00e2timent. | \u25b8 2 points : carnet sanitaire avec analyse des risques et actions correctives/pr\u00e9ventives couvrant les installations a\u00e9rauliques et hydrauliques. | Premier niveau (carnet sanitaire r\u00e9glementaire) : installation a\u00e9raulique (contr\u00f4le p\u00e9riodique des installations d\u2019a\u00e9ration conform\u00e9ment \u00e0 l\u2019arr\u00eat\u00e9 du 8 octobre 1987) et installation hydraulique (pr\u00e9vention des l\u00e9gionelles selon la r\u00e9glementation en vigueur). | Deuxi\u00e8me niveau (carnet sanitaire avec analyse des risques) : analyse des risques inh\u00e9rents \u00e0 l\u2019installation (a\u00e9raulique et hydraulique), identification des anomalies, dispositions pr\u00e9ventives/correctives.",reglementation:"Arr\u00eat\u00e9 du 8 octobre 1987 relatif au contr\u00f4le p\u00e9riodique des installations d\u2019a\u00e9ration. | Code du Travail (articles R4222-20 \u00e0 R4222-22). | Code de la sant\u00e9 publique (l\u00e9gionelles). | Arr\u00eat\u00e9 du 1er f\u00e9vrier 2010.",preuve:"<table class=\"pp-tbl\"><tr><th>Phases</th><th>Documents</th><th>Points v\u00e9rifi\u00e9s a minima</th></tr><tr><td><strong>Phase Exploitation axe Gestion</strong></td><td>Carnet sanitaire (a\u00e9raulique et hydraulique). | Rapports de contr\u00f4les p\u00e9riodiques. | Analyse des risques sanitaires le cas \u00e9ch\u00e9ant. | Plans d\u2019actions correctives et pr\u00e9ventives.</td><td>Sans objet</td></tr></table>"}
};
